/****** Object:  StoredProcedure [dbo].[cscp_20AbbeyFailures]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_20AbbeyFailures] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'CASE ID'
      , NULL AS 'JOB TYPE'
      , NULL AS 'COMPANY'
      , NULL AS 'PLAN'
      , NULL AS 'PRODUCT'
      , NULL AS 'INITIAL DECISION DATE'
      , NULL AS 'FINAL DECISION DATE'
      , NULL AS 'FINAL DECISION'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END
SELECT distinct Policies.PolicyRef AS 'CASE ID',
      (CASE WHEN ltrim(rtrim(TrackGroups.NBCCComments)) Like 'Abbey Replacement%' AND ltrim(rtrim(msit_AgentJobHistory.Job))<>'EXABBEY' THEN ''
    ELSE  msit_AgentJobHistory.Job
    END)    AS 'JOB TYPE',
       Policies.CompanyName AS 'COMPANY',
       Policies.PlanDescription AS 'PLAN',
       Products.ProductName AS 'PRODUCT',
       CONVERT(VARCHAR, TrackGroups.CaseCheckValidatedDate, 103) AS 'INITIAL DECISION DATE',
       CONVERT(VARCHAR, TrackGroups.FinalCheckValidatedDate, 103) AS 'FINAL DECISION DATE',
       TrackGroups.NBCCFinalStatus AS 'FINAL DECISION'
FROM msit_TrackGroups TrackGroups
INNER JOIN mstt_Policies Policies ON TrackGroups.PolicyID = Policies.POL_NUM
LEFT JOIN mstt_CodeBIProducts Products ON Policies.ProductCode = Products.ProductCode
LEFT JOIN mstt_Clients ON mstt_Clients.CLIENT_NUM = TrackGroups.ClientID 
LEFT JOIN mstt_Agents ON mstt_Clients.REFER = mstt_Agents.CODE
LEFT JOIN msit_AgentJobHistory ON mstt_Agents.Code=msit_AgentJobHistory.AgentCode
WHERE TrackGroups.NBCCHeaderID IS NOT NULL
  AND TrackGroups.NBCCFinalStatus in ('Fail', 'Rejected')
  AND TrackGroups.Description like 'case check for%'
  AND CAST(CONVERT(NVARCHAR, TrackGroups.finalcheckvalidateddate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @startdate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, TrackGroups.finalcheckvalidateddate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @enddate, 112) AS DATETIME) 
  AND (TrackGroups.policyid IN (SELECT DISTINCT TrackGroups_comment.policyid
                                FROM msit_trackgroups TrackGroups_comment
                                WHERE TrackGroups_comment.NBCCComments like 'Abbey Replacement%'
                               ) OR
       msit_AgentJobHistory.Job = 'EXABBEY')
ORDER BY Policies.PolicyRef

GO
/****** Object:  StoredProcedure [dbo].[cscp_21AbbeyOutstanding]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_21AbbeyOutstanding] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'CASE ID'
      , NULL AS 'COMPANY'
      , NULL AS 'PLAN'
      , NULL AS 'PRODUCT'
      , NULL AS 'INITIAL DECISION DATE'
      , NULL AS 'AGENT CODE'
      , NULL AS 'JOB TYPE'
      , NULL AS 'CASE STATUS'
      , NULL AS 'COMMENTS'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END
SELECT Policies.PolicyRef AS 'CASE ID',
       Policies.CompanyName AS 'COMPANY',
       Policies.PlanDescription AS 'PLAN',
       Products.ProductName AS 'PRODUCT',
       CONVERT(VARCHAR, TrackGroupsMain.CaseCheckValidatedDate, 103) AS 'INITIAL DECISION DATE',
       Agents.Code AS 'AGENT CODE',
       (CASE WHEN (TrackGroupsMain.NBCCComments like 'Abbey Replacement%' and agentjobhistory.job <> 'EXABBEY') then '' 
             ELSE agentjobhistory.Job 
        END) AS 'JOB TYPE',
       (case when TrackGroupsMain.description like 'Decide if response received within 10 days%' then 'REPLY OUTSTANDING'
                when TrackGroupsMain.description like 'Decide if response received within 20 days%' then 'CHASED REPLY OUTSTANDING'
                when TrackGroupsMain.description like 'Decide if reply received to 2nd reminder%' then 'CHASED PHONE CALL REPLY OUTSTANDING'
        end) AS 'CASE STATUS',
       TrackGroupsMain.NBCCComments AS 'COMMENTS',
       '' AS [Error] 
FROM msit_TrackGroups TrackGroupsMain
INNER JOIN msit_TrackItems TrackItems ON TrackItems.TrackGroupID = TrackGroupsMain.ID
INNER JOIN mstt_Policies Policies ON TrackGroupsMain.PolicyID = Policies.POL_NUM
LEFT JOIN mstt_CodeBIProducts Products ON Policies.ProductCode = Products.ProductCode
LEFT JOIN mstt_Clients ON mstt_Clients.CLIENT_NUM = TrackGroupsMain.ClientID 
LEFT JOIN mstt_Agents Agents ON mstt_Clients.REFER = Agents.CODE
LEFT JOIN msit_AgentJobHistory AgentJobHistory ON Agents.Code = AgentJobHistory.AgentCode
WHERE (TrackGroupsMain.policyid IN (SELECT DISTINCT trackgroups_comment.policyid
                                    FROM msit_trackgroups trackgroups_comment
                                    WHERE trackgroups_comment.NBCCComments like 'Abbey Replacement%'
                                    ) OR
       AgentJobHistory.job = 'EXABBEY')
AND (TrackGroupsMain.description like 'Decide if response received within 10 days%' or
     TrackGroupsMain.description like 'Decide if response received within 20 days%' or
     TrackGroupsMain.description like 'Decide if reply received to 2nd reminder%')
AND TrackItems.CompletedState = 0 -- outstanding
AND TrackGroupsMain.policyid IN 
(SELECT DISTINCT trackgroups_inner.policyid
 FROM msit_trackgroups trackgroups_inner
 WHERE trackgroups_inner.nbccheaderid is not null
 AND trackgroups_inner.description LIKE 'case check for%'
 AND cast(convert(nvarchar, trackgroups_inner.casecheckvalidateddate, 112) as datetime) >= cast(convert(nvarchar, @startdate, 112) as datetime)
 AND cast(convert(nvarchar, trackgroups_inner.casecheckvalidateddate, 112) as datetime) <= cast(convert(nvarchar, @enddate, 112) as datetime) 
)
ORDER BY Policies.PolicyRef

GO
