CREATE PROCEDURE [dbo].[cscp_2YearPaymentTerm] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
  NULL AS [Individual Name],
  NULL AS [Individual ID],
  NULL AS [Product Code],
  NULL AS [Plan Number],
  NULL AS [Case ID],
 NULL  AS [Division],
 NULL AS [Practice Name],
 NULL AS [Practice ID],
  CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END
SELECT 
   ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Individual Name]
 , Agents.Code as [Individual Id] 
 , PolicyTransaction.CommProductCode as [Product Code]
 , Policies.Cont_Num as [Plan Number]
 , Policies.PolicyRef as [Case ID]
 , AgencyNumbers.Division as [Division]
 , Practice.TradingName as [Practice Name]
 , Practice.Code as [Practice ID]
 , NULL AS [Error]
FROM 
   mstt_PolicyTransactions PolicyTransaction
   INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransaction.PolicyID 
   INNER JOIN mstt_Agents Agents ON Agents.Code = PolicyTransaction.AgentCode
   INNER JOIN mstt_AgentAgencyNumbers AgencyNumbers ON AgencyNumbers.AgentCode = COALESCE (Agents.FranchiseCode, Agents.AccessAgentCode,Agents.DirectlyAuthorisedCode,Agents.PFACompanyCode,Agents.StrategicAllianceCode)
   LEFT JOIN  mstt_Agents Practice ON COALESCE (Agents.FranchiseCode, Agents.AccessAgentCode,Agents.DirectlyAuthorisedCode,Agents.PFACompanyCode,Agents.StrategicAllianceCode) =  Practice.Code
WHERE PolicyTransaction.TransType = 39
  AND PolicyTransaction.ProductProviderCode = 'ZURICH NEW'
  AND CAST(CONVERT(NVARCHAR, PolicyTransaction.TransactionDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, PolicyTransaction.TransactionDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
  AND PolicyTransaction.ReportingProductCode NOT IN (8,48)
  AND AgencyNumbers.Division IS NOT NULL AND RTRIM(LTRIM(AgencyNumbers.Division)) <> ''
ORDER BY Agents.Code, Policies.PolicyRef

GO
