SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO


CREATE PROCEDURE [dbo].[cscp_62aOutstandingSuspenseStats] @UserID VARCHAR(255), @Comp_Code VARCHAR(10), @ValueBand VARCHAR(32), @UnallocReason VARCHAR(8), @Policy VARCHAR(36)
AS
/*  PR 10 Oct

  Changes for OriginatingSource
*/

SELECT EDI.ID AS [EDI_ID], -- used for grouping purposes only
       EDI.PolicyNumber AS [Policy],
       EDI.Initials AS [Inits],
       EDI.Surname AS [Surname],
       CAST(EDI.AmountReceived AS DECIMAL(15,2)) AS [Amount],
       CASE 
          WHEN EDI.AmountReceived < 0 THEN 'Negative'
          WHEN EDI.AmountReceived >= 0 AND EDI.AmountReceived < 10 THEN 'Less Than 10'
          WHEN EDI.AmountReceived >= 10 AND EDI.AmountReceived < 100 THEN 'Less Than 100' 
          WHEN EDI.AmountReceived >= 100 AND EDI.AmountReceived < 500 THEN 'Less Than 500'
          WHEN EDI.AmountReceived >= 500 AND EDI.AmountReceived < 1000 THEN 'Less Than 1000'
          WHEN EDI.AmountReceived >= 1000 THEN 'More Than 1000'
       END AS [ValueBand],
       CONVERT(VARCHAR, EDI.CommissionDueDate, 103) AS [DueDate],
       CONVERT(VARCHAR, EDI.CommissionReceivedDate, 103) AS [RecDate],
       UPPER(SUBSTRING(DATENAME(MONTH, EDI.CommissionReceivedDate), 1, 3)) AS [RecMonth],
       EDI.IFAReference AS [IFARef],
       EDI.IFAReferenceNumber AS [IFARefNo],
       CASE EDI.PaymentFrequency
          WHEN 'X' THEN 'IT'
          WHEN 'M' THEN 'Mth'
          WHEN 'A' THEN 'Ann'
          WHEN 'S' THEN 'Sin'
          ELSE 'Unk'
       END AS [PayFreq],
       CASE EDI.PaymentType
          WHEN 1 THEN 'Comm'
          WHEN 4 THEN 'Claw'
          WHEN 99 THEN 'Adj'
          ELSE 'Unk'
       END AS [PayType],

       STMTCT.Statement AS [Statement],
       CONVERT(VARCHAR, STMTCT.Stmnt_Date, 103) AS [StateDate],
       CASE STMTCT.State
          WHEN 1 THEN 'Unproc'
          WHEN 2 THEN 'Proc'
          ELSE 'Unk'
       END AS [Process],
       STMTCT.Comp_Code AS [Provider],

       Expectation1.ID AS [Expectation1_ID], -- used for grouping purposes only
       Expectation1.UnallocatedReasonCode AS [UnallocReason],

       Policies.Pol_Num AS [Policy_ID], -- used for grouping purposes only
       Policies.Policyref AS [CaseID],
       Policies.Cont_Num AS [ProviderPolNo],
       Policies.ProductCode AS [ProductCode],
       CASE
          WHEN Policies.OriginatingSource = 2 THEN CONVERT(VARCHAR, Policies.Prop_Date, 103) --use Proposal Date for ETi cases as Create Date not populated
          ELSE CONVERT(VARCHAR, Policies.CreateDate, 103)
       END AS [CreateDate],
       CASE
          WHEN Policies.OriginatingSource = 2 AND Policies.Prop_Date IS NOT NULL THEN 'Loaded' --use Proposal Date for ETi cases as Create Date not populated
          WHEN (Policies.OriginatingSource <> 2 OR Policies.OriginatingSource IS NULL) AND Policies.CreateDate IS NOT NULL THEN 'Loaded'
          ELSE ''
       END AS [OnSwift],
       CASE Policies.Replacement 
          WHEN 1 THEN 'RepA'
          WHEN 2 THEN 'RepB'
          WHEN 3 THEN 'RepC'
       END AS [Repl],
       CASE Policies.OriginatingSource
          WHEN 1 THEN 'Man'
          WHEN 2 THEN 'ETi'
          WHEN 3 THEN 'OTPm'
          WHEN 4 THEN 'OTPc'
       END AS [Source]

FROM msit_EDIFACTCommissionStatementContents EDI
INNER JOIN mstt_Expectation Expectation1 ON Expectation1.ID = EDI.Pacc_ID
LEFT JOIN mstt_Policies Policies ON Policies.Cont_Num = EDI.PolicyNumber
LEFT JOIN msit_S_STMTCT STMTCT ON STMTCT.Statement = Expectation1.Statement

WHERE Expectation1.Type IN (5, 6)
  AND Expectation1.INIT_ID IS NULL
  AND (@Comp_Code = 'ALL' 
       OR STMTCT.Comp_Code = @Comp_Code)
  AND (@ValueBand = 'ALL' 
       OR (EDI.AmountReceived < 0 AND @ValueBand = 'Negative')
       OR (EDI.AmountReceived >= 0 AND EDI.AmountReceived < 10 AND @ValueBand = 'Less Than 10')
       OR (EDI.AmountReceived >= 10 AND EDI.AmountReceived < 100 AND @ValueBand = 'Less Than 100')
       OR (EDI.AmountReceived >= 100 AND EDI.AmountReceived < 500 AND @ValueBand = 'Less Than 500')
       OR (EDI.AmountReceived >= 500 AND EDI.AmountReceived < 1000 AND @ValueBand = 'Less Than 1000')
       OR (EDI.AmountReceived >= 1000 AND @ValueBand = 'More Than 1000'))
  AND (@UnallocReason = 'ALL' 
       OR Expectation1.UnallocatedReasonCode = @UnallocReason)
  AND (@Policy = 'ALL' 
       OR EDI.PolicyNumber = @Policy)

ORDER BY EDI.PolicyNumber, STMTCT.Statement, Expectation1.ID


GO
/****** Object:  StoredProcedure [dbo].[cscp_62aPolicyList]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
