GO
CREATE PROCEDURE [dbo].[cscp_62bOutstandingSuspensePolicyMatches] @UserID VARCHAR(255), @Comp_Code VARCHAR(10), @UnallocReason VARCHAR(8), @Policy VARCHAR(36)
AS
/*  PR 10 Oct
  Changes for OriginatingSource
*/

/*  
02/07/2010  M Cawood    Replace mstt_transagentsplithierarchyhistory by 
                        sa_swift_transagentsplithierarchyhistory.
*/

SELECT EDI.ID AS [EDI_ID], -- used for grouping purposes only
       EDI.PolicyNumber AS [Policy],
       EDI.Initials AS [Inits],
       EDI.Surname AS [Surname],
       CAST(EDI.AmountReceived AS DECIMAL(15,2)) AS [Amount],
       CONVERT(VARCHAR, EDI.CommissionDueDate, 103) AS [DueDate],
       CONVERT(VARCHAR, EDI.CommissionReceivedDate, 103) AS [RecDate],
       UPPER(SUBSTRING(DATENAME(MONTH, EDI.CommissionReceivedDate), 1, 3)) AS [RecMonth],
       EDI.IFAReference AS [IFARef],
       EDI.IFAReferenceNumber AS [IFARefNo],
       CASE EDI.PaymentFrequency
          WHEN 'X' THEN 'IT'
          WHEN 'M' THEN 'Mth'
          WHEN 'A' THEN 'Ann'
          WHEN 'S' THEN 'Sin'
          ELSE 'Unk'
       END AS [PayFreq],
       CASE EDI.PaymentType
          WHEN 1 THEN 'Comm'
          WHEN 4 THEN 'Claw'
          WHEN 99 THEN 'Adj'
          ELSE 'Unk'
       END AS [PayType],

       STMTCT.Statement AS [Statement],
       CONVERT(VARCHAR, STMTCT.Stmnt_Date, 103) AS [StateDate],
       CASE STMTCT.State
          WHEN 1 THEN 'Unproc'
          WHEN 2 THEN 'Proc'
          ELSE 'Unk'
       END AS [Process],
       STMTCT.Comp_Code AS [Provider],

       Expectation2.ID AS [Expectation2_ID], -- used for grouping purposes only
       CAST(Expectation2.Amount_Due AS DECIMAL(15,2)) AS [AmountDue],
       (CAST(Expectation2.Amount_Due AS DECIMAL(15,2)) - CAST(EDI.AmountReceived AS DECIMAL(15,2))) AS [Difference],
       CAST((100 * (CAST(Expectation2.Amount_Due AS DECIMAL(15,2)) - CAST(EDI.AmountReceived AS DECIMAL(15,2))) / CAST(EDI.AmountReceived AS DECIMAL(15,2))) AS DECIMAL(15,2)) AS [DifferencePercent],
       CONVERT(VARCHAR, Expectation2.Date_Due, 103) AS [ExpDueDate],
       Expectation2.Type_Description AS [Type],
       Expectation2.StatusDescription AS [Status],

       Expectation1.ID AS [Expectation1_ID], -- used for grouping purposes only
       Expectation1.UnallocatedReasonCode AS [UnallocReason],

       Policies.Pol_Num AS [Policy_ID], -- used for grouping purposes only
       Policies.Policyref AS [CaseID],
       Policies.Cont_Num AS [ProviderPolNo],
       Policies.ProductCode AS [ProductCode],
       CASE
          WHEN Policies.OriginatingSource = 2 THEN CONVERT(VARCHAR, Policies.Prop_Date, 103) --use Proposal Date for ETi cases as Create Date not populated
          ELSE CONVERT(VARCHAR, Policies.CreateDate, 103)
       END AS [CreateDate],
       CASE
          WHEN Policies.OriginatingSource = 2 AND Policies.Prop_Date IS NOT NULL THEN 'Loaded' --use Proposal Date for ETi cases as Create Date not populated
          WHEN (Policies.OriginatingSource <> 2 OR Policies.OriginatingSource IS NULL) AND Policies.CreateDate IS NOT NULL THEN 'Loaded'
          ELSE ''
       END AS [OnSwift],
       CASE Policies.Replacement 
          WHEN 1 THEN 'RepA'
          WHEN 2 THEN 'RepB'
          WHEN 3 THEN 'RepC'
       END AS [Repl],
       CASE Policies.OriginatingSource
          WHEN 1 THEN 'Man'
          WHEN 2 THEN 'ETi'
          WHEN 3 THEN 'OTPm'
          WHEN 4 THEN 'OTPc'
       END AS [Source],

       PolicyTransactions.ID AS [Tran_ID], -- used for grouping purposes only
       CONVERT(VARCHAR, PolicyTransactions.TransactionDate, 103) AS [TranDate],
       PolicyTransactions.AgentCode AS [Agent],
       CAST(PolicyTransactions.Amount AS DECIMAL(15,2)) AS [Premium],
       CAST(PolicyTransactions.CommInitialAmount AS DECIMAL(15,2)) AS [DA],
       PolicyTransactions.CommInitialPeriod AS [IP],
       CASE PolicyTransactions.commtype 
          WHEN 'F' THEN 'Accr'
          WHEN 'L' THEN 'Lvl'
          WHEN 'T' THEN 'IT'
          ELSE 'Unk'
       END AS [Basis],
       PolicyTransactions.FrequencyDescription AS [Freq],

       Agents.Code AS [SellerUID],
       ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [SellerName],
       Agents.AgentTypeDescription AS [SellerType],

       Agents2.Code AS [BusinessUID],
       COALESCE(Agents2.TradingName, Agents2.Descn) AS [BusinessName],
       Agents2.AgentTypeDescription AS [BusinessType],

       COALESCE(TASH.FranchiseAgentCode, TASH.AccessAgentCode, TASH.DirectlyAuthorisedAgentCode) AS [SaleBusinessUID]


FROM msit_EDIFACTCommissionStatementContents EDI
INNER JOIN mstt_Expectation Expectation1 ON Expectation1.ID = EDI.Pacc_ID
LEFT JOIN mstt_Policies Policies ON Policies.Cont_Num = EDI.PolicyNumber
LEFT JOIN msit_S_STMTCT STMTCT ON STMTCT.Statement = Expectation1.Statement
LEFT JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.PolicyID = Policies.Pol_Num
                                                    AND PolicyTransactions.TransType in (1, 17)
LEFT JOIN mstt_Expectation Expectation2 ON Expectation2.TransactionID = PolicyTransactions.ID
                                       AND CAST(CONVERT(NVARCHAR, Expectation2.Date_Due, 112) AS DATETIME) < CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME)
                                       AND Expectation2.Status = 1
LEFT JOIN mstt_Agents Agents on Agents.Code = PolicyTransactions.AgentCode 
LEFT JOIN mstt_Agents Agents2 on Agents2.Code = Agents.Firm 
LEFT JOIN sa_swift_transagentsplithierarchyhistory TASH ON PolicyTransactions.ID = TASH.TransactionID     --MPC 02/07/2010
                                                   AND PolicyTransactions.AgentCode = TASH.AgentCode
                                                   AND TASH.CommissionType = 1

WHERE Expectation1.Type IN (5, 6)
  AND Expectation1.INIT_ID IS NULL
  AND EXISTS (SELECT Policies.Cont_Num 
              FROM mstt_Policies Policies
              WHERE RTRIM(EDI.PolicyNumber) <> ''
                AND EDI.PolicyNumber IS NOT NULL
                AND Policies.Cont_Num = EDI.PolicyNumber
             )
  AND (@Comp_Code = 'ALL' 
       OR STMTCT.Comp_Code = @Comp_Code)
  AND (@UnallocReason = 'ALL' 
       OR Expectation1.UnallocatedReasonCode = @UnallocReason)
  AND (@Policy = 'ALL' 
       OR EDI.PolicyNumber = @Policy)

ORDER BY EDI.PolicyNumber, Expectation1.ID




GO
