SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- Get the relevant track items, competence details and manager details for each agent beneath the agent code passed in
CREATE PROCEDURE [dbo].[cscp_AbandonedEvents] @UserID VARCHAR(255), @AgentCode CHAR(7), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Query name'
      , NULL AS 'Agent code'
      , NULL AS 'Agent name'
      , NULL AS 'Competence'
      , NULL AS 'Manager 4 name'
      , NULL AS 'Mgr4 code'
      , NULL AS 'Manager 3 name'
      , NULL AS 'Mgr3 code'
      , NULL AS 'Manager 2 name'
      , NULL AS 'Mgr2 code'
      , NULL AS 'Manager 1 name'
      , NULL AS 'Mgr1 code'
      , NULL AS 'Sales supervisor'
      , NULL AS 'Sales code'
      , NULL AS 'Span supervisor'
      , NULL AS 'Span code'
      , NULL AS 'Description'
      , NULL AS 'DueDate'
      , NULL AS 'Outcome'
      , NULL AS 'CompletionDate'
      , NULL AS 'CompletedBy'
      , NULL AS 'Notes'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS 'Error'
   RETURN 0
END
IF (CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
BEGIN
  SELECT 
        NULL AS 'Query name'
      , NULL AS 'Agent code'
      , NULL AS 'Agent name'
      , NULL AS 'Competence'
      , NULL AS 'Manager 4 name'
      , NULL AS 'Mgr4 code'
      , NULL AS 'Manager 3 name'
      , NULL AS 'Mgr3 code'
      , NULL AS 'Manager 2 name'
      , NULL AS 'Mgr2 code'
      , NULL AS 'Manager 1 name'
      , NULL AS 'Mgr1 code'
      , NULL AS 'Sales supervisor'
      , NULL AS 'Sales code'
      , NULL AS 'Span supervisor'
      , NULL AS 'Span code'
      , NULL AS 'Description'
      , NULL AS 'DueDate'
      , NULL AS 'Outcome'
      , NULL AS 'CompletionDate'
      , NULL AS 'CompletedBy'
      , NULL AS 'Notes'
      , 'Start Date cannot be greater than End Date' AS 'Error'
   RETURN 0
END
SELECT  (SELECT     ISNULL(RTRIM(SUBSTRING(mstt_Agents.Firstnames, 1, PATINDEX('%[^ ] %',mstt_Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_Agents.Name), '')
        FROM        mstt_Agents WHERE      code = @AgentCode) AS 'Query name', 
  mstt_AgentsMain.CODE AS 'Agent code', 
        ISNULL(RTRIM(SUBSTRING(mstt_AgentsMain.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsMain.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsMain.Name) , '') AS 'Agent name', 
  (SELECT dbo.cscf_GetAgentCompetencies(mstt_AgentsMain.ID, GetDate())) AS 'Competence',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM4.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM4.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM4.Name) , '') AS 'Manager 4 name',
  mstt_AgentsM4.code  AS 'Mgr4 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM3.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM3.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM3.Name) , '') AS 'Manager 3 name', 
  mstt_AgentsM3.code  AS 'Mgr3 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM2.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM2.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM2.Name) , '') AS 'Manager 2 name',
  mstt_AgentsM2.code  AS 'Mgr2 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM1.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM1.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM1.Name) , '') AS 'Manager 1 name', 
  mstt_AgentsM1.code  AS 'Mgr1 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsSa.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsSa.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsSa.Name) , '') AS 'Sales supervisor', 
  mstt_AgentsSa.code  AS 'Sales code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsSp.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsSp.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsSp.Name) , '')  AS 'Span supervisor', 
  mstt_AgentsSp.code  AS 'Span code',
  msit_TrackItems.Description AS 'Description',
  CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 103) AS NVARCHAR) AS 'DueDate',
  CASE msit_TrackItems.completedstate
  WHEN 1 THEN 'Successful'
  WHEN 2 THEN 'Abandoned'
  ELSE ' '
  END AS 'Outcome',
  CASE WHEN  CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME)
  THEN CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR) + 'L'
  WHEN msit_TrackItems.ClearedDate IS NULL THEN ''
  ELSE CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR)
  END AS 'CompletionDate',
  CompletedUsers.Name AS 'CompletedBy',
  msit_TrackItems.Notes AS 'Notes',
        NULL AS 'Error'
--Identify Track items by the individual they are assigned to
FROM  msit_TrackItems
        LEFT JOIN msit_IntUsers ON msit_TrackItems.AssignToUserID = msit_IntUsers.ID
        LEFT JOIN msit_IntUsers AS CompletedUsers ON msit_TrackItems.CompletedStateByID = CompletedUsers.ID
        LEFT JOIN mstt_Agents AS mstt_AgentsMain ON msit_IntUsers.AssociatedAgent = mstt_AgentsMain.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM4 ON mstt_AgentsMain.Manager4Code = mstt_AgentsM4.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM3 ON mstt_AgentsMain.Manager3Code = mstt_AgentsM3.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM2 ON mstt_AgentsMain.Manager2Code = mstt_AgentsM2.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM1 ON mstt_AgentsMain.Manager1Code = mstt_AgentsM1.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsSa ON mstt_AgentsMain.SaleSupervisorCode = mstt_AgentsSa.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsSp ON mstt_AgentsMain.SpanSupervisorcode = mstt_AgentsSp.CODE
  LEFT JOIN mstt_Agents AS Business ON COALESCE(mstt_AgentsMain.DirectlyAuthorisedCode, mstt_AgentsMain.OfficeCode, mstt_AgentsMain.AccessAgentCode, mstt_AgentsMain.StrategicAllianceCode) = Business.Code
--Check the track items are the correct type and that the agent reports to our agent code in some way
WHERE (mstt_AgentsMain.CODE IN
    (SELECT code
                 FROM mstt_Agents
                 WHERE  (CompanyCode = @AgentCode OR
      OrganisationCode = @AgentCode) OR
                        (SaleSupervisorCode = @AgentCode OR
                        SpanSupervisorcode = @AgentCode AND
      (manager1code <> @AgentCode OR
                        manager2code <> @AgentCode OR
                        manager3code <> @AgentCode OR
                        manager4code <> @AgentCode)) OR
      (manager1code = @AgentCode OR
                        manager2code = @AgentCode OR
                        manager3code = @AgentCode OR
                        manager4code = @AgentCode AND
      (SaleSupervisorCode <> @AgentCode OR --exclude supervisors where there is a 
                        SpanSupervisorcode <> @AgentCode))))--match on manager code else there will be duplicates 
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)) 
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
  AND (msit_TrackItems.CodeTrackItemCode LIKE 'SST%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'RAL%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'LMS%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'Q1%')
  AND msit_TrackItems.CompletedState = '2'
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
ORDER BY [Manager 4 name], [Manager 3 name], [Manager 2 name], [Manager 1 name], [Sales supervisor], [Span supervisor], [Agent name]

GO
/****** Object:  StoredProcedure [dbo].[cscp_AbandonedTeamEvents]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- Get the relevant track items, competence details and manager details for each agent beneath the agent code passed in
CREATE PROCEDURE [dbo].[cscp_AbandonedTeamEvents] @UserID VARCHAR(255), @AgentCode CHAR(7), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Query name'
      , NULL AS 'Description'
      , NULL AS 'DueDate'
      , NULL AS 'Outcome'
      , NULL AS 'CompletionDate'
      , NULL AS 'CompletedBy'
      , NULL AS 'Team name'
      , NULL AS 'Notes'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS 'Error'
   RETURN 0
END
SELECT  (SELECT     ISNULL(RTRIM(SUBSTRING(mstt_Agents.Firstnames, 1, PATINDEX('%[^ ] %',mstt_Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_Agents.Name), '')
        FROM        mstt_Agents WHERE      code = @AgentCode) AS 'Query name', 
  msit_TrackItems.Description AS 'Description',
  CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 103) AS NVARCHAR) AS 'DueDate',
  CASE msit_TrackItems.completedstate
  WHEN 1 THEN 'Successful'
  WHEN 2 THEN 'Abandoned'
  ELSE ' '
  END AS 'Outcome',
  CASE WHEN  CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME)
  THEN CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR) + 'L'
  WHEN msit_TrackItems.ClearedDate IS NULL THEN ''
  ELSE CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR)
  END AS 'CompletionDate',
  CompletedUsers.Name AS 'CompletedBy',
  msit_IntTeams.Name AS 'Team name',
  msit_TrackItems.Notes AS 'Notes',
        NULL AS 'Error'
--Identify Track items by the team they are assigned to
FROM  msit_TrackItems
  LEFT JOIN msit_IntTeams ON msit_TrackItems.AssignToTeamID = msit_IntTeams.ID
        LEFT JOIN msit_IntUsers AS CompletedUsers ON msit_TrackItems.CompletedStateByID = CompletedUsers.ID
--Check the track items are the correct type and that the agent reports to our agent code in some way
WHERE msit_TrackItems.AssignToTeamID IS NOT NULL
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)) 
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
  AND (msit_TrackItems.CodeTrackItemCode LIKE 'SST%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'RAL%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'LMS%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'Q1%')
  AND msit_TrackItems.CompletedState = '2'
ORDER BY [Team name]

GO
/****** Object:  StoredProcedure [dbo].[cscp_AdviserLicenceGaps]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[cscp_AdviserLicenceGaps] @UserID VARCHAR(255)
AS

--Drop temporary tables if exist
IF OBJECT_ID('tempdb..#SectorLicences') IS NOT NULL
   DROP TABLE #SectorLicences
IF OBJECT_ID('tempdb..#AgentLicences') IS NOT NULL
   DROP TABLE #AgentLicences
IF OBJECT_ID('tempdb..##MissingLicencesTable') IS NOT NULL
   DROP TABLE ##MissingLicencesTable
IF OBJECT_ID('tempdb..##MissingLicencesTableTemp') IS NOT NULL
   DROP TABLE ##MissingLicencesTableTemp

-- First, determine the collation sequence of mstt_Agents.Code as this must be matched in the temporary tables
DECLARE @CollateSeq VARCHAR(128)
DECLARE @QueryString VARCHAR(2048)

SELECT @CollateSeq = COLLATION
FROM SYSCOLUMNS 
INNER JOIN SYSOBJECTS ON SYSOBJECTS.Name = 'mstt_Agents'
WHERE SYSCOLUMNS.NAME = 'Code'
  AND SYSCOLUMNS.ID = SYSOBJECTS.ID

-- Create the temporary table using dynamic sql so that the collation sequence determined above can be specified for the ID column
SET @QueryString =
'CREATE TABLE ##MissingLicencesTable (ID VARCHAR(7) COLLATE ' + @CollateSeq + ', MissingLicence VARCHAR(64))'
EXEC (@QueryString)

--#SectorLicences Temp table variables
DECLARE
    @AdviserID AS VARCHAR(7),
    @Sector AS VARCHAR(64),
    @Licence AS VARCHAR(255)

-- 1) load licences by sector into a temporary table
SELECT DISTINCT msit_CodeClusterSector.Code AS [Sector],
                msit_CodeLicence.Code AS [Licence]
INTO #SectorLicences
FROM msit_CodeClusterSector
INNER JOIN msit_CodeCluster ON msit_CodeCluster.CodeClusterSectorID = msit_CodeClusterSector.ID
INNER JOIN msit_CodeLicenceCluster ON msit_CodeLicenceCluster.CodeClusterID = msit_CodeCluster.ID
INNER JOIN msit_CodeLicence ON msit_CodeLicence.ID = msit_CodeLicenceCluster.CodeLicenceID
WHERE msit_CodeLicence.Code NOT IN ('ERIN', 'ERPR', 'KBUS', 'PANN', 'PAL4') --exclude these licences
UNION
SELECT 'IP' AS [Sector],
       'PAL4' AS [Licence] --override 'real' entry for PAL4 - i.e. make part of IP not PA
ORDER BY Sector, Licence

CREATE INDEX ind_SectorLicences ON #SectorLicences (Sector, Licence)

-- 2a) load adviser open sectors and licences into another temporary table
SELECT Agents.Code AS [AgtCode],
       mstt_AgentSector.ClusterSectorCode AS [AgtSector],
       msit_CodeLicence.Code AS [AgtLicence]
INTO #AgentLicences
FROM mstt_Agents AS Agents
--all open sectors
INNER JOIN mstt_AgentSector on mstt_AgentSector.AgentID = Agents.id
  AND (mstt_AgentSector.StartDate IS NOT NULL AND CAST(CONVERT(NVARCHAR,mstt_AgentSector.StartDate,112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,getdate(),112) AS DATETIME))
  AND (mstt_AgentSector.EndDate IS NULL OR CAST(CONVERT(NVARCHAR,mstt_AgentSector.EndDate,112) AS DATETIME) >= CAST(CONVERT(NVARCHAR,getdate(),112) AS DATETIME))
--all open licences
INNER JOIN mstt_AgentLicence on mstt_AgentLicence.AgentID = Agents.id
  AND (mstt_AgentLicence.StartDate IS NOT NULL AND CAST(CONVERT(NVARCHAR,mstt_AgentLicence.StartDate,112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,getdate(),112) AS DATETIME))
  AND (mstt_AgentLicence.EndDate IS NULL OR CAST(CONVERT(NVARCHAR,mstt_AgentLicence.EndDate,112) AS DATETIME) >= CAST(CONVERT(NVARCHAR,getdate(),112) AS DATETIME))
LEFT JOIN msit_CodeLicence ON msit_CodeLicence.ID = mstt_AgentLicence.CodeLicenceID
--where sectors & licences are in #SectorLicences
INNER JOIN #SectorLicences AS SectorLicence ON SectorLicence.Sector = mstt_AgentSector.ClusterSectorCode
                                           AND SectorLicence.Licence = msit_CodeLicence.Code
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
WHERE Agents.AgentTypeB30 = 2 -- an individual (exclude businesses)
  AND Agents.CompetentStatus = 1 -- active
  AND Agents.AgentType NOT IN (3, 17, 44, 5, 45) -- not an IAR, Staff, Company Sec, Admin, 10% shareholder
  AND Agents.AgentCategory <> 'RI' -- not an RI
 AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
ORDER BY AgtSector, AgtLicence

-- 2b) add adviser open sectors with no associated open licences into the temporary table
INSERT INTO #AgentLicences
SELECT DISTINCT
       Agents.Code AS [AgtCode],
       mstt_AgentSector.ClusterSectorCode AS [AgtSector],
       NULL AS [AgtLicence]
FROM mstt_Agents AS Agents
--all open sectors
INNER JOIN mstt_AgentSector on mstt_AgentSector.AgentID = Agents.id
  AND (mstt_AgentSector.StartDate IS NOT NULL AND CAST(CONVERT(NVARCHAR,mstt_AgentSector.StartDate,112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,getdate(),112) AS DATETIME))
  AND (mstt_AgentSector.EndDate IS NULL OR CAST(CONVERT(NVARCHAR,mstt_AgentSector.EndDate,112) AS DATETIME) >= CAST(CONVERT(NVARCHAR,getdate(),112) AS DATETIME))
--where sectors are in #SectorLicences
INNER JOIN #SectorLicences AS SectorLicence ON SectorLicence.Sector = mstt_AgentSector.ClusterSectorCode
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
WHERE Agents.AgentTypeB30 = 2 -- an individual (exclude businesses)
  AND Agents.CompetentStatus = 1 -- active
  AND Agents.AgentType NOT IN (3, 17, 44, 5, 45) -- not an IAR, Staff, Company Sec, Admin, 10% shareholder
  AND Agents.AgentCategory <> 'RI' -- not an RI
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
--where no associated open licences
  AND NOT EXISTS (SELECT mstt_AgentLicence.CodeLicenceID
                  FROM mstt_AgentLicence 
                  LEFT JOIN msit_CodeLicence ON msit_CodeLicence.ID = mstt_AgentLicence.CodeLicenceID
                  INNER JOIN #SectorLicences AS SectorLicence ON SectorLicence.Sector = mstt_AgentSector.ClusterSectorCode
                                                             AND SectorLicence.Licence = msit_CodeLicence.Code
                  WHERE mstt_AgentLicence.AgentID = Agents.id
                    AND (mstt_AgentLicence.StartDate IS NOT NULL AND CAST(CONVERT(NVARCHAR,mstt_AgentLicence.StartDate,112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,getdate(),112) AS DATETIME))
                    AND (mstt_AgentLicence.EndDate IS NULL OR CAST(CONVERT(NVARCHAR,mstt_AgentLicence.EndDate,112) AS DATETIME) >= CAST(CONVERT(NVARCHAR,getdate(),112) AS DATETIME)))
ORDER BY AgtSector, AgtLicence

-- 3) from the two temporary tables, identify those licences which are not held by the adviser
INSERT INTO ##MissingLicencesTable
SELECT DISTINCT
       #AgentLicences.AgtCode 'Unique ID',
       #SectorLicences.Licence 'Lics Missing'
FROM #SectorLicences 
INNER JOIN #AgentLicences ON #AgentLicences.AgtSector = #SectorLicences.Sector
WHERE #SectorLicences.Licence NOT IN
(SELECT #AgentLicences1.AgtLicence
 FROM #AgentLicences #AgentLicences1
 WHERE #AgentLicences1.AgtSector = #SectorLicences.Sector AND #AgentLicences1.AgtLicence = #SectorLicences.Licence
 AND #AgentLicences1.AgtCode = #AgentLicences.AgtCode
)
ORDER BY AgtCode, Licence

-- 4) Now concatenate the missing licences
DECLARE 
   @Counter INT, 
   @NoOfRows INT, 
   @MissingLicId VARCHAR(7),
   @Licences VARCHAR(255)

-- Create the temporary table using dynamic sql so that the collation sequence determined above can be specified for the ID column
-- This table holds a single row of concatenated licences for each adviser
SET @QueryString =
'CREATE TABLE ##MissingLicencesTableTemp (RowNum INT IDENTITY, ID VARCHAR(7) COLLATE ' + @CollateSeq + ', MissingLicence VARCHAR(255))'
EXEC (@QueryString)

   -- add each adviser code from the old table into the new table
   INSERT INTO ##MissingLicencesTableTemp(ID) SELECT DISTINCT ID FROM ##MissingLicencesTable

   SELECT @NoOfRows = @@ROWCOUNT
   SELECT @Counter = 1, @Licences = ''

   -- for each adviser code in the new table
   SELECT @MissingLicId = ID 
   FROM ##MissingLicencesTableTemp 
   WHERE RowNum = @Counter

   WHILE @Counter <= @NoOfRows 
   BEGIN
      -- concatenate the licence codes found in the old table for this adviser
      SELECT @Licences = ISNULL(@Licences + ', ' , '') + MissingLicences.MissingLicence 
      FROM ##MissingLicencesTable MissingLicences 
      WHERE MissingLicences.ID = @MissingLicId 

      -- update the new table with the concatenated list of licences for this adviser
      UPDATE ##MissingLicencesTableTemp
      SET MissingLicence = LTRIM(SUBSTRING(@Licences,2,LEN(@Licences))) 
      WHERE RowNum = @Counter --ID = @MissingLicId 

      -- move to next adviser code in new table
      SET @Counter = @Counter + 1 
      SELECT @MissingLicId = ID, 
             @Licences = '' 
      FROM ##MissingLicencesTableTemp 
      WHERE RowNum = @Counter 
   END 

-- 5) report from the new missing licences temporary table
SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser],
       MissingLicences.ID AS [ID],
       Agents.AgentTypeDescription AS [Type],
       Agents.AgentCategory AS [Category],
       dbo.cscf_GetAgentSectors(Agents.ID, GetDate()) AS [SectorsHeld],
       MissingLicences.MissingLicence AS [Missing_Licences],
       'Supervisor: '
        + ISNULL(RTRIM(SUBSTRING(AgentsSvr.FirstNames, 1, PATINDEX('%[^ ] %', AgentsSvr.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(AgentsSvr.Name), '')
        + RTRIM(ISNULL(' (' + AgentsSvr.Code + ')', '')) AS [Svr], -- sort/group by field
       CASE Agents_mgr2.AgentCategory
          WHEN 'ASQMNS' THEN 'Area Sales Quality Manager: '
          ELSE 'Regional Sales Manager: '
       END
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr2.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr2.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr2.Name), '')
        + RTRIM(ISNULL(' (' + Agents_mgr2.Code + ')', '')) AS [Mgr2], -- sort/group by field
       'Area Sales Director: '
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr4.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr4.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr4.Name), '') AS [Mgr4] -- sort/group by field

FROM ##MissingLicencesTableTemp MissingLicences
INNER JOIN mstt_Agents AS Agents ON Agents.Code = MissingLicences.ID
LEFT JOIN mstt_Agents AS AgentsSvr ON Agents.SpanSupervisorCode = AgentsSvr.Code
LEFT JOIN mstt_Agents AS Agents_mgr2 ON Agents.Manager2Code = Agents_mgr2.Code
LEFT JOIN mstt_Agents AS Agents_mgr4 ON Agents.Manager4Code = Agents_mgr4.Code

ORDER BY [Mgr4], [Mgr2], [Svr], [Adviser], [ID]

-- 8) drop the temporary tables
DROP TABLE #SectorLicences
DROP TABLE #AgentLicences
DROP TABLE ##MissingLicencesTable
DROP TABLE ##MissingLicencesTableTemp

GO
/****** Object:  StoredProcedure [dbo].[cscp_AdviserLicenceOutSector]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_AdviserLicenceOutSector] @UserID VARCHAR(255)
AS
--Drop temporary tables if exist
IF OBJECT_ID('tempdb..#SectorLicences') IS NOT NULL
   DROP TABLE #SectorLicences
IF OBJECT_ID('tempdb..#AgentLicences') IS NOT NULL
   DROP TABLE #AgentLicences
IF OBJECT_ID('tempdb..##LicsOutideSectorTable') IS NOT NULL
   DROP TABLE ##LicsOutideSectorTable
IF OBJECT_ID('tempdb..##LicencesTableTemp') IS NOT NULL
   DROP TABLE ##LicencesTableTemp
-- First, determine the collation sequence of mstt_Agents.Code as this must be matched in the temporary tables
DECLARE @CollateSeq VARCHAR(128)
DECLARE @QueryString VARCHAR(2048)
SELECT @CollateSeq = COLLATION
FROM SYSCOLUMNS 
INNER JOIN SYSOBJECTS ON SYSOBJECTS.Name = 'mstt_Agents'
WHERE SYSCOLUMNS.NAME = 'Code'
  AND SYSCOLUMNS.ID = SYSOBJECTS.ID
-- Create the temporary table using dynamic sql so that the collation sequence determined above can be specified for the ID column
SET @QueryString =
'CREATE TABLE ##LicsOutideSectorTable (ID VARCHAR(7) COLLATE ' + @CollateSeq + ', Licence VARCHAR(64))'
EXEC (@QueryString)
--Temp table variables
DECLARE
    @AdviserID AS VARCHAR(7)
  , @Sector AS VARCHAR(64)
  , @Licence AS VARCHAR(255)
-- 1) load licences by sector into a temporary table
SELECT msit_CodeClusterSector.Code AS [Sector],
       msit_CodeLicence.Code AS [Licence]
INTO #SectorLicences
FROM msit_CodeClusterSector
INNER JOIN msit_CodeCluster ON msit_CodeCluster.CodeClusterSectorID = msit_CodeClusterSector.ID
INNER JOIN msit_CodeLicenceCluster ON msit_CodeLicenceCluster.CodeClusterID = msit_CodeCluster.ID
INNER JOIN msit_CodeLicence ON msit_CodeLicence.ID = msit_CodeLicenceCluster.CodeLicenceID
WHERE msit_CodeLicence.Code NOT IN ('ERIN', 'ERPR') -- exclude these two licences
ORDER BY Sector, Licence
CREATE INDEX ind_SectorLicences ON #SectorLicences (Sector, Licence)
-- 2) load adviser open licences, which are associated with a sector (whether adviser has the sector or not), into another temporary table
SELECT Agents.Code AS [AgtCode],
       #SectorLicences.Sector AS [AgtSector],
       AgentLicence.LicenceCode AS [AgtLicence]
INTO #AgentLicences
FROM mstt_agents AS Agents
--open licences
INNER JOIN mstt_AgentLicence AS AgentLicence ON AgentLicence.AgentID = Agents.id
  AND (AgentLicence.StartDate IS NOT NULL AND CAST(CONVERT(NVARCHAR,AgentLicence.StartDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,getdate(), 112) AS DATETIME))
  AND (AgentLicence.EndDate IS NULL OR CAST(CONVERT(NVARCHAR,AgentLicence.EndDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR,getdate(), 112) AS DATETIME))
--licence associated with a sector
INNER JOIN #SectorLicences ON #SectorLicences.Licence = AgentLicence.LicenceCode
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
WHERE Agents.AgentTypeB30 = 2 -- an individual (exclude businesses)
  AND Agents.CompetentStatus = 1 -- active
  AND Agents.AgentType NOT IN (3, 17, 44, 5, 45) -- not an IAR, Staff, Company Sec, Admin, 10% shareholder
  AND Agents.AgentCategory <> 'RI' -- not an RI
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
ORDER BY Sector, Licence
-- 3) from the two temporary tables, identify those licences held by the adviser where the associated sector is not also held
INSERT INTO ##LicsOutideSectorTable
select distinct 
       #AgentLicences.AgtCode 'Unique ID',
       #SectorLicences.Licence 'Outside Sector Lics'
from #SectorLicences 
inner join #AgentLicences on #AgentLicences.AgtLicence = #SectorLicences.Licence
where #SectorLicences.Licence not in 
--All sectors held by advisor
(select #AgentLicences1.AgtLicence 
 from #AgentLicences #AgentLicences1
    inner join msit_CodeClusterSector on msit_CodeClusterSector.code = #AgentLicences1.AgtSector
    inner join mstt_agentsector on mstt_agentsector.CodeClusterSectorID = msit_CodeClusterSector.id
    inner join mstt_agents on #AgentLicences1.AgtCode = mstt_agents.code
 where mstt_AgentSector.AgentID = mstt_agents.id
 and (mstt_AgentSector.StartDate IS NOT NULL AND CAST(CONVERT(NVARCHAR, mstt_AgentSector.StartDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME))
 and (mstt_AgentSector.EndDate IS NULL OR CAST(CONVERT(NVARCHAR, mstt_AgentSector.EndDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME))
 and #AgentLicences1.AgtCode = #AgentLicences.AgtCode
)
ORDER BY AgtCode, Licence
-- 4) Now concatenate the licences
DECLARE 
   @Counter INT, 
   @NoOfRows INT, 
   @LicId VARCHAR(7),
   @Licences VARCHAR(255)
-- Create the temporary table using dynamic sql so that the collation sequence determined above can be specified for the ID column
-- This table holds a single row of concatenated licences for each adviser
SET @QueryString =
'CREATE TABLE ##LicencesTableTemp (RowNum INT IDENTITY, ID VARCHAR(7) COLLATE ' + @CollateSeq + ', Licence VARCHAR(255))'
EXEC (@QueryString)
   -- add each adviser code from the old table into the new table
   INSERT INTO ##LicencesTableTemp(ID) SELECT DISTINCT ID FROM ##LicsOutideSectorTable
   SELECT @NoOfRows = @@ROWCOUNT
   SELECT @Counter = 1, @Licences = ''
   -- for each adviser code in the new table
   SELECT @LicId = ID 
   FROM ##LicencesTableTemp 
   WHERE RowNum = @Counter
   WHILE @Counter <= @NoOfRows 
   BEGIN
      -- concatenate the licence codes found in the old table for this adviser
      SELECT @Licences = ISNULL(@Licences + ', ' , '') + Licences.Licence 
      FROM ##LicsOutideSectorTable Licences 
      WHERE Licences.ID = @LicId 
      -- update the new table with the concatenated list of licences for this adviser
      UPDATE ##LicencesTableTemp
      SET Licence = LTRIM(SUBSTRING(@Licences,2,LEN(@Licences))) 
      WHERE RowNum = @Counter --ID = @LicId 
      -- move to next adviser code in new table
      SET @Counter = @Counter + 1 
      SELECT @LicId = ID, 
             @Licences = '' 
      FROM ##LicencesTableTemp 
      WHERE RowNum = @Counter 
   END 
-- 5) report from the new licences temporary table
SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser],
       Licences.ID AS [ID],
       Agents.AgentTypeDescription AS [Type],
       Agents.AgentCategory AS [Category],
       dbo.cscf_GetAgentSectors(Agents.ID, GetDate()) AS [SectorsHeld],
       Licences.Licence AS [Licences],
       'Supervisor: '
        + ISNULL(RTRIM(SUBSTRING(AgentsSvr.FirstNames, 1, PATINDEX('%[^ ] %', AgentsSvr.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(AgentsSvr.Name), '')
        + RTRIM(ISNULL(' (' + AgentsSvr.Code + ')', '')) AS [Svr], -- sort/group by field
       CASE Agents_mgr2.AgentCategory
          WHEN 'ASQMNS' THEN 'Area Sales Quality Manager: '
          ELSE 'Regional Sales Manager: '
       END
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr2.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr2.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr2.Name), '')
        + RTRIM(ISNULL(' (' + Agents_mgr2.Code + ')', '')) AS [Mgr2], -- sort/group by field
       'Area Sales Director: '
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr4.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr4.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr4.Name), '') AS [Mgr4] -- sort/group by field
FROM ##LicencesTableTemp Licences
INNER JOIN mstt_Agents AS Agents ON Agents.Code = Licences.ID
LEFT JOIN mstt_Agents AS AgentsSvr ON Agents.SpanSupervisorCode = AgentsSvr.Code
LEFT JOIN mstt_Agents AS Agents_mgr2 ON AgentsSvr.Manager2Code = Agents_mgr2.Code
LEFT JOIN mstt_Agents AS Agents_mgr4 ON Agents_mgr2.Manager4Code = Agents_mgr4.Code
ORDER BY [Mgr4], [Mgr2], [Svr], [Adviser], [ID]
-- 6) drop the temporary tables
DROP TABLE #SectorLicences
DROP TABLE #AgentLicences
DROP TABLE ##LicsOutideSectorTable
DROP TABLE ##LicencesTableTemp

GO
/****** Object:  StoredProcedure [dbo].[cscp_AdvisersNoSector]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_AdvisersNoSector] @UserID VARCHAR(255)
AS
SELECT Agents.Code [Unique ID],
       ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser],
       Agents.AgentCategory AS [Category],
       AgentCompetence.ComplianceCategoryCode AS [Competency],
       AgentCompetence.AgentControlFunctionCode AS [Comp Status],
       CASE Agents.AgentType
          WHEN 52 THEN 'Y'
          WHEN 53 THEN 'Y'
          WHEN 54 THEN 'Y'
          WHEN 55 THEN 'Y'
          ELSE ''
       END AS [Mgr?],
       CASE
          WHEN Agents.CanSupervise = '1' AND Agents.SupervisorTypeCode IN ('SOS', 'RSOS', 'SOSNA') THEN 'S'
          WHEN Agents.CanSupervise = '1' THEN 'Y'
          ELSE 'N'
       END AS [Sup?],
       CONVERT(VARCHAR, Agents.DateStarted, 103) AS [Appointed],
       ISNULL(RTRIM(SUBSTRING(Agents_4.Firstnames, 1, PATINDEX('%[^ ] %', Agents_4.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_4.Name), '') AS [Area Sales Director],
       ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') AS [Supervisor]
FROM mstt_Agents AS Agents
LEFT JOIN mstt_AgentCompetence AS AgentCompetence ON AgentCompetence.AgentID = Agents.id
      AND (AgentCompetence.DateAppointed IS NOT NULL AND CAST(CONVERT(NVARCHAR, AgentCompetence.DateAppointed, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME))
      AND (AgentCompetence.EndDate IS NULL OR CAST(CONVERT(NVARCHAR, AgentCompetence.EndDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME))
LEFT JOIN mstt_Agents AS Agents_svr ON Agents.SpanSupervisorCode = Agents_svr.CODE
LEFT JOIN mstt_Agents AS Agents_4 ON Agents.Manager4Code = Agents_4.CODE
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
WHERE Agents.CompetentStatus = 1 -- only include active advisers
  AND (Agents.GivesAdvice = 'Y' OR Agents.CanSupervise = 1) -- only include sellers and supervisors
  AND Agents.AgentTypeB30 = 2 -- exclude businesses
  AND Agents.AgentCategory NOT IN ('RSMN', 'RSMNS') -- exclude these categories
  AND NOT EXISTS
   (SELECT AgentSector.CodeClusterSectorID
    FROM  mstt_AgentSector AS AgentSector
    WHERE AgentSector.AgentID = Agents.ID
      AND (AgentSector.StartDate IS NOT NULL AND CAST(CONVERT(NVARCHAR,AgentSector.StartDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,getdate(), 112) AS DATETIME))
      AND (AgentSector.EndDate IS NULL OR CAST(CONVERT(NVARCHAR,AgentSector.EndDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR,getdate(), 112) AS DATETIME))
   )
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
ORDER BY [Area Sales Director], [Supervisor], Agents.Code

GO
/****** Object:  StoredProcedure [dbo].[cscp_AdvisersWithPaymentShieldNoprovider]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[cscp_AdvisersWithPaymentShieldNoprovider] @UserID VARCHAR(255)
AS
--Used a temporary table to save on time for Missing licences
IF OBJECT_ID('tempdb..#TempPaymntShld') IS NOT NULL
   DROP TABLE #TempPaymntShld
SELECT
     Agents.ID AS 'AgentID'
   , ISNULL(RTRIM(SUBSTRING(Agents.FirstNames, 1, PATINDEX('%[^ ] %', Agents.FirstNames + ' '))) + ' ', '') +
     ISNULL(RTRIM(Agents.Name), '') AS 'Adviser Name'
   , Agents.Code AS 'Adviser ID'
   , Agents.AgentTypeDescription AS 'Agent Type'
   , Agents.AgentCategory AS 'Agent Category'
   , (SELECT CASE WHEN dbo.cscf_AgentHasSector(Agents.ID, GetDate(), 'GIP') = 'N' --No sector exists
                       AND EXISTS (SELECT ID
                                   FROM mstt_AgentAgencyNumbers AS AgentAgencyNumbers
                                   WHERE AgentAgencyNumbers.ProductProviderCode = 'PYMTSHLD' --Provider exists
                                   AND AgentAgencyNumbers.AgentCode = Agents.CODE
                                   )
                  THEN 'Y' ELSE '' END
      ) AS 'Payment Shield sector missing'
   , (SELECT CASE WHEN dbo.cscf_AgentHasSector(Agents.ID, GetDate(), 'GIP') = 'Y' --Sector exists
                       AND NOT EXISTS (SELECT ID
                                       FROM mstt_AgentAgencyNumbers AS AgentAgencyNumbers
                                       WHERE AgentAgencyNumbers.ProductProviderCode = 'PYMTSHLD' --Provider does not exists
                                       AND AgentAgencyNumbers.AgentCode = Agents.CODE
                                       )
                  THEN 'Y' ELSE '' END
     ) AS 'Payment Shield provider missing'
   , 'N' AS 'Payment Shield licence missing' --Dummy value
   , ISNULL(RTRIM(SUBSTRING(AgentsSup.FirstNames, 1, PATINDEX('%[^ ] %', AgentsSup.FirstNames + ' '))) + ' ', '')
     + ISNULL(RTRIM(AgentsSup.Name), '') AS 'Supervisor'
   , ISNULL(RTRIM(SUBSTRING(AgentsMgr4.FirstNames, 1, PATINDEX('%[^ ] %', AgentsMgr4.FirstNames + ' '))) + ' ', '')
     + ISNULL(RTRIM(AgentsMgr4.Name), '') AS 'ASD'  
INTO #TempPaymntShld
FROM mstt_Agents Agents
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
LEFT JOIN mstt_Agents AgentsSup ON AgentsSup.CODE = Agents.SpanSupervisorCode --for supervisor
LEFT JOIN mstt_Agents AgentsMgr4 ON AgentsMgr4.CODE = Agents.Manager4Code --for Manager4/Area Sales Director
WHERE Agents.AgentTypeB30 = 2 --individual (exclude businesses)
  AND Agents.CompetentStatus = 1 --active agents
  AND Agents.AgentType NOT IN (3, 17, 44, 5, 45) --not an IAR, Staff, Company Sec, Admin, 10% shareholder
  AND Agents.AgentCategory <> 'RI' --not an RI
 AND (Business.AgentType IS NULL OR Business.AgentType <> 49) --exclude directly authorised
ORDER BY [ASD], [Supervisor], [Adviser Name]
--Set Payment Shield licence missing field (would be much faster this way!)
UPDATE #TempPaymntShld
   SET #TempPaymntShld.[Payment Shield licence missing] = 
       (CASE WHEN dbo.cscf_AgentHasLicence(#TempPaymntShld.AgentID, GetDate(), 'PGIP') = 'N' -- No 'PGIP' licence exists
             THEN 'Y' ELSE '' END)
--Select ONLY those rows which have sector or provider missing (i.e. omit rows with only licence missing = TPR2022)
SELECT 
   [Adviser Name]
  ,[Adviser ID]
  ,[Agent Type]
  ,[Agent Category]
  ,[Payment Shield sector missing]
  ,[Payment Shield provider missing]
  ,[Payment Shield licence missing] AS [Payment Shield licence missing]
  ,[Supervisor]
  ,[ASD]
  ,'' AS [Notes]
FROM #TempPaymntShld
WHERE [Payment Shield sector missing] = 'Y' OR 
      [Payment Shield provider missing] = 'Y'
ORDER BY [ASD], [Supervisor], [Adviser Name]
DROP TABLE #TempPaymntShld

GO
/****** Object:  StoredProcedure [dbo].[cscp_AdvisorEmail]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO


CREATE PROCEDURE [dbo].[cscp_AdvisorEmail] @UserID VARCHAR(255)
AS

--Drop temporary tables if exist
IF OBJECT_ID('tempdb..#Temp69a') IS NOT NULL
   DROP TABLE #Temp69a
IF OBJECT_ID('tempdb..#Temp69b') IS NOT NULL
   DROP TABLE #Temp69b

SELECT 
     ISNULL(RTRIM(Agents.FirstNames), '') AS 'First Names'
   , ISNULL(RTRIM(Agents.Name), '') AS 'Surname'  
   , Agents.EMAIL AS 'E-mail'  
   , Agents.CODE AS 'Unique ID'  
   , Agents.AgentCategoryDescription AS 'Agent Category'  
   , Agents.AgentTypeDescription AS 'Agent Type'  
   , CodeCustomerFunction.Description AS 'Customer Function'  
   
   , ISNULL(RTRIM(SUBSTRING(AgentsSup.FirstNames, 1, PATINDEX('%[^ ] %', AgentsSup.FirstNames + ' '))) + ' ', '')
     + ISNULL(RTRIM(AgentsSup.Name), '') AS 'Supervisor'
   
   , ISNULL(RTRIM(SUBSTRING(AgentsMgr1.FirstNames, 1, PATINDEX('%[^ ] %', AgentsMgr1.FirstNames + ' '))) + ' ', '')
     + ISNULL(RTRIM(AgentsMgr1.Name), '') AS 'Manager 1 (SQM)'  
   
   , ISNULL(RTRIM(SUBSTRING(AgentsMgr2.FirstNames, 1, PATINDEX('%[^ ] %', AgentsMgr2.FirstNames + ' '))) + ' ', '')
     + ISNULL(RTRIM(AgentsMgr2.Name), '') AS 'Manager 2 (RSM)'
   
   , ISNULL(RTRIM(SUBSTRING(AgentsMgr4.FirstNames, 1, PATINDEX('%[^ ] %', AgentsMgr4.FirstNames + ' '))) + ' ', '')
     + ISNULL(RTRIM(AgentsMgr4.Name), '') AS 'Area Sales Director'  

   , Agents.ADDRESS1 AS 'Work Address 1'
   , Agents.ADDRESS2 AS 'Work Address 2'
   , Agents.ADDRESS3 AS 'Work Address 3'
   , Agents.ADDRESS4 AS 'Work Address 4'
   , Agents.ADDRESS5 AS 'Work Address 5'
   , Agents.POSTCODE AS 'Work Address Postcode'

   , Clients.ADDRESS1 AS 'Home Address 1'
   , Clients.ADDRESS2 AS 'Home Address 2'
   , Clients.ADDRESS3 AS 'Home Address 3'
   , Clients.TOWN AS 'Home Address 4'
   , Clients.COUNTY AS 'Home Address 5'
   , Clients.POSTCODE AS 'Home Address Postcode'

   , CASE WHEN Clients.CorrAddressDifferent = -1 THEN Clients.CorrAddress1 ELSE '' END AS 'Correspondence Address 1 – if different from work'
   , CASE WHEN Clients.CorrAddressDifferent = -1 THEN Clients.CorrAddress2 ELSE '' END AS 'Correspondence Address 2 – if different from work'
   , CASE WHEN Clients.CorrAddressDifferent = -1 THEN Clients.CorrAddress3 ELSE '' END AS 'Correspondence Address 3 – if different from work'
   , CASE WHEN Clients.CorrAddressDifferent = -1 THEN Clients.CorrTown ELSE '' END AS 'Correspondence Address 4 – if different from work'
   , CASE WHEN Clients.CorrAddressDifferent = -1 THEN Clients.CorrCounty ELSE '' END AS 'Correspondence Address 5 – if different from work'
   , CASE WHEN Clients.CorrAddressDifferent = -1 THEN Clients.CorrPostcode ELSE '' END AS 'Correspondence Address PostCode – if different from work'
   , CASE   --if the phone number is longer than 5 chars and doesn't have a space character, then insert one between the 4th and 5th.
      --this is needed to stop Excel stripping off the leading zero's
     WHEN LEN(Agents.TELEPHONE)>5 THEN  
  CASE PATINDEX('% %', LTRIM(RTRIM(CAST(Agents.TELEPHONE AS VARCHAR))))
  WHEN 0 THEN SUBSTRING(Agents.TELEPHONE, 1, 4) + ' ' + SUBSTRING(Agents.TELEPHONE, 5, LEN(Agents.TELEPHONE)- 4)
  ELSE Agents.TELEPHONE
  END
     ELSE Agents.TELEPHONE
     END AS 'Work Telephone Number'
   , CASE   --if the fax number is longer than 5 chars and doesn't have a space character, then insert one between the 4th and 5th.
      --this is needed to stop Excel stripping off the leading zero's
     WHEN LEN(Agents.FAX_NUMBER)>5 THEN   
  CASE PATINDEX('% %', LTRIM(RTRIM(CAST(Agents.FAX_NUMBER AS VARCHAR))))
  WHEN 0 THEN SUBSTRING(Agents.FAX_NUMBER, 1, 4) + ' ' + SUBSTRING(Agents.FAX_NUMBER, 5, LEN(Agents.FAX_NUMBER)- 4)
  ELSE Agents.FAX_NUMBER
  END
     ELSE Agents.FAX_NUMBER 
     END AS 'Work Fax'
   , CONVERT(VARCHAR, Agents.DateStarted, 103) AS 'Date Appointed' 
   , CONVERT(VARCHAR, Clients.BIRTHDATE, 103) AS 'Date of Birth' 
   , (CASE Clients.GENDER 
         WHEN 'M' THEN 'Male'
         WHEN 'F' THEN 'Female'
         ELSE ''
      END) AS 'Gender'
   , (CASE Agents.CompetentStatus 
         WHEN 0 THEN 'N/A'
         WHEN 1 THEN 'Active'
         WHEN 2 THEN 'Left'
         WHEN 3 THEN 'Deceased'
         WHEN 4 THEN 'Cancelled'
         WHEN 5 THEN 'Pre-Appointment'
         ELSE ''
      END) AS 'Status' 
   , (CASE msitAgents.MCVIndicator 
         WHEN 1 THEN 'Potential'
         WHEN 2 THEN '3 Months Period'
         WHEN 3 THEN 'MCV Taker'
         ELSE '' 
      END) AS 'MCV Indicator' 

INTO #Temp69a
FROM mstt_Agents Agents
LEFT JOIN msit_S_CLIENT Clients ON Clients.REFER = Agents.CODE
LEFT JOIN msit_S_AGENTS msitAgents ON msitAgents.CODE = Agents.CODE --for MCV Indicator
LEFT JOIN msit_CodeCustomerFunction CodeCustomerFunction ON CodeCustomerFunction.Code = Agents.CustomerFunctionCode  --for customer function
LEFT JOIN mstt_Agents AgentsSup ON AgentsSup.CODE = Agents.SpanSupervisorCode --for supervisor
LEFT JOIN mstt_Agents AgentsMgr1 ON AgentsMgr1.CODE = Agents.Manager1Code --for Manager1
LEFT JOIN mstt_Agents AgentsMgr2 ON AgentsMgr2.CODE = Agents.Manager2Code --for Manager2
LEFT JOIN mstt_Agents AgentsMgr4 ON AgentsMgr4.CODE = Agents.Manager4Code --for Manager4/Area Sales Director
WHERE Agents.AgentTypeB30 = 2 -- individuals only (exclude businesses)
ORDER BY [Surname], [First Names], [Unique ID] 

--Add an identity column to the sorted results
SELECT CAST(9 AS INT) AS 'Seq'
   , IDENTITY(INT, 1,1) AS 'RowNum'
   , a.*
INTO #Temp69b
FROM #Temp69a a

--Split the results into 'sets' of 2700 rows - this 'magic number' appears to be the max no. of rows in Excel (when 
--exported from Reporting Services) that will not cause Excel to crash when rows/columns added/deleted - see TPR2800
UPDATE #Temp69b
SET Seq = (RowNum / 2700)

--Retrieve the results
SELECT *
FROM #Temp69b
ORDER BY RowNum

--Tidy up
DROP TABLE #Temp69a
DROP TABLE #Temp69b


GO
/****** Object:  StoredProcedure [dbo].[cscp_AllEvents]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- Get the relevant track items, competence details and manager details for each agent beneath the agent code passed in
CREATE PROCEDURE [dbo].[cscp_AllEvents] @UserID VARCHAR(255), @AgentCode CHAR(7), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Query name'
      , NULL AS 'Agent code'
      , NULL AS 'Agent name'
      , NULL AS 'Competence'
      , NULL AS 'Manager 4 name'
      , NULL AS 'Mgr4 code'
      , NULL AS 'Manager 3 name'
      , NULL AS 'Mgr3 code'
      , NULL AS 'Manager 2 name'
      , NULL AS 'Mgr2 code'
      , NULL AS 'Manager 1 name'
      , NULL AS 'Mgr1 code'
      , NULL AS 'Sales supervisor'
      , NULL AS 'Sales code'
      , NULL AS 'Span supervisor'
      , NULL AS 'Span code'
      , NULL AS 'Description'
      , NULL AS 'DueDate'
      , NULL AS 'Outcome'
      , NULL AS 'CompletionDate'
      , NULL AS 'CompletedBy'
      , NULL AS 'Notes'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS 'Error'
   RETURN 0
END
IF (CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
BEGIN
  SELECT 
        NULL AS 'Query name'
      , NULL AS 'Agent code'
      , NULL AS 'Agent name'
      , NULL AS 'Competence'
      , NULL AS 'Manager 4 name'
      , NULL AS 'Mgr4 code'
      , NULL AS 'Manager 3 name'
      , NULL AS 'Mgr3 code'
      , NULL AS 'Manager 2 name'
      , NULL AS 'Mgr2 code'
      , NULL AS 'Manager 1 name'
      , NULL AS 'Mgr1 code'
      , NULL AS 'Sales supervisor'
      , NULL AS 'Sales code'
      , NULL AS 'Span supervisor'
      , NULL AS 'Span code'
      , NULL AS 'Description'
      , NULL AS 'DueDate'
      , NULL AS 'Outcome'
      , NULL AS 'CompletionDate'
      , NULL AS 'CompletedBy'
      , NULL AS 'Notes'
      , 'Start Date cannot be greater than End Date' AS 'Error'
   RETURN 0
END
SELECT  (SELECT     ISNULL(RTRIM(SUBSTRING(mstt_Agents.Firstnames, 1, PATINDEX('%[^ ] %',mstt_Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_Agents.Name) , '') 
          FROM          mstt_Agents WHERE      code = @AgentCode) AS 'Query name', 
  mstt_AgentsMain.CODE AS 'Agent code', 
        ISNULL(RTRIM(SUBSTRING(mstt_AgentsMain.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsMain.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsMain.Name) , '')  AS 'Agent name', 
  (SELECT dbo.cscf_GetAgentCompetencies(mstt_AgentsMain.ID, GetDate())) AS 'Competence',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM4.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM4.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM4.Name) , '')  AS 'Manager 4 name',
  mstt_AgentsM4.code  AS 'Mgr4 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM3.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM3.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM3.Name) , '')  AS 'Manager 3 name', 
  mstt_AgentsM3.code  AS 'Mgr3 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM2.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM2.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM2.Name) , '')  AS 'Manager 2 name',
  mstt_AgentsM2.code  AS 'Mgr2 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM1.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM1.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM1.Name) , '')  AS 'Manager 1 name', 
  mstt_AgentsM1.code  AS 'Mgr1 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsSa.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsSa.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsSa.Name) , '')  AS 'Sales supervisor', 
  mstt_AgentsSa.code  AS 'Sales code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsSp.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsSp.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsSp.Name) , '')  AS 'Span supervisor', 
  mstt_AgentsSp.code  AS 'Span code',
  msit_TrackItems.Description AS 'Description',
  CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 103) AS NVARCHAR) AS 'DueDate',
  CASE msit_TrackItems.completedstate
  WHEN 1 THEN 'Successful'
  WHEN 2 THEN 'Abandoned'
  ELSE ' '
  END AS 'Outcome',
  CASE WHEN  CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME)
  THEN CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR) + 'L'
  WHEN msit_TrackItems.ClearedDate IS NULL THEN ''
  ELSE CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR)
  END AS 'CompletionDate',
  CompletedUsers.Name AS 'CompletedBy',
  msit_TrackItems.Notes as 'Notes',
  NULL AS 'Error'
--Identify Track items by the individual they are assigned to
FROM  msit_TrackItems
        LEFT JOIN msit_IntUsers ON msit_TrackItems.AssignToUserID = msit_IntUsers.ID
        LEFT JOIN msit_IntUsers AS CompletedUsers ON msit_TrackItems.CompletedStateByID = CompletedUsers.ID
        LEFT JOIN mstt_Agents AS mstt_AgentsMain ON msit_IntUsers.AssociatedAgent = mstt_AgentsMain.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM4 ON mstt_AgentsMain.Manager4Code = mstt_AgentsM4.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM3 ON mstt_AgentsMain.Manager3Code = mstt_AgentsM3.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM2 ON mstt_AgentsMain.Manager2Code = mstt_AgentsM2.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM1 ON mstt_AgentsMain.Manager1Code = mstt_AgentsM1.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsSa ON mstt_AgentsMain.SaleSupervisorCode = mstt_AgentsSa.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsSp ON mstt_AgentsMain.SpanSupervisorcode = mstt_AgentsSp.CODE
  LEFT JOIN mstt_Agents AS Business ON COALESCE(mstt_AgentsMain.DirectlyAuthorisedCode, mstt_AgentsMain.OfficeCode, mstt_AgentsMain.AccessAgentCode, mstt_AgentsMain.StrategicAllianceCode) = Business.Code
--Check the track items are the correct type and that the agent reports to our agent code in some way
WHERE (mstt_AgentsMain.CODE IN
    (SELECT code
                 FROM mstt_Agents
                 WHERE  (CompanyCode = @AgentCode OR
      OrganisationCode = @AgentCode) OR
                        (SaleSupervisorCode = @AgentCode OR
                        SpanSupervisorcode = @AgentCode AND
      (manager1code <> @AgentCode OR
                        manager2code <> @AgentCode OR
                        manager3code <> @AgentCode OR
                        manager4code <> @AgentCode)) OR
      (manager1code = @AgentCode OR
                        manager2code = @AgentCode OR
                        manager3code = @AgentCode OR
                        manager4code = @AgentCode AND
      (SaleSupervisorCode <> @AgentCode OR --exclude supervisors where there is a 
                        SpanSupervisorcode <> @AgentCode))))--match on manager code else there will be duplicates
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)) 
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
  AND (msit_TrackItems.CodeTrackItemCode LIKE 'SST%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'RAL%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'LMS%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'Q1%')
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
ORDER BY [Manager 4 name], [Manager 3 name], [Manager 2 name], [Manager 1 name], [Sales supervisor], [Span supervisor], [Agent name]

GO
