-- Get the relevant track items, competence details and manager details for each agent beneath the agent code passed in
CREATE PROCEDURE [dbo].[cscp_AllTeamEvents] @UserID VARCHAR(255), @AgentCode CHAR(7), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Query name'
      , NULL AS 'Description'
      , NULL AS 'DueDate'
      , NULL AS 'Outcome'
      , NULL AS 'CompletionDate'
      , NULL AS 'CompletedBy'
      , NULL AS 'Team name'
      , NULL AS 'Notes'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS 'Error'
   RETURN 0
END
SELECT  (SELECT     ISNULL(RTRIM(SUBSTRING(mstt_Agents.Firstnames, 1, PATINDEX('%[^ ] %', mstt_Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_Agents.Name), '') 
          FROM          mstt_Agents WHERE      code = @AgentCode) AS 'Query name', 
  msit_TrackItems.Description AS 'Description',
  CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 103) AS NVARCHAR) AS 'DueDate',
  CASE msit_TrackItems.completedstate
  WHEN 1 THEN 'Successful'
  WHEN 2 THEN 'Abandoned'
  ELSE ' '
  END AS 'Outcome',
  CASE WHEN  CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME)
  THEN CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR) + 'L'
  WHEN msit_TrackItems.ClearedDate IS NULL THEN ''
  ELSE CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR)
  END AS 'CompletionDate',
  CompletedUsers.Name AS 'CompletedBy',
  msit_IntTeams.Name as 'Team name',
  msit_TrackItems.Notes as 'Notes',
  NULL AS 'Error'
--Identify Track items by the individual they are assigned to
FROM  msit_TrackItems
  LEFT JOIN msit_IntTeams ON msit_TrackItems.AssignToTeamID = msit_IntTeams.ID
  LEFT JOIN msit_IntUsers AS CompletedUsers ON msit_TrackItems.CompletedStateByID = CompletedUsers.ID
--Check the track items are the correct type and that the agent reports to our agent code in some way
WHERE msit_TrackItems.AssignToTeamID IS NOT NULL
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)) 
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
  AND (msit_TrackItems.CodeTrackItemCode LIKE 'SST%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'RAL%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'LMS%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'Q1%')
ORDER BY [Team name]

GO
/****** Object:  StoredProcedure [dbo].[cscp_CCL]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[cscp_CCL] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10), @Mode CHAR(1)
AS

IF @Mode = 'E' -- expiring licences
BEGIN
   IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
   BEGIN
      SELECT 
        NULL AS [Adviser]
      , NULL AS [Adviser Id] 
      , NULL AS [Status]
      , NULL AS [Expiry Date] 
      , NULL AS [Reference] 
      , NULL AS [Supervisor] 
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy.'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
      RETURN 0
   END
   IF (CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
   BEGIN
      SELECT 
        NULL AS [Adviser]
      , NULL AS [Adviser Id] 
      , NULL AS [Status]
      , NULL AS [Expiry Date] 
      , NULL AS [Reference] 
      , NULL AS [Supervisor] 
      , 'Start Date cannot be greater than End Date' AS 'Error'
      RETURN 0
   END
END
ELSE --@Mode = 'M' -- missing licences
BEGIN
   IF (@StartDate <> 'n/a' AND @StartDate <> '') OR (@EndDate <> 'n/a' AND @EndDate <> '')
   BEGIN
      SELECT 
        NULL AS [Adviser]
      , NULL AS [Adviser Id] 
      , NULL AS [Status]
      , NULL AS [Expiry Date] 
      , NULL AS [Reference] 
      , NULL AS [Supervisor] 
      , CASE WHEN @StartDate <> 'n/a' AND @StartDate <> '' THEN 'Start Date not relevant to Missing Licence Report. Please blank out this parameter.'
             WHEN @EndDate <> 'n/a' AND @EndDate <> '' THEN  'End Date not relevant to Missing Licence Report. Please blank out this parameter.'           
        END AS [Error]
      RETURN 0
   END
END

IF @Mode = 'E' -- expiring licences
BEGIN
   SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %',Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name) , '')  AS [Adviser],
          Agents.Code AS [Adviser Id],
          CASE Agents.CompetentStatus
             WHEN 1 THEN 'Active'
             WHEN 5 THEN 'Pre-appointed'
             ELSE 'Unknown'  --should never happen as where clause restricts to 1 or 5 only
          END AS [Status],
          CONVERT(VARCHAR, AgentLicence.ExpiryDate, 103) AS [Expiry Date],
          AgentLicence.Reference AS [Reference],
          CASE
             WHEN Agents.SpanSupervisorCode IS NOT NULL THEN ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') 
             ELSE 'NO SUPERVISOR'
          END AS [Supervisor],
          NULL AS [Error]

   FROM mstt_Agents AS Agents
   INNER JOIN mstt_AgentLicence AS AgentLicence ON AgentLicence.AgentID = Agents.id
   LEFT JOIN mstt_Agents AS Agents_svr ON Agents.SpanSupervisorCode = Agents_svr.CODE
   LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code

   WHERE AgentLicence.CodeLicenceID = 8 -- CCL licence id
     AND AgentLicence.EndDate IS NULL
     AND CAST(CONVERT(NVARCHAR, AgentLicence.ExpiryDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
     AND CAST(CONVERT(NVARCHAR, AgentLicence.ExpiryDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) -- Parameters
     AND Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents only
     AND Agents.AgentTypeB30 = 2 -- exclude businesses
     AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
     AND Agents.AgentType NOT IN (3, 17, 44, 5, 45, 55) -- exlcude IAR, Staff, Company Sec, Admin, 10% shareholder, Mgr4
     AND Agents.AgentCategory NOT IN ('RI', 'SQMNS', 'ASQMNS', 'RSMNS', 'SRSMNS', 'DIRNS', 'MBRNS', 'PRINNS', 'PTNRNS') -- exclude these categories

   ORDER BY ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), ''), AgentLicence.ExpiryDate, [Adviser]
END

ELSE --@Mode = 'M' -- missing licences

BEGIN
   --1. has a licence record with no start date or with an end date, and no other current/valid licence
   SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %',Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name) , '')  AS [Adviser],
          Agents.Code AS [Adviser Id],
          CASE Agents.CompetentStatus
             WHEN 1 THEN 'Active'
             WHEN 5 THEN 'Pre-appointed'
             ELSE 'Unknown'  --should never happen as where clause restricts to 1 or 5 only
          END AS [Status],
          CONVERT(VARCHAR, AgentLicence.ExpiryDate, 103) AS [Expiry Date],
          AgentLicence.Reference AS [Reference],
          CASE
             WHEN Agents.SpanSupervisorCode IS NOT NULL THEN ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') 
             ELSE 'NO SUPERVISOR'
          END AS [Supervisor],
          ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') AS [Svr Name],
          NULL AS [Error]

   FROM mstt_Agents AS Agents
   INNER JOIN mstt_AgentLicence AS AgentLicence ON AgentLicence.AgentID = Agents.id
   LEFT JOIN mstt_Agents AS Agents_svr ON Agents.SpanSupervisorCode = Agents_svr.CODE
   LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code

   WHERE AgentLicence.CodeLicenceID = 8 -- CCL licence id
     AND (AgentLicence.StartDate IS NULL -- with no start date
          OR (AgentLicence.EndDate IS NOT NULL AND CAST(CONVERT(NVARCHAR, AgentLicence.EndDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME))) -- with an end date in the past
     AND NOT EXISTS (SELECT LicenceCode
                     FROM mstt_AgentLicence AS AgentLicence
                     WHERE AgentLicence.AgentCode = Agents.Code
                       AND AgentLicence.CodeLicenceID = 8 -- CCL licence id
                       AND AgentLicence.StartDate IS NOT NULL AND CAST(CONVERT(NVARCHAR, AgentLicence.StartDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME)
                       AND (AgentLicence.EndDate IS NULL OR CAST(CONVERT(NVARCHAR, AgentLicence.EndDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME))
                    ) -- there is not another current/valid licence record
     AND Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents only
     AND Agents.AgentTypeB30 = 2 -- exclude businesses
     AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
     AND Agents.AgentType NOT IN (3, 17, 44, 5, 45, 55) -- exlcude IAR, Staff, Company Sec, Admin, 10% shareholder, Mgr4
     AND Agents.AgentCategory NOT IN ('RI', 'SQMNS', 'ASQMNS', 'RSMNS', 'SRSMNS', 'DIRNS', 'MBRNS', 'PRINNS', 'PTNRNS') -- exclude these categories

   UNION

   --2. has no licence record at all
   SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %',Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name) , '')  AS [Adviser],
          Agents.Code AS [Adviser Id],
          CASE Agents.CompetentStatus
             WHEN 1 THEN 'Active'
             WHEN 5 THEN 'Pre-appointed'
             ELSE 'Unknown'  --should never happen as where clause restricts to 1 or 5 only
          END AS [Status],
          '' AS [Expiry Date],
          '' AS [Reference],
          CASE
             WHEN Agents.SpanSupervisorCode IS NOT NULL THEN ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') 
             ELSE 'NO SUPERVISOR'
          END AS [Supervisor],
          ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') AS [Svr Name],
          NULL AS [Error]

   FROM mstt_Agents AS Agents
   LEFT JOIN mstt_Agents AS Agents_svr ON Agents.SpanSupervisorCode = Agents_svr.CODE
   LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code

   WHERE NOT EXISTS (SELECT LicenceCode
                     FROM mstt_AgentLicence AS AgentLicence
                     WHERE AgentLicence.AgentCode = Agents.Code
                       AND AgentLicence.CodeLicenceID = 8 -- CCL licence id
                    )
     AND Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents only
     AND Agents.AgentTypeB30 = 2 -- exclude businesses
     AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
     AND Agents.AgentType NOT IN (3, 17, 44, 5, 45, 55) -- exlcude IAR, Staff, Company Sec, Admin, 10% shareholder, Mgr4
     AND Agents.AgentCategory NOT IN ('RI', 'SQMNS', 'ASQMNS', 'RSMNS', 'SRSMNS', 'DIRNS', 'MBRNS', 'PRINNS', 'PTNRNS') -- exclude these categories

   ORDER BY [Svr Name], [Adviser]
END



GO
