      , NULL AS 'DueDate'
      , NULL AS 'Outcome'
      , NULL AS 'CompletionDate'
      , NULL AS 'CompletedBy'
      , NULL AS 'Notes'
      , 'Start Date cannot be greater than End Date' AS 'Error'
   RETURN 0
END
SELECT  (SELECT     ISNULL(RTRIM(SUBSTRING(mstt_Agents.Firstnames, 1, PATINDEX('%[^ ] %',mstt_Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_Agents.Name) , '') 
          FROM          mstt_Agents WHERE      code = @AgentCode) AS 'Query name', 
  mstt_AgentsMain.CODE AS 'Agent code', 
        ISNULL(RTRIM(SUBSTRING(mstt_AgentsMain.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsMain.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsMain.Name) , '')  AS 'Agent name', 
  (SELECT dbo.cscf_GetAgentCompetencies(mstt_AgentsMain.ID, GetDate())) AS 'Competence',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM4.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM4.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM4.Name) , '')  AS 'Manager 4 name',
  mstt_AgentsM4.code  AS 'Mgr4 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM3.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM3.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM3.Name) , '')  AS 'Manager 3 name', 
  mstt_AgentsM3.code  AS 'Mgr3 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM2.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM2.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM2.Name) , '')  AS 'Manager 2 name',
  mstt_AgentsM2.code  AS 'Mgr2 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsM1.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsM1.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsM1.Name) , '')  AS 'Manager 1 name', 
  mstt_AgentsM1.code  AS 'Mgr1 code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsSa.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsSa.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsSa.Name) , '')  AS 'Sales supervisor', 
  mstt_AgentsSa.code  AS 'Sales code',
  ISNULL(RTRIM(SUBSTRING(mstt_AgentsSp.Firstnames, 1, PATINDEX('%[^ ] %',mstt_AgentsSp.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_AgentsSp.Name) , '')  AS 'Span supervisor', 
  mstt_AgentsSp.code  AS 'Span code',
  msit_TrackItems.Description AS 'Description',
  CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 103) AS NVARCHAR) AS 'DueDate',
  CASE msit_TrackItems.completedstate
  WHEN 1 THEN 'Successful'
  WHEN 2 THEN 'Abandoned'
  ELSE ' '
  END AS 'Outcome',
  CASE WHEN  CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME)
  THEN CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR) + 'L'
  WHEN msit_TrackItems.ClearedDate IS NULL THEN ''
  ELSE CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR)
  END AS 'CompletionDate',
  CompletedUsers.Name AS 'CompletedBy',
  msit_TrackItems.Notes AS 'Notes',
  NULL AS 'Error'
--Identify Track items by the individual they are assigned to
FROM  msit_TrackItems
        LEFT JOIN msit_IntUsers ON msit_TrackItems.AssignToUserID = msit_IntUsers.ID
        LEFT JOIN msit_IntUsers AS CompletedUsers ON msit_TrackItems.CompletedStateByID = CompletedUsers.ID
        LEFT JOIN mstt_Agents AS mstt_AgentsMain ON msit_IntUsers.AssociatedAgent = mstt_AgentsMain.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM4 ON mstt_AgentsMain.Manager4Code = mstt_AgentsM4.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM3 ON mstt_AgentsMain.Manager3Code = mstt_AgentsM3.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM2 ON mstt_AgentsMain.Manager2Code = mstt_AgentsM2.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsM1 ON mstt_AgentsMain.Manager1Code = mstt_AgentsM1.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsSa ON mstt_AgentsMain.SaleSupervisorCode = mstt_AgentsSa.CODE
  LEFT JOIN mstt_Agents AS mstt_AgentsSp ON mstt_AgentsMain.SpanSupervisorcode = mstt_AgentsSp.CODE
  LEFT JOIN mstt_Agents AS Business ON COALESCE(mstt_AgentsMain.DirectlyAuthorisedCode, mstt_AgentsMain.OfficeCode, mstt_AgentsMain.AccessAgentCode, mstt_AgentsMain.StrategicAllianceCode) = Business.Code
--Check the track items are the correct type and that the agent reports to our agent code in some way
WHERE (mstt_AgentsMain.CODE IN
    (SELECT code
                 FROM mstt_Agents
                 WHERE  (CompanyCode = @AgentCode OR
      OrganisationCode = @AgentCode) OR
                        (SaleSupervisorCode = @AgentCode OR
                        SpanSupervisorcode = @AgentCode AND
      (manager1code <> @AgentCode OR
                        manager2code <> @AgentCode OR
                        manager3code <> @AgentCode OR
                        manager4code <> @AgentCode)) OR
      (manager1code = @AgentCode OR
                        manager2code = @AgentCode OR
                        manager3code = @AgentCode OR
                        manager4code = @AgentCode AND
      (SaleSupervisorCode <> @AgentCode OR --exclude supervisors where there is a 
                        SpanSupervisorcode <> @AgentCode))))--match on manager code else there will be duplicates
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)) 
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
  AND (msit_TrackItems.CodeTrackItemCode LIKE 'SST%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'RAL%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'LMS%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'Q1%')
  AND msit_TrackItems.CompletedState = '1'
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
ORDER BY [Manager 4 name], [Manager 3 name], [Manager 2 name], [Manager 1 name], [Sales supervisor], [Span supervisor], [Agent name]

GO
/****** Object:  StoredProcedure [dbo].[cscp_CompletedTeamEvents]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- Get the relevant track items, competence details and manager details for each agent beneath the agent code passed in
CREATE PROCEDURE [dbo].[cscp_CompletedTeamEvents] @UserID VARCHAR(255), @AgentCode CHAR(7), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Query name'
      , NULL AS 'Description'
      , NULL AS 'DueDate'
      , NULL AS 'Outcome'
      , NULL AS 'CompletionDate'
      , NULL AS 'CompletedBy'
      , NULL AS 'Team name'
      , NULL AS 'Notes'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS 'Error'
   RETURN 0
END
SELECT  (SELECT     ISNULL(RTRIM(SUBSTRING(mstt_Agents.Firstnames, 1, PATINDEX('%[^ ] %',mstt_Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(mstt_Agents.Name) , '') 
          FROM          mstt_Agents WHERE      code = @AgentCode) AS 'Query name', 
  msit_TrackItems.Description AS 'Description',
  CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 103) AS NVARCHAR) AS 'DueDate',
  CASE msit_TrackItems.completedstate
  WHEN 1 THEN 'Successful'
  WHEN 2 THEN 'Abandoned'
  ELSE ' '
  END AS 'Outcome',
  CASE WHEN  CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME)
  THEN CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR) + 'L'
  WHEN msit_TrackItems.ClearedDate IS NULL THEN ''
  ELSE CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 103) AS NVARCHAR)
  END AS 'CompletionDate',
  CompletedUsers.Name AS 'CompletedBy',
  msit_IntTeams.Name AS 'Team name',
  msit_TrackItems.Notes AS 'Notes',
  NULL AS 'Error'
--Identify Track items by the individual they are assigned to
FROM  msit_TrackItems
  LEFT JOIN msit_IntTeams ON msit_TrackItems.AssignToTeamID = msit_IntTeams.ID
        LEFT JOIN msit_IntUsers AS CompletedUsers ON msit_TrackItems.CompletedStateByID = CompletedUsers.ID
--Check the track items are the correct type and that the agent reports to our agent code in some way
WHERE msit_TrackItems.AssignToTeamID IS NOT NULL
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)) 
  AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.FollowUpDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
  AND (msit_TrackItems.CodeTrackItemCode LIKE 'SST%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'RAL%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'LMS%'
        OR msit_TrackItems.CodeTrackItemCode LIKE 'Q1%')
  AND msit_TrackItems.CompletedState = '1'
ORDER BY [Team name]

GO
/****** Object:  StoredProcedure [dbo].[cscp_DataProt]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
