CREATE PROCEDURE [dbo].[cscp_DataProt] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10), @Mode CHAR(1)
AS

IF @Mode = 'E' -- expiring licences
BEGIN
   IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
   BEGIN
      SELECT 
        NULL AS [Adviser]
      , NULL AS [Adviser Id] 
      , NULL AS [Status]
      , NULL AS [Expiry Date] 
      , NULL AS [Reference] 
      , NULL AS [Supervisor] 
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy.'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
      RETURN 0
   END
   IF (CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
   BEGIN
      SELECT 
        NULL AS [Adviser]
      , NULL AS [Adviser Id] 
      , NULL AS [Status]
      , NULL AS [Expiry Date] 
      , NULL AS [Reference] 
      , NULL AS [Supervisor] 
      , 'Start Date cannot be greater than End Date' AS 'Error'
      RETURN 0
   END
END
ELSE --@Mode = 'M' -- missing licences
BEGIN
   IF (@StartDate <> 'n/a' AND @StartDate <> '') OR (@EndDate <> 'n/a' AND @EndDate <> '')
   BEGIN
      SELECT 
        NULL AS [Adviser]
      , NULL AS [Adviser Id] 
      , NULL AS [Status]
      , NULL AS [Expiry Date] 
      , NULL AS [Reference] 
      , NULL AS [Supervisor] 
      , CASE WHEN @StartDate <> 'n/a' AND @StartDate <> '' THEN 'Start Date not relevant to Missing Licence Report. Please blank out this parameter.'
             WHEN @EndDate <> 'n/a' AND @EndDate <> '' THEN  'End Date not relevant to Missing Licence Report. Please blank out this parameter.'           
        END AS [Error]
      RETURN 0
   END
END

IF @Mode = 'E' -- expiring licences
BEGIN
   SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %',Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name) , '')  AS [Adviser],
          Agents.Code AS [Adviser Id],
          CASE Agents.CompetentStatus
             WHEN 1 THEN 'Active'
             WHEN 5 THEN 'Pre-appointed'
             ELSE 'Unknown'  --should never happen as where clause restricts to 1 or 5 only
          END AS [Status],
          CONVERT(VARCHAR, AgentLicence.ExpiryDate, 103) AS [Expiry Date],
          AgentLicence.Reference AS [Reference],
          CASE
             WHEN Agents.SpanSupervisorCode IS NOT NULL THEN ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') 
             ELSE 'NO SUPERVISOR'
          END AS [Supervisor],
          NULL AS [Error]

   FROM mstt_Agents AS Agents
   INNER JOIN mstt_AgentLicence AS AgentLicence ON AgentLicence.AgentID = Agents.id
   LEFT JOIN mstt_Agents AS Agents_svr ON Agents.SpanSupervisorCode = Agents_svr.CODE
   LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code

   WHERE AgentLicence.CodeLicenceID = 86 -- DP licence id
     AND AgentLicence.EndDate IS NULL
     AND CAST(CONVERT(NVARCHAR, AgentLicence.ExpiryDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
     AND CAST(CONVERT(NVARCHAR, AgentLicence.ExpiryDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) -- Parameters
     AND Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents only
     AND Agents.AgentTypeB30 = 2 -- exclude businesses
     AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
     AND Agents.AgentType NOT IN (3, 17, 44, 5, 45, 55) -- exlcude IAR, Staff, Company Sec, Admin, 10% shareholder, Mgr4
     AND Agents.AgentCategory NOT IN ('RI', 'SQMNS', 'ASQMNS', 'RSMNS', 'SRSMNS', 'DIRNS', 'MBRNS', 'PRINNS', 'PTNRNS') -- exclude these categories

   ORDER BY ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), ''), AgentLicence.ExpiryDate, [Adviser]
END

ELSE --@Mode = 'M' -- missing licences

BEGIN
   --1. has a licence record with no start date or with an end date, and no other current/valid licence
   SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %',Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name) , '')  AS [Adviser],
          Agents.Code AS [Adviser Id],
          CASE Agents.CompetentStatus
             WHEN 1 THEN 'Active'
             WHEN 5 THEN 'Pre-appointed'
             ELSE 'Unknown'  --should never happen as where clause restricts to 1 or 5 only
          END AS [Status],
          CONVERT(VARCHAR, AgentLicence.ExpiryDate, 103) AS [Expiry Date],
          AgentLicence.Reference AS [Reference],
          CASE
             WHEN Agents.SpanSupervisorCode IS NOT NULL THEN ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') 
             ELSE 'NO SUPERVISOR'
          END AS [Supervisor],
          ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') AS [Svr Name],
          NULL AS [Error]

   FROM mstt_Agents AS Agents
   INNER JOIN mstt_AgentLicence AS AgentLicence ON AgentLicence.AgentID = Agents.id
   LEFT JOIN mstt_Agents AS Agents_svr ON Agents.SpanSupervisorCode = Agents_svr.CODE
   LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code

   WHERE AgentLicence.CodeLicenceID = 86 -- DP licence id
     AND (AgentLicence.StartDate IS NULL -- with no start date
          OR (AgentLicence.EndDate IS NOT NULL AND CAST(CONVERT(NVARCHAR, AgentLicence.EndDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME))) -- with an end date in the past
     AND NOT EXISTS (SELECT LicenceCode
                     FROM mstt_AgentLicence AS AgentLicence
                     WHERE AgentLicence.AgentCode = Agents.Code
                       AND AgentLicence.CodeLicenceID = 86 -- DP licence id
                       AND AgentLicence.StartDate IS NOT NULL AND CAST(CONVERT(NVARCHAR, AgentLicence.StartDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME)
                       AND (AgentLicence.EndDate IS NULL OR CAST(CONVERT(NVARCHAR, AgentLicence.EndDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME))
                    ) -- there is not another current/valid licence record
     AND Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents only
     AND Agents.AgentTypeB30 = 2 -- exclude businesses
     AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
     AND Agents.AgentType NOT IN (3, 17, 44, 5, 45, 55) -- exlcude IAR, Staff, Company Sec, Admin, 10% shareholder, Mgr4
     AND Agents.AgentCategory NOT IN ('RI', 'SQMNS', 'ASQMNS', 'RSMNS', 'SRSMNS', 'DIRNS', 'MBRNS', 'PRINNS', 'PTNRNS') -- exclude these categories

   UNION

   --2. has no licence record at all
   SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %',Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name) , '')  AS [Adviser],
          Agents.Code AS [Adviser Id],
          CASE Agents.CompetentStatus
             WHEN 1 THEN 'Active'
             WHEN 5 THEN 'Pre-appointed'
             ELSE 'Unknown'  --should never happen as where clause restricts to 1 or 5 only
          END AS [Status],
          '' AS [Expiry Date],
          '' AS [Reference],
          CASE
             WHEN Agents.SpanSupervisorCode IS NOT NULL THEN ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') 
             ELSE 'NO SUPERVISOR'
          END AS [Supervisor],
          ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') AS [Svr Name],
          NULL AS [Error]

   FROM mstt_Agents AS Agents
   LEFT JOIN mstt_Agents AS Agents_svr ON Agents.SpanSupervisorCode = Agents_svr.CODE
   LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code

   WHERE NOT EXISTS (SELECT LicenceCode
                     FROM mstt_AgentLicence AS AgentLicence
                     WHERE AgentLicence.AgentCode = Agents.Code
                       AND AgentLicence.CodeLicenceID = 86 -- DP licence id
                    )
     AND Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents only
     AND Agents.AgentTypeB30 = 2 -- exclude businesses
     AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
     AND Agents.AgentType NOT IN (3, 17, 44, 5, 45, 55) -- exlcude IAR, Staff, Company Sec, Admin, 10% shareholder, Mgr4
     AND Agents.AgentCategory NOT IN ('RI', 'SQMNS', 'ASQMNS', 'RSMNS', 'SRSMNS', 'DIRNS', 'MBRNS', 'PRINNS', 'PTNRNS') -- exclude these categories

   ORDER BY [Svr Name], [Adviser]
END



GO
/****** Object:  StoredProcedure [dbo].[cscp_EnhancementRateMissing]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[cscp_EnhancementRateMissing] @UserID VARCHAR(255), @AgType AS VARCHAR (50), @Min varchar (8), @Max varchar (8), @ProdType VARCHAR (255), @Provider VARCHAR(255)
AS

IF OBJECT_ID('tempdb..#TEMPTABLE53') IS NOT NULL
   DROP TABLE #TEMPTABLE53

IF OBJECT_ID('tempdb..#TEMPTABLE53a') IS NOT NULL
   DROP TABLE #TEMPTABLE53a

IF OBJECT_ID('tempdb..#TEMPTABLE53b') IS NOT NULL
   DROP TABLE #TEMPTABLE53b

IF OBJECT_ID('tempdb..#TEMPTABLE53c') IS NOT NULL
   DROP TABLE #TEMPTABLE53c


SELECT CASE
  WHEN Uplifts.UpliftRate < @Min THEN
  'Enhancement Rates below ' + @Min + '%age'
  WHEN Uplifts.UpliftRate > @Max THEN
  'Enhancement Rates above ' + @Max + '%age'
  WHEN (Uplifts.UpliftRate BETWEEN @Min AND @Max) AND Uplifts.Status = 2 THEN
  'Valid Enhancements Rates awaiting Authorisation'
  END AS [Reason],
       Agents.Code AS [UniqueID],
       RTRIM(Agents.Descn) AS [BusinessName],
       Agents.AgentTypeDescription AS Type,
       Uplifts.UpliftRate AS Uplift,
       CASE Uplifts.Status
       WHEN 0 THEN 'Authorised'
       WHEN 1 THEN 'Rejected'
       WHEN 2 THEN 'Pending'
       END AS [Status],
       Uplifts.DateInForce AS DateinForce,
       CONVERT(VARCHAR, Uplifts.CreatedDate, 103) AS [CreatedDate],
       CONVERT(VARCHAR, Uplifts.AuthorisedDate, 103) AS [Authorised Date],
       BIProd.ProductName,
       SubGroup.ProductSubGroupName  AS ProductType,
       BIProd.ProductProviderCode AS ProductProvider
INTO #TEMPTABLE53
FROM   mstt_AgentUplifts Uplifts
INNER JOIN mstt_Agents AS Agents ON Uplifts.AgentCode = Agents.Code
INNER JOIN mstt_CodeBIProducts AS BIProd ON Uplifts.ProductCode = BIProd.ProductCode
INNER JOIN mstt_CodeReportingProductCode ON BIProd.ReportingProductCode = mstt_CodeReportingProductCode.ReportingProductCode
INNER JOIN mstt_CodeProductSubGroup AS SubGroup ON mstt_CodeReportingProductCode.ProductSubGroupCode = SubGroup.ProductSubGroupCode
INNER JOIN mstt_CodeProductGroup AS ProdGroup ON SubGroup.ProductGroupCode = ProdGroup.ProductGroupCode
WHERE (Agents.AgentTypeDescription = @AgType OR @AgType = 'All')
      AND (SubGroup.ProductSubGroupName = @ProdType OR @ProdType = 'All')
      AND (BIProd.ProductProviderCode = @Provider OR @Provider = 'All')
      AND BIProd.ProductType NOT IN ('Transition','Adjustment')
      AND BIProd.ProductCode NOT IN ('CHILTRU','INTELL', 'NEWBS')
      AND BIProd.ProductProviderCode <> 'SCOT EQLEG'
      AND (Agents.AgentType <> 49 AND (BIProd.ReportingProductCode <> 8 OR BIProd.ProductCode NOT IN ('BOSCLOAN','FODCLOAN', 'NWCLOAN', 'NRBTLET') OR ProdGroup.ProductCategoryCode <> 1))
      AND ((Uplifts.Status = 0 AND(Uplifts.UpliftRate < @Min OR Uplifts.UpliftRate > @Max)) 
  OR (Uplifts.Status = 2 AND Uplifts.UpliftRate BETWEEN @Min AND @Max))
      AND BIProd.EndDate IS NULL
      AND Agents.CompetentStatus = '1' 
      AND Agents.AgentTypeGrouping = '1'
      AND Uplifts.ID =  (SELECT TOP 1 mstt_AgentUplifts.ID 
      FROM mstt_AgentUplifts 
      WHERE mstt_AgentUplifts.AgentCode = Uplifts.AgentCode
      AND mstt_AgentUplifts.ProductCode = BIProd.ProductCode
      ORDER BY mstt_AgentUplifts.CreatedDate ASC)

--Avoid Create Table as this can cause a collation conflict in IT
SELECT
   CAST(' ' AS VARCHAR(50)) AS Reason,
   Code AS UniqueID,
   Descn AS BusinessName,
   AgentTypeDescription AS Type,
   CAST(' ' AS VARCHAR(10)) AS Uplift,
   CAST(' ' AS VARCHAR(10)) AS Status,
   CAST(' ' AS VARCHAR(10)) AS DateinForce,
   CAST(' ' AS VARCHAR(10)) AS CreatedDate,
   CAST(' ' AS VARCHAR(10)) AS AuthorisedDate,
   CAST(' ' AS VARCHAR(50)) AS ProductName,
   CAST(' ' AS VARCHAR(50)) AS ProductType,
   CAST(' ' AS VARCHAR(50)) AS ProductProvider
INTO #TEMPTABLE53a 
FROM mstt_Agents 
WHERE 1=0

DECLARE @Product VARCHAR(50)
DECLARE @ProductSubName VARCHAR(50)
DECLARE @ReportingProductCode VARCHAR(50)
DECLARE @ProductCategoryCode VARCHAR(50)

DECLARE PRODUCT_CURSOR CURSOR FOR 

SELECT BIProducts.ProductCode, SubGroup.ProductSubGroupName, BIProducts.ReportingProductCode, ProdGroup.ProductCategoryCode
FROM mstt_CodeBIProducts AS BIProducts
INNER JOIN mstt_CodeReportingProductCode ON BIProducts.ReportingProductCode = mstt_CodeReportingProductCode.ReportingProductCode
INNER JOIN mstt_CodeProductSubGroup AS SubGroup ON mstt_CodeReportingProductCode.ProductSubGroupCode = SubGroup.ProductSubGroupCode
INNER JOIN mstt_CodeProductGroup AS ProdGroup ON SubGroup.ProductGroupCode = ProdGroup.ProductGroupCode
WHERE (@ProdType = SubGroup.ProductSubGroupName OR @ProdType = 'All')
AND (@Provider = BIProducts.ProductProviderCode OR @Provider = 'All')
AND BIProducts.EndDate IS NULL
AND BIProducts.ProductType NOT IN ('Transition','Adjustment')
AND BIProducts.ProductCode NOT IN ('CHILTRU','INTELL', 'NEWBS')
AND BIProducts.ProductProviderCode <> 'SCOT EQLEG'

OPEN PRODUCT_CURSOR

--Loop through the first table and get details from both where there is a match on client details but not franchise or transaction ID
--and where the old transaction date is within two years of the new transaction date.
FETCH NEXT FROM PRODUCT_CURSOR 
INTO @Product, @ProductSubName, @ReportingProductCode, @ProductCategoryCode

WHILE @@FETCH_STATUS = 0
BEGIN 
        INSERT INTO #TEMPTABLE53a
        SELECT DISTINCT 'Enhancement Rates Missing' AS Reason,
        Agents.Code AS UniqueID,
        RTRIM(Agents.Descn) AS BusinessName,
        Agents.AgentTypeDescription AS Type,
        ' ' AS Uplift,
        ' ' AS Status,
        ' ' AS DateinForce,
        ' ' AS CreatedDate,
        ' ' AS AuthorisedDate,
  (SELECT ProductName FROM mstt_CodeBIProducts 
    WHERE @Product = mstt_CodeBIProducts.ProductCode) AS ProductName,
  @ProductSubName  AS ProductType,
  (SELECT ProductProviderCode FROM mstt_CodeBIProducts WHERE mstt_CodeBIProducts.ProductCode = @Product) AS ProductProvider
  FROM   mstt_Agents AS Agents
  LEFT JOIN mstt_AgentUplifts ON mstt_AgentUplifts.AgentCode = Agents.Code
  WHERE (Agents.AgentTypeDescription = @AgType OR @AgType = 'All')
  AND mstt_AgentUplifts.AgentCode IS NOT NULL
  AND (Agents.AgentType <> 49 AND (@ReportingProductCode <> 8 OR @Product NOT IN ('BOSCLOAN','FODCLOAN', 'NWCLOAN', 'NRBTLET') OR @ProductCategoryCode <> 1))
  AND NOT EXISTS (SELECT * FROM mstt_AgentUplifts WHERE mstt_AgentUplifts.ProductCode = @Product AND mstt_AgentUplifts.AGENTCODE = Agents.Code)
  AND Agents.CompetentStatus = '1' 
  AND Agents.AgentTypeGrouping = '1'
FETCH NEXT FROM PRODUCT_CURSOR 
   INTO @Product, @ProductSubName, @ReportingProductCode, @ProductCategoryCode
END

CLOSE PRODUCT_CURSOR
DEALLOCATE PRODUCT_CURSOR

SELECT 'Franchise with no Enhancement Rates' AS [Reason],
       Agents.Code AS [UniqueID],
       RTRIM(Agents.Descn) AS [BusinessName],
       Agents.AgentTypeDescription AS Type,
       mstt_AgentUplifts.UpliftRate AS Uplift,
       CASE mstt_AgentUplifts.Status
       WHEN 0 THEN 'Authorised'
       WHEN 1 THEN 'Rejected'
       WHEN 2 THEN 'Pending'
       END AS [Status],
       mstt_AgentUplifts.DateInForce AS DateinForce,
       CONVERT(VARCHAR, mstt_AgentUplifts.CreatedDate, 103) AS [CreatedDate],
       CONVERT(VARCHAR, mstt_AgentUplifts.AuthorisedDate, 103) AS [AuthorisedDate],
       ' ' AS ProductName,
       ' ' AS ProductType,
       ' ' AS ProductProvider
INTO #TEMPTABLE53b
FROM   mstt_Agents AS Agents 
LEFT JOIN mstt_AgentUplifts ON mstt_AgentUplifts.AgentCode = Agents.Code
WHERE (Agents.AgentTypeDescription = @AgType OR @AgType = 'All')
AND mstt_AgentUplifts.AgentCode IS NULL
AND Agents.CompetentStatus = '1' 
AND Agents.AgentTypeGrouping = '1'


SELECT 'Enhancement Rates Missing' AS [Reason],
       Agents.Code AS [UniqueID],
       RTRIM(Agents.Descn) AS [BusinessName],
       Agents.AgentTypeDescription AS Type,
        ' ' AS Uplift,
        ' ' AS [Status],
        ' ' AS DateinForce,
        ' ' AS [CreatedDate],
        ' ' AS [AuthorisedDate],
  Products.ProductName,
       SubGroup.ProductSubGroupName  AS ProductType,
       Products.ProductProviderCode AS ProductProvider
INTO #TEMPTABLE53c
FROM   mstt_Agents AS Agents
LEFT JOIN mstt_AgentUplifts AS Uplifts1 ON Agents.Code = Uplifts1.AgentCode
INNER JOIN mstt_CodeBIProducts AS Products ON Uplifts1.ProductCode = Products.ProductCode
INNER JOIN mstt_CodeReportingProductCode ON Products.ReportingProductCode = mstt_CodeReportingProductCode.ReportingProductCode
INNER JOIN mstt_CodeProductSubGroup AS SubGroup ON mstt_CodeReportingProductCode.ProductSubGroupCode = SubGroup.ProductSubGroupCode
INNER JOIN mstt_CodeProductGroup AS ProdGroup ON SubGroup.ProductGroupCode = ProdGroup.ProductGroupCode
WHERE (Agents.AgentTypeDescription = @AgType OR @AgType = 'All')
      AND (SubGroup.ProductSubGroupName = @ProdType OR @ProdType = 'All')
      AND (Products.ProductProviderCode = @Provider OR @Provider = 'All')
      AND Products.ProductType NOT IN ('Transition','Adjustment')
      AND Products.ProductCode NOT IN ('CHILTRU','INTELL', 'NEWBS')
      AND Products.ProductProviderCode <> 'SCOT EQLEG'
      AND (Agents.AgentType <> 49 AND (Products.ReportingProductCode <> 8 OR Products.ProductCode NOT IN ('BOSCLOAN','FODCLOAN', 'NWCLOAN', 'NRBTLET') OR ProdGroup.ProductCategoryCode <> 1))
      AND (Uplifts1.Status = 1 AND NOT EXISTS (SELECT Agents1.Code FROM   mstt_Agents AS Agents1
            LEFT JOIN mstt_AgentUplifts AS Uplifts2 ON Agents1.Code = Uplifts2.AgentCode
            LEFT JOIN mstt_CodeBIProducts AS Products1 ON Uplifts1.ProductCode = Products1.ProductCode
            WHERE Uplifts2.ProductCode = Uplifts1.ProductCode
            AND Agents.Code = Agents1.Code
            AND (Uplifts1.Status = 0 OR Uplifts1.Status = 2)))
AND Products.EndDate IS NULL
AND Agents.CompetentStatus = '1' 
AND Agents.AgentTypeGrouping = '1'

SELECT CASE
WHEN (SELECT COUNT(Reason) FROM #TEMPTABLE53 WHERE Reason = 'Enhancement Rates below ' + @Min + '%age') < 1 
  THEN 'Enhancement Rates below ' + @Min + '%age - Nothing to Report'
  ELSE 'Dummy'
  END AS [Reason],
' ' AS UniqueID,
' ' AS [BusinessName],
' ' AS Type,
' ' AS Uplift,
' ' AS [Status],
' ' AS DateinForce,
' ' AS [CreatedDate],
' ' AS [AuthorisedDate],
' ' AS ProductName,
' ' AS ProductType,
' ' AS ProductProvider

UNION ALL

SELECT CASE
WHEN (SELECT COUNT(Reason) FROM #TEMPTABLE53 WHERE Reason = 'Enhancement Rates above ' + @Max + '%age')< 1 
  THEN 'Enhancement Rates above ' + @Max + '%age - Nothing to Report'
  ELSE 'Dummy'
  END AS [Reason],
' ' AS UniqueID,
' ' AS [BusinessName],
' ' AS Type,
' ' AS Uplift,
' ' AS [Status],
' ' AS DateinForce,
' ' AS [CreatedDate],
' ' AS [AuthorisedDate],
' ' AS ProductName,
' ' AS ProductType,
' ' AS ProductProvider

UNION ALL

SELECT CASE
WHEN (SELECT COUNT(Reason) FROM #TEMPTABLE53 WHERE Reason = 'Valid Enhancements Rates awaiting Authorisation')< 1 
  THEN 'Valid Enhancements Rates awaiting Authorisation - Nothing to Report'
  ELSE 'Dummy'
  END AS [Reason],
' ' AS UniqueID,
' ' AS [BusinessName],
' ' AS Type,
' ' AS Uplift,
' ' AS [Status],
' ' AS DateinForce,
' ' AS [CreatedDate],
' ' AS [AuthorisedDate],
' ' AS ProductName,
' ' AS ProductType,
' ' AS ProductProvider

UNION ALL

SELECT * FROM #TEMPTABLE53

UNION ALL

SELECT CASE
WHEN (SELECT COUNT(Reason) FROM #TEMPTABLE53a)< 1 AND (SELECT COUNT(Reason) FROM #TEMPTABLE53c)< 1
  THEN 'Enhancement Rates Missing - Nothing to Report'
  ELSE 'Dummy'  
  END AS [Reason],
' ' AS UniqueID,
' ' AS [BusinessName],
' ' AS Type,
' ' AS Uplift,
' ' AS [Status],
' ' AS DateinForce,
' ' AS [CreatedDate],
' ' AS [AuthorisedDate],
' ' AS ProductName,
' ' AS ProductType,
' ' AS ProductProvider

UNION ALL

SELECT * FROM #TEMPTABLE53a

UNION ALL

SELECT * FROM #TEMPTABLE53c

UNION ALL

SELECT CASE
WHEN (SELECT COUNT(Reason) FROM #TEMPTABLE53b)< 1
  THEN 'Franchise with no Enhancement Rates - Nothing to Report'
  ELSE 'Dummy'  
  END AS [Reason],
' ' AS UniqueID,
' ' AS [BusinessName],
' ' AS Type,
' ' AS Uplift,
' ' AS [Status],
' ' AS DateinForce,
' ' AS [CreatedDate],
' ' AS [AuthorisedDate],
' ' AS ProductName,
' ' AS ProductType,
' ' AS ProductProvider

UNION ALL

SELECT * FROM #TEMPTABLE53b

ORDER BY [BusinessName]
DROP TABLE #TEMPTABLE53
DROP TABLE #TEMPTABLE53a
DROP TABLE #TEMPTABLE53b
DROP TABLE #TEMPTABLE53c

GO
/****** Object:  StoredProcedure [dbo].[cscp_ExamFailures]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[cscp_ExamFailures] @UserID VARCHAR(255), @StartDate AS VARCHAR(10), @EndDate AS VARCHAR(10)
AS

IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS [Adviser ID]
      , NULL AS [Adviser Name] 
      , NULL AS [Exam Code] 
      , NULL AS [Exam Description] 
      , NULL AS [Date Taken]
      , NULL AS [Date Created]
      , NULL AS [Result] 
      , NULL AS [Mark] 
      , NULL AS [Attempts]
      , NULL AS [Refresher] 
      , NULL AS [Licence Code] 
      , NULL AS [Licence Description] 
      , NULL AS [Licence Start Date] 
      , NULL AS [Licence Expiry Date] 
      , NULL AS [Licence End Date]
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

IF (CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
BEGIN
  SELECT 
        NULL AS [Adviser ID]
      , NULL AS [Adviser Name] 
      , NULL AS [Exam Code] 
      , NULL AS [Exam Description] 
      , NULL AS [Date Taken]
      , NULL AS [Date Created]
      , NULL AS [Result] 
      , NULL AS [Mark] 
      , NULL AS [Attempts]
      , NULL AS [Refresher] 
      , NULL AS [Licence Code] 
      , NULL AS [Licence Description] 
      , NULL AS [Licence Start Date] 
      , NULL AS [Licence Expiry Date] 
      , NULL AS [Licence End Date]
      , 'Start Date cannot be greater than End Date' AS [Error]
   RETURN 0
END

SELECT AgentExams.AgentCode AS [Adviser ID],
       ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser Name],
       AgentExams.Type AS [Exam Code],
       AgentExams.AgentExamDescription AS [Exam Description],
       CONVERT(VARCHAR, AgentExams.DateTaken, 103) AS [Date Taken],
       CONVERT(VARCHAR, AgentExams.DateCreated, 103) AS [Date Created],
       CASE AgentExams.Result
          WHEN 1 THEN 'Pass'
          WHEN 2 THEN 'Fail'
          ELSE ''
       END AS [Result],
       AgentExams.Percentage AS [Mark],
       AgentExams.NumberOfAttempts AS [Attempts],
       CASE AgentExams.Refresher
          WHEN 1 THEN 'Yes'
          ELSE 'No'
       END AS [Refresher],
       CodeLicence.Code AS [Licence Code], -- required even if adviser does not have licence
       CodeLicence.Description AS [Licence Description], -- required even if adviser does not have licence
       CONVERT(VARCHAR, AgentLicence.StartDate, 103) AS [Licence Start Date],
       CONVERT(VARCHAR, AgentLicence.ExpiryDate, 103) AS [Licence Expiry Date],
       CONVERT(VARCHAR, AgentLicence.EndDate, 103) AS [Licence End Date],
       NULL AS [Error]

FROM mstt_AgentExams AS AgentExams
INNER JOIN mstt_Agents AS Agents ON Agents.Code = AgentExams.AgentCode
LEFT JOIN msit_CodeAgentExams AS CodeAgentExams ON CodeAgentExams.Code = AgentExams.Type
LEFT JOIN msit_CodeExamLicence AS CodeExamLicence ON CodeExamLicence.CodeAgentExamsID = CodeAgentExams.ID
LEFT JOIN msit_CodeLicence AS CodeLicence ON CodeLicence.ID = CodeExamLicence.CodeLicenceID
LEFT JOIN mstt_AgentLicence AS AgentLicence ON AgentLicence.CodeLicenceID = CodeExamLicence.CodeLicenceID
      AND AgentLicence.AgentID = Agents.ID
      AND NOT EXISTS (SELECT AgentLicence_2.ID
                      FROM mstt_AgentLicence AgentLicence_2
                      WHERE AgentLicence_2.AgentID = AgentLicence.AgentID
                        AND AgentLicence_2.CodeLicenceID = AgentLicence.CodeLicenceID
                        AND CAST(CONVERT(NVARCHAR,AgentLicence_2.StartDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR,AgentLicence.StartDate, 112) AS DATETIME)
                     ) -- only show one licence of each type per agent (the one with the latest StartDate)
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code

WHERE AgentExams.Result = 2 -- failed exam
  AND Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents only
  AND CAST(CONVERT(NVARCHAR, AgentExams.DateCreated, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, AgentExams.DateCreated, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) -- Parameters
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised

ORDER BY [Adviser Name], AgentExams.DateTaken, AgentExams.Type

GO
/****** Object:  StoredProcedure [dbo].[cscp_ExpensesReimbursed]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****************************************************************************************
Program:  	    cscp_ExpensesReimbursed						
					
											
Description:	
This program is a "wrap" to enable FINSTAT0025a to be called via 
a batch process allowing the automation of the Month End report.

This proc is called as follows:
      set dateformat dmy 
      exec cscp_ExpensesReimbursed '', '01/01/2006', '31/03/2011'				
				
Amendment History								
-----------------								
										
Date		    Who			    Description				
----		    ---			    -----------			
09/02/2011  M Cawood    Cater for variable VAT Rates as per owp_BatchFINSTAT0052: 

                        Derive VAT Rates from msit_MIWarehouseCodesandDescriptions 
                        and store for use against each Payment.
                        
                        Determine VAT Rate according to the PaymentDueDate held on 
                        the mstt_PaymentsPending table (defaulting to CreateDatetime
                        if not set or dummy date (i.e. prior to 1 Jan 2005). If
                        Payment on S_AGMPAY derive VAT Rate by deriving VATAmount
                        into NetAmount and rounding to 2 dec places. Default values to
                        15%, 17.5% or 20% to cater for rounding differences.
                        
                        Default Net Amount to value held on S_AGMPAY table if present
                        as this represents the actual value derived on SWIFT.
	
****************************************************************************************/
CREATE PROCEDURE [dbo].[cscp_ExpensesReimbursed] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

declare 
@StartDt as datetime,
@EndDt as datetime

--1. validate input dates
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 --If the dates are not valid then returns all NULL's and an error message
BEGIN
  SELECT 
  NULL AS [StandingOrder],
        NULL AS [Franchise Code],
        NULL AS [Franchise],
  NULL AS [GrossAmount], 
  NULL AS [VAT], 
  NULL AS [NetAmount], 
        CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   --NULL  AS [Error]
   RETURN 0
END
set @StartDt = convert(datetime, right(@StartDate,4) + '/'+ substring(@StartDate,4,2) + '/' + left(@StartDate,2), 111) 
set @EndDt = convert(datetime, right(@EndDate,4) + '/'+ substring(@EndDate,4,2) + '/' + left(@EndDate,2), 111) 

--DECLARE @VAT DECIMAL(15,2) --MPC 09/02/2011

--2. determine VAT rate
--MPC 09/02/2011 NEW CODE - START
declare @VAT table (VATRate        decimal(8,2)  not null,
                    VATStartDate   datetime      not null,
                    VATEndDate     datetime      not null)

insert into @VAT
Select VATRate    = convert(decimal(8,2),ShortDescription),
       StartDate  = convert(datetime,Code,111),
       EndDate    = convert(datetime,Description,111)
from msit_MIWarehouseCodesandDescriptions
where ColumnName = 'VATRate'
  and ShortDescription is not null 
  and Description is not null    
--MPC 09/02/2011 NEW CODE - END

/*    MPC 09/02/2011 REMOVE OLD CODE - START
SELECT @VAT = CAST(KeyValue AS DECIMAL(15,2))
FROM msit_Settings
WHERE SectionName = 'Assumptions'
  AND KeyName = 'VAT'

      MPC 09/02/2011 REMOVE OLD CODE - END      */

--3. extract data into temp table
IF OBJECT_ID('tempdb..#OTH0001') IS NOT NULL
   DROP TABLE #OTH0001

SELECT  ltrim(ISNULL(PaymentsPending.StandingOrderCode, 'Unknown')) + ' / ' + ISNULL(PaymentsPending.StandingOrderCodeDesc, 'Unknown') AS 'StandingOrder',
        CASE 
           WHEN Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' THEN Agents_fr.Code
           ELSE Agents.Code 
        END AS 'Franchise Code',
  CASE
     WHEN agents.Firm IS NOT NULL AND RTRIM(agents.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown'))
     ELSE RTRIM(ISNULL(Agents.DESCN, 'Unknown'))
  END AS [Franchise],
  CAST(PaymentsPending.Amount AS DECIMAL(15,2)) AS [GrossAmount], 
  NULL AS [VAT], 
  CASE
     WHEN PaymentsPending.SubjectToVAT = 1 AND isnull(PA.NetAmount,0) <> 0 THEN PA.NetAmount   --MPC: 09/02/2011
--     WHEN PaymentsPending.SubjectToVAT = 1 THEN CAST(PaymentsPending.Amount / (1.00 + (@VAT / 100.00)) AS DECIMAL(15,2))    --MPC: 09/02/2011
     WHEN PaymentsPending.SubjectToVAT = 1 THEN CAST(PaymentsPending.Amount / (1.00 + (V.VATRate / 100.00)) AS DECIMAL(15,2))   --MPC: 09/02/2011
     ELSE CAST(PaymentsPending.Amount AS DECIMAL(15,2))
  END AS [NetAmount], 
--  NULL AS [Error]  --MPC: 09/02/2011
  CASE              --MPC: 09/02/2011
     WHEN PaymentsPending.SubjectToVAT = 1 AND isnull(PA.NetAmount,0) <> 0 THEN round(100*(isnull(PA.VATAmount,0)/PA.NetAmount) ,2)   --MPC: 09/02/2011
     WHEN PaymentsPending.SubjectToVAT = 1 THEN V.VATRate                                                                          --MPC: 09/02/2011
  END AS [VATRate]    --MPC: 09/02/2011
INTO #OTH0001
FROM mstt_PaymentsPending PaymentsPending 
LEFT JOIN mstt_agents AS agents ON PaymentsPending.Agent_Code = agents.code
LEFT JOIN mstt_agents AS agents_fr ON agents.Firm = agents_fr.code
LEFT JOIN @VAT V on DATEADD(dd,0,DATEDIFF(dd,0,CASE WHEN PaymentsPending.PaymentDueDate >= '1 Jan 2005' THEN PaymentsPending.PaymentDueDate ELSE PaymentsPending.CreateDatetime END)) between V.VATStartDate and V.VATEndDate   --MPC: 09/02/2011
LEFT JOIN sa_swift_S_AGMPAY PA ON PA.AGMID = PaymentsPending.ID      --MPC: 09/02/2011
WHERE PaymentsPending.CommissionType = 8
  AND CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) between @StartDt and @EndDt
  --AND CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) <= @EndDt

--4. select data for report
SELECT 
     [StandingOrder]
   , [Franchise Code]
   , [Franchise]
   , ISNULL(SUM(ISNULL(CAST([GrossAmount] AS DECIMAL(15,2)), 0.00)), 0.00) AS [GrossAmount]
   , ISNULL(SUM(ISNULL(CAST([GrossAmount] AS DECIMAL(15,2)), 0.00)), 0.00) - ISNULL(SUM(ISNULL(CAST([NetAmount] AS DECIMAL(15,2)), 0.00)), 0.00) AS [VAT]
   , ISNULL(SUM(ISNULL(CAST([NetAmount] AS DECIMAL(15,2)), 0.00)), 0.00) AS [NetAmount]
   , CASE when [VATRate] between 17.3 and 17.7 then 17.50       --MPC: 09/02/2011
          when [VATRate] between 14.8 and 15.2 then 15.00       --MPC: 09/02/2011
          when [VATRate] between 19.8 and 20.2 then 20.00       --MPC: 09/02/2011
          else [VATRate] End as [Error]                         --MPC: 09/02/2011
FROM  #OTH0001
WHERE [GrossAmount] <> 0.00 --Display only non-zero values
GROUP BY [StandingOrder], [Franchise Code], [Franchise], 
CASE when [VATRate] between 17.3 and 17.7 then 17.50            --MPC: 09/02/2011
          when [VATRate] between 14.8 and 15.2 then 15.00       --MPC: 09/02/2011
          when [VATRate] between 19.8 and 20.2 then 20.00       --MPC: 09/02/2011
          else [VATRate] End                                    --MPC: 09/02/2011
ORDER BY [StandingOrder], [Franchise Code], [Franchise]

--5. tidy up
DROP TABLE #OTH0001;
GO
/****** Object:  StoredProcedure [dbo].[cscp_FeeProtection]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[cscp_FeeProtection] @UserID VARCHAR(255), @StartDate VARCHAR(10),@EndDate VARCHAR(10)
AS

IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'ClientRef'
      , NULL AS 'ClientName'
      , NULL AS 'NewCaseID'
      , NULL AS 'NewPolNum'
      , NULL AS 'NewTransDate'
      , NULL AS 'NewCode'
      , NULL AS 'NewAgentName'
      , NULL AS 'NewFranchise'
      , NULL AS 'NewFranchiseName'
      , NULL AS 'OldCaseID'
      , NULL AS 'OldPolNum'
      , NULL AS 'OldTransDate'
      , NULL AS 'OldCode'
      , NULL AS 'OldAgentName'
      , NULL AS 'OldFranchise'
      , NULL AS 'OldFranchiseName'
      , NULL AS 'SortName'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

IF OBJECT_ID('tempdb..#56TempTable1') IS NOT NULL
   DROP TABLE #56TempTable1

IF OBJECT_ID('tempdb..#56TempTable2') IS NOT NULL
   DROP TABLE #56TempTable2

IF OBJECT_ID('tempdb..#ClientTempTable') IS NOT NULL
   DROP TABLE #ClientTempTable

--1. Get details for CURRENT type 39 (proposal) commmission transactions (i.e. in the specified date range)
SELECT DISTINCT
    Policies.PolicyRef AS [NewCaseID]
  , Policies.Pol_Num AS [NewPolNum]
  , Client1.Refer AS [Client1Ref]
  , ISNULL(RTRIM(Client1.FirstNames)+ ' ', '') + ISNULL(RTRIM(Client1.Name), '')AS [Client1 Name]
  , ISNULL(RTRIM(Client1.Name), '')AS [SortName1]
  , Client2.Refer AS [Client2Ref]
  , ISNULL(RTRIM(Client2.FirstNames)+ ' ', '') + ISNULL(RTRIM(Client2.Name), '')AS [Client2 Name] 
  , ISNULL(RTRIM(Client2.Name), '')AS [SortName2]        
  , CommissionsT.Client_NUM AS [ClientNum]
        , CommissionsT.Joint_Num AS [Joint_Num]
  , Agents.Firm AS [Firm]
  , Agents.Code AS [NewAgentCode]
  , ISNULL(RTRIM(Agents.FirstNames)+ ' ', '') + ISNULL(RTRIM(Agents.Name), '')AS [NewAgentName]
  , CASE 
       WHEN Business.TradingName IS NOT NULL THEN Business.TradingName
       ELSE Business.Descn 
    END AS [NewFranchiseName]
  , PolicyTransactions.TransactionDate AS [NewTransactionDate]
  , PolicyTransactions.ID AS [NewTransactionID]

INTO #56TempTable1

FROM mstt_Commissions CommissionsT
INNER JOIN mstt_Policies Policies ON CommissionsT.PolicyID = Policies.POL_NUM
INNER JOIN mstt_PolicyTransactions PolicyTransactions ON CommissionsT.TransactionID = PolicyTransactions.ID
LEFT JOIN mstt_Agents Agents ON CommissionsT.AGENT_CODE = Agents.CODE
LEFT JOIN mstt_Agents Business ON Agents.Firm = Business.Code
LEFT JOIN mstt_clients Client1 ON CommissionsT.CLIENT_NUM = Client1.CLIENT_NUM
LEFT JOIN mstt_clients Client2 ON CommissionsT.JOINT_NUM = Client2.CLIENT_NUM AND CommissionsT.JOINT_NUM IS NOT NULL

WHERE CommissionsT.CommissionType = 1 --IC
  AND CommissionsT.GrossorNet = 'G' --not openworks margin
  AND Business.AgentType <> 49 --directly authorised
  AND Agents.AgentType <> 3 --introducer
  AND PolicyTransactions.TransactionDate BETWEEN (SELECT CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)) AND (SELECT CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
  AND PolicyTransactions.TransType = 39

ORDER BY CommissionsT.Client_NUM

--2. Get details for PREVIOUS type 39 (proposal) commmission transactions
SELECT DISTINCT
    Policies.PolicyRef AS [OldCaseID]
  , Policies.Pol_Num AS [OldPolNum]
  , Client1.Refer AS [Client1Ref]
  , ISNULL(RTRIM(Client1.FirstNames)+ ' ', '') + ISNULL(RTRIM(Client1.Name), '')AS [Client1 Name]
  , ISNULL(RTRIM(Client1.Name), '')AS [SortName1]
  , Client2.Refer AS [Client2Ref]
  , ISNULL(RTRIM(Client2.FirstNames)+ ' ', '') + ISNULL(RTRIM(Client2.Name), '')AS [Client2 Name] 
  , ISNULL(RTRIM(Client2.Name), '')AS [SortName2]        
  , CommissionsT.Client_NUM AS [ClientNum]
        , CommissionsT.Joint_Num AS [Joint_Num]
  , Agents.Firm AS [Firm]
  , Agents.Code AS [OldAgentCode]
  , ISNULL(RTRIM(Agents.FirstNames)+ ' ', '') + ISNULL(RTRIM(Agents.Name), '')AS [OldAgentName]
  , CASE 
       WHEN Business.TradingName IS NOT NULL THEN Business.TradingName
       ELSE Business.Descn 
    END AS [OldFranchiseName]
  , PolicyTransactions.TransactionDate AS [OldTransactionDate]
  , PolicyTransactions.ID AS [OldTransactionID]

INTO #56TempTable2

FROM mstt_Commissions CommissionsT
INNER JOIN mstt_Policies Policies ON CommissionsT.PolicyID = Policies.POL_NUM
INNER JOIN mstt_PolicyTransactions PolicyTransactions ON CommissionsT.TransactionID = PolicyTransactions.ID
LEFT JOIN mstt_Agents Agents ON CommissionsT.AGENT_CODE = Agents.CODE
LEFT JOIN mstt_Agents Business ON COALESCE (Agents.DirectlyAuthorisedCode, Agents.StrategicAllianceCode, Agents.AccessAgentCode, Agents.FranchiseCode, Agents.PFACompanyCode) = Business.Code
LEFT JOIN mstt_clients Client1 ON CommissionsT.CLIENT_NUM = Client1.CLIENT_NUM
LEFT JOIN mstt_clients Client2 ON CommissionsT.JOINT_NUM = Client2.CLIENT_NUM AND CommissionsT.JOINT_NUM IS NOT NULL

WHERE CommissionsT.CommissionType = 1 --IC
  AND CommissionsT.GrossorNet = 'G' --not openworks margin
  AND Business.AgentType <> 49 --directly authorised
  AND Agents.AgentType <> 3 --introducer
  AND PolicyTransactions.TransType = 39

ORDER BY CommissionsT.Client_NUM

--3. Loop through the first table and get details from both where there is a match on client details
--   but not franchise or transaction ID and where the old transaction date is within two years of the new transaction date.
CREATE TABLE #ClientTempTable 
  (ClientRef VARCHAR(50),
   ClientName VARCHAR(500),
   NewCaseID VARCHAR(20),
   NewPolNum VARCHAR(10),
   NewTransDate VARCHAR(10),
   NewCode VARCHAR(10),
   NewAgentName VARCHAR(50),
   NewFranchise VARCHAR(10),
   NewFranchiseName VARCHAR(500),
   OldCaseID VARCHAR(20),
   OldPolNum VARCHAR(10),
   OldTransDate VARCHAR(10),
   OldCode VARCHAR(10),
   OldAgentName VARCHAR(50),
   OldFranchise VARCHAR(10),
   OldFranchiseName VARCHAR(500),
   SortName VARCHAR(500)
   )

DECLARE @cl_num varchar(50), @Jcl_num varchar(50), @NewCaseID varchar(50), @NewPolNum VARCHAR(10), 
        @TransDate datetime, @NewCode varchar (10), @NewName varchar(50), @Firm varchar(50), 
        @FirmName varchar(50), @TransID varchar(50)

DECLARE CLIENTNUM_CURSOR CURSOR FOR 
SELECT ClientNum, Joint_Num, NewCaseID, NewPolNum, NewTransactionDate, NewAgentCode, 
       NewAgentName, Firm, NewFranchiseName, NewTransactionID  
FROM #56TempTable1 
ORDER BY ClientNum

OPEN CLIENTNUM_CURSOR

FETCH NEXT FROM CLIENTNUM_CURSOR 
INTO @cl_num, @Jcl_num, @NewCaseID, @NewPolNum, @TransDate, @NewCode, @NewName, @Firm, @FirmName, @TransID

WHILE @@FETCH_STATUS = 0
BEGIN 
        INSERT INTO #ClientTempTable
  SELECT DISTINCT
         CASE
            WHEN (TempTable2.ClientNum = @cl_num OR TempTable2.ClientNum = @Jcl_num) THEN TempTable2.[Client1Ref]
              WHEN (TempTable2.Joint_Num = @Jcl_num OR TempTable2.Joint_Num = @cl_num) THEN TempTable2.[Client2Ref]
         END AS [ClientRef]
       , CASE
            WHEN (TempTable2.ClientNum = @cl_num OR TempTable2.ClientNum = @Jcl_num) THEN TempTable2.[Client1 Name]
            WHEN (TempTable2.Joint_Num = @Jcl_num OR TempTable2.Joint_Num = @cl_num) THEN TempTable2.[Client2 Name]
         END AS [ClientName]
       , @NewCaseID
       , @NewPolNum
       , CONVERT(VARCHAR, @TransDate, 103)
       , @NewCode
       , @NewName
       , @Firm
       , @FirmName
       , TempTable2.[OldCaseID] 
       , TempTable2.[OldPolNum] 
             , CONVERT(VARCHAR, TempTable2.[OldTransactionDate], 103)
       , TempTable2.[OldAgentCode]
       , TempTable2.[OldAgentName]
             , TempTable2.[Firm]
       , TempTable2.OldFranchiseName
       , CASE
            WHEN (TempTable2.ClientNum = @cl_num OR TempTable2.ClientNum = @Jcl_num) THEN TempTable2.[SortName1]
            WHEN (TempTable2.Joint_Num = @Jcl_num OR TempTable2.Joint_Num = @cl_num) THEN TempTable2.[SortName2]
         END AS [SortName]
        
  FROM #56TempTable2 TempTable2
        
  WHERE TempTable2.Firm NOT IN (SELECT TempTable1.Firm
              FROM #56TempTable1 TempTable1
              WHERE TempTable1.NewTransactionID = @TransID) --cater for split cases
    AND (TempTable2.ClientNum = @cl_num OR TempTable2.Joint_Num = @cl_num OR TempTable2.ClientNum = @Jcl_num OR TempTable2.Joint_Num = @Jcl_num)
    AND DATEDIFF (Day, TempTable2.OldTransactionDate, @TransDate) BETWEEN 0 AND 730
    AND @TransID <> TempTable2.OldTransactionID

  FETCH NEXT FROM CLIENTNUM_CURSOR 
  INTO @cl_num, @Jcl_num, @NewCaseID, @NewPolNum, @TransDate, @NewCode, @NewName, @Firm, @FirmName, @TransID
END

CLOSE CLIENTNUM_CURSOR
DEALLOCATE CLIENTNUM_CURSOR

--4. Now just get the collated details from this table.
SELECT *
     , NULL AS [Error]
FROM #ClientTempTable
ORDER BY SortName, NewCaseId, NewPolNum, OldCaseId DESC, OldPolNum DESC

DROP TABLE #56TempTable1
DROP TABLE #56TempTable2
DROP TABLE #ClientTempTable


GO
/****** Object:  StoredProcedure [dbo].[cscp_FindNearest]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_FindNearest] @UserID VARCHAR(255)
AS
SELECT 
     agents.Name as 'SortSurname'
   , Agents.FirstNames as 'SortFirstNames'
   , ISNULL(RTRIM(Agents.Title) + ' ', '') +
     ISNULL(RTRIM(SUBSTRING(Agents.FirstNames, 1, PATINDEX('%[^ ] %', Agents.FirstNames + ' '))) + ' ', '') +
     ISNULL(RTRIM(Agents.Name), '') AS 'Name'
   , ISNULL(RTRIM(Agents.ADDRESS1) + ', ', '') + ISNULL(RTRIM(Agents.ADDRESS2), '') AS 'Street'
   , ISNULL(RTRIM(Agents.ADDRESS3) + ', ', '') + ISNULL(RTRIM(Agents.ADDRESS4) + ', ', '') + ISNULL(RTRIM(Agents.ADDRESS5), '') AS 'Town'
   , Agents.POSTCODE AS 'PC'
   , 'UK' AS 'Country'
   , 'Tel' =   --if the phone number is longer than 5 chars and doesn't have a space character, then insert one between the 4th and 5th.
     CASE      --this is needed to stop Excel stripping off the leading zero's  DS 20/01/2006
     WHEN LEN(Agents.TELEPHONE)>5 THEN  
  CASE PATINDEX('% %', LTRIM(RTRIM(CAST(Agents.TELEPHONE AS VARCHAR))))
  WHEN 0 THEN SUBSTRING(Agents.TELEPHONE, 1, 4) + ' ' + SUBSTRING(Agents.TELEPHONE, 5, LEN(Agents.TELEPHONE)- 4)
  ELSE Agents.TELEPHONE
  END
     ELSE Agents.TELEPHONE
     END
   , 'Fax' =   --if the fax number is longer than 5 chars and doesn't have a space character, then insert one between the 4th and 5th.
     CASE      --this is needed to stop Excel stripping off the leading zero's  DS 20/01/2006
     WHEN LEN(Agents.FAX_NUMBER)>5 THEN   
  CASE PATINDEX('% %', LTRIM(RTRIM(CAST(Agents.FAX_NUMBER AS VARCHAR))))
  WHEN 0 THEN SUBSTRING(Agents.FAX_NUMBER, 1, 4) + ' ' + SUBSTRING(Agents.FAX_NUMBER, 5, LEN(Agents.FAX_NUMBER)- 4)
  ELSE Agents.FAX_NUMBER
  END
     ELSE Agents.FAX_NUMBER
     END
   , Agents.Website AS 'URL'
   , '' AS 'ID'  
   , '' AS 'Geoquality'  
   , '' AS 'Lon'  
   , '' AS 'Lat'  
   , '' AS 'Geocode date'  
   , '' AS 'Geocode source'  
   , Agents.EMAIL AS 'E-mail Address'  
FROM mstt_Agents Agents
WHERE Agents.AgentTypeB30 = 2 -- individuals only (exclude businesses)
ORDER by SortSurname, SortFirstNames

GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0001a]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO
CREATE procedure [dbo].[cscp_FINSTAT0001a] 
  @UserID VARCHAR(255), 
  @StartDate VARCHAR(10), 
  @EndDate VARCHAR(10)

as


/*
  RH [Openwork] 24 Jan 2007
  Selected Finstat procs rewritten to improve performance
  Including 
    - moved logic for cscf_CalcMarginPercent UDF into proc rather than function call
    - IRD determination pulled into temp table rather than subselect
    - logic for each component part of calculated figures broken out to make it more readable
    - bizarre structure of select distinct ... with subqueries removed


  RH 17 Jan 2007
  Rework of original Finstat procedure for performance

  Figures returned by this version differ from original due to commisson records
  where sum(FixedAmount) is zero, resulting in a null margin.  This version still includes the +ve amount
  in the 'Franchise Commission' column, the original excludes it.
  see TPR3644 re data cleanup needed
  
  RH 18 Nov 2007
  Added call to proc owp_FinstatFixExpSign to determine sign based on expectation type and status

  AH 4 Sep 2008
  Drop tables removed from end of proc to facilitate running of BatchFINSTAT report (already exist within query)

  AH 17 Sep 2008
  Create temp finstat table and final select statement for batchfinstat report
*/


set nocount on


--IF OBJECT_ID('tempdb..#IRD') IS NOT NULL
--   DROP TABLE #IRD
--IF OBJECT_ID('tempdb..#Exp') IS NOT NULL
--   DROP TABLE #Exp


-- Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Type'
      , NULL AS 'Commission Type'
      , NULL AS 'Basis Code'
      , NULL AS 'Basis'
      , NULL AS 'Provider'
      , NULL AS 'Distribution Allowance'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END




DECLARE @OD DATETIME
DECLARE @CD DATETIME


SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)


-- Calculate Income Recognition Date for each transaction/type combination
create table #IRD 
  (TransactionID  int, 
  Type    tinyint, 
  IRD     datetime,
  Primary Key (TransactionID,Type)
  )

insert #IRD
select  TransactionID,
  Type,
  min(CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME))
from  mstt_expectation
where TransactionID is not null
  and Type is not null
group by TransactionID,
  Type



-- Table to store calculated data for each expectation
create table #Exp (
  ExpectationID int,
  TransactionID int,
  Type    tinyint,
  Status    tinyint,
  DisplayType tinyint,
  ProviderCode  varchar(10) collate LATIN1_GENERAL_CI_AS,
  BasisCode varchar(1) collate LATIN1_GENERAL_CI_AS,
  Basis   varchar(50) collate LATIN1_GENERAL_CI_AS,
  Amount_Due  decimal(15,2),
  Amount_Rec  decimal(15,2),
  Date_Due  datetime,
  Date_Recv datetime,
  IRD   datetime
  )

insert #Exp
Select  e.ID,
  e.TransactionID,
  e.Type,
  e.Status,
  CASE e.Type
    WHEN 1 THEN 1 -- IC
    WHEN 17 THEN 1 -- IC adjustment (treat as negative below)
    WHEN 4 THEN 4 -- RC
    WHEN 18 THEN 4 -- RC adjustment (treat as negative below)
    WHEN 10 THEN 10 -- Trail
    WHEN 19 THEN 10 -- Trail adjustment (treat as negative below)
  END , -- Display Type
  e.COMP_CODE,  -- provider code
  CASE
          WHEN e.Type = 1 or e.Type=17 THEN pt.CommType
          ELSE NULL
  END , -- Basis only relevant to initial commission
  CASE
          WHEN e.Type = 1 or e.Type=17 THEN ISNULL(pt.CommissionTypeDesc, 'Unknown')
          ELSE NULL
  END ,
  e.Amount_Due,
--  CASE
--    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Due,0)
--    ELSE COALESCE(e.Amount_Due,0) * (-1)
--  END,  -- Amount_Due
  CASE 
    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Rec,0)
    ELSE COALESCE(e.Amount_Rec,0) * (-1)
  END,  -- Amount_Recv
  CAST(CONVERT(NVARCHAR, e.Date_Due, 112) AS DATETIME),
  CAST(CONVERT(NVARCHAR, e.Date_Recv, 112) AS DATETIME),  -- convert to "whole day" 
  i.IRD -- IRD
from  mstt_Expectation e
  inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
  INNER JOIN mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork
  left outer join #IRD i on e.transactionID = i.TransactionID and e.Type = i.Type
where e.Type IN (1, 4, 10, 17, 18, 19)
  and a.CompanyCode = 10002 -- Openwork


exec owp_FinstatFixExpSign



--Extract report data into a temp table
IF OBJECT_ID('tempdb..#FINSTAT0001a') IS NULL
begin
  create table #FINSTAT0001a
  (Type           tinyint,
  [Commission Type]     varchar(50),
  [Basis Code]        varchar(1), --collate LATIN1_GENERAL_CI_AS,
  Basis           varchar(50), --collate LATIN1_GENERAL_CI_AS,
  Provider          varchar (255),
  [Distribution Allowance]  decimal(15,2),
  Error           varchar(6)
  )
end
else
  Truncate table #FINSTAT0001a



-- final output sums values over expectations and then Manual Adjustments
insert INTO #FINSTAT0001a
select * from (
  select  e.DisplayType AS [Type],
  ISNULL(Codes.Description, 'Unknown') AS 'Commission Type',
  e.BasisCode AS 'Basis Code',
  e.Basis ,
  ISNULL(ProductProviders.ReportingProductProviderName, 'Unknown') AS 'Provider',
  sum(convert(decimal(15,2),
    case
      when  (e.Date_Recv <= @CD AND e.Amount_Rec <> 0.00)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD AND e.Date_Recv >= @OD)
          OR (e.IRD <= @CD AND e.Date_Due > @CD AND e.Date_Recv >= @OD)
        )
      then  e.Amount_Rec * (-1)
      else  0
    end --RptCommRec,
    +
    case
      when  ((e.Date_Recv > @CD AND e.Amount_Rec <> 0.00) OR e.Date_Recv IS NULL)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD)
        )
      then  e.Amount_Due * (-1)
      else  0
    end --RptCommDue,
    +
    case
      when
        (e.IRD < @OD 
                     AND e.Date_Due < @OD
                     AND e.Date_Recv >= @OD
                     AND e.Date_Recv <= @CD
                     AND e.Amount_Rec <> 0.00
                    )
      then  (e.Amount_Due - e.Amount_Rec)
      else  0
    end
  )) --RptCommOverDue
  AS 'Distribution Allowance',
  Null AS 'Error'
from  #exp e
  LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON e.DisplayType = Codes.Code AND ColumnName = 'CommissionType'
  LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = e.ProviderCode
group by 
  e.DisplayType,
  Codes.Description,
  e.BasisCode,
  e.Basis,
  ProductProviders.ReportingProductProviderName

) a
where [Distribution Allowance]<>0

--Select statement for batchFINSTAT
SELECT  Type,
  [Commission Type],
  [Basis Code],
  Basis,
  Provider,
  [Distribution Allowance],
  Error
FROM #FINSTAT0001a
ORDER BY
  [Type], [Basis Code], [Provider]


--Remove drop tables to make this report work in owp_BatchFINSTAT0001a

-- tidy up
--drop table #IRD
--drop table #Exp




GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0001a_2a]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[cscp_FINSTAT0001a_2a] @UserID VARCHAR(255), @CommType VARCHAR(1), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

-- Validate @CommType
IF @CommType <> 'T' -- indemnity
AND @CommType <> 'F' -- accruals
AND @CommType <> 'L' -- level
AND @CommType <> 'Z' -- combination value - accruals AND level
AND @CommType <> 'X' -- special value - trail fee
AND @CommType <> 'Y' -- special value - other fee
BEGIN
  SELECT 
        NULL AS 'Provider'
      , NULL AS 'Distribution Allowance'
      , 'Invalid Commission Type: <' + @CommType + '>' AS [Error]
   RETURN 0
END

--Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Provider'
      , NULL AS 'Distribution Allowance'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

IF OBJECT_ID('tempdb..#FINSTAT0001a_2a') IS NOT NULL
   DROP TABLE #FINSTAT0001a_2a

SELECT 
      DISTINCT ProductProviders.ReportingProductProviderName AS 'Provider'
   , ProductProviders.ProductProviderCode AS 'Provider Code' --Added to ensure uniqueness/omitted in final resultset
   , -(SELECT ISNULL(SUM(ISNULL(CAST(Expectation.AMOUNT_DUE AS DECIMAL(15,2)), 0.00)), 0.00)
      FROM mstt_Expectation Expectation
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
         INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
      WHERE ( ((@CommType = 'T' OR @CommType = 'F' OR @CommType = 'L') AND PolicyTransactions.CommType = @CommType AND Expectation.TYPE = 1) OR --Indemnity/Accruals/Level initial comm.
              (@CommType = 'Z' AND (PolicyTransactions.CommType = 'F' OR PolicyTransactions.CommType = 'L') AND Expectation.TYPE = 1) OR --Accruals AND Level initial comm.
              (@CommType = 'X' AND Expectation.TYPE = 10) OR --Trail Fee
              (@CommType = 'Y' AND Expectation.TYPE = 13)) --Other Fee
      AND Expectation.DATE_DUE IS NOT NULL
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
      AND EXISTS
          (SELECT Commissions.PolicyID 
           FROM mstt_Commissions Commissions
              INNER JOIN mstt_Agents Agents ON Agents.CODE = Commissions.AGENT_CODE
           WHERE Commissions.PolicyID = PolicyTransactions.PolicyID
           AND RTRIM(Agents.descn) = 'Openwork'
          )
      AND (Expectation.COMP_CODE = ProductProviders.ProductProviderCode
           OR ((Expectation.COMP_CODE IS NULL OR Expectation.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
               AND ProductProviders.ProductProviderCode IS NULL))
     ) AS 'Distribution Allowance'

   , NULL AS [Error]

INTO #FINSTAT0001a_2a
FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID 
INNER JOIN mstt_Expectation Expectation ON Expectation.TransactionID = PolicyTransactions.ID
LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = Expectation.COMP_CODE

WHERE ( ((@CommType = 'T' OR @CommType = 'F' OR @CommType = 'L') AND PolicyTransactions.CommType = @CommType AND Expectation.TYPE = 1) OR --Indemnity/Accruals/Level initial comm.
        (@CommType = 'Z' AND (PolicyTransactions.CommType = 'F' OR PolicyTransactions.CommType = 'L') AND Expectation.TYPE = 1) OR --Accruals AND Level initial comm.
        (@CommType = 'X' AND Expectation.TYPE = 10) OR --Trail Fee
        (@CommType = 'Y' AND Expectation.TYPE = 13)) --Other Fee
  AND Expectation.DATE_DUE IS NOT NULL
  AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
  AND EXISTS
      (SELECT Commissions.PolicyID 
       FROM mstt_Commissions Commissions
          INNER JOIN mstt_Agents Agents ON Agents.CODE = Commissions.AGENT_CODE
       WHERE Commissions.PolicyID = PolicyTransactions.PolicyID
       AND RTRIM(Agents.descn) = 'Openwork'
      )
ORDER BY [Provider], [Distribution Allowance]

SELECT 
     CASE WHEN [Provider] IS NOT NULL THEN [Provider] ELSE 'Unknown' END AS [Provider]
   , ISNULL(SUM(ISNULL(CAST([Distribution Allowance] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Distribution Allowance]
   , [Error]
FROM  #FINSTAT0001a_2a
GROUP BY [Provider], [Error]
ORDER BY [Provider], [Distribution Allowance]

DROP TABLE #FINSTAT0001a_2a

GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0001b]    Script Date: 7/3/2026 3:44:25 PM ******/
