CREATE procedure [dbo].[cscp_FINSTAT0001b] 
  @UserID VARCHAR(255), 
  @LegacyFlag VARCHAR(10),
  @StartDate VARCHAR(10), 
  @EndDate VARCHAR(10)

as


/*
  RH [Openwork] 24 Jan 2007
  Selected Finstat procs rewritten to improve performance
  Including 
    - moved logic for cscf_CalcMarginPercent UDF into proc rather than function call
    - IRD determination pulled into temp table rather than subselect
    - logic for each component part of calculated figures broken out to make it more readable
    - bizarre structure of select distinct ... with subqueries removed


  RH 17 Jan 2007
  Rework of original Finstat procedure for performance

  Figures returned by this version differ from original due to commisson records
  where sum(FixedAmount) is zero, resulting in a null margin.  This version still includes the +ve amount
  in the 'Franchise Commission' column, the original excludes it.
  see TPR3644 re data cleanup needed
  
  RH 18 Nov 2007
  Added call to proc owp_FinstatFixExpSign to determine sign based on expectation type and status
*/


set nocount on


IF OBJECT_ID('tempdb..#IRD') IS NOT NULL
   DROP TABLE #IRD
IF OBJECT_ID('tempdb..#Exp') IS NOT NULL
   DROP TABLE #Exp


-- Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Type'
      , NULL AS 'Commission Type'
      , NULL AS 'Basis Code'
      , NULL AS 'Basis'
      , NULL AS 'Product'
      , NULL AS 'Product Sub Group'
      , NULL AS 'Distribution Allowance'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END



DECLARE @OD DATETIME
DECLARE @CD DATETIME


SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)


-- Calculate Income Recognition Date for each transaction/type combination
create table #IRD 
  (TransactionID  int, 
  Type    tinyint, 
  IRD     datetime,
  Primary Key (TransactionID,Type)
  )

insert #IRD
select  TransactionID,
  Type,
  min(CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME))
from  mstt_expectation
where TransactionID is not null
  and Type is not null
group by TransactionID,
  Type



-- Table to store calculated data for each expectation
create table #Exp (
  ExpectationID int,
  TransactionID int,
  PolicyID  int,
  Type    tinyint,
  Status    tinyint,
  DisplayType tinyint,
  ProviderCode  varchar(10) collate LATIN1_GENERAL_CI_AS,
  BasisCode varchar(1) collate LATIN1_GENERAL_CI_AS,
  Basis   varchar(50) collate LATIN1_GENERAL_CI_AS,
  Amount_Due  decimal(15,2),
  Amount_Rec  decimal(15,2),
  Date_Due  datetime,
  Date_Recv datetime,
  IRD   datetime
  )

insert #Exp
Select  e.ID,
  e.TransactionID,
  pt.PolicyID,
  e.Type,
  e.Status,
  CASE e.Type
    WHEN 1 THEN 1 -- IC
    WHEN 17 THEN 1 -- IC adjustment (treat as negative below)
    WHEN 4 THEN 4 -- RC
    WHEN 18 THEN 4 -- RC adjustment (treat as negative below)
    WHEN 10 THEN 10 -- Trail
    WHEN 19 THEN 10 -- Trail adjustment (treat as negative below)
  END , -- Display Type
  e.COMP_CODE,  -- provider code
  CASE
          WHEN e.Type = 1 or e.Type=17 THEN pt.CommType
          ELSE NULL
  END , -- Basis only relevant to initial commission
  CASE
          WHEN e.Type = 1 or e.Type=17 THEN ISNULL(pt.CommissionTypeDesc, 'Unknown')
          ELSE NULL
  END ,
  e.Amount_Due ,
--  CASE
--    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Due,0)
--    ELSE COALESCE(e.Amount_Due,0) * (-1)
--  END,  -- Amount_Due
  CASE 
    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Rec,0)
    ELSE COALESCE(e.Amount_Rec,0) * (-1)
  END,  -- Amount_Recv
  CAST(CONVERT(NVARCHAR, e.Date_Due, 112) AS DATETIME),
  CAST(CONVERT(NVARCHAR, e.Date_Recv, 112) AS DATETIME),  -- convert to "whole day" 
  i.IRD -- IRD
from  mstt_Expectation e
  inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
  INNER JOIN mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork
  left outer join #IRD i on e.transactionID = i.TransactionID and e.Type = i.Type
where e.Type IN (1, 4, 10, 17, 18, 19)
  and a.CompanyCode = 10002 -- Openwork


exec owp_FinstatFixExpSign


-- final output sums values over expectations and then Manual Adjustments
select * from (
select  e.DisplayType AS [Type],
  ISNULL(Codes.Description, 'Unknown') AS 'Commission Type',
  e.BasisCode AS 'Basis Code',
  e.Basis ,
  ISNULL(CodeProductGroup.ProductGroupName, 'Unknown') AS 'Product',
  ISNULL(CodeProductSubGroup.ProductSubGroupName, 'Unknown') AS 'Product Sub Group',

  sum(convert(decimal(15,2),
    case
      when  (e.Date_Recv <= @CD AND e.Amount_Rec <> 0.00)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD AND e.Date_Recv >= @OD)
          OR (e.IRD <= @CD AND e.Date_Due > @CD AND e.Date_Recv >= @OD)
        )
      then  e.Amount_Rec * (-1)
      else  0
    end --RptCommRec,
    +
    case
      when  ((e.Date_Recv > @CD AND e.Amount_Rec <> 0.00) OR e.Date_Recv IS NULL)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD)
        )
      then  e.Amount_Due * (-1)
      else  0
    end --RptCommDue,
    +
    case
      when
        (e.IRD < @OD 
                     AND e.Date_Due < @OD
                     AND e.Date_Recv >= @OD
                     AND e.Date_Recv <= @CD
                     AND e.Amount_Rec <> 0.00
                    )
      then  (e.Amount_Due - e.Amount_Rec)
      else  0
    end
  )) --RptCommOverDue
  AS 'Distribution Allowance',
  Null AS 'Error'
from  #exp e
  INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = e.PolicyID 
  LEFT JOIN mstt_CodeBIProducts CodeBIProducts ON CodeBIProducts.ProductCode = Policies.ProductCode
  LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON e.DisplayType = Codes.Code AND ColumnName = 'CommissionType'
  LEFT JOIN mstt_CodeProductGroup CodeProductGroup ON Policies.ProductGroupCode = CodeProductGroup.ProductGroupCode
  LEFT JOIN mstt_CodeProductSubGroup CodeProductSubGroup ON Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode
where
  ((@LegacyFlag = 'Legacy' AND CodeBIProducts.ProductType = @LegacyFlag) --Legacy/Non-Legacy
  OR
        (@LegacyFlag = 'Non-Legacy' AND (CodeBIProducts.ProductType <> 'Legacy' OR CodeBIProducts.ProductType IS NULL)) 
  OR
        (@LegacyFlag = 'Both'))

group by 
  e.DisplayType,
  Codes.Description,
  e.BasisCode,
  e.Basis,
  CodeProductGroup.ProductGroupName,
  CodeProductSubGroup.ProductSubGroupName
) a
where [Distribution Allowance]<>0
ORDER BY
  [Type], [Basis Code], [Product], [Product Sub Group]



-- tidy up
drop table #IRD
drop table #Exp




GO
