CREATE PROCEDURE [dbo].[cscp_FINSTAT0001d] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

/*

  
  RH 18 Nov 2007
  Added logic to determine sign of amount_due based on expectation type and status

*/
--1. Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Type'
      , NULL AS 'Commission Type'
      , NULL AS 'Basis Code'
      , NULL AS 'Basis'
      , NULL AS 'Income period'
      , NULL AS 'IRDate'
      , NULL AS 'Distribution Allowance'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

--2. Convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

--3. Extract Expectation data into a temp table
IF OBJECT_ID('tempdb..#FINSTAT0001dExpectation') IS NOT NULL
   DROP TABLE #FINSTAT0001dExpectation

SELECT Expectation.ID, 
       CASE Expectation.Type
          WHEN 1 THEN 1 -- IC
          WHEN 17 THEN 1 -- IC adjustment (treat as negative below)
          WHEN 4 THEN 4 -- RC
          WHEN 18 THEN 4 -- RC adjustment (treat as negative below)
          WHEN 10 THEN 10 -- Trail
          WHEN 19 THEN 10 -- Trail adjustment (treat as negative below)
       END AS Type,
       Expectation.TransactionID,
       CASE 
          WHEN Expectation.Type in (1,4,10) THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          WHEN Expectation.Type in (17,18,19) and Expectation.Status = 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
       END AS Amount_Due,
--       CASE Expectation.Type
--          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
--          WHEN 4 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
--          WHEN 10 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
--          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
--       END AS Amount_Due,
       CASE Expectation.Type
          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN 4 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN 10 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
       END AS Amount_Rec,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) AS Date_Due,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #FINSTAT0001dExpectation
FROM mstt_Expectation Expectation
   INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
   INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
   INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (1, 4, 10, 17, 18, 19)          --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD    --of the temp table
       OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD   --by omitting data which
           AND Expectation.DATE_RECV IS NOT NULL))          --we KNOW we don't need
GROUP BY Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
  Expectation.Status,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

CREATE CLUSTERED INDEX ind_FINSTAT0001 ON #FINSTAT0001dExpectation (ID, Type, TransactionID, Amount_Due, Amount_Rec, Date_Due, Date_Recv, IRD)

--4. Extract report data into another temp table
IF OBJECT_ID('tempdb..#FINSTAT0001d') IS NOT NULL
   DROP TABLE #FINSTAT0001d

SELECT DISTINCT
     PolicyTransactions.CommType -- required to ensure uniqueness of records
   , Expectation.TYPE AS 'Type'
   , ISNULL(Codes.Description, 'Unknown') AS 'Commission Type'
   , CASE
        WHEN Expectation.TYPE = 1 THEN PolicyTransactions.CommType
        ELSE NULL
     END AS 'Basis Code' -- Basis only relevant to initial commission
   , CASE
        WHEN Expectation.TYPE = 1 THEN ISNULL(PolicyTransactions.CommissionTypeDesc, 'Unknown')
        ELSE NULL
     END AS 'Basis' -- Basis only relevant to initial commission
   , CAST(YEAR(Expectation.IRD) AS NVARCHAR(4)) + ' ' + UPPER(SUBSTRING(DATENAME(MONTH, Expectation.IRD), 1, 3)) AS 'Income Period'
   , CAST(CAST(YEAR(Expectation.IRD) AS NVARCHAR(4)) + 
     SUBSTRING ('00', 1, 2 - LEN(CAST(MONTH(Expectation.IRD) AS NVARCHAR(2)))) +
     CAST(MONTH(Expectation.IRD) AS NVARCHAR(2)) AS INT) AS IRDate --Dummy field added to ensure ordering/omitted in final resultset
   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0001dExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (PolicyTransactions1.CommType = PolicyTransactions.CommType
               OR (PolicyTransactions1.CommType IS NULL AND PolicyTransactions.CommType IS NULL))
            AND YEAR(Expectation1.IRD) = YEAR(Expectation.IRD)
            AND MONTH(Expectation1.IRD) = MONTH(Expectation.IRD)
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0001dExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (PolicyTransactions1.CommType = PolicyTransactions.CommType
               OR (PolicyTransactions1.CommType IS NULL AND PolicyTransactions.CommType IS NULL))
            AND YEAR(Expectation1.IRD) = YEAR(Expectation.IRD)
            AND MONTH(Expectation1.IRD) = MONTH(Expectation.IRD)
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0001dExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (PolicyTransactions1.CommType = PolicyTransactions.CommType
               OR (PolicyTransactions1.CommType IS NULL AND PolicyTransactions.CommType IS NULL))
            AND YEAR(Expectation1.IRD) = YEAR(Expectation.IRD)
            AND MONTH(Expectation1.IRD) = MONTH(Expectation.IRD)
         )
        )
     ) AS 'Distribution Allowance'
   , NULL AS [Error]
INTO #FINSTAT0001d
FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN #FINSTAT0001dExpectation Expectation ON Expectation.TransactionID = PolicyTransactions.ID
LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON Expectation.Type = Codes.Code AND ColumnName = 'CommissionType'
ORDER BY [Type], [Basis Code], [IRDate]

--5. Select data for report
SELECT 
     [Type]
   , [Commission Type]
   , [Basis Code]
   , [Basis]
   , [Income period]
   , [IRDate]
   , ISNULL(SUM(ISNULL(CAST([Distribution Allowance] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Distribution Allowance]
   , [Error]
FROM  #FINSTAT0001d
WHERE [Type] IN (1, 4, 10)
GROUP BY [Type], [Commission Type], [Basis Code], [Basis], [Income period], [IRDate], [Error]
HAVING ISNULL(SUM(ISNULL(CAST([Distribution Allowance] AS DECIMAL(15,2)), 0.00)), 0.00) <> 0.00 --Display only non-zero values
ORDER BY [Type], [Basis Code], [IRDate]

--6. Tidy Up
DROP TABLE #FINSTAT0001d
DROP TABLE #FINSTAT0001dExpectation


GO
