CREATE PROCEDURE [dbo].[cscp_FINSTAT0004b] @UserID VARCHAR(255), @LegacyFlag VARCHAR(10), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Product'
      , NULL AS 'Product Sub Group'
      , NULL AS 'Distribution Allowance'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

IF OBJECT_ID('tempdb..#FINSTAT0004b') IS NOT NULL
   DROP TABLE #FINSTAT0004b

SELECT 
     DISTINCT CodeProductGroup.ProductGroupName AS 'Product'
   , CodeProductSubGroup.ProductSubGroupName AS 'Product Sub Group'

   , -(SELECT ISNULL(SUM(ISNULL(CAST(Expectation.AMOUNT_DUE AS DECIMAL(15,2)), 0.00)), 0.00)
      FROM mstt_Expectation Expectation
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
         INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
         LEFT JOIN mstt_CodeBIProducts CodeBIProducts ON CodeBIProducts.ProductCode = Policies.ProductCode 
      WHERE Expectation.TYPE = 4 --Renewal
      AND Expectation.DATE_DUE IS NOT NULL
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
      AND EXISTS
          (SELECT Commissions.PolicyID 
           FROM mstt_Commissions Commissions
              INNER JOIN mstt_Agents Agents ON Agents.CODE = Commissions.AGENT_CODE
           WHERE Commissions.PolicyID = PolicyTransactions.PolicyID
           AND RTRIM(Agents.descn) = 'Openwork'
          )
      AND ((@LegacyFlag = 'Legacy' AND CodeBIProducts.ProductType = @LegacyFlag) OR --Legacy/Non-Legacy
           (@LegacyFlag = 'Non-Legacy' AND CodeBIProducts.ProductType <> 'Legacy') OR
           (@LegacyFlag = 'Both'))
      AND Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
     ) AS 'Distribution Allowance' -- made negative as income to Openwork

   , NULL AS [Error]
INTO #FINSTAT0004b
FROM mstt_CodeProductGroup CodeProductGroup -- For All Product Groups
INNER JOIN mstt_CodeProductSubGroup CodeProductSubGroup ON CodeProductSubGroup.ProductGroupCode = CodeProductGroup.ProductGroupCode

ORDER BY [Product], [Product Sub Group]

--Display only non-zero values
SELECT 
     [Product] AS [Product]
   , [Product Sub Group] AS [Product Sub Group]
   , ISNULL(SUM(ISNULL(CAST([Distribution Allowance] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Distribution Allowance]
   , [Error]
FROM  #FINSTAT0004b
WHERE [Distribution Allowance] <> 0.00
GROUP BY [Product], [Product Sub Group], [Error]
ORDER BY [Product], [Product Sub Group]

DROP TABLE #FINSTAT0004b

