CREATE PROCEDURE [dbo].[cscp_FINSTAT0005a_b_c] @UserID VARCHAR(255), @CommType VARCHAR(1), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
   IF @CommType = 'A' 
      EXEC cscp_FINSTAT0001a_2a @UserID, 'Y', @StartDate, @EndDate
   ELSE
   IF @CommType = 'B' 
      EXEC cscp_FINSTAT0001b_2b @UserID, 'Both', 'Y', @StartDate, @EndDate
   ELSE
   IF @CommType = 'C' 
      EXEC cscp_FINSTAT0001c_2c @UserID, 'Y', @StartDate, @EndDate

