CREATE PROCEDURE [dbo].[cscp_FINSTAT0006a_7a] @UserID VARCHAR(255), @CommType VARCHAR(1), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

-- Validate @CommType
IF @CommType <> 'T' -- indemnity
AND @CommType <> 'F' -- accruals
AND @CommType <> 'L' -- level
AND @CommType <> 'Z' -- combination value - accruals AND level
BEGIN
  SELECT 
        NULL AS 'Provider'
      , NULL AS 'Distribution Allowance'
      , 'Invalid Commission Type: <' + @CommType + '>' AS [Error]
   RETURN 0
END

--Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Provider'
      , NULL AS 'Franchise commission'
      , NULL AS 'Openwork margin'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

IF OBJECT_ID('tempdb..#FINSTAT0006a_7a') IS NOT NULL
   DROP TABLE #FINSTAT0006a_7a

SELECT 
      DISTINCT ProductProviders.ReportingProductProviderName AS 'Provider'
   , ProductProviders.ProductProviderCode AS 'Provider Code' --Added to ensure uniqueness/omitted in final resultset
   , (SELECT ISNULL(SUM(ISNULL(CAST(dbo.cscf_CalcCommissionDue(Expectation.ID) AS DECIMAL(15,2)), 0.00)), 0.00)
      FROM mstt_Expectation Expectation
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
         INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
      WHERE (((@CommType = 'T' OR @CommType = 'F' OR @CommType = 'L') AND PolicyTransactions.CommType = @CommType) OR --Indemnity/Accruals/Level initial comm.
              (@CommType = 'Z' AND (PolicyTransactions.CommType = 'F' OR PolicyTransactions.CommType = 'L'))) --Accruals AND Level initial comm.
      AND Expectation.TYPE = 1 --Initial commission
      AND Expectation.DATE_DUE IS NOT NULL
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
      AND EXISTS
          (SELECT Commissions.PolicyID 
           FROM mstt_Commissions Commissions
              INNER JOIN mstt_Agents Agents ON Agents.CODE = Commissions.AGENT_CODE
           WHERE Commissions.PolicyID = PolicyTransactions.PolicyID
           AND RTRIM(Agents.descn) = 'Openwork'
          )
      AND (Expectation.COMP_CODE = ProductProviders.ProductProviderCode
           OR ((Expectation.COMP_CODE IS NULL OR Expectation.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
               AND ProductProviders.ProductProviderCode IS NULL))
     ) AS 'Franchise commission'

   , (SELECT ISNULL(SUM(ISNULL(CAST(dbo.cscf_CalcMarginDue(Expectation.ID) AS DECIMAL(15,2)), 0.00)), 0.00)
      FROM mstt_Expectation Expectation
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
         INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
      WHERE (((@CommType = 'T' OR @CommType = 'F' OR @CommType = 'L') AND PolicyTransactions.CommType = @CommType) OR --Indemnity/Accruals/Level initial comm.
              (@CommType = 'Z' AND (PolicyTransactions.CommType = 'F' OR PolicyTransactions.CommType = 'L'))) --Accruals AND Level initial comm.
      AND Expectation.TYPE = 1 --Initial commission
      AND Expectation.DATE_DUE IS NOT NULL
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
      AND EXISTS
          (SELECT Commissions.PolicyID 
           FROM mstt_Commissions Commissions
              INNER JOIN mstt_Agents Agents ON Agents.CODE = Commissions.AGENT_CODE
           WHERE Commissions.PolicyID = PolicyTransactions.PolicyID
           AND RTRIM(Agents.descn) = 'Openwork'
          )
      AND (Expectation.COMP_CODE = ProductProviders.ProductProviderCode
           OR ((Expectation.COMP_CODE IS NULL OR Expectation.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
               AND ProductProviders.ProductProviderCode IS NULL))
     ) AS 'Openwork margin' 
   , NULL AS [Error]

INTO #FINSTAT0006a_7a
FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID 
INNER JOIN mstt_Expectation Expectation ON Expectation.TransactionID = PolicyTransactions.ID
LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = Expectation.COMP_CODE

WHERE (((@CommType = 'T' OR @CommType = 'F' OR @CommType = 'L') AND PolicyTransactions.CommType = @CommType) OR --Indemnity/Accruals/Level initial comm.
        (@CommType = 'Z' AND (PolicyTransactions.CommType = 'F' OR PolicyTransactions.CommType = 'L'))) --Accruals AND Level initial comm.
  AND Expectation.TYPE = 1 --Initial commission
  AND Expectation.DATE_DUE IS NOT NULL
  AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
  AND EXISTS
      (SELECT Commissions.PolicyID 
       FROM mstt_Commissions Commissions
          INNER JOIN mstt_Agents Agents ON Agents.CODE = Commissions.AGENT_CODE
       WHERE Commissions.PolicyID = PolicyTransactions.PolicyID
       AND RTRIM(Agents.descn) = 'Openwork'
      )
ORDER BY [Provider]

SELECT 
     CASE WHEN [Provider] IS NOT NULL THEN [Provider] ELSE 'Unknown' END AS [Provider]
   , ISNULL(SUM(ISNULL(CAST([Franchise commission] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Franchise commission]
   , ISNULL(SUM(ISNULL(CAST([Openwork margin] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Openwork margin]
   , [Error]
FROM  #FINSTAT0006a_7a
GROUP BY [Provider], [Error]
ORDER BY [Provider]

DROP TABLE #FINSTAT0006a_7a

GO
