      AND Expectation.TYPE = 1 --Initial commission
      AND Expectation.DATE_DUE IS NOT NULL
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
      AND EXISTS
          (SELECT Commissions.PolicyID 
           FROM mstt_Commissions Commissions
              INNER JOIN mstt_Agents Agents ON Agents.CODE = Commissions.AGENT_CODE
           WHERE Commissions.PolicyID = PolicyTransactions.PolicyID
           AND RTRIM(Agents.descn) = 'Openwork'
          )
      AND PolicyTransactions.AgentCode = Agents.CODE
     ) AS 'Openwork margin'


   , NULL AS [Error]

INTO #FINSTAT0006c_7c
FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN mstt_Expectation Expectation ON Expectation.TransactionID = PolicyTransactions.ID
LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
LEFT JOIN mstt_Agents Agents_fr ON Agents.Firm = Agents_fr.CODE

WHERE (((@CommType = 'T' OR @CommType = 'F' OR @CommType = 'L') AND PolicyTransactions.CommType = @CommType) OR --Indemnity/Accruals/Level initial comm.
        (@CommType = 'Z' AND (PolicyTransactions.CommType = 'F' OR PolicyTransactions.CommType = 'L'))) --Accruals AND Level initial comm.
  AND Expectation.TYPE = 1 --Initial commission
  AND Expectation.DATE_DUE IS NOT NULL
  AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
  AND EXISTS
      (SELECT Commissions.PolicyID 
       FROM mstt_Commissions Commissions
          INNER JOIN mstt_Agents Agents ON Agents.CODE = Commissions.AGENT_CODE
       WHERE Commissions.PolicyID = PolicyTransactions.PolicyID
       AND RTRIM(Agents.descn) = 'Openwork'
      )
ORDER BY [Franchise]

SELECT 
     CASE WHEN [Franchise] IS NOT NULL THEN [Franchise] ELSE 'Unknown' END AS [Franchise]
   , ISNULL(SUM(ISNULL(CAST([Franchise commission] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Franchise commission]
   , ISNULL(SUM(ISNULL(CAST([Openwork margin] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Openwork margin]
   , [Error]
FROM  #FINSTAT0006c_7c
GROUP BY [Franchise], [Error]
ORDER BY [Franchise]

DROP TABLE #FINSTAT0006c_7c

GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0007a]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE procedure [dbo].[cscp_FINSTAT0007a] 
  @UserID VARCHAR(255), 
  @StartDate VARCHAR(10), 
  @EndDate VARCHAR(10)

as


/*
  RH [Openwork] 24 Jan 2007
  Selected Finstat procs rewritten to improve performance
  Including 
    - moved logic for cscf_CalcMarginPercent UDF into proc rather than function call
    - IRD determination pulled into temp table rather than subselect
    - logic for each component part of calculated figures broken out to make it more readable
    - bizarre structure of select distinct ... with subqueries removed


  RH 17 Jan 2007
  Rework of original Finstat procedure for performance

  Figures returned by this version differ from original due to commisson records
  where sum(FixedAmount) is zero, resulting in a null margin.  This version still includes the +ve amount
  in the 'Franchise Commission' column, the original excludes it.
  see TPR3644 re data cleanup needed
  
  RH 18 Nov 2007
  Added call to proc owp_FinstatFixExpSign to determine sign based on expectation type and status

  AH 22 Sep 2008
  Create temporary table, final select query and remove final drop tables, to enable running of batchfinstat0001b
*/


set nocount on


/*
IF OBJECT_ID('tempdb..#IRD') IS NOT NULL
   DROP TABLE #IRD
IF OBJECT_ID('tempdb..#Comms') IS NOT NULL
   DROP TABLE #Comms
IF OBJECT_ID('tempdb..#Exp') IS NOT NULL
   DROP TABLE #Exp
*/


-- Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Section'
      , NULL AS 'Type'
      , NULL AS 'Commission Type'
      , NULL AS 'Basis Code'
      , NULL AS 'Basis'
      , NULL AS 'Provider'
      , NULL AS 'Franchise commission'
      , NULL AS 'Openwork margin'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END




DECLARE @OD DATETIME
DECLARE @CD DATETIME


SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)


-- Calculate Income Recognition Date for each transaction/type combination
create table #IRD 
  (TransactionID  int, 
  Type    tinyint, 
  IRD     datetime,
  Primary Key (TransactionID,Type)
  )

insert #IRD
select  TransactionID,
  Type,
  min(CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME))
from  mstt_expectation
where TransactionID is not null
  and Type is not null
group by TransactionID,
  Type



-- Calculate Margin percent for each Transaction
create table #Comms 
  (
  TransactionID   int, 
  NetAmount   decimal(15,2), 
  TotalAmount   decimal(15,2), 
  Margin_Pct  float,
  Primary Key (TransactionID)
  )


insert #Comms
select  TransactionID,
  sum(case GrossOrNet
    when 'N' then FixedAmount
    else 0
  end),
  sum(FixedAmount),
  case 
    when coalesce(sum(FixedAmount),0)<>0 then
      sum(case GrossOrNet when 'N' then FixedAmount else 0 end)
      /
      sum(FixedAmount)
    else null -- should this be null or 0 ?
    -- from UDF comments
    -- Set Margin % = 0 (i.e. Commission % = 100)
    -- Set Margin % = NULL (i.e. Margin % = 0; Commission % = 0)
  end
from  mstt_Commissions
where CommissionType = 1
group by TransactionID


-- Table to store calculated data for each expectation
create table #Exp (
  ExpectationID int,
  TransactionID int,
  Type    tinyint,
  Status    tinyint,
  DisplayType tinyint,
  ProviderCode  varchar(10) collate LATIN1_GENERAL_CI_AS,
  BasisCode varchar(1) collate LATIN1_GENERAL_CI_AS,
  Basis   varchar(50) collate LATIN1_GENERAL_CI_AS,
  Amount_Due  decimal(15,2),
  Amount_Recv decimal(15,2),
  Date_Due  datetime,
  Date_Recv datetime,
  Margin_Pct  float,
  Margin_Due  decimal(15,2),
  Margin_Recv decimal(15,2),
  Commission_Due  decimal(15,2),
  Commission_Recv decimal(15,2),
  IRD   datetime
  )

insert #Exp
Select  e.ID,
  e.TransactionID,
  e.Type,
  e.Status,
  CASE e.Type
    WHEN 1 THEN 1 -- IC
    WHEN 17 THEN 1 -- IC adjustment (treat as negative below)
    WHEN 4 THEN 4 -- RC
    WHEN 18 THEN 4 -- RC adjustment (treat as negative below)
    WHEN 10 THEN 10 -- Trail
    WHEN 19 THEN 10 -- Trail adjustment (treat as negative below)
  END , -- Display Type
  e.COMP_CODE,  -- provider code
  CASE
          WHEN e.Type = 1 or e.Type=17 THEN pt.CommType
          ELSE NULL
  END , -- Basis only relevant to initial commission
  CASE
          WHEN e.Type = 1 or e.Type=17 THEN ISNULL(pt.CommissionTypeDesc, 'Unknown')
          ELSE NULL
  END ,
  e.Amount_Due,
--  CASE
--    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Due,0)
--    ELSE COALESCE(e.Amount_Due,0) * (-1)
--  END,  -- Amount_Due
  CASE 
    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Rec,0)
    ELSE COALESCE(e.Amount_Rec,0) * (-1)
  END,  -- Amount_Recv
  CAST(CONVERT(NVARCHAR, e.Date_Due, 112) AS DATETIME),
  CAST(CONVERT(NVARCHAR, e.Date_Recv, 112) AS DATETIME),  -- convert to "whole day" 
  c.Margin_Pct, -- Margin Pct
  
  COALESCE(e.Amount_Due
--  * CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,17) THEN c.Margin_Pct ELSE 0 END,0) 
  , -- Margin Due

  COALESCE(e.Amount_Rec
  * CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,17) THEN c.Margin_Pct ELSE 0 END,0) 
  , -- Margin Recv

  COALESCE(
--  CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  CASE WHEN e.Type in (1,17) THEN (convert(decimal(15,2),e.Amount_Due) - convert(decimal(15,2),e.Amount_Due * c.Margin_Pct)) ELSE e.Amount_Due END
  ,0) , -- Commission Due

  COALESCE(
  CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,17) THEN (convert(decimal(15,2),e.Amount_Rec) - convert(decimal(15,2),e.Amount_Rec * c.Margin_Pct)) ELSE e.Amount_Rec END
  ,0) , -- Commission Recv

  i.IRD -- IRD
from  mstt_Expectation e
  inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
  INNER JOIN mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork
  left outer join #IRD i on e.transactionID = i.TransactionID and e.Type = i.Type
  left outer join #Comms c on e.transactionID = c.TransactionID
where e.Type IN (1, 4, 10, 17, 18, 19)
  and a.CompanyCode = 10002 -- Openwork


exec owp_FinstatFixExpSign

--Extract report data into a temp table
IF OBJECT_ID('tempdb..#FINSTAT0007a') IS NULL
begin
create table #FINSTAT0007a
  (
  [Section]   varchar(255),
  [Type]      tinyint,
  [Commission Type] varchar(50),
  [Basis Code]    varchar(1), 
  Basis     varchar(50), 
  Provider    varchar (255),
  [Franchise Commission]  decimal(15,2),
  [Openwork Margin] decimal(15,2),
  Error     varchar(6)
  )
end
else
  Truncate table #FINSTAT0007a  


-- final output sums values over expectations and then Manual Adjustments
INSERT into #FINSTAT0007a
select * from (
select  'Commission' AS [Section],
  e.DisplayType AS [Type],
  ISNULL(Codes.Description, 'Unknown') AS 'Commission Type',
  e.BasisCode AS 'Basis Code',
  e.Basis ,
  ISNULL(ProductProviders.ReportingProductProviderName, 'Unknown') AS 'Provider',
  sum(convert(decimal(15,2),
    case
      when  (e.Date_Recv <= @CD AND e.Amount_Recv <> 0.00)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD AND e.Date_Recv >= @OD)
          OR (e.IRD <= @CD AND e.Date_Due > @CD AND e.Date_Recv >= @OD)
        )
      then  e.Commission_Recv
      else  0
    end --RptCommRec,
    +
    case
      when  ((e.Date_Recv > @CD AND e.Amount_Recv <> 0.00) OR e.Date_Recv IS NULL)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD)
        )
      then  e.Commission_Due
      else  0
    end --RptCommDue,
    +
    case
      when
        (e.IRD < @OD 
                     AND e.Date_Due < @OD
                     AND e.Date_Recv >= @OD
                     AND e.Date_Recv <= @CD
                     AND e.Amount_Recv <> 0.00
                    )
      then  (e.Commission_Due - e.Commission_Recv) * (-1)
      else  0
    end
  )) --RptCommOverDue
  AS 'Franchise Commission',

  sum(convert(decimal(15,2),
    case
      when  (e.Date_Recv <= @CD AND e.Amount_Recv <> 0.00)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD AND e.Date_Recv >= @OD)
          OR (e.IRD <= @CD AND e.Date_Due > @CD AND e.Date_Recv >= @OD)
        )
      then  e.Margin_Recv
      else  0
    end --RptMarginRec,
    +
    case
      when  ((e.Date_Recv > @CD AND e.Amount_Recv <> 0.00) OR e.Date_Recv IS NULL)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD)
        )
      then  e.Margin_Due
      else  0
    end --RptMarginDue,
    +
    case
      when
        (e.IRD < @OD 
                     AND e.Date_Due < @OD
                     AND e.Date_Recv >= @OD
                     AND e.Date_Recv <= @CD
                     AND e.Amount_Recv <> 0.00
                    )
      then  (e.Margin_Due - e.Margin_Recv) * (-1)
      else  0
    end
  )) --RptMarginOverDue
  AS 'Openwork Margin',
  Null AS 'Error'
from  #exp e
  LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON e.DisplayType = Codes.Code AND ColumnName = 'CommissionType'
  LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = e.ProviderCode
group by 
  e.DisplayType,
  Codes.Description,
  e.BasisCode,
  e.Basis,
  ProductProviders.ReportingProductProviderName

UNION ALL

SELECT 
     'Manual'
   , PaymentsPending.CommissionType AS 'Type'
   , ISNULL(Codes.Description, 'Unknown') AS 'Commission Type'
   , NULL AS 'Basis Code' -- Basis only relevant to initial commission
   , NULL AS 'Basis' -- Basis only relevant to initial commission
   , ISNULL(ProductProviders.ReportingProductProviderName, 'Unknown') AS 'Provider'
   , sum(convert(decimal(15,2),PaymentsPending.Amount)) AS 'Franchise commission'
   , sum(convert(decimal(15,2),PaymentsPending.Amount)) * (-1) AS 'Openwork margin' 
   , NULL AS [Error]

FROM  mstt_PaymentsPending PaymentsPending
  LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = PaymentsPending.COMP_CODE
  LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON PaymentsPending.CommissionType = Codes.Code AND ColumnName = 'CommissionType'
  LEFT JOIN mstt_AgentPayments AS AgPay ON PaymentsPending.Id = AgPay.AgmId
  LEFT JOIN mstt_Agents AS Agents ON PaymentsPending.Agent_Code = Agents.Code

WHERE   Codes.Code IN ('20')
  and Agents.Descn <> 'Openwork'
  AND (CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) BETWEEN @OD AND @CD
    or (PaymentsPending.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME) BETWEEN @OD AND @CD))
group by 
  PaymentsPending.CommissionType,
  Codes.Description,
  ProductProviders.ReportingProductProviderName,
  ProductProviders.ProductProviderCode
) a
where [Franchise Commission]<>0 or [Openwork Margin]<>0

SELECT  [Section],
  [Type],
  [Commission Type],
  [Basis Code],
  Basis,
  Provider,
  [Franchise Commission],
  [Openwork Margin],
  Error
FROM #FINSTAT0007a
ORDER BY
  [Section], [Type], [Basis Code], [Provider]



-- tidy up
--drop table #IRD
--drop table #Comms
--drop table #Exp
GO
