CREATE procedure [dbo].[cscp_FINSTAT0007b] 
  @UserID VARCHAR(255), 
  @LegacyFlag VARCHAR(10),
  @StartDate VARCHAR(10), 
  @EndDate VARCHAR(10)

as


/*
  RH [Openwork] 24 Jan 2007
  Selected Finstat procs rewritten to improve performance
  Including 
    - moved logic for cscf_CalcMarginPercent UDF into proc rather than function call
    - IRD determination pulled into temp table rather than subselect
    - logic for each component part of calculated figures broken out to make it more readable
    - bizarre structure of select distinct ... with subqueries removed


  RH 17 Jan 2007
  Rework of original Finstat procedure for performance

  Figures returned by this version differ from original due to commisson records
  where sum(FixedAmount) is zero, resulting in a null margin.  This version still includes the +ve amount
  in the 'Franchise Commission' column, the original excludes it.
  see TPR3644 re data cleanup needed
  
  RH 18 Nov 2007
  Added call to proc owp_FinstatFixExpSign to determine sign based on expectation type and status
*/


set nocount on


IF OBJECT_ID('tempdb..#IRD') IS NOT NULL
   DROP TABLE #IRD
IF OBJECT_ID('tempdb..#Comms') IS NOT NULL
   DROP TABLE #Comms
IF OBJECT_ID('tempdb..#Exp') IS NOT NULL
   DROP TABLE #Exp


-- Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Section'
      , NULL AS 'Type'
      , NULL AS 'Commission Type'
      , NULL AS 'Basis Code'
      , NULL AS 'Basis'
      , NULL AS 'Product'
      , NULL AS 'Product Sub Group'
      , NULL AS 'Franchise commission'
      , NULL AS 'Openwork margin'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END



DECLARE @OD DATETIME
DECLARE @CD DATETIME


SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)


-- Calculate Income Recognition Date for each transaction/type combination
create table #IRD 
  (TransactionID  int, 
  Type    tinyint, 
  IRD     datetime,
  Primary Key (TransactionID,Type)
  )

insert #IRD
select  TransactionID,
  Type,
  min(CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME))
from  mstt_expectation
where TransactionID is not null
  and Type is not null
group by TransactionID,
  Type



-- Calculate Margin percent for each Transaction
create table #Comms 
  (
  TransactionID   int, 
  NetAmount   decimal(15,2), 
  TotalAmount   decimal(15,2), 
  Margin_Pct  float,
  Primary Key (TransactionID)
  )


insert #Comms
select  TransactionID,
  sum(case GrossOrNet
    when 'N' then FixedAmount
    else 0
  end),
  sum(FixedAmount),
  case 
    when coalesce(sum(FixedAmount),0)<>0 then
      sum(case GrossOrNet when 'N' then FixedAmount else 0 end)
      /
      sum(FixedAmount)
    else null -- should this be null or 0 ?
    -- from UDF comments
    -- Set Margin % = 0 (i.e. Commission % = 100)
    -- Set Margin % = NULL (i.e. Margin % = 0; Commission % = 0)
  end
from  mstt_Commissions
where CommissionType = 1
group by TransactionID


-- Table to store calculated data for each expectation
create table #Exp (
  ExpectationID int,
  TransactionID int,
  PolicyID  int,
  Type    tinyint,
  Status    tinyint,
  DisplayType tinyint,
  ProviderCode  varchar(10) collate LATIN1_GENERAL_CI_AS,
  BasisCode varchar(1) collate LATIN1_GENERAL_CI_AS,
  Basis   varchar(50) collate LATIN1_GENERAL_CI_AS,
  Amount_Due  decimal(15,2),
  Amount_Recv decimal(15,2),
  Date_Due  datetime,
  Date_Recv datetime,
  Margin_Pct  float,
  Margin_Due  decimal(15,2),
  Margin_Recv decimal(15,2),
  Commission_Due  decimal(15,2),
  Commission_Recv decimal(15,2),
  IRD   datetime
  )

insert #Exp
Select  e.ID,
  e.TransactionID,
  pt.PolicyID,
  e.Type,
  e.Status,
  CASE e.Type
    WHEN 1 THEN 1 -- IC
    WHEN 17 THEN 1 -- IC adjustment (treat as negative below)
    WHEN 4 THEN 4 -- RC
    WHEN 18 THEN 4 -- RC adjustment (treat as negative below)
    WHEN 10 THEN 10 -- Trail
    WHEN 19 THEN 10 -- Trail adjustment (treat as negative below)
  END , -- Display Type
  e.COMP_CODE,  -- provider code
  CASE
          WHEN e.Type = 1 or e.Type=17 THEN pt.CommType
          ELSE NULL
  END , -- Basis only relevant to initial commission
  CASE
          WHEN e.Type = 1 or e.Type=17 THEN ISNULL(pt.CommissionTypeDesc, 'Unknown')
          ELSE NULL
  END ,
  e.Amount_Due,
--  CASE
--    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Due,0)
--    ELSE COALESCE(e.Amount_Due,0) * (-1)
--  END,  -- Amount_Due
  CASE 
    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Rec,0)
    ELSE COALESCE(e.Amount_Rec,0) * (-1)
  END,  -- Amount_Recv
  CAST(CONVERT(NVARCHAR, e.Date_Due, 112) AS DATETIME),
  CAST(CONVERT(NVARCHAR, e.Date_Recv, 112) AS DATETIME),  -- convert to "whole day" 
  c.Margin_Pct, -- Margin Pct
  
  COALESCE(e.Amount_Due
  * CASE WHEN e.Type in (1,17) THEN c.Margin_Pct ELSE 0 END,0) 
  , -- Margin Due

  COALESCE(e.Amount_Rec
  * CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,17) THEN c.Margin_Pct ELSE 0 END,0) 
  , -- Margin Recv

  COALESCE(
  CASE WHEN e.Type in (1,17) THEN (convert(decimal(15,2),e.Amount_Due) - convert(decimal(15,2),e.Amount_Due * c.Margin_Pct)) ELSE e.Amount_Due END
  ,0) , -- Commission Due

  COALESCE(
  CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,17) THEN (convert(decimal(15,2),e.Amount_Rec) - convert(decimal(15,2),e.Amount_Rec * c.Margin_Pct)) ELSE e.Amount_Rec END
  ,0) , -- Commission Recv

  i.IRD -- IRD
from  mstt_Expectation e
  inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
  INNER JOIN mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork
  left outer join #IRD i on e.transactionID = i.TransactionID and e.Type = i.Type
  left outer join #Comms c on e.transactionID = c.TransactionID
where e.Type IN (1, 4, 10, 17, 18, 19)
  and a.CompanyCode = 10002 -- Openwork


exec owp_FinstatFixExpSign


-- final output sums values over expectations and then Manual Adjustments
select * from (
select  'Commission' AS [Section],
  e.DisplayType AS [Type],
  ISNULL(Codes.Description, 'Unknown') AS 'Commission Type',
  e.BasisCode AS 'Basis Code',
  e.Basis ,
  ISNULL(CodeProductGroup.ProductGroupName, 'Unknown') AS 'Product',
  ISNULL(CodeProductSubGroup.ProductSubGroupName, 'Unknown') AS 'Product Sub Group',

  sum(convert(decimal(15,2),
    case
      when  (e.Date_Recv <= @CD AND e.Amount_Recv <> 0.00)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD AND e.Date_Recv >= @OD)
          OR (e.IRD <= @CD AND e.Date_Due > @CD AND e.Date_Recv >= @OD)
        )
      then  e.Commission_Recv
      else  0
    end --RptCommRec,
    +
    case
      when  ((e.Date_Recv > @CD AND e.Amount_Recv <> 0.00) OR e.Date_Recv IS NULL)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD)
        )
      then  e.Commission_Due
      else  0
    end --RptCommDue,
    +
    case
      when
        (e.IRD < @OD 
                     AND e.Date_Due < @OD
                     AND e.Date_Recv >= @OD
                     AND e.Date_Recv <= @CD
                     AND e.Amount_Recv <> 0.00
                    )
      then  (e.Commission_Due - e.Commission_Recv) * (-1)
      else  0
    end
  )) --RptCommOverDue
  AS 'Franchise Commission',

  sum(convert(decimal(15,2),
    case
      when  (e.Date_Recv <= @CD AND e.Amount_Recv <> 0.00)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD AND e.Date_Recv >= @OD)
          OR (e.IRD <= @CD AND e.Date_Due > @CD AND e.Date_Recv >= @OD)
        )
      then  e.Margin_Recv
      else  0
    end --RptMarginRec,
    +
    case
      when  ((e.Date_Recv > @CD AND e.Amount_Recv <> 0.00) OR e.Date_Recv IS NULL)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD)
        )
      then  e.Margin_Due
      else  0
    end --RptMarginDue,
    +
    case
      when
        (e.IRD < @OD 
                     AND e.Date_Due < @OD
                     AND e.Date_Recv >= @OD
                     AND e.Date_Recv <= @CD
                     AND e.Amount_Recv <> 0.00
                    )
      then  (e.Margin_Due - e.Margin_Recv) * (-1)
      else  0
    end
  )) --RptMarginOverDue
  AS 'Openwork Margin',
  Null AS 'Error'
from  #exp e
  INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = e.PolicyID 
  LEFT JOIN mstt_CodeBIProducts CodeBIProducts ON CodeBIProducts.ProductCode = Policies.ProductCode
  LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON e.DisplayType = Codes.Code AND ColumnName = 'CommissionType'
  LEFT JOIN mstt_CodeProductGroup CodeProductGroup ON Policies.ProductGroupCode = CodeProductGroup.ProductGroupCode
  LEFT JOIN mstt_CodeProductSubGroup CodeProductSubGroup ON Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode
where
  ((@LegacyFlag = 'Legacy' AND CodeBIProducts.ProductType = @LegacyFlag) --Legacy/Non-Legacy
  OR
        (@LegacyFlag = 'Non-Legacy' AND (CodeBIProducts.ProductType <> 'Legacy' OR CodeBIProducts.ProductType IS NULL)) 
  OR
        (@LegacyFlag = 'Both'))

group by 
  e.DisplayType,
  Codes.Description,
  e.BasisCode,
  e.Basis,
  CodeProductGroup.ProductGroupName,
  CodeProductSubGroup.ProductSubGroupName

UNION ALL

SELECT 
     'Manual'
   , PaymentsPending.CommissionType AS 'Type'
   , ISNULL(Codes.Description, 'Unknown') AS 'Commission Type'
   , NULL AS 'Basis Code' -- Basis only relevant to initial commission
   , NULL AS 'Basis' -- Basis only relevant to initial commission
   , ISNULL(CodeProductGroup.ProductGroupName, 'Unknown') AS 'Product'
   , ISNULL(CodeProductSubGroup.ProductSubGroupName, 'Unknown') AS 'Product Sub Group'
   , sum(convert(decimal(15,2),PaymentsPending.Amount)) AS 'Franchise commission'
   , sum(convert(decimal(15,2),PaymentsPending.Amount)) * (-1) AS 'Openwork margin' 
   , NULL AS [Error]

FROM  mstt_PaymentsPending PaymentsPending
  LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON PaymentsPending.CommissionType = Codes.Code AND ColumnName = 'CommissionType'
  LEFT JOIN mstt_Agents AS Agents ON PaymentsPending.Agent_Code = Agents.Code
  LEFT JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = PaymentsPending.TransactionID
  LEFT JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID 
  LEFT JOIN mstt_CodeBIProducts CodeBIProducts ON CodeBIProducts.ProductCode = Policies.ProductCode
  LEFT JOIN mstt_CodeProductGroup CodeProductGroup ON Policies.ProductGroupCode = CodeProductGroup.ProductGroupCode
  LEFT JOIN mstt_CodeProductSubGroup CodeProductSubGroup ON Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode

WHERE   Codes.Code IN ('20')
  and Agents.Descn <> 'Openwork'
  AND (CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) BETWEEN @OD AND @CD
    or (PaymentsPending.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME) BETWEEN @OD AND @CD))
  AND
    ((@LegacyFlag = 'Legacy' AND CodeBIProducts.ProductType = @LegacyFlag) --Legacy/Non-Legacy
    OR
          (@LegacyFlag = 'Non-Legacy' AND (CodeBIProducts.ProductType <> 'Legacy' OR CodeBIProducts.ProductType IS NULL)) 
    OR
          (@LegacyFlag = 'Both'))
group by 
  PaymentsPending.CommissionType,
  Codes.Description,
  CodeProductGroup.ProductGroupName,
  CodeProductSubGroup.ProductSubGroupName
) a
where [Franchise Commission]<>0 or [Openwork Margin]<>0
ORDER BY
  [Section], [Type], [Basis Code], [Product], [Product Sub Group]



-- tidy up
drop table #IRD
drop table #Comms
drop table #Exp




GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0007c]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER OFF
GO
CREATE procedure [dbo].[cscp_FINSTAT0007c] 
  @UserID VARCHAR(255), 
  @StartDate VARCHAR(10), 
  @EndDate VARCHAR(10)

as


/*
  RH [Openwork] 24 Jan 2007
  Selected Finstat procs rewritten to improve performance
  Including 
    - moved logic for cscf_CalcMarginPercent UDF into proc rather than function call
    - IRD determination pulled into temp table rather than subselect
    - logic for each component part of calculated figures broken out to make it more readable
    - bizarre structure of select distinct ... with subqueries removed


  RH 17 Jan 2007
  Rework of original Finstat procedure for performance

  Figures returned by this version differ from original due to commisson records
  where sum(FixedAmount) is zero, resulting in a null margin.  This version still includes the +ve amount
  in the 'Franchise Commission' column, the original excludes it.
  see TPR3644 re data cleanup needed
  
  RH 18 Nov 2007
  Added call to proc owp_FinstatFixExpSign to determine sign based on expectation type and status

  AH 22 Sep 2008
  Create temporary table, final select query and remove final drop tables, to enable running of batchfinstat0001b
*/


set nocount on


/*
IF OBJECT_ID('tempdb..#IRD') IS NOT NULL
   DROP TABLE #IRD
IF OBJECT_ID('tempdb..#Comms') IS NOT NULL
   DROP TABLE #Comms
IF OBJECT_ID('tempdb..#Exp') IS NOT NULL
   DROP TABLE #Exp
*/


-- Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Section'
      , NULL AS 'Type'
      , NULL AS 'Commission Type'
      , NULL AS 'Basis Code'
      , NULL AS 'Basis'
      , NULL AS 'Franchise Code'
      , NULL AS 'Franchise'
      , NULL AS 'Franchise commission'
      , NULL AS 'Openwork margin'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END



DECLARE @OD DATETIME
DECLARE @CD DATETIME


SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)


-- Calculate Income Recognition Date for each transaction/type combination
create table #IRD 
  (TransactionID  int, 
  Type    tinyint, 
  IRD     datetime,
  Primary Key (TransactionID,Type)
  )

insert #IRD
select  TransactionID,
  Type,
  min(CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME))
from  mstt_expectation
where TransactionID is not null
  and Type is not null
group by TransactionID,
  Type



-- Calculate Margin percent for each Transaction
create table #Comms 
  (
  TransactionID   int, 
  NetAmount   decimal(15,2), 
  TotalAmount   decimal(15,2), 
  Margin_Pct  float,
  Primary Key (TransactionID)
  )


insert #Comms
select  TransactionID,
  sum(case GrossOrNet
    when 'N' then FixedAmount
    else 0
  end),
  sum(FixedAmount),
  case 
    when coalesce(sum(FixedAmount),0)<>0 then
      sum(case GrossOrNet when 'N' then FixedAmount else 0 end)
      /
      sum(FixedAmount)
    else null -- should this be null or 0 ?
    -- from UDF comments
    -- Set Margin % = 0 (i.e. Commission % = 100)
    -- Set Margin % = NULL (i.e. Margin % = 0; Commission % = 0)
  end
from  mstt_Commissions
where CommissionType = 1
group by TransactionID


-- Table to store calculated data for each expectation
create table #Exp (
  ExpectationID int,
  TransactionID int,
  PolicyID  int,
  AgentCode varchar(7) collate LATIN1_GENERAL_CI_AS,
  Type    tinyint,
  Status    tinyint,
  DisplayType tinyint,
  ProviderCode  varchar(10) collate LATIN1_GENERAL_CI_AS,
  BasisCode varchar(1) collate LATIN1_GENERAL_CI_AS,
  Basis   varchar(50) collate LATIN1_GENERAL_CI_AS,
  Amount_Due  decimal(15,2),
  Amount_Recv decimal(15,2),
  Date_Due  datetime,
  Date_Recv datetime,
  Margin_Pct  float,
  Margin_Due  decimal(15,2),
  Margin_Recv decimal(15,2),
  Commission_Due  decimal(15,2),
  Commission_Recv decimal(15,2),
  IRD   datetime
  )

insert #Exp
Select  e.ID,
  e.TransactionID,
  pt.PolicyID,
  pt.AgentCode,
  e.Type,
  e.Status,
  CASE e.Type
    WHEN 1 THEN 1 -- IC
    WHEN 17 THEN 1 -- IC adjustment (treat as negative below)
    WHEN 4 THEN 4 -- RC
    WHEN 18 THEN 4 -- RC adjustment (treat as negative below)
    WHEN 10 THEN 10 -- Trail
    WHEN 19 THEN 10 -- Trail adjustment (treat as negative below)
  END , -- Display Type
  e.COMP_CODE,  -- provider code
  CASE
          WHEN e.Type = 1 or e.Type=17 THEN pt.CommType
          ELSE NULL
  END , -- Basis only relevant to initial commission
  CASE
          WHEN e.Type = 1 or e.Type=17 THEN ISNULL(pt.CommissionTypeDesc, 'Unknown')
          ELSE NULL
  END ,
  e.Amount_Due,
--  CASE
--    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Due,0)
--    ELSE COALESCE(e.Amount_Due,0) * (-1)
--  END,  -- Amount_Due
  CASE 
    WHEN e.Type in (1,4,10) THEN COALESCE(e.Amount_Rec,0)
    ELSE COALESCE(e.Amount_Rec,0) * (-1)
  END,  -- Amount_Recv
  CAST(CONVERT(NVARCHAR, e.Date_Due, 112) AS DATETIME),
  CAST(CONVERT(NVARCHAR, e.Date_Recv, 112) AS DATETIME),  -- convert to "whole day" 
  c.Margin_Pct, -- Margin Pct
  
  COALESCE(e.Amount_Due
  * CASE WHEN e.Type in (1,17) THEN c.Margin_Pct ELSE 0 END,0) 
  , -- Margin Due

  COALESCE(e.Amount_Rec
  * CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,17) THEN c.Margin_Pct ELSE 0 END,0) 
  , -- Margin Recv

  COALESCE(
  CASE WHEN e.Type in (1,17) THEN (convert(decimal(15,2),e.Amount_Due) - convert(decimal(15,2),e.Amount_Due * c.Margin_Pct)) ELSE e.Amount_Due END
  ,0) , -- Commission Due

  COALESCE(
  CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,17) THEN (convert(decimal(15,2),e.Amount_Rec) - convert(decimal(15,2),e.Amount_Rec * c.Margin_Pct)) ELSE e.Amount_Rec END
  ,0) , -- Commission Recv

  i.IRD -- IRD
from  mstt_Expectation e
  inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
  INNER JOIN mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork
  left outer join #IRD i on e.transactionID = i.TransactionID and e.Type = i.Type
  left outer join #Comms c on e.transactionID = c.TransactionID
where e.Type IN (1, 4, 10, 17, 18, 19)
  and a.CompanyCode = 10002 -- Openwork


exec owp_FinstatFixExpSign

--Extract report data into a temp table
IF OBJECT_ID('tempdb..#FINSTAT0007c') IS NULL
begin
  create table #FINSTAT0007c
  (
  [Section]   varchar(255),
  [Type]      tinyint,
  [Commission Type] varchar(50),
  [Basis Code]    varchar(1), --collate LATIN1_GENERAL_CI_AS,
  Basis     varchar(50), --collate LATIN1_GENERAL_CI_AS,
  [Franchise Code]  varchar(7),
  Franchise   varchar(255), 
  [Franchise Commission]  decimal(15,2),
  [Openwork Margin] decimal(15,2),
  Error     varchar(6)
  )
end
else
  Truncate table #FINSTAT0007c

-- final output sums values over expectations and then Manual Adjustments
INSERT into #FINSTAT0007c
select * from (
select  'Commission' AS [Section],
  e.DisplayType AS [Type],
  ISNULL(Codes.Description, 'Unknown') AS 'Commission Type',
  e.BasisCode AS 'Basis Code',
  e.Basis ,
    CASE 
        WHEN Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' THEN Agents_fr.Code
        ELSE Agents.Code 
     END AS 'Franchise Code',
    CASE 
        WHEN Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown')) 
        ELSE RTRIM(ISNULL(Agents.DESCN, 'Unknown')) 
     END AS 'Franchise',

  sum(convert(decimal(15,2),
    case
      when  (e.Date_Recv <= @CD AND e.Amount_Recv <> 0.00)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD AND e.Date_Recv >= @OD)
          OR (e.IRD <= @CD AND e.Date_Due > @CD AND e.Date_Recv >= @OD)
        )
      then  e.Commission_Recv
      else  0
    end --RptCommRec,
    +
    case
      when  ((e.Date_Recv > @CD AND e.Amount_Recv <> 0.00) OR e.Date_Recv IS NULL)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD)
        )
      then  e.Commission_Due
      else  0
    end --RptCommDue,
    +
    case
      when
        (e.IRD < @OD 
                     AND e.Date_Due < @OD
                     AND e.Date_Recv >= @OD
                     AND e.Date_Recv <= @CD
                     AND e.Amount_Recv <> 0.00
                    )
      then  (e.Commission_Due - e.Commission_Recv) * (-1)
      else  0
    end
  )) --RptCommOverDue
  AS 'Franchise Commission',

  sum(convert(decimal(15,2),
    case
      when  (e.Date_Recv <= @CD AND e.Amount_Recv <> 0.00)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD AND e.Date_Recv >= @OD)
          OR (e.IRD <= @CD AND e.Date_Due > @CD AND e.Date_Recv >= @OD)
        )
      then  e.Margin_Recv
      else  0
    end --RptMarginRec,
    +
    case
      when  ((e.Date_Recv > @CD AND e.Amount_Recv <> 0.00) OR e.Date_Recv IS NULL)
        AND ( (e.IRD >= @OD AND e.IRD <= @CD AND e.Date_Due <= @CD)
          OR (e.IRD < @OD AND e.Date_Due >= @OD AND e.Date_Due <= @CD)
        )
      then  e.Margin_Due
      else  0
    end --RptMarginDue,
    +
    case
      when
        (e.IRD < @OD 
                     AND e.Date_Due < @OD
                     AND e.Date_Recv >= @OD
                     AND e.Date_Recv <= @CD
                     AND e.Amount_Recv <> 0.00
                    )
      then  (e.Margin_Due - e.Margin_Recv) * (-1)
      else  0
    end
  )) --RptMarginOverDue
  AS 'Openwork Margin',
  Null AS 'Error'
from  #exp e
  INNER JOIN mstt_Agents Agents ON e.AgentCode = Agents.Code
  LEFT JOIN mstt_Agents Agents_fr ON Agents.Firm = Agents_fr.CODE
  LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON e.DisplayType = Codes.Code AND ColumnName = 'CommissionType'
group by 
  e.DisplayType,
  Codes.Description,
  e.BasisCode,
  e.Basis,
    CASE 
        WHEN Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' THEN Agents_fr.Code
        ELSE Agents.Code 
     END,
    CASE 
        WHEN Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown')) 
        ELSE RTRIM(ISNULL(Agents.DESCN, 'Unknown')) 
     END

UNION ALL

SELECT 
     'Manual'
   , PaymentsPending.CommissionType AS 'Type'
   , ISNULL(Codes.Description, 'Unknown') AS 'Commission Type'
   , NULL AS 'Basis Code' -- Basis only relevant to initial commission
   , NULL AS 'Basis' -- Basis only relevant to initial commission
   , CASE 
        WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN Agents_fr.Code
        ELSE AgentsMain.Code 
     END AS 'Franchise Code'
   , CASE 
        WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown')) 
        ELSE RTRIM(ISNULL(AgentsMain.DESCN, 'Unknown')) 
     END AS 'Franchise'
   , sum(convert(decimal(15,2),PaymentsPending.Amount)) AS 'Franchise commission'
   , sum(convert(decimal(15,2),PaymentsPending.Amount)) * (-1) AS 'Openwork margin' 
   , NULL AS [Error]

FROM  mstt_PaymentsPending PaymentsPending
  INNER JOIN mstt_Agents AgentsMain ON PaymentsPending.Agent_Code = AgentsMain.Code
  LEFT JOIN mstt_Agents Agents_fr ON AgentsMain.Firm = Agents_fr.CODE
  LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON PaymentsPending.CommissionType = Codes.Code AND ColumnName = 'CommissionType'

WHERE   Codes.Code IN ('20')
  and AgentsMain.Descn <> 'Openwork'
  AND (CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) BETWEEN @OD AND @CD
    or (PaymentsPending.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME) BETWEEN @OD AND @CD))
group by 
  PaymentsPending.CommissionType,
  Codes.Description,
  CASE 
          WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN Agents_fr.Code
          ELSE AgentsMain.Code 
  END ,
  CASE 
          WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown')) 
          ELSE RTRIM(ISNULL(AgentsMain.DESCN, 'Unknown')) 
      END ) a
where [Franchise Commission]<>0 or [Openwork Margin]<>0

SELECT [Section],
  [Type],
  [Commission Type],
  [Basis Code],
  Basis,
  [Franchise Code],
  Franchise,  
  [Franchise Commission],
  [Openwork Margin],
  Error
FROM #FINSTAT0007c
ORDER BY
  [Section], [Type], [Basis Code], [Franchise Code], [Franchise]



-- tidy up
--drop table #IRD
--drop table #Comms
--drop table #Exp
GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0007d]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[cscp_FINSTAT0007d] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

/*

  
  RH 18 Nov 2007
  Added logic to determine sign based on expectation type and status

*/
--1. Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Section'
      , NULL AS 'Type'
      , NULL AS 'Commission Type'
      , NULL AS 'Basis Code'
      , NULL AS 'Basis'
      , NULL AS 'Income period'
      , NULL AS 'IRDate'
      , NULL AS 'Franchise commission'
      , NULL AS 'Openwork margin'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

--2. Convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

--3. Extract Expectation data into a temp table
IF OBJECT_ID('tempdb..#FINSTAT0007dExpectation') IS NOT NULL
   DROP TABLE #FINSTAT0007dExpectation

SELECT Expectation.ID, 
       CASE Expectation.Type
          WHEN 1 THEN 1 -- IC
          WHEN 17 THEN 1 -- IC adjustment (treat as negative below)
          WHEN 4 THEN 4 -- RC
          WHEN 18 THEN 4 -- RC adjustment (treat as negative below)
          WHEN 10 THEN 10 -- Trail
          WHEN 19 THEN 10 -- Trail adjustment (treat as negative below)
       END AS Type,
       Expectation.TransactionID,
       CASE 
          WHEN Expectation.Type in (1,4,10) THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          WHEN Expectation.Type in (17,18,19) and Expectation.Status = 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
       END AS Amount_Due,
--       CASE Expectation.Type
--          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
--          WHEN 4 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
--          WHEN 10 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
--          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
--       END AS Amount_Due,
       CASE Expectation.Type
          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN 4 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN 10 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
       END AS Amount_Rec,
       dbo.cscf_CalcMarginPercent(Expectation.ID) AS Margin_Pct,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Rec,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Rec,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) AS Date_Due,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #FINSTAT0007dExpectation
FROM mstt_Expectation Expectation
   INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
   INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
   INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (1, 4, 10, 17, 18, 19)          --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD    --of the temp table
       OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD   --by omitting data which
           AND Expectation.DATE_RECV IS NOT NULL))          --we KNOW we don't need
GROUP BY Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
  Expectation.Status,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

-- 3.1 bypass Margin Calcs for margin and commission values to avoid calling cscf_CalcMarginPercent more than once per Expectation
UPDATE #FINSTAT0007dExpectation
SET Margin_Due = ISNULL(CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Due = ISNULL(CAST((Amount_Due - CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00),
    Margin_Rec = ISNULL(CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Rec = ISNULL(CAST((Amount_Rec - CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00)

CREATE CLUSTERED INDEX ind_FINSTAT0007 ON #FINSTAT0007dExpectation (ID, Type, TransactionID, Amount_Due, Amount_Rec, Margin_Pct, Margin_Due, Commission_Due, Margin_Rec, Commission_Rec, Date_Due, Date_Recv, IRD)

--4. Extract Paymentspending data into another temp table
IF OBJECT_ID('tempdb..#FINSTAT0007dPaymentsPending') IS NOT NULL
   DROP TABLE #FINSTAT0007dPaymentsPending

SELECT
     PaymentsPending.CommissionType AS 'Type'
   , ISNULL(Codes.Description, 'Unknown') AS 'Commission Type'
   , CASE 
        WHEN PaymentsPending.PaymentDueDate IS NOT NULL
           THEN CAST(YEAR(PaymentsPending.PaymentDueDate) AS NVARCHAR(4)) + ' ' + UPPER(SUBSTRING(DATENAME(MONTH, PaymentsPending.PaymentDueDate), 1, 3))
        ELSE CAST(YEAR(PaymentsPending.CreatedDate) AS NVARCHAR(4)) + ' ' + UPPER(SUBSTRING(DATENAME(MONTH, PaymentsPending.CreatedDate), 1, 3))
     END AS 'Income Period'
   , CASE 
        WHEN PaymentsPending.PaymentDueDate IS NOT NULL
           THEN CAST(CAST(YEAR(PaymentsPending.PaymentDueDate) AS NVARCHAR(4)) + 
                SUBSTRING ('00', 1, 2 - LEN(CAST(MONTH(PaymentsPending.PaymentDueDate) AS NVARCHAR(2)))) +
                CAST(MONTH(PaymentsPending.PaymentDueDate) AS NVARCHAR(2)) AS INT) --Dummy field added to ensure ordering/omitted in final resultset
        ELSE CAST(CAST(YEAR(PaymentsPending.CreatedDate) AS NVARCHAR(4)) + 
             SUBSTRING ('00', 1, 2 - LEN(CAST(MONTH(PaymentsPending.CreatedDate) AS NVARCHAR(2)))) +
             CAST(MONTH(PaymentsPending.CreatedDate) AS NVARCHAR(2)) AS INT) --Dummy field added to ensure ordering/omitted in final resultset
     END AS IRDate
   , ISNULL(CAST(PaymentsPending.Amount AS DECIMAL(15,2)), 0.00) AS Commission
   , ISNULL(CAST(PaymentsPending.Amount AS DECIMAL(15,2)), 0.00) * (-1) AS Margin
INTO #FINSTAT0007dPaymentsPending
FROM mstt_PaymentsPending AS PaymentsPending
LEFT JOIN mstt_Agents AS Agents ON PaymentsPending.Agent_Code = Agents.Code
LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON PaymentsPending.CommissionType = Codes.Code AND ColumnName = 'CommissionType'
WHERE PaymentsPending.CommissionType = 20 
  AND Agents.Descn <> 'Openwork'
  AND (CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) >= @OD
    OR (PaymentsPending.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME) >= @OD))
  AND (CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) <= @CD
    OR (PaymentsPending.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME) <= @CD))

--5. Extract report data into a final temp table
IF OBJECT_ID('tempdb..#FINSTAT0007d') IS NOT NULL
   DROP TABLE #FINSTAT0007d


SELECT DISTINCT
     PolicyTransactions.CommType -- required to ensure uniqueness of records
   , Expectation.TYPE AS 'Type'
   , ISNULL(Codes.Description, 'Unknown') AS 'Commission Type'
   , CASE
        WHEN Expectation.TYPE = 1 THEN PolicyTransactions.CommType
        ELSE NULL
     END AS 'Basis Code' -- Basis only relevant to initial commission
   , CASE
        WHEN Expectation.TYPE = 1 THEN ISNULL(PolicyTransactions.CommissionTypeDesc, 'Unknown')
        ELSE NULL
     END AS 'Basis' -- Basis only relevant to initial commission
   , CAST(YEAR(Expectation.IRD) AS NVARCHAR(4)) + ' ' + UPPER(SUBSTRING(DATENAME(MONTH, Expectation.IRD), 1, 3)) AS 'Income Period'
   , CAST(CAST(YEAR(Expectation.IRD) AS NVARCHAR(4)) + 
     SUBSTRING ('00', 1, 2 - LEN(CAST(MONTH(Expectation.IRD) AS NVARCHAR(2)))) +
     CAST(MONTH(Expectation.IRD) AS NVARCHAR(2)) AS INT) AS IRDate --Dummy field added to ensure ordering/omitted in final resultset
   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0007dExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (PolicyTransactions1.CommType = PolicyTransactions.CommType
               OR (PolicyTransactions1.CommType IS NULL AND PolicyTransactions.CommType IS NULL))
            AND YEAR(Expectation1.IRD) = YEAR(Expectation.IRD)
            AND MONTH(Expectation1.IRD) = MONTH(Expectation.IRD)
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0007dExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (PolicyTransactions1.CommType = PolicyTransactions.CommType
               OR (PolicyTransactions1.CommType IS NULL AND PolicyTransactions.CommType IS NULL))
            AND YEAR(Expectation1.IRD) = YEAR(Expectation.IRD)
            AND MONTH(Expectation1.IRD) = MONTH(Expectation.IRD)
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0007dExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (PolicyTransactions1.CommType = PolicyTransactions.CommType
               OR (PolicyTransactions1.CommType IS NULL AND PolicyTransactions.CommType IS NULL))
            AND YEAR(Expectation1.IRD) = YEAR(Expectation.IRD)
            AND MONTH(Expectation1.IRD) = MONTH(Expectation.IRD)
         ) * (-1)
        )
     ) AS 'Franchise commission'
   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0007dExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (PolicyTransactions1.CommType = PolicyTransactions.CommType
               OR (PolicyTransactions1.CommType IS NULL AND PolicyTransactions.CommType IS NULL))
            AND YEAR(Expectation1.IRD) = YEAR(Expectation.IRD)
            AND MONTH(Expectation1.IRD) = MONTH(Expectation.IRD)
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0007dExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (PolicyTransactions1.CommType = PolicyTransactions.CommType
               OR (PolicyTransactions1.CommType IS NULL AND PolicyTransactions.CommType IS NULL))
            AND YEAR(Expectation1.IRD) = YEAR(Expectation.IRD)
            AND MONTH(Expectation1.IRD) = MONTH(Expectation.IRD)
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0007dExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (PolicyTransactions1.CommType = PolicyTransactions.CommType
               OR (PolicyTransactions1.CommType IS NULL AND PolicyTransactions.CommType IS NULL))
            AND YEAR(Expectation1.IRD) = YEAR(Expectation.IRD)
            AND MONTH(Expectation1.IRD) = MONTH(Expectation.IRD)
         ) * (-1)
        )
     ) AS 'Openwork margin' 
   , NULL AS [Error]
INTO #FINSTAT0007d
FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN #FINSTAT0007dExpectation Expectation ON Expectation.TransactionID = PolicyTransactions.ID
LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON Expectation.Type = Codes.Code AND ColumnName = 'CommissionType'
WHERE Codes.Code IN ('1', '4', '10')

UNION ALL

SELECT
     NULL AS CommType
   , [Type]
   , ISNULL(Codes.Description, 'Unknown') AS 'Commission Type'
   , NULL AS 'Basis Code' -- Basis only relevant to initial commission
   , NULL AS 'Basis' -- Basis only relevant to initial commission
   , [Income Period]
   , [IRDate]
   , [Commission] AS 'Franchise commission'
   , [Margin] AS 'Openwork margin' 
   , NULL AS [Error]

FROM #FINSTAT0007dPaymentsPending PaymentsPending
LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON PaymentsPending.Type = Codes.Code AND ColumnName = 'CommissionType'

ORDER BY [Type], [Basis Code], [IRDate]

--6. Select data for report
SELECT 
     CASE Type
        WHEN 20 THEN 'Manual'
        ELSE 'Commission'
     END AS [Section]
   , [Type]
   , [Commission Type]
   , [Basis Code]
   , [Basis]
   , [Income period]
   , [IRDate]
   , ISNULL(SUM(ISNULL(CAST([Franchise commission] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Franchise commission]
   , ISNULL(SUM(ISNULL(CAST([Openwork margin] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Openwork margin]
   , [Error]
FROM  #FINSTAT0007d
GROUP BY CASE Type
            WHEN 20 THEN 'Manual'
            ELSE 'Commission'
         END
       , [Type]
       , [Commission Type]
       , [Basis Code]
       , [Basis]
       , [Income period]
       , [IRDate]
       , [Error]
HAVING ISNULL(SUM(ISNULL(CAST([Franchise commission] AS DECIMAL(15,2)), 0.00)), 0.00) <> 0.00 OR ISNULL(SUM(ISNULL(CAST([Openwork margin] AS DECIMAL(15,2)), 0.00)), 0.00) <> 0.00 --Display only non-zero values
ORDER BY [Section], [Type], [Basis Code], [IRDate]

--7. Tidy Up
DROP TABLE #FINSTAT0007d
DROP TABLE #FINSTAT0007dExpectation
DROP TABLE #FINSTAT0007dPaymentsPending


GO
