CREATE PROCEDURE [dbo].[cscp_FINSTAT0009c] @UserID VARCHAR(255), @StartDate VARCHAR(10) ,@EndDate VARCHAR(10)
AS

IF ISDATE(@EndDate) = 0 OR ISDATE(@StartDate) = 0
BEGIN
  SELECT 
        NULL AS 'Franchise'
      , NULL AS 'Distribution Allowance'
      , NULL AS 'Renewal margin'
      , 'Invalid Date Entered. Please enter it in the format dd/mm/yyyy' AS [Error]
   RETURN 0
END

IF OBJECT_ID('tempdb..#FINSTAT0009c') IS NOT NULL
   DROP TABLE #FINSTAT0009c

SELECT 
      DISTINCT
      CASE WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN RTRIM(Agents_fr.DESCN) ELSE RTRIM(AgentsMain.DESCN) END AS 'Franchise'
   ,  AgentsMain.Code AS 'Agent Code' --Added to ensure uniqueness/omitted in final resultset
   , (SELECT ISNULL(SUM(ISNULL(CAST((DBO.cscf_CalcCommissionDue(Expectation.ID)) AS DECIMAL(15,2)), 0.00)), 0.00)  
      FROM mstt_Expectation Expectation
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
      WHERE Expectation.DATE_DUE IS NOT NULL
      AND Expectation.Type = 4 -- Other Fee Commission  
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)  
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
      AND EXISTS
          (SELECT Commissions.PolicyID 
           FROM mstt_Commissions Commissions
              INNER JOIN mstt_Agents Agents ON Agents.CODE = Commissions.AGENT_CODE
           WHERE Commissions.PolicyID = PolicyTransactions.PolicyID
           AND RTRIM(Agents.descn) = 'Openwork'
          )
     AND PolicyTransactions.AgentCode = AgentsMain.CODE) As 'Distribution Allowance'
   

,  (SELECT ISNULL(SUM(ISNULL(CAST((DBO.cscf_CalcMarginDue(Expectation.ID)) AS DECIMAL(15,2)), 0.00)), 0.00)  
      FROM mstt_Expectation Expectation
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
      WHERE Expectation.DATE_DUE IS NOT NULL
      AND Expectation.Type = 4 -- Other Fee Commission  
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)  
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
      AND EXISTS
          (SELECT Commissions.PolicyID 
           FROM mstt_Commissions Commissions
              INNER JOIN mstt_Agents Agents ON Agents.CODE = Commissions.AGENT_CODE
           WHERE Commissions.PolicyID = PolicyTransactions.PolicyID
           AND RTRIM(Agents.descn) = 'Openwork'
          )
      AND PolicyTransactions.AgentCode = AgentsMain.CODE) As 'Renewal margin'

   , NULL AS [Error]

INTO #FINSTAT0009c
FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN mstt_Expectation Expectation ON Expectation.TransactionID = PolicyTransactions.ID
LEFT JOIN mstt_Agents AgentsMain ON AgentsMain.CODE = PolicyTransactions.AgentCode
LEFT JOIN mstt_Agents Agents_fr ON AgentsMain.Firm = Agents_fr.CODE
WHERE Expectation.DATE_DUE IS NOT NULL
AND Expectation.Type = 4 -- Other Fee Commission  
AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)  
AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
AND EXISTS
    (SELECT Commissions.PolicyID 
     FROM mstt_Commissions Commissions
        INNER JOIN mstt_Agents Agents ON Agents.CODE = Commissions.AGENT_CODE
     WHERE Commissions.PolicyID = PolicyTransactions.PolicyID
     AND RTRIM(Agents.descn) = 'Openwork'
    )
ORDER BY [Franchise]

SELECT 
     CASE WHEN [Franchise] IS NOT NULL THEN [Franchise] ELSE 'Unknown' END AS [Franchise]
   , ISNULL(SUM(ISNULL(CAST([Distribution Allowance] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Distribution Allowance]
   , ISNULL(SUM(ISNULL(CAST([Renewal margin] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Renewal margin]
   , [Error]
FROM  #FINSTAT0009c
GROUP BY [Franchise], [Error]
ORDER BY [Franchise]

DROP TABLE #FINSTAT0009c

GO
