CREATE PROCEDURE [dbo].[cscp_FINSTAT0013] @UserID VARCHAR(255), @StartDate AS VARCHAR(10), @EndDate AS VARCHAR(10)
AS

IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
       NULL AS 'PolNum',
       NULL AS 'Date Received',
       NULL AS 'Provider',
       NULL AS 'Issued Date',
       NULL AS 'Transaction Date',
       NULL AS 'Full Transaction Date',
       NULL AS 'Initial Period Months',
       NULL AS 'Initial Period Months Passed',
       NULL AS 'Frequency',
       NULL AS 'Indemnity/Accruals',
       NULL AS 'Clawback',
       NULL AS 'Franchise Code',
       NULL AS 'Franchise',
       NULL AS 'Product Group',
       NULL AS 'Due Date',
       NULL AS 'Received Amount',
       NULL AS 'GrossDA',
       CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
       END AS [Error]
   RETURN 0
END

SELECT 
      Policies.Pol_Num AS 'PolNum', --Dummy field added to allow count distinct on number of policies
      CONVERT(VARCHAR, Expectation.DATE_RECV, 103) as 'Date Received',
      CASE
         WHEN ProductProviders.ReportingProductProviderName IS NOT NULL THEN ProductProviders.ReportingProductProviderName
         ELSE 'Unknown'
      END AS 'Provider',
      CAST(YEAR(PolicyTransactions.TransactionDate) AS NVARCHAR(4)) + ' ' + 
      UPPER(SUBSTRING(DATENAME(MONTH, PolicyTransactions.TransactionDate), 1, 3)) AS 'Issued Date',
      CAST(CAST(YEAR(PolicyTransactions.TransactionDate) AS NVARCHAR(4)) + 
        SUBSTRING ('00', 1, 2 - LEN(CAST(MONTH(PolicyTransactions.TransactionDate) AS NVARCHAR(2)))) +
        CAST(MONTH(PolicyTransactions.TransactionDate) AS NVARCHAR(2)) AS INT) AS 'Transaction Date', --Dummy field added to ensure ordering
      PolicyTransactions.TransactionDate AS 'Full Transaction Date', --Dummy field added to ensure ordering
      PolicyTransactions.CommInitialPeriod as 'Initial Period Months',
      -- The following code calculates the number of complete months between Expectation.DATE_RECV and PolicyTransactions.TransactionDate, 
      -- taking into account month-ends
      -- i.e. 26/5/06 - 27/4/06 = 0 months
      --      29/7/06 - 17/4/05 = 15 months 
      --      15/7/06 - 15/6/06 = 1 months
      --      30/4/06 - 31/3/06 = 1 months (because both dates are month-ends)
      --      28/4/06 - 3/7/06 = -2 months (it's the absolute difference; negated)
      -- A simple DATEDIFF cannot be used because this simply returns the number of month boundaries crossed between two specified dates
      -- Hence, we:
      --  (1) do a MONTH DATEDIFF
      --  (2) add this difference on to the 2nd date using DATEADD (which understands about month ends)
      --  (3) compare the 1st date with the result from (2)
      --  (4) adjust the result from (1) if necessary
      -- Note that negative differrences are handled slightly differently
      CASE
         WHEN DATEDIFF(MONTH, CAST(CONVERT(NVARCHAR,PolicyTransactions.TransactionDate, 112) AS DATETIME), 
                              CAST(CONVERT(NVARCHAR,Expectation.DATE_RECV, 112) AS DATETIME)) > 0
            THEN -- positive number of month boundaries
               CASE
                  WHEN DATEADD(MONTH, 
                               DATEDIFF(MONTH, CAST(CONVERT(NVARCHAR,PolicyTransactions.TransactionDate, 112) AS DATETIME), 
                                               CAST(CONVERT(NVARCHAR,Expectation.DATE_RECV, 112) AS DATETIME)),
                               CAST(CONVERT(NVARCHAR,PolicyTransactions.TransactionDate, 112) AS DATETIME))
                       > Expectation.DATE_RECV
                     THEN -- adding the difference back on gives a later date, so round the result down by one month
                          DATEDIFF(MONTH, CAST(CONVERT(NVARCHAR,PolicyTransactions.TransactionDate, 112) AS DATETIME), 
                                         CAST(CONVERT(NVARCHAR,Expectation.DATE_RECV, 112) AS DATETIME)) - 1
                  ELSE DATEDIFF(MONTH, CAST(CONVERT(NVARCHAR,PolicyTransactions.TransactionDate, 112) AS DATETIME), 
                                       CAST(CONVERT(NVARCHAR,Expectation.DATE_RECV, 112) AS DATETIME))
               END
         WHEN DATEDIFF(MONTH, CAST(CONVERT(NVARCHAR,PolicyTransactions.TransactionDate, 112) AS DATETIME), 
                              CAST(CONVERT(NVARCHAR,Expectation.DATE_RECV, 112) AS DATETIME)) < 0
            THEN -- negative number of month boundaries
               CASE
                  WHEN DATEADD(MONTH, 
                               DATEDIFF(MONTH, CAST(CONVERT(NVARCHAR,Expectation.DATE_RECV, 112) AS DATETIME), 
                                               CAST(CONVERT(NVARCHAR,PolicyTransactions.TransactionDate, 112) AS DATETIME)),
                               CAST(CONVERT(NVARCHAR,Expectation.DATE_RECV, 112) AS DATETIME))
                       > PolicyTransactions.TransactionDate
                     THEN -- adding the difference back on gives a later date, so round the absolute value of the result down by one month
                          -(DATEDIFF(MONTH, CAST(CONVERT(NVARCHAR,Expectation.DATE_RECV, 112) AS DATETIME), 
                                         CAST(CONVERT(NVARCHAR,PolicyTransactions.TransactionDate, 112) AS DATETIME)) - 1)
                  ELSE -(DATEDIFF(MONTH, CAST(CONVERT(NVARCHAR,Expectation.DATE_RECV, 112) AS DATETIME), 
                                       CAST(CONVERT(NVARCHAR,PolicyTransactions.TransactionDate, 112) AS DATETIME)))
               END
         ELSE 0 -- zero month boundaries --> rounded result must also be zero
      END AS 'Initial Period Months Passed',
      PolicyTransactions.FrequencyDescription as 'Frequency',
      PolicyTransactions.CommType as 'Indemnity/Accruals',
      Expectation.TYPE as 'Clawback',
      CASE 
         WHEN Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' THEN Agents_fr.Code
         ELSE Agents.Code 
      END AS 'Franchise Code',
      CASE 
         WHEN Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown')) 
         ELSE RTRIM(ISNULL(Agents.DESCN, 'Unknown')) 
      END AS 'Franchise',
      ISNULL(CodeProductGroup.ProductGroupName, 'Unknown') as 'Product Group',
      CONVERT(VARCHAR, Expectation.DATE_DUE, 103) as 'Due Date',
      ISNULL(CAST(Expectation.AMOUNT_REC AS DECIMAL(15,2)), 0.00) as 'Received Amount',
     --N.B. the following subquery will need to be revisited once a link has been deisgned between a clawback and its original DA
     --in the meantime, the simple logic below (which assumes there is only ever one IC matching each clawback on transaction id), is the best we can do!
     (SELECT ISNULL(SUM(ISNULL(CAST(ExpectationIC.AMOUNT_REC AS DECIMAL(15,2)), 0.00)), 0.00)
      FROM mstt_Expectation ExpectationIC
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = ExpectationIC.TransactionID
         INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
         INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
      WHERE ExpectationIC.Type = 1
        AND ExpectationIC.TransactionID = Expectation.TransactionID
     ) AS 'GrossDA',
      NULL AS 'Error'
      FROM mstt_Expectation Expectation
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
         INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
         INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
         INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
   LEFT JOIN mstt_Agents Agents_fr ON Agents.Firm = Agents_fr.CODE
   LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = Expectation.COMP_CODE
   LEFT JOIN mstt_CodeProductGroup CodeProductGroup ON CodeProductGroup.ProductGroupCode = Policies.ProductGroupCode  
    WHERE Expectation.TYPE = 2 --Clawback
      AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
      AND  CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))

GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0013a]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
