CREATE PROCEDURE [dbo].[cscp_FINSTAT0013c] @UserID VARCHAR(255), @StartDate VARCHAR(255), @EndDate VARCHAR(10)
AS

/*
  
  RH 18 Nov 2007
  Added logic to determine sign based on expectation type and status
*/
--1. Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR  ISDATE(@EndDate) = 0
BEGIN
  SELECT DISTINCT
        NULL AS 'Income period'
      , NULL AS 'IRDate'
      , NULL AS 'Provider'
      , NULL AS 'Product'
      , NULL AS 'GrossDA'
      , NULL AS 'Clawback'
      , NULL AS 'Number of Policies'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN 'Invalid Closing Date Entered. Please enter it in the format dd/mm/yyyy' 
        END AS [Error]
   RETURN 0
END

--2. Convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

--3. select all required Clawback data into a temporary table
IF OBJECT_ID('tempdb..#FINSTAT0013cClawbacks') IS NOT NULL
   DROP TABLE #FINSTAT0013cClawbacks

SELECT Policies.POL_NUM,
       Expectation.ID,
       Expectation.Type,
       Expectation.TransactionID,
       Expectation.COMP_CODE,
       Policies.ProductGroupCode AS ProductGroupCode,
       ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) AS Amount_Due,
       ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) AS Amount_Rec,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) AS Date_Due,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD,
        CAST(NULL AS DATETIME) AS IC_IRD
INTO #FINSTAT0013cClawbacks
FROM mstt_Expectation Expectation
INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (2)             --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD  --of the temp table
     OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD --by omitting data which
         AND Expectation.DATE_RECV IS NOT NULL))        --we KNOW we don't need
GROUP BY Policies.POL_NUM,
         Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
         Expectation.COMP_CODE,
         Policies.ProductGroupCode,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

CREATE CLUSTERED INDEX ind_Clawbacks ON #FINSTAT0013cClawbacks (POL_NUM, ID, TransactionID, COMP_CODE, ProductGroupCode, Amount_Due, Amount_Rec, Date_Due, Date_Recv, IRD, IC_IRD)

--4. select all required IC data into another temporary table
IF OBJECT_ID('tempdb..#FINSTAT0013cNonClawbacks') IS NOT NULL
   DROP TABLE #FINSTAT0013cNonClawbacks

SELECT Policies.POL_NUM,
       Expectation.ID,
       Expectation.Type,
       Expectation.TransactionID,
       Expectation.COMP_CODE,
       Policies.ProductGroupCode AS ProductGroupCode,
      CASE 
          WHEN Expectation.Type = 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN Expectation.Type = 17 and expectation.Status = 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
       END AS Amount_Due,
--      CASE Expectation.Type
--          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
--          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
--       END AS Amount_Due,
       CASE Expectation.Type
          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
       END AS Amount_Rec,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #FINSTAT0013cNonClawbacks
FROM mstt_Expectation Expectation
INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE PolicyTransactions.ID IN (SELECT Clawbacks.TransactionID
                                FROM #FINSTAT0013cClawbacks Clawbacks)
  AND Expectation.Type IN (1, 17)           --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD  --of the temp table
     OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD --by omitting data which
         AND Expectation.DATE_RECV IS NOT NULL))        --we KNOW we don't need
GROUP BY Policies.POL_NUM,
         Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
  Expectation.Status,
         Expectation.COMP_CODE,
         Policies.ProductGroupCode,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

CREATE CLUSTERED INDEX ind_NonClawbacks ON #FINSTAT0013cNonClawbacks (POL_NUM, ID, TransactionID, COMP_CODE, ProductGroupCode, Amount_Due, Amount_Rec, IRD)

--4.2 update IC_IRD in the Clawbacks table with the IRD of the corresponding Non-Clawback
UPDATE #FINSTAT0013cClawbacks
SET IC_IRD = (SELECT TOP 1 NonClawbacks.IRD
              FROM #FINSTAT0013cNonClawbacks NonClawbacks
              WHERE NonClawbacks.TransactionID = Clawbacks.TransactionID
              ORDER BY NonClawbacks.IRD)
FROM #FINSTAT0013cClawbacks Clawbacks

--5. now use the two temporary tables to determine the report data
IF OBJECT_ID('tempdb..#FINSTAT0013c') IS NOT NULL
   DROP TABLE #FINSTAT0013c

SELECT DISTINCT 
     CAST(YEAR(Expectation.IC_IRD) AS NVARCHAR(4)) + ' ' + UPPER(SUBSTRING(DATENAME(MONTH, Expectation.IC_IRD), 1, 3)) AS 'Income Period'

   , CAST(CAST(YEAR(Expectation.IC_IRD) AS NVARCHAR(4)) + 
     SUBSTRING ('00', 1, 2 - LEN(CAST(MONTH(Expectation.IC_IRD) AS NVARCHAR(2)))) +
     CAST(MONTH(Expectation.IC_IRD) AS NVARCHAR(2)) AS INT) AS 'IRDate' --Dummy field

   , ProductProviders.ReportingProductProviderName AS 'Provider'

   , CodeProductGroup.ProductGroupName as 'Product' 

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013cClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND YEAR(Clawbacks.IC_IRD) = YEAR(Expectation.IC_IRD)
            AND MONTH(Clawbacks.IC_IRD) = MONTH(Expectation.IC_IRD)
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (Clawbacks.ProductGroupCode = CodeProductGroup.ProductGroupCode  
               OR (Clawbacks.ProductGroupCode IS NULL AND CodeProductGroup.ProductGroupCode IS NULL))
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013cClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND YEAR(Clawbacks.IC_IRD) = YEAR(Expectation.IC_IRD)
            AND MONTH(Clawbacks.IC_IRD) = MONTH(Expectation.IC_IRD)
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (Clawbacks.ProductGroupCode = CodeProductGroup.ProductGroupCode  
               OR (Clawbacks.ProductGroupCode IS NULL AND CodeProductGroup.ProductGroupCode IS NULL))
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013cClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND YEAR(Clawbacks.IC_IRD) = YEAR(Expectation.IC_IRD)
            AND MONTH(Clawbacks.IC_IRD) = MONTH(Expectation.IC_IRD)
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (Clawbacks.ProductGroupCode = CodeProductGroup.ProductGroupCode  
               OR (Clawbacks.ProductGroupCode IS NULL AND CodeProductGroup.ProductGroupCode IS NULL))
         )
        )
     ) AS 'Clawback'

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013cNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0013cClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE Date_Recv <= @CD
                                                 AND Amount_Rec <> 0.00
                                                 AND ((IRD >= @OD
                                                       AND IRD <= @CD
                                                       AND Date_Due <= @CD
                                                      )
                                                   OR (IRD < @OD
                                                       AND Date_Due >= @OD
                                                       AND Date_Due <= @CD
                                                       AND Date_Recv >= @OD
                                                      )
                                                   OR (IRD <= @CD
                                                       AND Date_Due > @CD
                                                       AND Date_Recv >= @OD
                                                      )
                                                     )
                                                 AND YEAR(Clawbacks.IC_IRD) = YEAR(Expectation.IC_IRD)
                                                 AND MONTH(Clawbacks.IC_IRD) = MONTH(Expectation.IC_IRD)
                                                 AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
                                                    OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                                                        AND ProductProviders.ProductProviderCode IS NULL))
                                                 AND (Clawbacks.ProductGroupCode = CodeProductGroup.ProductGroupCode   
                                                    OR (Clawbacks.ProductGroupCode IS NULL AND CodeProductGroup.ProductGroupCode IS NULL))
                                              )
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013cNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0013cClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                                                 AND ((IRD >= @OD
                                                       AND IRD <= @CD
                                                       AND Date_Due <= @CD
                                                      )
                                                   OR (IRD < @OD
                                                       AND Date_Due >= @OD
                                                       AND Date_Due <= @CD
                                                      )
                                                     )
                                                 AND YEAR(Clawbacks.IC_IRD) = YEAR(Expectation.IC_IRD)
                                                 AND MONTH(Clawbacks.IC_IRD) = MONTH(Expectation.IC_IRD)
                                                 AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
                                                    OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                                                        AND ProductProviders.ProductProviderCode IS NULL))
                                                 AND (Clawbacks.ProductGroupCode = CodeProductGroup.ProductGroupCode   
                                                    OR (Clawbacks.ProductGroupCode IS NULL AND CodeProductGroup.ProductGroupCode IS NULL))
                                              )
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013cNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0013cClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE (IRD < @OD
                                                      AND Date_Due < @OD
                                                      AND Date_Recv >= @OD
                                                      AND Date_Recv <= @CD
                                                      AND Amount_Rec <> 0.00
                                                     )
                                                 AND YEAR(Clawbacks.IC_IRD) = YEAR(Expectation.IC_IRD)
                                                 AND MONTH(Clawbacks.IC_IRD) = MONTH(Expectation.IC_IRD)
                                                 AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
                                                    OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                                                        AND ProductProviders.ProductProviderCode IS NULL))
                                                 AND (Clawbacks.ProductGroupCode = CodeProductGroup.ProductGroupCode   
                                                    OR (Clawbacks.ProductGroupCode IS NULL AND CodeProductGroup.ProductGroupCode IS NULL))
                                              )
         ) * (-1)
        )
     ) AS 'GrossDA'

   , (SELECT COUNT(DISTINCT Clawbacks.POL_NUM)
      FROM #FINSTAT0013cClawbacks AS Clawbacks
      INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
      INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
      WHERE
           (Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND YEAR(Clawbacks.IC_IRD) = YEAR(Expectation.IC_IRD)
            AND MONTH(Clawbacks.IC_IRD) = MONTH(Expectation.IC_IRD)
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (Clawbacks.ProductGroupCode = CodeProductGroup.ProductGroupCode  
               OR (Clawbacks.ProductGroupCode IS NULL AND CodeProductGroup.ProductGroupCode IS NULL))
           )
         OR
           (((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND YEAR(Clawbacks.IC_IRD) = YEAR(Expectation.IC_IRD)
            AND MONTH(Clawbacks.IC_IRD) = MONTH(Expectation.IC_IRD)
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (Clawbacks.ProductGroupCode = CodeProductGroup.ProductGroupCode  
               OR (Clawbacks.ProductGroupCode IS NULL AND CodeProductGroup.ProductGroupCode IS NULL))
           )
         OR
           ((IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND YEAR(Clawbacks.IC_IRD) = YEAR(Expectation.IC_IRD)
            AND MONTH(Clawbacks.IC_IRD) = MONTH(Expectation.IC_IRD)
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (Clawbacks.ProductGroupCode = CodeProductGroup.ProductGroupCode  
               OR (Clawbacks.ProductGroupCode IS NULL AND CodeProductGroup.ProductGroupCode IS NULL))
           )
     ) AS 'NumberofPolicies'  
  
   , NULL AS [Error]
        
INTO #FINSTAT0013c

FROM #FINSTAT0013cClawbacks Expectation
        INNER JOIN mstt_PolicyTransactions PolicyTransactions ON Expectation.TransactionID = PolicyTransactions.ID
  INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID 
  LEFT JOIN mstt_CodeProductGroup CodeProductGroup on CodeProductGroup.ProductGroupCode = Policies.ProductGroupCode
  LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = Expectation.COMP_CODE

ORDER BY IRDate

SELECT * FROM(
SELECT  
      [Income period]
    , [IRDate]
    , CASE WHEN [Provider] IS NULL THEN 'Unknown' ELSE [PROVIDER] END AS [PROVIDER]
    , CASE WHEN [Product] IS NULL THEN 'Unknown' ELSE [Product] END AS [Product]  
    , ISNULL(SUM(ISNULL(CAST([GrossDA] AS DECIMAL(15,2)), 0.00)), 0.00) AS [GrossDA] 
    , ISNULL(SUM(ISNULL(CAST([Clawback] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Clawback]  
    , ISNULL(SUM([NumberofPolicies]),0) AS [Number of Policies]     
    , [Error]   
FROM  #FINSTAT0013c

GROUP BY [Income period], [IRDate], [Provider], [Product], [Error] 
) AS FINSTAT0013cTEMP
WHERE [GrossDA] <> 0.00
  OR [Clawback] <> 0.00
ORDER BY [IRDate], [Provider], [Product]

DROP TABLE #FINSTAT0013cClawbacks
DROP TABLE #FINSTAT0013cNonClawbacks
DROP TABLE #FINSTAT0013c


GO
