CREATE PROCEDURE [dbo].[cscp_FINSTAT0013e] @UserID VARCHAR(255), @StartDate VARCHAR(255), @EndDate VARCHAR(10)
AS
/*
  
  RH 18 Nov 2007
  Added logic to determine sign based on expectation type and status
*/

--1. Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR  ISDATE(@EndDate) = 0
BEGIN
  SELECT 
        NULL AS 'Indemnity/Accruals'
      , NULL AS 'Frequency'
      , NULL AS 'GrossDA'
      , NULL AS 'Clawback'
      , NULL AS 'Number of Policies'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN 'Invalid Closing Date Entered. Please enter it in the format dd/mm/yyyy' 
        END AS [Error]
   RETURN 0
END

--2. Convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

--3. select all required Clawback data into a temporary table
IF OBJECT_ID('tempdb..#FINSTAT0013eClawbacks') IS NOT NULL
   DROP TABLE #FINSTAT0013eClawbacks

SELECT Policies.POL_NUM,
       Expectation.ID,
       Expectation.Type,
       Expectation.TransactionID,
       PolicyTransactions.CommType AS CommType,
       PolicyTransactions.FrequencyDescription AS FrequencyDescription,
       ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) AS Amount_Due,
       ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) AS Amount_Rec,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) AS Date_Due,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #FINSTAT0013eClawbacks
FROM mstt_Expectation Expectation
INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (2)             --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD  --of the temp table
     OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD --by omitting data which
         AND Expectation.DATE_RECV IS NOT NULL))        --we KNOW we don't need
GROUP BY Policies.POL_NUM,
         Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
         PolicyTransactions.CommType,
         PolicyTransactions.FrequencyDescription,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

CREATE CLUSTERED INDEX ind_Clawbacks ON #FINSTAT0013eClawbacks (POL_NUM, ID, TransactionID, CommType, FrequencyDescription, Amount_Due, Amount_Rec, Date_Due, Date_Recv, IRD)

--4. select all required IC data into another temporary table
IF OBJECT_ID('tempdb..#FINSTAT0013eNonClawbacks') IS NOT NULL
   DROP TABLE #FINSTAT0013eNonClawbacks

SELECT Policies.POL_NUM,
       Expectation.ID,
       Expectation.Type,
       Expectation.TransactionID,
       PolicyTransactions.CommType AS CommType,
       PolicyTransactions.FrequencyDescription AS FrequencyDescription,
      CASE 
          WHEN Expectation.Type = 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN Expectation.Type = 17 and Expectation.Status = 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
       END AS Amount_Due,
--      CASE Expectation.Type
--          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
--          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
--       END AS Amount_Due,
       CASE Expectation.Type
          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
       END AS Amount_Rec
INTO #FINSTAT0013eNonClawbacks
FROM mstt_Expectation Expectation
INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE PolicyTransactions.ID IN (SELECT Clawbacks.TransactionID
                                FROM #FINSTAT0013eClawbacks Clawbacks)
  AND Expectation.Type IN (1, 17)           --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD  --of the temp table
     OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD --by omitting data which
         AND Expectation.DATE_RECV IS NOT NULL))        --we KNOW we don't need
GROUP BY Policies.POL_NUM,
         Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
  Expectation.Status,
         PolicyTransactions.CommType,
         PolicyTransactions.FrequencyDescription,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

CREATE CLUSTERED INDEX ind_NonClawbacks ON #FINSTAT0013eNonClawbacks (POL_NUM, ID, TransactionID, CommType, FrequencyDescription, Amount_Due, Amount_Rec)

--5. now use the two temporary tables to determine the report data
IF OBJECT_ID('tempdb..#FINSTAT0013e') IS NOT NULL
   DROP TABLE #FINSTAT0013e

SELECT DISTINCT  
     PolicyTransactions.CommType AS PolCommType
  
   , CASE PolicyTransactions.FrequencyDescription 
  WHEN 'Annually' THEN 'Annually'
  WHEN 'Monthly' THEN 'Monthly'
        WHEN 'Single' THEN 'Single'
        ELSE 'Unknown'
     END AS 'Frequency' 

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013eClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
      AND Clawbacks.CommType = PolicyTransactions.CommType
      AND Clawbacks.FrequencyDescription = PolicyTransactions.FrequencyDescription  
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013eClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
      AND Clawbacks.CommType = PolicyTransactions.CommType
      AND Clawbacks.FrequencyDescription = PolicyTransactions.FrequencyDescription  
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013eClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
      AND Clawbacks.CommType = PolicyTransactions.CommType
      AND Clawbacks.FrequencyDescription = PolicyTransactions.FrequencyDescription  
         )
        )
     ) AS 'Clawback'

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013eNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0013eClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE Date_Recv <= @CD
                                                 AND Amount_Rec <> 0.00
                                                 AND ((IRD >= @OD
                                                       AND IRD <= @CD
                                                       AND Date_Due <= @CD
                                                      )
                                                   OR (IRD < @OD
                                                       AND Date_Due >= @OD
                                                       AND Date_Due <= @CD
                                                       AND Date_Recv >= @OD
                                                      )
                                                   OR (IRD <= @CD
                                                       AND Date_Due > @CD
                                                       AND Date_Recv >= @OD
                                                      )
                                                     )
                                                 AND Clawbacks.CommType = PolicyTransactions.CommType
                                                 AND Clawbacks.FrequencyDescription = PolicyTransactions.FrequencyDescription
                                              )
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013eNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0013eClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                                                 AND ((IRD >= @OD
                                                       AND IRD <= @CD
                                                       AND Date_Due <= @CD
                                                      )
                                                   OR (IRD < @OD
                                                       AND Date_Due >= @OD
                                                       AND Date_Due <= @CD
                                                      )
                                                     )
                                                 AND Clawbacks.CommType = PolicyTransactions.CommType
                                                 AND Clawbacks.FrequencyDescription = PolicyTransactions.FrequencyDescription
                                              )
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0013eNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0013eClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE (IRD < @OD
                                                      AND Date_Due < @OD
                                                      AND Date_Recv >= @OD
                                                      AND Date_Recv <= @CD
                                                      AND Amount_Rec <> 0.00
                                                     )
                                                 AND Clawbacks.CommType = PolicyTransactions.CommType
                                                 AND Clawbacks.FrequencyDescription = PolicyTransactions.FrequencyDescription
                                              )
         ) * (-1)
        )
     ) AS 'GrossDA'

   , (SELECT COUNT(DISTINCT Clawbacks.POL_NUM)
      FROM #FINSTAT0013eClawbacks AS Clawbacks
      INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
      INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
      WHERE
           (Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
      AND Clawbacks.CommType = PolicyTransactions.CommType
      AND Clawbacks.FrequencyDescription = PolicyTransactions.FrequencyDescription  
           )
         OR
           (((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
      AND Clawbacks.CommType = PolicyTransactions.CommType
      AND Clawbacks.FrequencyDescription = PolicyTransactions.FrequencyDescription  
           )
         OR
           ((IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
      AND Clawbacks.CommType = PolicyTransactions.CommType
      AND Clawbacks.FrequencyDescription = PolicyTransactions.FrequencyDescription  
           )
     ) AS 'NumberofPolicies'  
  
   , NULL AS [Error]
        
INTO #FINSTAT0013e

FROM #FINSTAT0013eClawbacks Expectation
INNER JOIN mstt_PolicyTransactions PolicyTransactions ON Expectation.TransactionID = PolicyTransactions.ID

SELECT * FROM(
SELECT 
      PolCommType
    , CASE PolCommType
   WHEN 'T' THEN 'Indemnity'
   WHEN 'F' THEN 'Accrual'    
   WHEN 'L' THEN 'Level'
      END AS [Indemnity/Accruals]
    , [Frequency] 
    , ISNULL(SUM(ISNULL(CAST([GrossDA] AS DECIMAL(15,2)), 0.00)), 0.00) AS [GrossDA] 
    , ISNULL(SUM(ISNULL(CAST([Clawback] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Clawback]  
    , ISNULL(SUM([NumberofPolicies]),0) AS [Number of Policies]     
    , [Error]

FROM  #FINSTAT0013e

GROUP BY PolCommType, [Frequency], [Error]
) AS FINSTAT0013eTEMP

WHERE [GrossDA] <> 0.00
  OR [Clawback] <> 0.00

ORDER BY PolCommType

DROP TABLE #FINSTAT0013eClawbacks
DROP TABLE #FINSTAT0013eNonClawbacks
DROP TABLE #FINSTAT0013e


GO
