CREATE PROCEDURE [dbo].[cscp_FINSTAT0020a] @UserID VARCHAR(255), @StartDate VARCHAR(255), @EndDate VARCHAR(10)
AS

/*
  
  RH 18 Nov 2007
  Added logic to determine sign based on expectation type and status

  AH 22 Sep 2008
  Create temporary table, final select query and remove final drop tables, to enable running of batchfinstat0001b
*/

--1. Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR  ISDATE(@EndDate) = 0
BEGIN
  SELECT 
        NULL AS 'Provider'
      , NULL AS 'Gross Commisson Franchise'
      , NULL AS 'Clawback due From Franchise'
      , NULL AS 'Gross Margin Openwork' 
      , NULL AS 'ClawBack Due From Openwork'
      , NULL AS 'Number of Policies'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN 'Invalid Closing Date Entered. Please enter it in the format dd/mm/yyyy' 
        END AS [Error]
   RETURN 0
END

--2. Convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

--3. select all required Clawback data into a temporary table
--IF OBJECT_ID('tempdb..#FINSTAT0020aClawbacks') IS NOT NULL
--   DROP TABLE #FINSTAT0020aClawbacks

SELECT Policies.POL_NUM,
       Expectation.ID,
       Expectation.Type,
       Expectation.TransactionID,
       Expectation.COMP_CODE,
       ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) AS Amount_Due,
       ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) AS Amount_Rec,
       dbo.cscf_CalcMarginPercent(Expectation.ID) AS Margin_Pct,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Rec,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Rec,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) AS Date_Due,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #FINSTAT0020aClawbacks
FROM mstt_Expectation Expectation
INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (2)             --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD  --of the temp table
     OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD --by omitting data which
         AND Expectation.DATE_RECV IS NOT NULL))        --we KNOW we don't need
GROUP BY Policies.POL_NUM,
         Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
         Expectation.COMP_CODE,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

-- 3.1 bypass Margin Calcs for margin and commission values to avoid calling cscf_CalcMarginPercent more than once per Expectation
UPDATE #FINSTAT0020aClawbacks
SET Margin_Due = ISNULL(CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Due = ISNULL(CAST((Amount_Due - CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00),
    Margin_Rec = ISNULL(CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Rec = ISNULL(CAST((Amount_Rec - CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00)

CREATE CLUSTERED INDEX ind_Clawbacks ON #FINSTAT0020aClawbacks (POL_NUM, ID, TransactionID, COMP_CODE, Amount_Due, Amount_Rec, Margin_Pct, Margin_Due, Commission_Due, Margin_Rec, Commission_Rec, Date_Due, Date_Recv, IRD)

--4. select all required IC data into another temporary table
--IF OBJECT_ID('tempdb..#FINSTAT0020aNonClawbacks') IS NOT NULL
--   DROP TABLE #FINSTAT0020aNonClawbacks

SELECT Policies.POL_NUM,
       Expectation.ID,
       Expectation.Type,
       Expectation.TransactionID,
       Expectation.COMP_CODE,
      CASE 
          WHEN Expectation.Type = 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN Expectation.Type = 17 and Expectation.Status = 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
       END AS Amount_Due,
       CASE Expectation.Type
          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) * (-1)
       END AS Amount_Rec,
       dbo.cscf_CalcMarginPercent(Expectation.ID) AS Margin_Pct,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Rec,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Rec
INTO #FINSTAT0020aNonClawbacks
FROM mstt_Expectation Expectation
INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE PolicyTransactions.ID IN (SELECT Clawbacks.TransactionID
                                FROM #FINSTAT0020aClawbacks Clawbacks)
  AND Expectation.Type IN (1, 17)           --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD  --of the temp table
     OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD --by omitting data which
         AND Expectation.DATE_RECV IS NOT NULL))        --we KNOW we don't need
GROUP BY Policies.POL_NUM,
         Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
  Expectation.Status,
         Expectation.COMP_CODE,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

-- 4.1 bypass Margin Calcs for margin and commission values to avoid calling cscf_CalcMarginPercent more than once per Expectation
UPDATE #FINSTAT0020aNonClawbacks
SET Margin_Due = ISNULL(CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Due = ISNULL(CAST((Amount_Due - CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00),
    Margin_Rec = ISNULL(CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Rec = ISNULL(CAST((Amount_Rec - CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00)

CREATE CLUSTERED INDEX ind_NonClawbacks ON #FINSTAT0020aNonClawbacks (POL_NUM, ID, TransactionID, COMP_CODE, Amount_Due, Amount_Rec, Margin_Pct, Margin_Due, Commission_Due, Margin_Rec, Commission_Rec)

--5. now use the two temporary tables to determine the report data
--IF OBJECT_ID('tempdb..#FINSTAT0020a') IS NOT NULL
--   DROP TABLE #FINSTAT0020a

SELECT DISTINCT
     ProductProviders.ReportingProductProviderName AS 'Provider' 

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
         )
        )
     ) AS 'ClawbackdueFromFranchise'

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0020aClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE Date_Recv <= @CD
                                                 AND Amount_Rec <> 0.00
                                                 AND ((IRD >= @OD
                                                       AND IRD <= @CD
                                                       AND Date_Due <= @CD
                                                      )
                                                   OR (IRD < @OD
                                                       AND Date_Due >= @OD
                                                       AND Date_Due <= @CD
                                                       AND Date_Recv >= @OD
                                                      )
                                                   OR (IRD <= @CD
                                                       AND Date_Due > @CD
                                                       AND Date_Recv >= @OD
                                                      )
                                                     )
                                                 AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
                                                    OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                                                        AND ProductProviders.ProductProviderCode IS NULL))
                                              )
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0020aClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                                                 AND ((IRD >= @OD
                                                       AND IRD <= @CD
                                                       AND Date_Due <= @CD
                                                      )
                                                   OR (IRD < @OD
                                                       AND Date_Due >= @OD
                                                       AND Date_Due <= @CD
                                                      )
                                                     )
                                                 AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
                                                    OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                                                        AND ProductProviders.ProductProviderCode IS NULL))
                                              )
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0020aClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE (IRD < @OD
                                                      AND Date_Due < @OD
                                                      AND Date_Recv >= @OD
                                                      AND Date_Recv <= @CD
                                                      AND Amount_Rec <> 0.00
                                                     )
                                                 AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
                                                    OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                                                        AND ProductProviders.ProductProviderCode IS NULL))
                                              )
         ) * (-1)
        )
     ) AS 'GrossCommissonFranchise'

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aClawbacks AS Clawbacks
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
         )
        )
     ) AS 'ClawbackDueFromOpenWork'

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0020aClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE Date_Recv <= @CD
                                                 AND Amount_Rec <> 0.00
                                                 AND ((IRD >= @OD
                                                       AND IRD <= @CD
                                                       AND Date_Due <= @CD
                                                      )
                                                   OR (IRD < @OD
                                                       AND Date_Due >= @OD
                                                       AND Date_Due <= @CD
                                                       AND Date_Recv >= @OD
                                                      )
                                                   OR (IRD <= @CD
                                                       AND Date_Due > @CD
                                                       AND Date_Recv >= @OD
                                                      )
                                                     )
                                                 AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
                                                    OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                                                        AND ProductProviders.ProductProviderCode IS NULL))
                                              )
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0020aClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                                                 AND ((IRD >= @OD
                                                       AND IRD <= @CD
                                                       AND Date_Due <= @CD
                                                      )
                                                   OR (IRD < @OD
                                                       AND Date_Due >= @OD
                                                       AND Date_Due <= @CD
                                                      )
                                                     )
                                                 AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
                                                    OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                                                        AND ProductProviders.ProductProviderCode IS NULL))
                                              )
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #FINSTAT0020aNonClawbacks AS NonClawbacks
          WHERE NonClawbacks.TransactionID IN (SELECT Clawbacks.TransactionID
                                               FROM #FINSTAT0020aClawbacks Clawbacks
                                               INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
                                               INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
                                               WHERE (IRD < @OD
                                                      AND Date_Due < @OD
                                                      AND Date_Recv >= @OD
                                                      AND Date_Recv <= @CD
                                                      AND Amount_Rec <> 0.00
                                                     )
                                                 AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
                                                    OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                                                        AND ProductProviders.ProductProviderCode IS NULL))
                                              )
         ) * (-1)
        )
     ) AS 'GrossMarginOpenWork'

   , (SELECT COUNT(DISTINCT Clawbacks.POL_NUM)
      FROM #FINSTAT0020aClawbacks AS Clawbacks
      INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Clawbacks.TransactionID
      INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
      WHERE
           (Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
           )
         OR
           (((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
           )
         OR
           ((IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (Clawbacks.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Clawbacks.COMP_CODE IS NULL OR Clawbacks.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
           )
     ) AS 'NumberofPolicies'  
  
   , NULL AS [Error]
        
INTO #FINSTAT0020a

FROM #FINSTAT0020aClawbacks Expectation
LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = Expectation.COMP_CODE

ORDER BY [Provider]

--Extract report data into a temp table
IF OBJECT_ID('tempdb..#BatchFINSTAT0020a') IS NULL
begin
  Create table #BatchFINSTAT0020a
  (
  Provider            varchar(255),
  [Gross Commisson Franchise] decimal(15,2),
  [Clawback Due From Franchise] decimal(15,2),
  [Gross Margin Openwork]     decimal(15,2),
  [Clawback Due From Openwork]  decimal(15,2),
  [Number of Policies]      int,
  Error             varchar(6)
  )
end
else
  Truncate table #BatchFINSTAT0020a

INSERT INTO #BatchFINSTAT0020a
SELECT * FROM (
SELECT 
     CASE WHEN [Provider]IS NULL THEN 'Unknown' ELSE [PROVIDER] END AS [PROVIDER]
    , ISNULL(SUM(ISNULL(CAST([GrossCommissonFranchise] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Gross Commisson Franchise] 
    , ISNULL(SUM(ISNULL(CAST([ClawbackdueFromFranchise] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Clawback Due from Franchise]   
    , ISNULL(SUM(ISNULL(CAST([GrossMarginOpenWork] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Gross Margin OpenWork]  
    , ISNULL(SUM(ISNULL(CAST([ClawbackDueFromOpenWork] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Clawback Due from OpenWork]   
    , ISNULL(SUM([NumberofPolicies]),0) AS [Number of Policies]     
    , [Error]
      
FROM  #FINSTAT0020a

GROUP BY [Provider], [Error]

) AS FINSTAT0020aTemp

WHERE [Gross Commisson Franchise] <> 0.00
  OR [Clawback Due from Franchise] <> 0.00
  OR [Gross Margin OpenWork] <> 0.00
  OR [Clawback Due from OpenWork] <> 0.00

--Select statement for batchFINSTAT
SELECT  Provider,
  [Gross Commisson Franchise],
  [Clawback Due From Franchise],
  [Gross Margin Openwork],
  [Clawback Due From Openwork],
  [Number of Policies],
  Error
FROM #BatchFINSTAT0020a
ORDER BY [Provider]

--DROP TABLE #FINSTAT0020aClawbacks
--DROP TABLE #FINSTAT0020aNonClawbacks
--DROP TABLE #FINSTAT0020a
GO
