CREATE PROCEDURE [dbo].[cscp_FINSTAT0025a] @UserID VARCHAR(255), @DueDate VARCHAR(10)
AS
/*
  RH [Openwork] 24 Jan 2007
  Selected Finstat procs rewritten to improve performance
  Including 
    - moved logic for cscf_CalcMarginPercent UDF into proc rather than function call
    - IRD determination pulled into temp table rather than subselect
    - logic for each component part of calculated figures broken out to make it more readable
    - bizarre structure of select distinct ... with subqueries removed


  RH [Openwork] 19 Jan 2007
  BI-182 Aging bands expanded ref Paul Atkinson

  RH 17 Jan 2007
  Rework of original Finstat procedure for performance

  Figures returned by this version differ from original due to commisson records
  where sum(FixedAmount) is zero, resulting in a null margin.  This version still includes the +ve amount
  in the 'Franchise Commission' column, the original excludes it.
  see TPR3644 re data cleanup needed
  
  RH 18 Nov 2007
  Added call to proc owp_FinstatFixExpSign to determine sign based on expectation type and status

  AH 22 Sep 2008
  Create temporary table, final select query and remove final drop tables, to enable running of batchfinstat0001b

*/


set nocount on


--IF OBJECT_ID('tempdb..#IRD') IS NOT NULL
--   DROP TABLE #IRD
--IF OBJECT_ID('tempdb..#Exp') IS NOT NULL
--   DROP TABLE #Exp

--1. Validate @DueDate
IF ISDATE(@DueDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Provider'
      , NULL AS 'OutstandingRecptUpTo30'
      , NULL AS 'OutstandingRecpt31to90'
      , NULL AS 'OutstandingRecpt91to120'
      , NULL AS 'OutstandingRecpt121to180'
      , NULL AS 'OutstandingRecpt181to365'
      , NULL AS 'OutstandingRecptMore365'
      , NULL AS 'OutstandingRecptTotal'
      , 'Invalid Due Date Entered. Please enter it in the format dd/mm/yyyy' AS [Error]
   RETURN 0
END

--2. Convert input date into DateTime
DECLARE @CD DATETIME
SET @CD = CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME)


-- Calculate Income Recognition Date for each transaction/type combination
create table #IRD 
  (TransactionID  int, 
  Type    tinyint, 
  IRD     datetime,
  Primary Key (TransactionID,Type)
  )

insert #IRD
select  TransactionID,
  Type,
  min(CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME))
from  mstt_expectation
where TransactionID is not null
  and Type is not null
group by TransactionID,
  Type



-- Table to store calculated data for each expectation
create table #Exp (
  ExpectationID int,
  TransactionID int,
  PolicyID  int,
  AgentCode varchar(7) collate LATIN1_GENERAL_CI_AS,
  Type    tinyint,
  DisplayType tinyint,
  Status    tinyint,
  ProviderCode  varchar(10) collate LATIN1_GENERAL_CI_AS,
  Amount_Due  decimal(15,2),
  Amount_Rec  decimal(15,2),
  Date_Due  datetime,
  Date_Recv datetime,
  DateDueDiff varchar(8) collate LATIN1_GENERAL_CI_AS,
  IRD   datetime
  )


insert #Exp
Select  e.ID,
  e.TransactionID,
  pt.PolicyID,
  pt.AgentCode,
  e.Type,
  CASE e.Type
    WHEN 1 THEN 1 -- IC
    WHEN 17 THEN 1 -- IC adjustment (treat as negative below)
    WHEN 4 THEN 4 -- RC
    WHEN 18 THEN 4 -- RC adjustment (treat as negative below)
    WHEN 10 THEN 10 -- Trail
    WHEN 19 THEN 10 -- Trail adjustment (treat as negative below)
  END , -- Display Type
  e.Status,
  e.COMP_CODE,  -- provider code
  e.Amount_Due, -- Amount_Due
--  CASE
--    WHEN e.Type in (2,15,16,17,18,19) THEN COALESCE(e.Amount_Due,0) * (-1)
--    ELSE COALESCE(e.Amount_Due,0)
--  END,  -- Amount_Due
  CASE 
    WHEN e.Type in (2,15,16,17,18,19) THEN COALESCE(e.Amount_Rec,0) * (-1)
    ELSE COALESCE(e.Amount_Rec,0)
  END,  -- Amount_Recv
  CAST(CONVERT(NVARCHAR, e.Date_Due, 112) AS DATETIME),
  CAST(CONVERT(NVARCHAR, e.Date_Recv, 112) AS DATETIME),  -- convert to "whole day" 
  CASE
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) < 31
               THEN 'UpTo30'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 31 and 90
               THEN '31to90'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 91 and 120
               THEN '91to120'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 121 and 180
               THEN '121to180'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 181 and 365
               THEN '181to365'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) > 365
               THEN 'More365'
  else '???'
  END AS DateDueDiff,
  i.IRD -- IRD
from  mstt_Expectation e
  inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
  INNER JOIN mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork
  left outer join #IRD i on e.transactionID = i.TransactionID and e.Type = i.Type
where e.Type not IN (5, 6)
  and a.CompanyCode = 10002 -- Openwork
  AND (CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME) <= @CD
          OR (CAST(CONVERT(NVARCHAR, e.DATE_RECV, 112) AS DATETIME) <= @CD) 
      AND e.DATE_RECV IS NOT NULL)


exec owp_FinstatFixExpSign

--Extract report data into a temp table
IF OBJECT_ID('tempdb..#BatchFINSTAT0025a') IS NULL
begin
  Create table #BatchFINSTAT0025a
  (
  Provider      varchar(255),
  OutstandingRecptUpTo30    decimal(15,2),
  OutstandingRecpt31To90    decimal(15,2),
  OutstandingRecpt91To120   decimal(15,2),
  OutstandingRecpt121To180  decimal(15,2),
  OutstandingRecpt181To365  decimal(15,2),
  OutstandingRecptMore365   decimal(15,2),
  OutstandingRecptTotal   decimal(15,2),
  Error       varchar(6)
  ) 

end
else
  Truncate table #BatchFINSTAT0025a

INSERT into #BatchFINSTAT0025a
select * from (
SELECT 
      CASE WHEN pp.ReportingProductProviderName IS NOT NULL THEN pp.ReportingProductProviderName ELSE 'Unknown' END AS [Provider]
   ,  SUM(CASE WHEN DateDueDiff <> 'UpTo30' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) AS 'OutstandingRecptUpTo30'
   ,  SUM(CASE WHEN DateDueDiff <> '31TO90' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) AS 'OutstandingRecpt31to90'
   ,  SUM(CASE WHEN DateDueDiff <> '91TO120' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) as 'OutstandingRecpt91to120'
   ,  SUM(CASE WHEN DateDueDiff <> '121TO180' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) AS 'OutstandingRecpt121to180'
   ,  SUM(CASE WHEN DateDueDiff <> '181TO365' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) AS 'OutstandingRecpt181to365'
   ,  SUM(CASE WHEN DateDueDiff <> 'More365' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) AS 'OutstandingRecptMore365'
   ,  SUM(
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  ) AS 'OutstandingRecptTotal'
   ,  NULL AS [Error]

FROM  #Exp
  LEFT JOIN mstt_ProductProviders pp ON pp.ProductProviderCode = #Exp.ProviderCode
GROUP BY pp.ReportingProductProviderName) a
WHERE   [OutstandingRecptUpTo30] <> 0 
  OR [OutstandingRecpt31to90] <> 0 
  OR [OutstandingRecpt91to120] <> 0
  OR [OutstandingRecpt121To180] <> 0 
  OR [OutstandingRecpt181To365] <> 0 
  OR [OutstandingRecptMore365] <> 0

SELECT  Provider,
  OutstandingRecptUpTo30,
  OutstandingRecpt31To90,
  OutstandingRecpt91To120,
  OutstandingRecpt121To180,
  OutstandingRecpt181To365,
  OutstandingRecptMore365,
  OutstandingRecptTotal,
  Error
FROM #BatchFINSTAT0025a
ORDER BY [Provider]



-- tidy up
--drop table #IRD
--drop table #Exp
GO
