CREATE PROCEDURE [dbo].[cscp_FINSTAT0025b] @UserID VARCHAR(255), @DueDate VARCHAR(10)
AS

/*
  RH [Openwork] 24 Jan 2007
  Selected Finstat procs rewritten to improve performance
  Including 
    - moved logic for cscf_CalcMarginPercent UDF into proc rather than function call
    - IRD determination pulled into temp table rather than subselect
    - logic for each component part of calculated figures broken out to make it more readable
    - bizarre structure of select distinct ... with subqueries removed


  RH [Openwork] 19 Jan 2007
  BI-182 Aging bands expanded ref Paul Atkinson

  RH 17 Jan 2007
  Rework of original Finstat procedure for performance

  Figures returned by this version differ from original due to commisson records
  where sum(FixedAmount) is zero, resulting in a null margin.  This version still includes the +ve amount
  in the 'Franchise Commission' column, the original excludes it.
  see TPR3644 re data cleanup needed
  
  RH 18 Nov 2007
  Added call to proc owp_FinstatFixExpSign to determine sign based on expectation type and status

  AH 22 Sep 2008
  Create temporary table, final select query and remove final drop tables, to enable running of batchfinstat0001b

*/


set nocount on


--IF OBJECT_ID('tempdb..#IRD') IS NOT NULL
--   DROP TABLE #IRD
--IF OBJECT_ID('tempdb..#Exp') IS NOT NULL
--   DROP TABLE #Exp


--1. Validate @DueDate
IF ISDATE(@DueDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Type'
      , NULL AS 'Type of DA'
      , NULL AS 'OutstandingRecptUpTo30'
      , NULL AS 'OutstandingRecpt31to90'
      , NULL AS 'OutstandingRecpt91to120'
      , NULL AS 'OutstandingRecpt121to180'
      , NULL AS 'OutstandingRecpt181to365'
      , NULL AS 'OutstandingRecptMore365'
      , NULL AS 'OutstandingRecptTotal'
      , 'Invalid Due Date Entered. Please enter it in the format dd/mm/yyyy' AS [Error]
   RETURN 0
END

--2. Convert input date into DateTime
DECLARE @CD DATETIME
SET @CD = CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME)


-- Calculate Income Recognition Date for each transaction/type combination
create table #IRD 
  (TransactionID  int, 
  Type    tinyint, 
  IRD     datetime,
  Primary Key (TransactionID,Type)
  )

insert #IRD
select  TransactionID,
  Type,
  min(CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME))
from  mstt_expectation
where TransactionID is not null
  and Type is not null
group by TransactionID,
  Type



-- Table to store calculated data for each expectation
create table #Exp (
  ExpectationID int,
  TransactionID int,
  PolicyID  int,
  AgentCode varchar(7) collate LATIN1_GENERAL_CI_AS,
  Type    tinyint,
  DisplayType tinyint,
  Status    tinyint,
  ProviderCode  varchar(10) collate LATIN1_GENERAL_CI_AS,
  Amount_Due  decimal(15,2),
  Amount_Rec  decimal(15,2),
  Date_Due  datetime,
  Date_Recv datetime,
  DateDueDiff varchar(8) collate LATIN1_GENERAL_CI_AS,
  IRD   datetime
  )


insert #Exp
Select  e.ID,
  e.TransactionID,
  pt.PolicyID,
  pt.AgentCode,
  e.Type,
  CASE e.Type
    WHEN 1 THEN 1 -- IC
    WHEN 17 THEN 1 -- IC adjustment (treat as negative below)
    WHEN 4 THEN 4 -- RC
    WHEN 18 THEN 4 -- RC adjustment (treat as negative below)
    WHEN 10 THEN 10 -- Trail
    WHEN 19 THEN 10 -- Trail adjustment (treat as negative below)
  END , -- Display Type
  e.Status,
  e.COMP_CODE,  -- provider code
  e.Amount_Due, -- Amount_Due
--  CASE
--    WHEN e.Type in (2,15,16,17,18,19) THEN COALESCE(e.Amount_Due,0) * (-1)
--    ELSE COALESCE(e.Amount_Due,0)
--  END,  -- Amount_Due
  CASE 
    WHEN e.Type in (2,15,16,17,18,19) THEN COALESCE(e.Amount_Rec,0) * (-1)
    ELSE COALESCE(e.Amount_Rec,0)
  END,  -- Amount_Recv
  CAST(CONVERT(NVARCHAR, e.Date_Due, 112) AS DATETIME),
  CAST(CONVERT(NVARCHAR, e.Date_Recv, 112) AS DATETIME),  -- convert to "whole day" 
  CASE
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) < 31
               THEN 'UpTo30'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 31 and 90
               THEN '31to90'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 91 and 120
               THEN '91to120'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 121 and 180
               THEN '121to180'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 181 and 365
               THEN '181to365'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) > 365
               THEN 'More365'
  else '???'
  END AS DateDueDiff,
  i.IRD -- IRD
from  mstt_Expectation e
  inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
  INNER JOIN mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork
  left outer join #IRD i on e.transactionID = i.TransactionID and e.Type = i.Type
where e.Type not IN (5, 6)
  and a.CompanyCode = 10002 -- Openwork
  AND (CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME) <= @CD
          OR (CAST(CONVERT(NVARCHAR, e.DATE_RECV, 112) AS DATETIME) <= @CD) 
      AND e.DATE_RECV IS NOT NULL)

exec owp_FinstatFixExpSign

--Extract report data into a temp table
IF OBJECT_ID('tempdb..#BatchFINSTAT0025b') IS NULL
begin

Create table #BatchFINSTAT0025b
  (
  Type            tinyint,
  [Type of DA]        varchar(255),
  OutstandingRecptUpTo30    decimal(15,2),
  OutstandingRecpt31To90    decimal(15,2),
  OutstandingRecpt91To120   decimal(15,2),
  OutstandingRecpt121To180  decimal(15,2),
  OutstandingRecpt181To365  decimal(15,2),
  OutstandingRecptMore365   decimal(15,2),
  OutstandingRecptTotal   decimal(15,2),
  Error           varchar(6)
  ) 
end
else
  Truncate table #batchFINSTAT0025b


INSERT into #BatchFINSTAT0025b
select * from (
SELECT 
      Type AS 'Type'
   ,  ISNULL(Codes.Description, 'Unknown') AS 'Type of DA'
   ,  SUM(CASE WHEN DateDueDiff <> 'UpTo30' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) AS 'OutstandingRecptUpTo30'
   ,  SUM(CASE WHEN DateDueDiff <> '31TO90' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) AS 'OutstandingRecpt31to90'
   ,  SUM(CASE WHEN DateDueDiff <> '91TO120' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) as 'OutstandingRecpt91to120'
   ,  SUM(CASE WHEN DateDueDiff <> '121TO180' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) AS 'OutstandingRecpt121to180'
   ,  SUM(CASE WHEN DateDueDiff <> '181TO365' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) AS 'OutstandingRecpt181to365'
   ,  SUM(CASE WHEN DateDueDiff <> 'More365' THEN 0 ELSE
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  END) AS 'OutstandingRecptMore365'
   ,  SUM(
    CASE  
      WHEN (IRD <= @CD AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
    +
    CASE  
      WHEN (IRD <= @CD AND Date_Due <= @CD AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) 
                    OR Date_Recv IS NULL))
        THEN Amount_Due
      ELSE 0
    END
    -
    CASE
      WHEN (Date_Due IS NOT NULL AND Date_Recv <= @CD)
        THEN Amount_Rec
      ELSE 0
    END
  ) AS 'OutstandingRecptTotal'
   ,  NULL AS [Error]

FROM  #Exp
  LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON #Exp.Type = Codes.Code AND ColumnName = 'CommissionType'
GROUP BY Type,
  Codes.Description) a
WHERE   [OutstandingRecptUpTo30] <> 0 
  OR [OutstandingRecpt31to90] <> 0 
  OR [OutstandingRecpt91to120] <> 0
  OR [OutstandingRecpt121To180] <> 0 
  OR [OutstandingRecpt181To365] <> 0 
  OR [OutstandingRecptMore365] <> 0

--Select statement for batchFINSTAT
SELECT  Type,
  [Type of DA],
  OutstandingRecptUpTo30,
  OutstandingRecpt31To90,
  OutstandingRecpt91To120,
  OutstandingRecpt121To180,
  OutstandingRecpt181To365,
  OutstandingRecptMore365,
  OutstandingRecptTotal,
  Error
FROM #BatchFINSTAT0025b
ORDER BY [Type], [Type of DA]



-- tidy up
--drop table #IRD
--drop table #Exp
GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0026a]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_FINSTAT0026a] @UserID VARCHAR(255), @DueDate VARCHAR(10), @Filter CHAR(1)
AS

/*
  RH [Openwork] 24 Jan 2007
  Selected Finstat procs rewritten to improve performance
  Including 
    - moved logic for cscf_CalcMarginPercent UDF into proc rather than function call
    - IRD determination pulled into temp table rather than subselect
    - logic for each component part of calculated figures broken out to make it more readable
    - bizarre structure of select distinct ... with subqueries removed


  RH [Openwork] 19 Jan 2007
  BI-182 Aging bands expanded ref Paul Atkinson

  RH 18 Nov 2007
  Added logic to determine sign based on expectation type and status

  KK 5 Dec 2007
  Amended to use mstt_AgentPayments.AGT_TYPE instead of mstt_AgentPayments.PaymentType

  AH 22 Sep 2008
  Create temporary table, final select query and remove final drop tables, to enable running of batchfinstat0001b

*/



--IF OBJECT_ID('tempdb..#IRD') IS NOT NULL
--   DROP TABLE #IRD
--IF OBJECT_ID('tempdb..#Comms') IS NOT NULL
--   DROP TABLE #Comms
--IF OBJECT_ID('tempdb..#Exp') IS NOT NULL
--   DROP TABLE #Exp




--1. Validate @DueDate
IF ISDATE(@DueDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Franchise Code'
      , NULL AS 'Franchise'
      , NULL AS 'OutstandingPaymentUpTo30'
      , NULL AS 'OutstandingPayment31to90'
      , NULL AS 'OutstandingPayment91to120'
      , NULL AS 'OutstandingPayment121to180'
      , NULL AS 'OutstandingPayment181to365'
      , NULL AS 'OutstandingPaymentMore365'
      , NULL AS 'OutstandingPaymentTotal'
      , 'Invalid Due Date Entered. Please enter it in the format dd/mm/yyyy' AS [Error]
   RETURN 0
END

--2. Convert input date into DateTime
DECLARE @CD DATETIME
SET @CD = CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME)


-- Calculate Income Recognition Date for each transaction/type combination
create table #IRD 
  (TransactionID  int, 
  Type    tinyint, 
  IRD     datetime,
  Primary Key (TransactionID,Type)
  )

insert #IRD
select  TransactionID,
  Type,
  min(CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME))
from  mstt_expectation
where TransactionID is not null
  and Type is not null
group by TransactionID,
  Type



-- Calculate Margin percent for each Transaction
create table #Comms 
  (
  TransactionID   int, 
  NetAmount   decimal(15,2), 
  TotalAmount   decimal(15,2), 
  Margin_Pct  float,
  Primary Key (TransactionID)
  )


insert #Comms
select  TransactionID,
  sum(case GrossOrNet
    when 'N' then FixedAmount
    else 0
  end),
  sum(FixedAmount),
  case 
    when coalesce(sum(FixedAmount),0)<>0 then
      sum(case GrossOrNet when 'N' then FixedAmount else 0 end)
      /
      sum(FixedAmount)
    else null -- should this be null or 0 ?
    -- from UDF comments
    -- Set Margin % = 0 (i.e. Commission % = 100)
    -- Set Margin % = NULL (i.e. Margin % = 0; Commission % = 0)
  end
from  mstt_Commissions
where CommissionType = 1
group by TransactionID


-- Table to store calculated data for each expectation
create table #Exp (
  ExpectationID int,
  TransactionID int,
  Type    tinyint,
  Amount_Due  decimal(15,2),
  Amount_Rec  decimal(15,2),
  Date_Due  datetime,
  Date_Recv datetime,
  Margin_Pct  float,
  Commission_Due  decimal(15,2),
  Commission_Rec  decimal(15,2),
  DateDueDiff varchar(8),
  IRD   datetime
  )


insert #Exp
SELECT
      e.ID,
      e.TransactionID,
      e.Type,
      CASE when e.Type in (1,4,10) then 1 when e.Type in (17,18,19) and e.status = 1 then 1 else -1 end
  * coalesce(e.Amount_Due,0) AS Amount_Due,
      CASE when e.Type not in (1,4,10) then -1 else 1 end
  * coalesce(e.Amount_Rec,0) AS Amount_Rec,
      CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME) AS Date_Due,
      CAST(CONVERT(NVARCHAR, e.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
      c.Margin_Pct AS Margin_Pct,

  COALESCE(
  CASE WHEN e.Type in (1,4,10) THEN 1 WHEN e.Type in (17,18,19) and e.status = 1 THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,2,17) THEN (convert(decimal(15,2),e.Amount_Due) - convert(decimal(15,2),e.Amount_Due * c.Margin_Pct)) ELSE e.Amount_Due END
  ,0) , -- Commission Due

  COALESCE(
  CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,2,17) THEN (convert(decimal(15,2),e.Amount_Rec) - convert(decimal(15,2),e.Amount_Rec * c.Margin_Pct)) ELSE e.Amount_Rec END
  ,0) , -- Commission Recv

      CASE
    WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) < 31 THEN 'UpTo30'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 31 and 90 THEN '31to90'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 91 and 120 THEN '91to120'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 121 and 180 THEN '121to180'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 181 and 365 THEN '181to365'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) > 365 THEN 'More365'
      END AS DateDueDiff,
  i.IRD -- IRD

from  mstt_Expectation e
  inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
  INNER JOIN mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork
  left outer join #IRD i on e.transactionID = i.TransactionID and e.Type = i.Type
  left outer join #Comms c on e.transactionID = c.TransactionID
where e.Type IN (1, 2, 4, 10, 15, 16, 17, 18, 19)
  and a.CompanyCode = 10002 -- Openwork
    AND (CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME) <= @CD    
         OR (CAST(CONVERT(NVARCHAR, e.DATE_RECV, 112) AS DATETIME) <= @CD   
             AND e.DATE_RECV IS NOT NULL))          

--Extract report datta into a temp table
IF OBJECT_ID('tempdb..#FINSTAT0026a') IS NULL
Begin
  Create table #FINSTAT0026a
  (
  FranchiseCode       varchar(15),
  Franchise         varchar(255),
  OutstandingPaymentUpTo30  decimal(15,2),
  OutstandingPayment31To90  decimal(15,2),
  OutstandingPayment91To120 decimal(15,2),
  OutstandingPayment121To180  decimal(15,2),
  OutstandingPayment181To365  decimal(15,2),
  OutstandingPaymentMore365 decimal(15,2),
  OutstandingPaymentTotal   decimal(15,2),
  Rep             varchar(1),
  Error           varchar(6)
  )
End
Else
  Truncate table #FINSTAT0026a

INSERT into #FINSTAT0026a
select
  CASE 
    WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN Agents_fr.Code
    ELSE AgentsMain.Code 
  END AS 'Franchise Code',
  CASE 
    WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown'))
    ELSE RTRIM(ISNULL(AgentsMain.DESCN, 'Unknown'))
  END AS 'Franchise',
  sum(PaymentUpTo30) AS 'OutstandingPaymentUpTo30',
  sum(Payment31To90) AS 'OutstandingPayment31To90',
  sum(Payment91To120) AS 'OutstandingPayment91To120',
  sum(Payment121To180) AS 'OutstandingPayment121To180',
  sum(Payment181To365) AS 'OutstandingPayment181To365',
  sum(PaymentMore365) AS 'OutstandingPaymentMore365',
  sum(PaymentTotal) AS 'OutstandingPaymentTotal',
----anne
  case when @filter = 'A' then 1
  when @filter = 'C' then 2
  when @filter = 'D' then 3
  end as Rep,
----anne
  null AS 'Error'
from  (
  SELECT
    AgentsMain.Firm as 'Firm',
    AgentsMain.Code as 'Code',
  
    SUM(coalesce(case when DateDueDiff = 'UpTo30' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'PaymentUpTo30',
  
    SUM(coalesce(case when DateDueDiff = '31To90' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'Payment31To90',
  
    SUM(coalesce(case when DateDueDiff = '91To120' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'Payment91To120',
  
    SUM(coalesce(case when DateDueDiff = '121To180' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'Payment121To180',
  
    SUM(coalesce(case when DateDueDiff = '181To365' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'Payment181To365',
  
    SUM(coalesce(case when DateDueDiff = 'More365' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'PaymentMore365',
  
    SUM(coalesce(
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    ,0)) * (-1) AS 'PaymentTotal',
  ----anne
    case when @filter = 'A' then 1
    when @filter = 'C' then 2
    when @filter = 'D' then 3
    end as Rep
  ----anne
  
  FROM  
    mstt_Agents AgentsMain 
    INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.AgentCode = AgentsMain.CODE
    INNER JOIN #Exp e ON PolicyTransactions1.ID = e.TransactionID
  group by 
    AgentsMain.Firm ,
    AgentsMain.Code
  

UNION ALL
  
  SELECT
    AgentsMain.Firm as 'Firm',
    AgentsMain.Code as 'Code',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) <=30 
          -- RH 22 Jan we think this should be changed to read 0 <= x <= 30 after discussion with Paul Atkinson.  Will result in discrepancies compared to original, so leaving it as was for performance work
          -- to ease testing.  Raise the point for clarification and future fix.
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'PaymentUpTo30',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 31 and 90
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'Payment31to90',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 91 and 120
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'Payment91to120',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 121 and 180
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'Payment121to180',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 181 and 365
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'Payment181to365',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) > 365
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'PaymentMore365',
  
    SUM(coalesce(convert(decimal(15,2),AgentPayments.AMOUNT),0)) AS 'PaymentTotal',
    ----anne
    case when @filter = 'A' then 1
    when @filter = 'C' then 2
    when @filter = 'D' then 3
    end as Rep
    ----anne

  FROM  
    mstt_Agents AgentsMain 
    INNER JOIN mstt_AgentPayments AgentPayments on AgentsMain.CODE = AgentPayments.AGENT_CODE
    INNER JOIN mstt_PaymentsPending PaymentsPending on PaymentsPending.ID = AgentPayments.AGMID
  
  WHERE   RTRIM(AgentsMain.descn) <> 'Openwork' --Agent Code is NOT OPWK
    AND AgentPayments.AGT_TYPE IN (1, 2, 4, 10, 15, 16, 17, 18, 19)
    AND AgentPayments.EXPORT_DATE IS NOT NULL
    and CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) <= @CD
  group by 
    AgentsMain.Firm ,
    AgentsMain.Code
  
UNION ALL
  
  SELECT
    AgentsMain.Firm as 'Firm',
    AgentsMain.Code as 'Code',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 0 and 30
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 0 and 30
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) between 0 and 30))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'PaymentUpTo30',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 31 and 90
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 31 and 90
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) between 31 and 90))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'Payment31To90',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 91 and 120
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 91 and 120
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) between 91 and 120))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'Payment91To120',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 121 and 180
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 121 and 180
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) between 121 and 180))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'Payment121to180',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 181 and 365
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 181 and 365
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) between 181 and 365))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'Payment181to365',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD)>365
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) >365
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) >365))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'PaymentMore365',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
                AND CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) <= @CD 
                AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
                    OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
                AND (CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) <= @CD
                    OR (PaymentsPending.PaymentDueDate IS NULL
                      AND CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME) <= @CD))
                AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
                    OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'PaymentTotal',

    ----anne
    case when @filter = 'A' then 1
    when @filter = 'C' then 2
    when @filter = 'D' then 3
    end as Rep
    ----anne
  
  FROM  
    mstt_Agents AgentsMain 
    inner JOIN mstt_PaymentsPending PaymentsPending on AgentsMain.CODE = PaymentsPending.AGENT_CODE
          LEFT JOIN mstt_AgentPayments AgentPayments ON PaymentsPending.ID = AgentPayments.AGMID
  
  WHERE   RTRIM(AgentsMain.descn) <> 'Openwork' --Agent Code is NOT OPWK
  
  group by 
    AgentsMain.Firm ,
    AgentsMain.Code

  ) a
  inner join mstt_Agents AgentsMain on a.Code = AgentsMain.Code
  left join mstt_Agents Agents_fr on a.Firm = Agents_fr.Code

group by 
  CASE 
    WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN Agents_fr.Code
    ELSE AgentsMain.Code 
  END,

  CASE 
    WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown'))
    ELSE RTRIM(ISNULL(AgentsMain.DESCN, 'Unknown'))
  END
HAVING ((@Filter = 'A' AND ISNULL(SUM(PaymentTotal), 0.00) <> 0.00) OR
        (@Filter = 'D' AND ISNULL(SUM(PaymentTotal), 0.00) > 0.00) OR
        (@Filter = 'C' AND ISNULL(SUM(PaymentTotal), 0.00) < 0.00)
       )

SELECT  FranchiseCode,
  Franchise,
  OutstandingPaymentUpTo30,
  OutstandingPayment31To90,
  OutstandingPayment91To120,
  OutstandingPayment121To180,
  OutstandingPayment181To365,
  OutstandingPaymentMore365,
  OutstandingPaymentTotal,
  Error
from #FINSTAT0026a
order by 1,2
GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0026b]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_FINSTAT0026b] @UserID VARCHAR(255), @DueDate VARCHAR(10), @Filter CHAR(1)
AS

/*
  RH [Openwork] 24 Jan 2007
  Selected Finstat procs rewritten to improve performance
  Including 
    - moved logic for cscf_CalcMarginPercent UDF into proc rather than function call
    - IRD determination pulled into temp table rather than subselect
    - logic for each component part of calculated figures broken out to make it more readable
    - bizarre structure of select distinct ... with subqueries removed


  RH [Openwork] 19 Jan 2007
  BI-182 Aging bands expanded ref Paul Atkinson

  
  RH 18 Nov 2007
  Added logic to determine sign based on expectation type and status

  KK 5 Dec 2007
  Amended to use mstt_AgentPayments.AGT_TYPE instead of mstt_AgentPayments.PaymentType

  AH 22 Sep 2008
  Create temporary table, final select query and remove final drop tables, to enable running of batchfinstat0026b

*/


--IF OBJECT_ID('tempdb..#IRD') IS NOT NULL
--   DROP TABLE #IRD
--IF OBJECT_ID('tempdb..#Comms') IS NOT NULL
--   DROP TABLE #Comms
--IF OBJECT_ID('tempdb..#Exp') IS NOT NULL
--   DROP TABLE #Exp
--IF OBJECT_ID('tempdb..#Agents1') IS NOT NULL
--   DROP TABLE #Agents1
--IF OBJECT_ID('tempdb..#Agents') IS NOT NULL
--   DROP TABLE #Agents



--1. Validate @DueDate
IF ISDATE(@DueDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Type of Commission'
      , NULL AS 'OutstandingPaymentUpTo30'
      , NULL AS 'OutstandingPayment31to90'
      , NULL AS 'OutstandingPayment91to120'
      , NULL AS 'OutstandingPayment121to180'
      , NULL AS 'OutstandingPayment181to365'
      , NULL AS 'OutstandingPaymentMore365'
      , NULL AS 'OutstandingPaymentTotal'
      , 'Invalid Due Date Entered. Please enter it in the format dd/mm/yyyy' AS [Error]
   RETURN 0
END

--2. Convert input date into DateTime
DECLARE @CD DATETIME
SET @CD = CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME)


-- Calculate Income Recognition Date for each transaction/type combination
create table #IRD 
  (TransactionID  int, 
  Type    tinyint, 
  IRD     datetime,
  Primary Key (TransactionID,Type)
  )

insert #IRD
select  TransactionID,
  Type,
  min(CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME))
from  mstt_expectation
where TransactionID is not null
  and Type is not null
group by TransactionID,
  Type



-- Calculate Margin percent for each Transaction
create table #Comms 
  (
  TransactionID   int, 
  NetAmount   decimal(15,2), 
  TotalAmount   decimal(15,2), 
  Margin_Pct  float,
  Primary Key (TransactionID)
  )


insert #Comms
select  TransactionID,
  sum(case GrossOrNet
    when 'N' then FixedAmount
    else 0
  end),
  sum(FixedAmount),
  case 
    when coalesce(sum(FixedAmount),0)<>0 then
      sum(case GrossOrNet when 'N' then FixedAmount else 0 end)
      /
      sum(FixedAmount)
    else null -- should this be null or 0 ?
    -- from UDF comments
    -- Set Margin % = 0 (i.e. Commission % = 100)
    -- Set Margin % = NULL (i.e. Margin % = 0; Commission % = 0)
  end
from  mstt_Commissions
where CommissionType = 1
group by TransactionID


-- Table to store calculated data for each expectation
create table #Exp (
  ExpectationID int,
  TransactionID int,
  Type    tinyint,
  Amount_Due  decimal(15,2),
  Amount_Rec  decimal(15,2),
  Date_Due  datetime,
  Date_Recv datetime,
  Margin_Pct  float,
  Commission_Due  decimal(15,2),
  Commission_Rec  decimal(15,2),
  DateDueDiff varchar(8),
  IRD   datetime
  )


insert #Exp
SELECT
      e.ID,
      e.TransactionID,
      e.Type,
      CASE when e.Type in (1,4,10) then 1 when e.Type in (17,18,19) and e.status = 1 then 1 else -1 end
  * coalesce(e.Amount_Due,0) AS Amount_Due,
      CASE when e.Type in (1,4,10) then 1 else -1 end
  * coalesce(e.Amount_Rec,0) AS Amount_Rec,
      CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME) AS Date_Due,
      CAST(CONVERT(NVARCHAR, e.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
      c.Margin_Pct AS Margin_Pct,

  COALESCE(
  CASE WHEN e.Type in (1,4,10) THEN 1 WHEN e.Type in (17,18,19) and e.status = 1 THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,2,17) THEN (convert(decimal(15,2),e.Amount_Due) - convert(decimal(15,2),e.Amount_Due * c.Margin_Pct)) ELSE e.Amount_Due END
  ,0) , -- Commission Due

  COALESCE(
  CASE WHEN e.Type in (1,4,10) THEN 1 ELSE -1 END 
  * CASE WHEN e.Type in (1,2,17) THEN (convert(decimal(15,2),e.Amount_Rec) - convert(decimal(15,2),e.Amount_Rec * c.Margin_Pct)) ELSE e.Amount_Rec END
  ,0) , -- Commission Recv

      CASE
    WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) < 31 THEN 'UpTo30'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 31 and 90 THEN '31to90'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 91 and 120 THEN '91to120'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 121 and 180 THEN '121to180'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) between 181 and 365 THEN '181to365'
          WHEN DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME), @CD) > 365 THEN 'More365'
      END AS DateDueDiff,
  i.IRD -- IRD

from  mstt_Expectation e
  inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
  INNER JOIN mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork
  left outer join #IRD i on e.transactionID = i.TransactionID and e.Type = i.Type
  left outer join #Comms c on e.transactionID = c.TransactionID
where e.Type IN (1, 2, 4, 10, 15, 16, 17, 18, 19)
  and a.CompanyCode = 10002 -- Openwork
    AND (CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME) <= @CD    
         OR (CAST(CONVERT(NVARCHAR, e.DATE_RECV, 112) AS DATETIME) <= @CD   
             AND e.DATE_RECV IS NOT NULL))          


-- stores agent codes (may be dupes)
CREATE TABLE #Agents1 (
  Code varchar(7)  collate LATIN1_GENERAL_CI_AS
  )

-- deduped
CREATE TABLE #Agents (
  Code varchar(7)  collate LATIN1_GENERAL_CI_AS
  )


-- GET AGENTS AND FRANCHISES WHERE FILTER IS MATCHED
INSERT #Agents1
select 
  [Franchise Code]
from  (

  SELECT
    CASE 
      WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN AgentsMain.Firm
      ELSE AgentsMain.Code 
    END AS 'Franchise Code',
  
    SUM(coalesce(
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    ,0)) * (-1) AS 'PaymentTotal'
  
  FROM  
    mstt_Agents AgentsMain 
    INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.AgentCode = AgentsMain.CODE
    INNER JOIN #Exp e ON PolicyTransactions1.ID = e.TransactionID
  group by 
    CASE 
      WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN AgentsMain.Firm
      ELSE AgentsMain.Code 
    END 

UNION ALL
  
  SELECT
    CASE 
      WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN AgentsMain.Firm
      ELSE AgentsMain.Code 
    END AS 'Franchise Code',
    
    SUM(coalesce(convert(decimal(15,2),AgentPayments.AMOUNT),0)) AS 'PaymentTotal'
  FROM  
    mstt_Agents AgentsMain 
    INNER JOIN mstt_AgentPayments AgentPayments on AgentsMain.CODE = AgentPayments.AGENT_CODE
    INNER JOIN mstt_PaymentsPending PaymentsPending on PaymentsPending.ID = AgentPayments.AGMID
  
  WHERE   RTRIM(AgentsMain.descn) <> 'Openwork' --Agent Code is NOT OPWK
    AND AgentPayments.AGT_TYPE IN (1, 2, 4, 10, 15, 16, 17, 18, 19)
    AND AgentPayments.EXPORT_DATE IS NOT NULL
    and CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) <= @CD
  
  group by 
    CASE 
      WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN AgentsMain.Firm
      ELSE AgentsMain.Code 
    END
  
UNION ALL
  
  SELECT
    CASE 
      WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN AgentsMain.Firm
      ELSE AgentsMain.Code 
    END AS 'Franchise Code',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
                AND CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) <= @CD 
                AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
                    OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
                AND (CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) <= @CD
                    OR (PaymentsPending.PaymentDueDate IS NULL
                      AND CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME) <= @CD))
                AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
                    OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'PaymentTotal'
  
  FROM  
    mstt_Agents AgentsMain 
    inner JOIN mstt_PaymentsPending PaymentsPending on AgentsMain.CODE = PaymentsPending.AGENT_CODE
          LEFT JOIN mstt_AgentPayments AgentPayments ON PaymentsPending.ID = AgentPayments.AGMID
  
  WHERE   RTRIM(AgentsMain.descn) <> 'Openwork' --Agent Code is NOT OPWK
  
  group by 
    CASE 
      WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN AgentsMain.Firm
      ELSE AgentsMain.Code 
    END
  ) a

group by a.[Franchise Code]

HAVING ((@Filter = 'A' AND ISNULL(SUM(PaymentTotal), 0.00) <> 0.00) OR
        (@Filter = 'D' AND ISNULL(SUM(PaymentTotal), 0.00) > 0.00) OR
        (@Filter = 'C' AND ISNULL(SUM(PaymentTotal), 0.00) < 0.00)
       )

--5.1 add the agents which are part of the extracted franchises
INSERT INTO #Agents1
SELECT Agents.Code 
FROM #Agents1 Agents_fr
LEFT JOIN mstt_Agents Agents ON Agents.Firm = Agents_fr.Code


INSERT INTO #Agents
SELECT distinct #Agents1.Code 
FROM #Agents1


--Extract report data into a temp table
IF OBJECT_ID('tempdb..#FINSTAT0026b') IS NULL
Begin
  Create table #FINSTAT0026b
  (
  [Type of Commission]    varchar(50),
  CommCode          varchar(50),
  OutstandingPaymentUpTo30  decimal(15,2),
  OutstandingPayment31To90  decimal(15,2),
  OutstandingPayment91To120 decimal(15,2),
  OutstandingPayment121To180  decimal(15,2),
  OutstandingPayment181To365  decimal(15,2),
  OutstandingPaymentMore365 decimal(15,2),
  OutstandingPaymentTotal   decimal(15,2),
  Error           varchar(6)
  )
End
Else
  Truncate table #FINSTAT0026b


INSERT into #FINSTAT0026b
select
  MIWarehouseCodesAndDescriptions.Description AS 'Type of Commission',
  convert(int,MIWarehouseCodesAndDescriptions.Code) AS 'CommCode', --Used for ordering of fields
  sum(PaymentUpTo30) AS 'OutstandingPaymentUpTo30',
  sum(Payment31To90) AS 'OutstandingPayment31To90',
  sum(Payment91To120) AS 'OutstandingPayment91To120',
  sum(Payment121To180) AS 'OutstandingPayment121To180',
  sum(Payment181To365) AS 'OutstandingPayment181To365',
  sum(PaymentMore365) AS 'OutstandingPaymentMore365',
  sum(PaymentTotal) AS 'OutstandingPaymentTotal',
  null AS 'Error'
from  (

--select 'Start part 1',getdate()
  SELECT
    e.Type AS 'CommCode',
  
    SUM(coalesce(case when DateDueDiff = 'UpTo30' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'PaymentUpTo30',
  
    SUM(coalesce(case when DateDueDiff = '31To90' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'Payment31To90',
  
    SUM(coalesce(case when DateDueDiff = '91To120' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'Payment91To120',
  
    SUM(coalesce(case when DateDueDiff = '121To180' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'Payment121To180',

  
    SUM(coalesce(case when DateDueDiff = '181To365' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'Payment181To365',
  
    SUM(coalesce(case when DateDueDiff = 'More365' then
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 
      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    else 0
    end
    ,0)) * (-1) AS 'PaymentMore365',
  
    SUM(coalesce(
      case  when  IRD <= @CD 
          AND Date_Recv <= @CD 
        then  Commission_Rec 
        else  0 

      end
      +
      case  when  IRD <= @CD 
          AND Date_Due <= @CD
                  AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL) 
        then  Commission_Due 
        else  0 
      end
    ,0)) * (-1) AS 'PaymentTotal'
  
  FROM  
    mstt_PolicyTransactions PolicyTransactions1
    INNER JOIN #Exp e ON PolicyTransactions1.ID = e.TransactionID

  WHERE PolicyTransactions1.AgentCode in (select code from #Agents)

  group by 
    e.Type
  

UNION ALL
--select 'Start part 2',getdate() 
  SELECT
    AgentPayments.AGT_TYPE AS 'CommCode',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) <=30 
          -- RH 22 Jan we think this should be changed to read 0 <= x <= 30 after discussion with Paul Atkinson.  Will result in discrepancies compared to original, so leaving it as was for performance work
          -- to ease testing.  Raise the point for clarification and future fix.
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'PaymentUpTo30',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 31 and 90
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'Payment31to90',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 91 and 120
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'Payment91to120',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 121 and 180
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'Payment121to180',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 181 and 365
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'Payment181to365',
  
    SUM(coalesce(case when  DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) > 365
        then  convert(decimal(15,2),AgentPayments.AMOUNT)
        else  0 
    end,0)) AS 'PaymentMore365',
  
    SUM(coalesce(convert(decimal(15,2),AgentPayments.AMOUNT),0)) AS 'PaymentTotal'
  FROM  
    -- #Agents AgentsMain 
    --INNER JOIN mstt_AgentPayments AgentPayments on AgentsMain.CODE = AgentPayments.AGENT_CODE
    mstt_AgentPayments AgentPayments
    INNER JOIN mstt_PaymentsPending PaymentsPending on PaymentsPending.ID = AgentPayments.AGMID
    INNER JOIN mstt_Agents Agents on Agents.CODE = AgentPayments.AGENT_CODE
  
  WHERE   AgentPayments.AGT_TYPE IN (1, 2, 4, 10, 15, 16, 17, 18, 19)
    AND AgentPayments.EXPORT_DATE IS NOT NULL
    and AgentPayments.AGENT_CODE in (select code from #Agents)
    and RTRIM(Agents.descn) <> 'Openwork'
    and CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) <= @CD
  group by 
    AgentPayments.AGT_TYPE
  
UNION ALL
--select 'Start part 3',getdate()
  SELECT
    PaymentsPending.CommissionType,
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 0 and 30
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 0 and 30
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) between 0 and 30))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'PaymentUpTo30',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 31 and 90
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 31 and 90
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) between 31 and 90))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'Payment31To90',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 91 and 120
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 91 and 120
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) between 91 and 120))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'Payment91To120',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 121 and 180
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 121 and 180
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) between 121 and 180))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'Payment121to180',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 181 and 365
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) between 181 and 365
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) between 181 and 365))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'Payment181to365',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
        AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD)>365
        AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
          OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
          AND (DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), @CD) >365
              OR (PaymentsPending.PaymentDueDate IS NULL
                AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME), @CD) >365))
          AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
              OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'PaymentMore365',
  
    SUM(coalesce(
    case  when  
        PaymentsPending.CommissionType = 8
                AND CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) <= @CD 
                AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
                    OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    +
    case  when  
        PaymentsPending.CommissionType = 20
                AND (CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) <= @CD
                    OR (PaymentsPending.PaymentDueDate IS NULL
                      AND CAST(CONVERT(NVARCHAR, PaymentsPending.CreatedDate, 112) AS DATETIME) <= @CD))
                AND (CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) > @CD
                    OR AgentPayments.EXPORT_DATE IS NULL)
      then  convert(decimal(15,2),PaymentsPending.AMOUNT)
      else  0 
    end
    ,0)) * (-1) AS 'PaymentTotal'
  
  FROM  
    mstt_PaymentsPending PaymentsPending 
          LEFT JOIN mstt_AgentPayments AgentPayments ON PaymentsPending.ID = AgentPayments.AGMID
  
  WHERE   PaymentsPending.CommissionType in (8,20)
    AND PaymentsPending.AGENT_CODE in (select code from #Agents)

  group by 
    PaymentsPending.CommissionType
--select 'Done',getdate()

  ) a
  inner join msit_MIWarehouseCodesAndDescriptions MIWarehouseCodesAndDescriptions 
    on convert(int,MIWarehouseCodesAndDescriptions.Code) = a.CommCode
      and MIWarehouseCodesAndDescriptions.ColumnName = 'CommissionType'

group by 
  MIWarehouseCodesAndDescriptions.Description,
  convert(int,MIWarehouseCodesAndDescriptions.Code)

having  
  sum(PaymentUpTo30) <> 0
  or sum(Payment31To90) <> 0
  or sum(Payment91To120) <> 0
  or sum(Payment121To180) <> 0
  or sum(Payment181To365) <> 0
  or sum(PaymentMore365) <> 0
  or sum(PaymentTotal) <> 0


SELECT [Type of Commission],
  CommCode,
  OutstandingPaymentUpTo30,
  OutstandingPayment31To90,
  OutstandingPayment91To120,
  OutstandingPayment121To180,
  OutstandingPayment181To365,
  OutstandingPaymentMore365,
  OutstandingPaymentTotal,
  Error
FROM #FINSTAT0026b    
order by 2
GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0028]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_FINSTAT0028] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

/*
  RH [Openwork] 24 Jan 2007
  Selected Finstat procs rewritten to improve performance
  Including 
    - moved logic for cscf_CalcMarginPercent UDF into proc rather than function call
    - IRD determination pulled into temp table rather than subselect
    - logic for each component part of calculated figures broken out to make it more readable
    - bizarre structure of select distinct ... with subqueries removed


  
  RH 18 Nov 2007
  Added logic to determine sign based on expectation type and status

  KK 5 Dec 2007
  Amended to use mstt_AgentPayments.AGT_TYPE instead of mstt_AgentPayments.PaymentType

  MC 13 Dec 2007
  Amended to correct processing of adjustments and clawbacks

  AG 5 Sep 2008
  Drop tables removed from end of proc to facilitate running of BatchFINSTAT report (already exist within query)

  AG 7 Nov 2008
  Added "collate database_default" to temp table to stop collation error.
  Replaced commas with colons in section heading to avoid Excel formatting problems.
*/



-- 1. Input date validation
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
   SELECT 
      NULL AS [Section],
      NULL AS [Description],
      NULL AS [Opening],
      NULL AS [Movement],
      NULL AS [Closing],
      NULL AS [PLControlBalance],
      CASE 
         WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
         WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
      END AS [Error]
      RETURN 0
END

-- 2. convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

-- 3. Extract Expectation data into a temp table
--IF OBJECT_ID('tempdb..#FINSTAT0028aExpectation') IS NOT NULL
--   DROP TABLE #FINSTAT0028aExpectation
--IF OBJECT_ID('tempdb..#IRD') IS NOT NULL
--   DROP TABLE #IRD
--IF OBJECT_ID('tempdb..#Comms') IS NOT NULL
--   DROP TABLE #Comms



-- Calculate Income Recognition Date for each transaction/type combination
create table #IRD 
  (TransactionID  int, 
  Type    tinyint, 
  IRD     datetime,
  Primary Key (TransactionID,Type)
  )

insert #IRD
select  TransactionID,
  Type,
  min(CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME))
from  mstt_expectation
where TransactionID is not null
  and Type is not null
group by TransactionID,
  Type



-- Calculate Margin percent for each Transaction
create table #Comms 
  (
  TransactionID   int, 
  NetAmount   decimal(15,2), 
  TotalAmount   decimal(15,2), 
  Margin_Pct  float,
  Primary Key (TransactionID)
  )


insert #Comms
select  TransactionID,
  sum(case GrossOrNet
    when 'N' then FixedAmount
    else 0
  end),
  sum(FixedAmount),
  case 
    when coalesce(sum(FixedAmount),0)<>0 then
      sum(case GrossOrNet when 'N' then FixedAmount else 0 end)
      /
      sum(FixedAmount)
    else null -- should this be null or 0 ?
    -- from UDF comments
    -- Set Margin % = 0 (i.e. Commission % = 100)
    -- Set Margin % = NULL (i.e. Margin % = 0; Commission % = 0)
  end
from  mstt_Commissions
where CommissionType = 1
group by TransactionID


-- Table to store calculated data for each expectation
create table #FINSTAT0028aExpectation (
  ID  int,
  Type    tinyint,
  TransactionID int,
  Amount_Due  decimal(15,2),
  Amount_Rec  decimal(15,2),
  Date_Due  datetime,
  Date_Recv datetime,
  Margin_Pct  float,
  Margin_Due  decimal(15,2),
  Margin_Rec  decimal(15,2),
  Commission_Due  decimal(15,2),
  Commission_Rec  decimal(15,2),
  IRD   datetime
  )

insert #FINSTAT0028aExpectation
Select  e.ID,
  e.Type,
  e.TransactionID,
  case 
    when e.Type in (1,4,10) then 1
    when e.Type in (17,18,19) and e.Status = 1 then 1
    else -1
  end * COALESCE(e.Amount_Due,0),
  COALESCE(e.Amount_Rec,0),
  CAST(CONVERT(NVARCHAR, e.Date_Due, 112) AS DATETIME),
  CAST(CONVERT(NVARCHAR, e.Date_Recv, 112) AS DATETIME),  -- convert to "whole day" 
  c.Margin_Pct, -- Margin Pct
  
  COALESCE(e.Amount_Due
  * case 
    when e.Type in (1,4,10) then 1
    when e.Type in (17,18,19) and e.Status = 1 then 1
    else -1

  end
  * CASE WHEN e.Type in (1,2,17) THEN c.Margin_Pct ELSE 0 END,0) 
  , -- Margin Due

  COALESCE(e.Amount_Rec
  * CASE WHEN e.Type in (1,2,17) THEN c.Margin_Pct ELSE 0 END,0) 
  , -- Margin Recv

  COALESCE( -- need to get rounding right hence line below more complicated than it could be
  case 
    when e.Type in (1,4,10) then 1
    when e.Type in (17,18,19) and e.Status = 1 then 1
    else -1
  end *
  CASE WHEN e.Type in (1,2,17) THEN (convert(decimal(15,2),e.Amount_Due) - convert(decimal(15,2),e.Amount_Due * c.Margin_Pct)) ELSE e.Amount_Due END
  ,0) , -- Commission Due

  COALESCE(
  CASE WHEN e.Type in (1,2,17) THEN (convert(decimal(15,2),e.Amount_Rec) - convert(decimal(15,2),e.Amount_Rec * c.Margin_Pct)) ELSE e.Amount_Rec END
  ,0) , -- Commission Recv
  i.IRD -- IRD
from  mstt_Expectation e
  inner join mstt_PolicyTransactions pt on e.TransactionID = pt.ID
  INNER JOIN mstt_Agents a ON pt.AgentCode = a.Code                          --restrict to openwork
  left outer join #IRD i on e.transactionID = i.TransactionID and e.Type = i.Type
  left outer join #Comms c on e.transactionID = c.TransactionID
where e.Type IN (1, 2, 4, 10, 15, 16, 17, 18, 19)
  and a.CompanyCode = 10002 -- Openwork
  AND (CAST(CONVERT(NVARCHAR, e.DATE_DUE, 112) AS DATETIME) <= @CD    
         OR (CAST(CONVERT(NVARCHAR, e.DATE_RECV, 112) AS DATETIME) <= @CD   
             AND e.DATE_RECV IS NOT NULL))          


CREATE CLUSTERED INDEX ind_FINSTAT0028 ON #FINSTAT0028aExpectation (ID, Type, TransactionID, Amount_Due, Amount_Rec, Margin_Pct, Margin_Due, Commission_Due, Margin_Rec, Commission_Rec, Date_Due, Date_Recv, IRD)

-- 4. Extract report data into a temp table
--IF OBJECT_ID('tempdb..#FINSTAT0028a') IS NOT NULL
--   DROP TABLE #FINSTAT0028a
IF OBJECT_ID('tempdb..#FINSTAT0028a') IS NULL
begin
  create table #FINSTAT0028a
  (
    Section       varchar(255)collate database_default,
    [Section Seq]   tinyint,
    Description     varchar(50) collate database_default,
    Type        varchar(255) collate database_default,
    Opening       decimal(15,2),
    Movement      decimal(15,2),
    Closing       decimal(15,2),
    PLControlBalance  decimal(15,2),
    Error       varchar(6)collate database_default
  )
end
else
  truncate table #FINSTAT0028a


-- 4.1 Distribution Allowance
insert INTO #FINSTAT0028a
SELECT 'Distribution Allowance' AS [Section],
       1 AS [Section Seq],
       CASE --Pad out each description to at least 7 chars (by adding trailing blanks) to avoid error in SRS
          WHEN LEN(Codes.Description) < 7 THEN Codes.Description + SPACE(7 - LEN(Codes.Description))
          ELSE Codes.Description
       END AS [Description],
       Codes.Code AS [Type],
       -- 4.1.1 Sub-query for Opening DA
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv < @OD
                   )
                  )

                WHEN Codes.Code IN (2, 15, 16) THEN -- Clawbacks 
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv < @OD
                   )
                  ) * (-1)

                WHEN Codes.Code IN (17, 18, 19) THEN -- Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) )
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND (Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv < @OD
                   )
                  ) * (-1)

                WHEN Codes.Code IN (5, 6) THEN -- Suspense
                  (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_Expectation AS Expect
                   WHERE Type = Codes.Code
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) < @OD
                     AND INIT_ID IS NULL
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Opening],
       -- 4.1.2 Sub-query for DA Movement
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  )

                WHEN Codes.Code IN (2, 15, 16) THEN -- Clawbacks
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)

                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  ) * (-1)

                WHEN Codes.Code IN (17, 18, 19) THEN -- Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect

                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) )
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ( Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)

                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  ) * (-1)

                WHEN Codes.Code IN (5, 6) THEN -- Suspense
                  (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_Expectation AS Expect
                   WHERE Type = Codes.Code
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) >= @OD
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) <= @CD
                     AND INIT_ID IS NULL
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Movement],
       -- 4.1.3 Sub-query for Closing DA
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD

                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv <= @CD
                   )
                  )

                WHEN Codes.Code IN (2, 15, 16) THEN -- Clawbacks 
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv <= @CD
                   )
                  ) * (-1)

                WHEN Codes.Code IN (17, 18, 19) THEN -- Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00))
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND (Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv <= @CD
                   )
                  ) * (-1)

/*
                WHEN Codes.Code IN (5, 6) THEN -- Suspense
                  (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_Expectation AS Expect
                   WHERE Type = Codes.Code
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) <= @CD
                     AND INIT_ID IS NULL
                  ) * (-1)
*/
                ELSE
                   0
             END
       ) AS [Closing],
       CAST(NULL AS DECIMAL (15,2)) AS [PLControlBalance],
       NULL AS [Error]
--INTO #FINSTAT0028a
FROM msit_MIWarehouseCodesAndDescriptions Codes
WHERE ColumnName = 'CommissionType'
  AND Codes.Code IN (1, 2, 4, 5, 6, 10, 15, 16, 17, 18, 19)

UNION ALL

-- 4.2 Non Openwork Ltd Commissions, Expenses & Charges
SELECT 'Non Openwork Ltd Commissions: Expenses & Charges' AS [Section],
       2 AS [Section Seq],
       CASE --Pad out each description to at least 7 chars (by adding trailing blanks) to avoid error in SRS
          WHEN LEN(Codes.Description) < 7 THEN Codes.Description + SPACE(7 - LEN(Codes.Description))
          ELSE Codes.Description
       END AS [Description],
       Codes.Code AS [Type],
       -- 4.2.1 Sub-query for Opening non-Openwork
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM mstt_AgentPayments AS AgPay
                    LEFT JOIN mstt_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.AGT_TYPE = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) < @OD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16) THEN -- Clawbacks
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   ) * (-1)
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM mstt_AgentPayments AS AgPay
                    LEFT JOIN mstt_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.AGT_TYPE = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) < @OD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (17, 18, 19) THEN -- Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00))
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)

                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND (Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM mstt_AgentPayments AS AgPay
                    LEFT JOIN mstt_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.AGT_TYPE = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) < @OD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code 
                     AND Agents.Descn <> 'Openwork'
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) < @OD
                     AND (CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) >= @OD
                       OR AgPay.Export_Date IS NULL)
                  ) * (-1)

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code 
                     AND Agents.Descn <> 'Openwork'
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) < @OD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) < @OD))
                     AND (CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) >= @OD
                       OR AgPay.Export_Date IS NULL)
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Opening],
       -- 4.2.2 Sub-query for non-Openwork Movement
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16) THEN -- Clawbacks
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  )

                WHEN Codes.Code IN (17, 18, 19) THEN -- Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) )
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) 
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  )

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                  )

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) >= @OD))
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
                  )

                ELSE
                   0
             END
       ) AS [Movement],
       -- 4.2.3 Sub-query for Closing non-Openwork
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD  AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM mstt_AgentPayments AS AgPay
                    LEFT JOIN mstt_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.AGT_TYPE = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) <= @CD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16) THEN -- Clawbacks
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00) 
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   ) * (-1)
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM mstt_AgentPayments AS AgPay
                    LEFT JOIN mstt_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.AGT_TYPE = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) <= @CD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (17, 18, 19) THEN -- Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00) 
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND (Date_Recv IS NULL)
                   ) 
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM mstt_AgentPayments AS AgPay
                    LEFT JOIN mstt_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.AGT_TYPE = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) <= @CD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                     AND (CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) > @CD
                          OR AgPay.Export_Date IS NULL)
                  ) * (-1)

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
                     AND (CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) > @CD
                          OR AgPay.Export_Date IS NULL)
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Closing],
       CAST(NULL AS DECIMAL (15,2)) AS [PLControlBalance],
       NULL AS [Error]
FROM msit_MIWarehouseCodesAndDescriptions Codes
WHERE ColumnName = 'CommissionType'
  AND Codes.Code IN (1, 2, 4, 8, 10, 15, 16, 17, 18, 19, 20)

UNION ALL

-- 4.3 Openwork Ltd Commissions, Expenses & Charges
SELECT 'Openwork Ltd Commissions: Expenses & Charges' AS [Section],
       3 AS [Section Seq],
       CASE --Pad out each description to at least 7 chars (by adding trailing blanks) to avoid error in SRS
          WHEN LEN(Codes.Description) < 7 THEN Codes.Description + SPACE(7 - LEN(Codes.Description))
          ELSE Codes.Description
       END AS [Description],
       Codes.Code AS [Type],
       -- 4.3.1 Sub-query for Opening Openwork
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16) THEN -- Clawbacks 
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                  )

                WHEN Codes.Code IN (17, 18, 19) THEN -- Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) )
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ( Date_Recv IS NULL)
                   )
                  )

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork' -- NOTE: Non-Openwork values summed for Openwork totals!
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) < @OD
                  )

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork' -- NOTE: Non-Openwork values summed for Openwork totals!
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) < @OD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) < @OD))
                  )

                ELSE
                   0
             END
       ) AS [Opening],
       -- 4.3.2 Sub-query for Openwork Movement
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD

                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16) THEN -- Clawbacks
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  )

                WHEN Codes.Code IN (17, 18, 19) THEN -- Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) )
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) 
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  )

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork' -- NOTE: Non-Openwork values summed for Openwork totals!
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                  ) * (-1)

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) >= @OD))
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Movement],
       -- 4.3.3 Sub-query for Closing Openwork
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD  AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16) THEN -- Clawbacks 
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                  )

                WHEN Codes.Code IN (17, 18, 19) THEN -- Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) )
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ( Date_Recv IS NULL)
                   )
                  )

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork' -- NOTE: Non-Openwork values summed for Openwork totals!
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                  )

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork' -- NOTE: Non-Openwork values summed for Openwork totals!
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
                  )

                ELSE
                   0
             END
       ) AS [Closing],
       CAST(NULL AS DECIMAL (15,2)) AS [PLControlBalance],
       NULL AS [Error]
FROM msit_MIWarehouseCodesAndDescriptions Codes
WHERE ColumnName = 'CommissionType'
  AND Codes.Code IN (1, 2, 4, 8, 10, 15, 16, 17, 18, 19, 20)

UNION ALL

-- 4.4 Provider Cash Statements
SELECT '' AS [Section],
       4 AS [Section Seq],
       '<B>Provider Cash Statements</B>' AS [Description], -- <B> tag informs Reporting Services to show in bold
       1 AS [Type],
      (SELECT ISNULL(SUM(ISNULL(CAST(Stat.Total AS DECIMAL(15,2)), 0.00)), 0.00) 
       FROM msit_S_STMTCT AS Stat 
       WHERE CAST(CONVERT(NVARCHAR, Stat.Stmnt_Date, 112) AS DATETIME) < @OD
         AND (Stat.Deleted <> -1 OR Stat.Deleted IS NULL)
      ) AS [Opening],
      (SELECT ISNULL(SUM(ISNULL(CAST(Stat.Total AS DECIMAL(15,2)), 0.00)), 0.00) 
       FROM msit_S_STMTCT AS Stat 
       WHERE CAST(CONVERT(NVARCHAR, Stat.Stmnt_Date, 112) AS DATETIME) >= @OD 
         AND CAST(CONVERT(NVARCHAR, Stat.Stmnt_Date, 112) AS DATETIME) <= @CD
         AND (Stat.Deleted <> -1 OR Stat.Deleted IS NULL)
      ) AS [Movement],
      (SELECT ISNULL(SUM(ISNULL(CAST(Stat.Total AS DECIMAL(15,2)), 0.00)), 0.00) 
       FROM msit_S_STMTCT AS Stat 
       WHERE CAST(CONVERT(NVARCHAR, Stat.Stmnt_Date, 112) AS DATETIME) <= @CD
         AND (Stat.Deleted <> -1 OR Stat.Deleted IS NULL)
      ) AS [Closing],
       CAST(NULL AS DECIMAL (15,2)) AS [PLControlBalance],
       NULL AS [Error]

UNION ALL

-- 4.5 Franchise Cash Payments
SELECT '' AS [Section],
       5 AS [Section Seq],
       '<B>Franchise Cash Payments</B>' AS [Description], -- <B> tag informs Reporting Services to show in bold
       1 AS [Type],
       ((SELECT ISNULL(SUM(ISNULL(CAST(BACS.AmountPaid AS DECIMAL(15,2)), 0.00)), 0.00) 
         FROM msit_ReportBACSExport AS BACS 
         WHERE CAST(CONVERT(NVARCHAR, BACS.ExportDate, 112) AS DATETIME) < @OD
        )
        -
        (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00) 
         FROM mstt_AgentPayments AS AgPay 
         WHERE CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) < @OD
           AND AgPay.AGT_TYPE IN (0, 3, 7, 14, 21) -- Unknown, Adjustment(Type 3), Manual(Direct Credit), Manual (TT), Manual (Mort Early Pymts)
        )
       ) * (-1)
       AS [Opening],
       ((SELECT ISNULL(SUM(ISNULL(CAST(BACS.AmountPaid AS DECIMAL(15,2)), 0.00)), 0.00) 
         FROM msit_ReportBACSExport AS BACS 
         WHERE CAST(CONVERT(NVARCHAR, BACS.ExportDate, 112) AS DATETIME) >= @OD
           AND CAST(CONVERT(NVARCHAR, BACS.ExportDate, 112) AS DATETIME) <= @CD
        )
        -
        (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00) 
         FROM mstt_AgentPayments AS AgPay 
         WHERE CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) >= @OD
           AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) <= @CD
           AND AgPay.AGT_TYPE IN (0, 3, 7, 14, 21) -- Unknown, Adjustment(Type 3), Manual(Direct Credit), Manual (TT), Manual (Mort Early Pymts)
        )
       ) * (-1)
       AS [Movement],
       ((SELECT ISNULL(SUM(ISNULL(CAST(BACS.AmountPaid AS DECIMAL(15,2)), 0.00)), 0.00)
         FROM msit_ReportBACSExport AS BACS
         WHERE CAST(CONVERT(NVARCHAR, BACS.ExportDate, 112) AS DATETIME) <= @CD
        )
        -
        (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00) 
         FROM mstt_AgentPayments AS AgPay 
         WHERE CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) <= @CD
           AND AgPay.AGT_TYPE IN (0, 3, 7, 14, 21) -- Unknown, Adjustment(Type 3), Manual(Direct Credit), Manual (TT), Manual (Mort Early Pymts)
        )
       ) * (-1)
       AS [Closing],
       CAST(NULL AS DECIMAL (15,2)) AS [PLControlBalance],
       NULL AS [Error]

-- 5. Calculate P&L Control Balance and add to report temp table
UPDATE #FINSTAT0028a
SET PLControlBalance = (SELECT ISNULL(SUM(ISNULL(CAST(Movement AS DECIMAL(15,2)), 0.00)), 0.00)
                        FROM #FINSTAT0028a
                        WHERE Description NOT IN (SELECT Codes.Description
                                                  FROM msit_MIWarehouseCodesAndDescriptions Codes
                                                  WHERE Codes.ColumnName = 'CommissionType'
                                                    AND Codes.Code IN (5, 6))
                          AND Description NOT IN ('<B>Provider Cash Statements</B>', '<B>Franchise Cash Payments</B>'))

-- 6. Select data for report
SELECT [Section],
       [Description],
       [Opening],
       [Movement],
       [Closing],
       [PLControlBalance],
       [Error]
FROM #FINSTAT0028a
ORDER BY [Section Seq], [Type]

-- 7. tidy up
