CREATE PROCEDURE [dbo].[cscp_FINSTAT0028_SW] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

-- 2.1 Input date validation
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
   SELECT 
      NULL AS [Category_Desc],
      NULL AS [Commission_Desc],
      NULL AS [Opening_Amount],
      NULL AS [Movement_Amount],
      NULL AS [Closing_Amount],
      CASE 
         WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
         WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
      END AS [Error_MSG]
   RETURN 0
END

-- 2.2 convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

-- 2.3 Extract Expectation data into a temp table
IF OBJECT_ID('tempdb..#FINSTAT0028aExpectation') IS NOT NULL
   DROP TABLE #FINSTAT0028aExpectation

SELECT Expectation.ID, 
       Expectation.Type,
       Expectation.TransactionID,
       ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) AS Amount_Due,
       ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) AS Amount_Rec,
       dbo.cscf_CalcMarginPercent_SW(Expectation.ID) AS Margin_Pct,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Rec,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Rec,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) AS Date_Due,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM msit_S_PACC Expectation2
           INNER JOIN msit_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN msit_S_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN msit_S_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #FINSTAT0028aExpectation
FROM msit_S_PACC Expectation
   INNER JOIN msit_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
   INNER JOIN msit_S_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
   INNER JOIN msit_S_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (1, 2, 4, 10, 15, 16, 17, 18, 19)       --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD    --of the temp table
       OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD   --by omitting data which
           AND Expectation.DATE_RECV IS NOT NULL))          --we KNOW we don't need
GROUP BY Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

-- 2.3.1 bypass Margin Calcs for margin and commission values to avoid calling cscf_CalcMarginPercent_SW more than once per Expectation
UPDATE #FINSTAT0028aExpectation
SET Margin_Due = ISNULL(CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Due = ISNULL(CAST((Amount_Due - CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00),
    Margin_Rec = ISNULL(CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Rec = ISNULL(CAST((Amount_Rec - CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00)

CREATE CLUSTERED INDEX ind_FINSTAT0028 ON #FINSTAT0028aExpectation (ID, Type, TransactionID, Amount_Due, Amount_Rec, Margin_Pct, Margin_Due, Commission_Due, Margin_Rec, Commission_Rec, Date_Due, Date_Recv, IRD)

-- 2.4 Extract report data into a temp table
IF OBJECT_ID('tempdb..#FINSTAT0028a') IS NOT NULL
   DROP TABLE #FINSTAT0028a

-- 2.4.1 Distribution Allowance
SELECT 'Distribution Allowance' AS [Category_Desc],
       1 AS [Section Seq],
       CASE --Pad out each description to at least 7 chars (by adding trailing blanks) to avoid error in SRS
          WHEN LEN(Codes.Description) < 7 THEN Codes.Description + SPACE(7 - LEN(Codes.Description))
          ELSE Codes.Description
       END AS [Commission_Desc],
       Codes.Code AS [Type],
       -- 2.4.1.1 Sub-query for Opening DA
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv < @OD
                   )
                  )

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv < @OD
                   )
                  ) * (-1)

                WHEN Codes.Code IN (5, 6) THEN -- Suspense
                  (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_PACC AS Expect
                   LEFT JOIN msit_S_PACCSU S_PACCSU ON S_PACCSU.SUSP_ID = Expect.ID
                   WHERE Type = Codes.Code
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) < @OD
                     AND S_PACCSU.INIT_ID IS NULL
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Opening_Amount],
       -- 2.4.1.2 Sub-query for DA Movement
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  )

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  ) * (-1)

                WHEN Codes.Code IN (5, 6) THEN -- Suspense
                  (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_PACC AS Expect
                   LEFT JOIN msit_S_PACCSU S_PACCSU ON S_PACCSU.SUSP_ID = Expect.ID
                   WHERE Type = Codes.Code
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) >= @OD
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) <= @CD
                     AND S_PACCSU.INIT_ID IS NULL
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Movement_Amount],
       -- 2.4.1.3 Sub-query for Closing DA
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv <= @CD
                   )
                  )

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv <= @CD
                   )
                  ) * (-1)

                WHEN Codes.Code IN (5, 6) THEN -- Suspense
                  (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_PACC AS Expect
                   LEFT JOIN msit_S_PACCSU S_PACCSU ON S_PACCSU.SUSP_ID = Expect.ID
                   WHERE Type = Codes.Code
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) <= @CD
                     AND S_PACCSU.INIT_ID IS NULL
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Closing_Amount],
       NULL AS [Error_MSG]
INTO #FINSTAT0028a
FROM msit_MIWarehouseCodesAndDescriptions Codes
WHERE ColumnName = 'CommissionType'
  AND Codes.Code IN (1, 2, 4, 5, 6, 10, 15, 16, 17, 18, 19)

UNION ALL

-- 2.4.2 Non Openwork Ltd Commissions, Expenses & Charges
SELECT 'Non Openwork Ltd Commissions, Expenses & Charges' AS [Category_Desc],
       2 AS [Section Seq],
       CASE --Pad out each description to at least 7 chars (by adding trailing blanks) to avoid error in SRS
          WHEN LEN(Codes.Description) < 7 THEN Codes.Description + SPACE(7 - LEN(Codes.Description))
          ELSE Codes.Description
       END AS [Commission_Desc],
       Codes.Code AS [Type],
       -- 2.4.2.1 Sub-query for Opening non-Openwork
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM msit_S_AgmPay AS AgPay
                    LEFT JOIN msit_S_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.PaymentType = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) < @OD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   ) * (-1)
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM msit_S_AgmPay AS AgPay
                    LEFT JOIN msit_S_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.PaymentType = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) < @OD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_AgmFil AS Pay
                   LEFT JOIN msit_S_AgmPay AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN msit_S_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.Type = Codes.Code 
                     AND Agents.Descn <> 'Openwork'
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) < @OD
                     AND (CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) >= @OD
                       OR AgPay.Export_Date IS NULL)
                  ) * (-1)

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_AgmFil AS Pay
                   LEFT JOIN msit_S_AgmPay AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN msit_S_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.Type = Codes.Code 
                     AND Agents.Descn <> 'Openwork'
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) < @OD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) < @OD))
                     AND (CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) >= @OD
                       OR AgPay.Export_Date IS NULL)
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Opening_Amount],
       -- 2.4.2.2 Sub-query for non-Openwork Movement
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
