                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  )

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_AgmFil AS Pay
                   LEFT JOIN msit_S_AgmPay AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN msit_S_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.Type = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                  )

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_AgmFil AS Pay
                   LEFT JOIN msit_S_AgmPay AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN msit_S_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.Type = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) >= @OD))
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
                  )

                ELSE
                   0
             END
       ) AS [Movement_Amount],
       -- 2.4.2.3 Sub-query for Closing non-Openwork
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD  AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM msit_S_AgmPay AS AgPay
                    LEFT JOIN msit_S_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.PaymentType = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) <= @CD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
