-- 2.4.3 Openwork Ltd Commissions, Expenses & Charges
SELECT 'Openwork Ltd Commissions, Expenses & Charges' AS [Category_Desc],
       3 AS [Section Seq],
       CASE --Pad out each description to at least 7 chars (by adding trailing blanks) to avoid error in SRS
          WHEN LEN(Codes.Description) < 7 THEN Codes.Description + SPACE(7 - LEN(Codes.Description))
          ELSE Codes.Description
       END AS [Commission_Desc],
       Codes.Code AS [Type],
       -- 2.4.3.1 Sub-query for Opening Openwork
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                  )

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_AgmFil AS Pay
                   LEFT JOIN msit_S_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.Type = Codes.Code
                     AND Agents.Descn <> 'Openwork' -- NOTE: Non-Openwork values summed for Openwork totals!
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) < @OD
                  )

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_AgmFil AS Pay
                   LEFT JOIN msit_S_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.Type = Codes.Code
                     AND Agents.Descn <> 'Openwork' -- NOTE: Non-Openwork values summed for Openwork totals!
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) < @OD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) < @OD))
                  )

                ELSE
                   0
             END
       ) AS [Opening_Amount],
       -- 2.4.3.2 Sub-query for Openwork Movement
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  )

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_AgmFil AS Pay
                   LEFT JOIN msit_S_AgmPay AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN msit_S_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.Type = Codes.Code
                     AND Agents.Descn <> 'Openwork' -- NOTE: Non-Openwork values summed for Openwork totals!
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                  ) * (-1)

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_AgmFil AS Pay
                   LEFT JOIN msit_S_AgmPay AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN msit_S_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.Type = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) >= @OD))
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Movement_Amount],
       -- 2.4.3.3 Sub-query for Closing Openwork
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD  AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                  )

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_AgmFil AS Pay
                   LEFT JOIN msit_S_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.Type = Codes.Code
                     AND Agents.Descn <> 'Openwork' -- NOTE: Non-Openwork values summed for Openwork totals!
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                  )

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM msit_S_AgmFil AS Pay
                   LEFT JOIN msit_S_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.Type = Codes.Code
                     AND Agents.Descn <> 'Openwork' -- NOTE: Non-Openwork values summed for Openwork totals!
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
                  )

                ELSE
                   0
             END
       ) AS [Closing_Amount],
       NULL AS [Error_MSG]
FROM msit_MIWarehouseCodesAndDescriptions Codes
WHERE ColumnName = 'CommissionType'
  AND Codes.Code IN (1, 2, 4, 8, 10, 15, 16, 17, 18, 19, 20)

UNION ALL

-- 2.4.4 Provider Cash Statements
SELECT '' AS [Category_Desc],
       4 AS [Section Seq],
       '<B>Provider Cash Statements</B>' AS [Commission_Desc], -- <B> tag informs Reporting Services to show in bold
       1 AS [Type],
      (SELECT ISNULL(SUM(ISNULL(CAST(Stat.Total AS DECIMAL(15,2)), 0.00)), 0.00) 
       FROM msit_S_STMTCT AS Stat 
       WHERE CAST(CONVERT(NVARCHAR, Stat.Stmnt_Date, 112) AS DATETIME) < @OD
         AND (Stat.Deleted <> -1 OR Stat.Deleted IS NULL)
      ) AS [Opening_Amount],
      (SELECT ISNULL(SUM(ISNULL(CAST(Stat.Total AS DECIMAL(15,2)), 0.00)), 0.00) 
       FROM msit_S_STMTCT AS Stat 
       WHERE CAST(CONVERT(NVARCHAR, Stat.Stmnt_Date, 112) AS DATETIME) >= @OD 
         AND CAST(CONVERT(NVARCHAR, Stat.Stmnt_Date, 112) AS DATETIME) <= @CD
         AND (Stat.Deleted <> -1 OR Stat.Deleted IS NULL)
      ) AS [Movement_Amount],
      (SELECT ISNULL(SUM(ISNULL(CAST(Stat.Total AS DECIMAL(15,2)), 0.00)), 0.00) 
       FROM msit_S_STMTCT AS Stat 
       WHERE CAST(CONVERT(NVARCHAR, Stat.Stmnt_Date, 112) AS DATETIME) <= @CD
         AND (Stat.Deleted <> -1 OR Stat.Deleted IS NULL)
      ) AS [Closing_Amount],
       NULL AS [Error_MSG]

UNION ALL

-- 2.4.5 Franchise Cash Payments
SELECT '' AS [Category_Desc],
       5 AS [Section Seq],
       '<B>Franchise Cash Payments</B>' AS [Commission_Desc], -- <B> tag informs Reporting Services to show in bold
       1 AS [Type],
       ((SELECT ISNULL(SUM(ISNULL(CAST(BACS.AmountPaid AS DECIMAL(15,2)), 0.00)), 0.00) 
         FROM msit_ReportBACSExport AS BACS 
         WHERE CAST(CONVERT(NVARCHAR, BACS.ExportDate, 112) AS DATETIME) < @OD
        )
        -
        (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00) 
         FROM msit_S_AgmPay AS AgPay 
         WHERE CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) < @OD
           AND AgPay.PaymentType IN (0, 3, 7, 14, 21) -- Unknown, Adjustment(Type 3), Manual(Direct Credit), Manual (TT), Manual (Mort Early Pymts)
        )
       ) * (-1)
       AS [Opening_Amount],
       ((SELECT ISNULL(SUM(ISNULL(CAST(BACS.AmountPaid AS DECIMAL(15,2)), 0.00)), 0.00) 
         FROM msit_ReportBACSExport AS BACS 
         WHERE CAST(CONVERT(NVARCHAR, BACS.ExportDate, 112) AS DATETIME) >= @OD
           AND CAST(CONVERT(NVARCHAR, BACS.ExportDate, 112) AS DATETIME) <= @CD
        )
        -
        (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00) 
         FROM msit_S_AgmPay AS AgPay 
         WHERE CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) >= @OD
           AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) <= @CD
           AND AgPay.PaymentType IN (0, 3, 7, 14, 21) -- Unknown, Adjustment(Type 3), Manual(Direct Credit), Manual (TT), Manual (Mort Early Pymts)
        )
       ) * (-1)
       AS [Movement_Amount],
       ((SELECT ISNULL(SUM(ISNULL(CAST(BACS.AmountPaid AS DECIMAL(15,2)), 0.00)), 0.00)
         FROM msit_ReportBACSExport AS BACS
         WHERE CAST(CONVERT(NVARCHAR, BACS.ExportDate, 112) AS DATETIME) <= @CD
        )
        -
        (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00) 
         FROM msit_S_AgmPay AS AgPay 
         WHERE CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) <= @CD
           AND AgPay.PaymentType IN (0, 3, 7, 14, 21) -- Unknown, Adjustment(Type 3), Manual(Direct Credit), Manual (TT), Manual (Mort Early Pymts)
        )
       ) * (-1)
       AS [Closing_Amount],
       NULL AS [Error_MSG]

-- 2.5 Select data for report
SELECT [Category_Desc],
       [Commission_Desc],
       [Opening_Amount],
       [Movement_Amount],
       [Closing_Amount],
       [Error_MSG]
FROM #FINSTAT0028a
ORDER BY [Section Seq], [Type]

-- 2.6 tidy up
DROP TABLE #FINSTAT0028a
DROP TABLE #FINSTAT0028aExpectation

GO
