CREATE PROCEDURE [dbo].[cscp_FINSTAT0028Swift] @UserID VARCHAR(255), @RunDate VARCHAR(10)
AS

IF ISDATE(@RunDate) = 0
BEGIN
   SELECT 
      NULL AS [Category_Desc],
      NULL AS [Commission_Desc],
      NULL AS [Opening_Amount],
      NULL AS [Movement_Amount],
      NULL AS [Closing_Amount],
      NULL AS [PLControlBalance],
      'Invalid Run Date.' AS [Error_MSG]
   RETURN 0
END

DECLARE @ErrorText VARCHAR(512)
SELECT TOP 1 @ErrorText = Error_MSG
FROM mstt_TrialBalanceReport
WHERE CAST(CONVERT(NVARCHAR, Create_Timestamp, 112) AS DATETIME) = CAST(CONVERT(NVARCHAR, @RunDate, 112) AS DATETIME)
ORDER BY ID

IF @ErrorText IS NOT NULL AND @ErrorText <> ''
BEGIN
   SELECT 
      NULL AS [Category_Desc],
      NULL AS [Commission_Desc],
      NULL AS [Opening_Amount],
      NULL AS [Movement_Amount],
      NULL AS [Closing_Amount],
      NULL AS [PLControlBalance],
      @ErrorText AS [Error_MSG]
   RETURN 0
END

SELECT Category_Desc,
       Commission_Desc,
       Opening_Amount,
       Movement_Amount,
       Closing_Amount,
       (SELECT ISNULL(SUM(ISNULL(CAST(Movement_Amount AS DECIMAL(15,2)), 0.00)), 0.00)
        FROM mstt_TrialBalanceReport
        WHERE CAST(CONVERT(NVARCHAR, Create_Timestamp, 112) AS DATETIME) = CAST(CONVERT(NVARCHAR, @RunDate, 112) AS DATETIME)
          AND Commission_Desc NOT IN (SELECT Codes.Description
                                      FROM msit_MIWarehouseCodesAndDescriptions Codes
                                      WHERE Codes.ColumnName = 'CommissionType'
                                        AND Codes.Code IN (5, 6))
          AND Commission_Desc NOT IN ('<B>Provider Cash Statements</B>', '<B>Franchise Cash Payments</B>')
       ) AS PLControlBalance,
       Error_MSG
FROM mstt_TrialBalanceReport
WHERE CAST(CONVERT(NVARCHAR, Create_Timestamp, 112) AS DATETIME) = CAST(CONVERT(NVARCHAR, @RunDate, 112) AS DATETIME)
ORDER BY ID

GO
