CREATE PROCEDURE [dbo].[cscp_FINSTAT0030a_b_c_d] @UserID VARCHAR(255), @LegacyFlag VARCHAR(10), @CommType VARCHAR(1), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
   IF @CommType = 'A' 
      EXEC cscp_FINSTAT0001a_2a @UserID, 'X', @StartDate, @EndDate
   ELSE
   IF @CommType = 'B' 
      EXEC cscp_FINSTAT0001b_2b @UserID, @LegacyFlag, 'X', @StartDate, @EndDate
   ELSE
   IF @CommType = 'C' 
      EXEC cscp_FINSTAT0001c_2c @UserID, 'X', @StartDate, @EndDate
   ELSE
   IF @CommType = 'D' 
      EXEC cscp_FINSTAT0001d_2d @UserID, 'X', @StartDate, @EndDate

