CREATE PROCEDURE [dbo].[cscp_FINSTAT0032a] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

/*

  AH 22 Sep 2008
  Create temporary table, final select query and remove final drop tables, to enable running of batchfinstat0001b


*/


IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0
BEGIN
  SELECT 
        NULL AS 'Group/NonGroup'
      , NULL AS 'Provider'
      , NULL AS 'Statement Cash Received'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
       WHEN ISDATE(@EndDate) = 0 THEN 'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy'
        END AS [Error]
   RETURN 0
END

--IF OBJECT_ID('tempdb..#FINSTAT0032a') IS NOT NULL
--   DROP TABLE #FINSTAT0032a

SELECT DISTINCT 
     CASE ProductProviders.ZFSGroupFlag
        WHEN 'Y' THEN 'ZFS Group'
        WHEN 'N' THEN 'Non ZFS Group'
        ELSE 'Unknown'
     END AS 'Group/NonGroup'
   , ProductProviders.ReportingProductProviderName AS 'Provider'
   , ProductProviders.ProductProviderCode AS 'Provider Code' --Added to ensure uniqueness/omitted in final resultset
   , (SELECT ISNULL(SUM(ISNULL(CAST(ProviderStatements_Inner.TOTAL AS DECIMAL(15,2)), 0.00)), 0.00)
      FROM msit_S_STMTCT ProviderStatements_Inner
      WHERE ProviderStatements_Inner.STMNT_DATE IS NOT NULL
      AND CAST(CONVERT(NVARCHAR, ProviderStatements_Inner.STMNT_DATE , 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, ProviderStatements_Inner.STMNT_DATE , 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
      AND (ProviderStatements_Inner.Deleted <> -1 OR ProviderStatements_Inner.Deleted IS NULL)
      AND (ProviderStatements_Inner.COMP_CODE = ProductProviders.ProductProviderCode
          OR (ProviderStatements_Inner.COMP_CODE IS NULL AND ProductProviders.ProductProviderCode IS NULL))
   ) AS 'Statement Cash Received'
   , NULL AS [Error]

INTO #FINSTAT0032a
FROM msit_S_STMTCT ProviderStatements
LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = ProviderStatements.COMP_CODE 
WHERE ProviderStatements.STMNT_DATE IS NOT NULL
      AND CAST(CONVERT(NVARCHAR, ProviderStatements.STMNT_DATE , 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, ProviderStatements.STMNT_DATE , 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
      AND (ProviderStatements.Deleted <> -1 OR ProviderStatements.Deleted IS NULL)
ORDER BY [Group/NonGroup], [Provider]

--Extract report data into a temp table
IF OBJECT_ID('tempdb..#BatchFINSTAT0032a') IS NULL
begin
  Create table #BatchFINSTAT0032a
  (
  [Group/NonGroup]      varchar(50),
  Provider          varchar(255),
  [Statement Cash Received] decimal(15,2),
  Error           varchar(6)
  ) 
end
else
  Truncate table #BatchFINSTAT0032a


INSERT into #BatchFINSTAT0032a
SELECT 
     CASE WHEN [Group/NonGroup] IS NOT NULL THEN [Group/NonGroup] ELSE 'Unknown' END AS [Group/NonGroup]       
   , CASE WHEN [Provider] IS NOT NULL THEN [Provider] ELSE 'Unknown' END AS [Provider]
   , ISNULL(SUM(ISNULL(CAST([Statement Cash Received] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Statement Cash Received]
   , [Error]
FROM  #FINSTAT0032a
WHERE [Statement Cash Received] <> 0.00
GROUP BY [Group/NonGroup], [Provider], [Error]


--Select statement for batchFINSTAT
SELECT  [Group/NonGroup],
  Provider,
  [Statement Cash Received],
  Error
FROM #BatchFINSTAT0032a
ORDER BY [Group/NonGroup], [Provider]

--DROP TABLE #FINSTAT0032a
GO
