CREATE PROCEDURE [dbo].[cscp_FINSTAT0032b] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
/*
  
  RH 18 Nov 2007
  Changed treatment of type 17,18,19 where status=1 - should be +ve. Also rewritten main select for performance and readability

*/

IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0
BEGIN
  SELECT 
        NULL AS 'Type'
      , NULL AS 'Type of Distribution Allowance'
      , NULL AS 'Cash received in Expectation'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
       WHEN ISDATE(@EndDate) = 0 THEN 'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy'
        END AS [Error]
   RETURN 0
END

IF OBJECT_ID('tempdb..#FINSTAT0032b') IS NOT NULL
   DROP TABLE #FINSTAT0032b

SELECT 
        Expectation.Type AS 'Type'
      , Expectation.Type_Description AS 'Type of Distribution Allowance'
      , ISNULL(SUM(
    case
      when Expectation.Type in (1,4,10) then 1
      when Expectation.Type in (17,18,19) and Expectation.Status = 1 then 1
      else -1 
    end * 
  Expectation.Amount_Due), 0.00) AS 'Cash received in Expectation'
      , NULL AS [Error]
INTO #FINSTAT0032b
FROM    mstt_Expectation Expectation
WHERE   Expectation.DATE_RECV IS NOT NULL
        AND CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV , 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
        AND CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV , 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
        AND (
                (Expectation.INIT_ID IS NULL  
                    and 
                    (   (Expectation.Type NOT IN (2, 15, 16, 17, 18, 19) OR Expectation.Type IS NULL)
                        or (Expectation.Type IN (17, 18, 19) and Expectation.Status = 1)
                    )
                 )
              OR
              (  Expectation.Type IN (2, 15, 16) 
                or (Expectation.Type IN (17, 18, 19) and Expectation.Status in(2,3))
              )
  )
group by Expectation.Type
      , Expectation.Type_Description


SELECT 
     Type AS [Type]
   , CASE 
        WHEN [Type of Distribution Allowance] IS NOT NULL THEN [Type of Distribution Allowance] 
        ELSE 'Unknown' 
     END AS [Type of Distribution Allowance]
   , ISNULL(SUM(ISNULL(CAST([Cash received in Expectation] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Cash received in Expectation]
   , [Error]
FROM  #FINSTAT0032b
WHERE [Cash received in Expectation] <> 0.00
GROUP BY [Type], [Type of Distribution Allowance], [Error]
ORDER BY [Type], [Type of Distribution Allowance], [Cash received in Expectation]

DROP TABLE #FINSTAT0032b




GO
