CREATE PROCEDURE [dbo].[cscp_FINSTAT0032c] @UserID VARCHAR(255), @ClosingDate VARCHAR(10)
AS

IF ISDATE(@ClosingDate) = 0
BEGIN
  SELECT 
        NULL AS 'Unallocated receipt ID'
      , NULL AS 'Date Received'
      , NULL AS 'Policy Number'
      , NULL AS 'Statement Attached To'
      , NULL AS 'Unallocated Reason Code'
      , NULL AS 'UnallocatedUpTo30'
      , NULL AS 'Unallocated31to90'
      , NULL AS 'Unallocated91to120'
      , NULL AS 'Unallocated121to180'
      , NULL AS 'Unallocated181to365'
      , NULL AS 'UnallocatedOver365'
      , NULL AS 'UnallocatedTotal'
      , CASE WHEN ISDATE(@ClosingDate) = 0 THEN 'Invalid Closing Date Entered. Please enter it in the format dd/mm/yyyy'     
        END AS [Error]
   RETURN 0
END

IF OBJECT_ID('tempdb..#FINSTAT0032c') IS NOT NULL
   DROP TABLE #FINSTAT0032c

SELECT 
    ExpectationMain.ID as 'Unallocated receipt ID'
  , CONVERT(NVARCHAR, ProviderStatements.STMNT_DATE , 103)  as 'Date Received'
  , Policies.CONT_NUM as 'Policy Number'
  , ExpectationMain.STATEMENT as 'Statement Attached To'
  , ExpectationMain.UnallocatedReasonCode as 'Unallocated Reason Code'

  , (SELECT ISNULL(SUM(ISNULL(CAST((Expectation.AMOUNT_REC) AS DECIMAL(15,2)), 0.00)), 0.00)  
       FROM mstt_Expectation Expectation
         WHERE  Expectation.INIT_ID IS NULL
    AND Expectation.TYPE IN (5,6)
            AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) >= 0 
          AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) <= 30 
          AND Expectation.ID = ExpectationMain.ID
       ) AS 'UnallocatedUpTo30' 
  
  , (SELECT ISNULL(SUM(ISNULL(CAST((Expectation.AMOUNT_REC) AS DECIMAL(15,2)), 0.00)), 0.00)  
       FROM mstt_Expectation Expectation
         WHERE  Expectation.INIT_ID IS NULL
    AND Expectation.TYPE IN (5,6)
            AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) >= 31 
          AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) <= 90 
          AND Expectation.ID = ExpectationMain.ID
       ) AS 'Unallocated31to90' 

  , (SELECT ISNULL(SUM(ISNULL(CAST((Expectation.AMOUNT_REC) AS DECIMAL(15,2)), 0.00)), 0.00)  
       FROM mstt_Expectation Expectation
         WHERE  Expectation.INIT_ID IS NULL
    AND Expectation.TYPE IN (5,6)
            AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) >= 91 
          AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) <= 120 
          AND Expectation.ID = ExpectationMain.ID
       ) AS 'Unallocated91to120'  

  , (SELECT ISNULL(SUM(ISNULL(CAST((Expectation.AMOUNT_REC) AS DECIMAL(15,2)), 0.00)), 0.00)  
       FROM mstt_Expectation Expectation
         WHERE  Expectation.INIT_ID IS NULL
    AND Expectation.TYPE IN (5,6)
            AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) >= 121
          AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) <= 180 
          AND Expectation.ID = ExpectationMain.ID
       ) AS 'Unallocated121to180' 

  , (SELECT ISNULL(SUM(ISNULL(CAST((Expectation.AMOUNT_REC) AS DECIMAL(15,2)), 0.00)), 0.00)  
       FROM mstt_Expectation Expectation
         WHERE  Expectation.INIT_ID IS NULL
    AND Expectation.TYPE IN (5,6)
            AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) >= 181
          AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) <= 365 
          AND Expectation.ID = ExpectationMain.ID
       ) AS 'Unallocated181to365'

  , (SELECT ISNULL(SUM(ISNULL(CAST((Expectation.AMOUNT_REC) AS DECIMAL(15,2)), 0.00)), 0.00)  
       FROM mstt_Expectation Expectation
         WHERE  Expectation.INIT_ID IS NULL
    AND Expectation.TYPE IN (5,6)
          AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) >= 366 
          AND Expectation.ID = ExpectationMain.ID
       ) AS 'UnallocatedOver365'
  
  , (SELECT ISNULL(SUM(ISNULL(CAST((Expectation.AMOUNT_REC) AS DECIMAL(15,2)), 0.00)), 0.00)  
       FROM mstt_Expectation Expectation
         WHERE  Expectation.INIT_ID IS NULL
    AND Expectation.TYPE IN (5,6)
          AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME)) >= 0 
          AND Expectation.ID = ExpectationMain.ID
       ) AS 'UnallocatedTotal'
  , NULL AS [Error] 

INTO #FINSTAT0032c
FROM 
  mstt_Expectation ExpectationMain
  LEFT JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = ExpectationMain.TransactionID
  LEFT JOIN mstt_Policies Policies ON Policies.Pol_num = PolicyTransactions.PolicyID
  INNER JOIN msit_S_STMTCT ProviderStatements ON ProviderStatements.Statement =   ExpectationMain.Statement
WHERE   CAST(CONVERT(NVARCHAR, ProviderStatements.STMNT_DATE , 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @ClosingDate, 112) AS DATETIME) 

SELECT 
     CASE WHEN [Unallocated receipt ID] IS NOT NULL THEN [Unallocated receipt ID] ELSE 'Unknown' END AS [Unallocated receipt ID]
   , CASE WHEN [Date Received] IS NOT NULL THEN [Date Received] ELSE 'Unknown' END AS [Date Received]
   , CASE WHEN [Policy Number] IS NOT NULL THEN [Policy Number] ELSE 'Unknown' END AS [Policy Number]
   , CASE WHEN [Statement Attached To] IS NOT NULL THEN [Statement Attached To] ELSE 'Unknown' END AS [Statement Attached To]
   , CASE WHEN [Unallocated Reason Code] IS NOT NULL THEN [Unallocated Reason Code] ELSE 'Unknown' END AS [Unallocated Reason Code]
   , ISNULL(SUM(ISNULL(CAST(UnallocatedUpTo30 AS DECIMAL(15,2)), 0.00)), 0.00) AS 'UnallocatedUpTo30'
   , ISNULL(SUM(ISNULL(CAST(Unallocated31to90 AS DECIMAL(15,2)), 0.00)), 0.00) AS 'Unallocated31to90'
   , ISNULL(SUM(ISNULL(CAST(Unallocated91to120 AS DECIMAL(15,2)), 0.00)), 0.00) AS 'Unallocated91to120'
   , ISNULL(SUM(ISNULL(CAST(Unallocated121to180 AS DECIMAL(15,2)), 0.00)), 0.00) AS 'Unallocated121to180'
   , ISNULL(SUM(ISNULL(CAST(Unallocated181to365 AS DECIMAL(15,2)), 0.00)), 0.00) AS 'Unallocated181to365'
   , ISNULL(SUM(ISNULL(CAST(UnallocatedOver365 AS DECIMAL(15,2)), 0.00)), 0.00) AS 'UnallocatedOver365'
   , ISNULL(SUM(ISNULL(CAST(UnallocatedTotal AS DECIMAL(15,2)), 0.00)), 0.00) AS 'UnallocatedTotal'
   , [Error]
FROM  #FINSTAT0032c
WHERE UnallocatedTotal <> 0.00
GROUP BY [Unallocated receipt ID],[Date Received], [Policy Number], [Statement Attached To],[Unallocated Reason Code], [Error]
ORDER BY [Unallocated receipt ID]

DROP TABLE #FINSTAT0032c
  


GO
