CREATE PROCEDURE [dbo].[cscp_FINSTAT0033a] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0
BEGIN
  SELECT 
        NULL AS [Franchise Code]
      , NULL AS [Franchise]
      , NULL AS [Exported Cash paid to Franchise]
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

SELECT 
     DISTINCT
     CASE 
        WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN Agents_fr.Code
        ELSE AgentsMain.Code 
     END AS 'Franchise Code'
   , CASE 
        WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown')) 
        ELSE RTRIM(ISNULL(AgentsMain.DESCN, 'Unknown'))
     END AS [Franchise]
   , ISNULL(SUM(ISNULL(CAST((ReportBACSExportMain.AMOUNTPAID) AS DECIMAL(15,2)), 0.00)), 0.00) AS 'Exported Cash paid to Franchise'
   , NULL AS [Error] 
FROM msit_ReportBACSExport ReportBACSExportMain
INNER JOIN mstt_Agents AgentsMain ON AgentsMain.CODE = ReportBACSExportMain.AgentCode
LEFT JOIN mstt_Agents Agents_fr ON AgentsMain.Firm = Agents_fr.CODE
LEFT JOIN mstt_Agents Agents_COMP ON AgentsMain.CompanyCode = Agents_COMP.CODE

WHERE  ReportBACSExportMain.ExportDate IS NOT NULL
     AND CAST(CONVERT(NVARCHAR, ReportBACSExportMain.ExportDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
     AND CAST(CONVERT(NVARCHAR, ReportBACSExportMain.ExportDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)
     AND RTRIM(Agents_COMP.Descn) = 'Openwork'

GROUP BY 
     CASE 
        WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN Agents_fr.Code
        ELSE AgentsMain.Code 
     END
   , CASE 
        WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown')) 
        ELSE RTRIM(ISNULL(AgentsMain.DESCN, 'Unknown'))
     END
   , AgentsMain.Code


GO
