CREATE PROCEDURE [dbo].[cscp_FINSTAT0033b] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

/*
Change History

  AH 22 Sep 2008
  Create temporary table, final select query and remove final drop tables, to enable running of batchfinstat0001b


*/


IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0
BEGIN
  SELECT
        NULL AS [Type]
      , NULL AS [Commission Type]
      , NULL AS [Cash allocated to Payments]
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END


--Extract report data into a temp table
IF OBJECT_ID('tempdb..#BatchFINSTAT0033b') IS NULL
begin
  Create table #BatchFINSTAT0033b
  (
  Type        tinyint,
  [Commission Type]   varchar(255),
  [Cash Allocated To Payments]  decimal(15,2),
  Error       varchar(6)
  )
End
Else
  Truncate table #BatchFINSTAT0033b

INSERT into #BatchFINSTAT0033b
SELECT DISTINCT 
      PaymentsPending.CommissionType AS [Type]
    , (CASE
         WHEN PaymentsPending.CommissionTypeDesc IS NOT NULL THEN CommissionTypeDesc
         ELSE 'Unknown'
      END) AS [Commission Type]
    , ISNULL(SUM(ISNULL(CAST((AgentPaymentsMain.AMOUNT) AS DECIMAL(15,2)), 0.00)), 0.00) as 'Cash allocated to Payments'
    , NULL AS [Error] 
FROM mstt_AgentPayments AgentPaymentsMain
INNER JOIN mstt_PaymentsPending PaymentsPending ON AgentPaymentsMain.AgmID = PaymentsPending.ID
LEFT JOIN mstt_Agents AgentsMain ON AgentsMain.CODE = AgentPaymentsMain.AGENT_CODE
LEFT JOIN mstt_Agents Agents_Comp ON AgentsMain.CompanyCode = Agents_Comp.CODE
WHERE  AgentPaymentsMain.Export_Date IS NOT NULL
     AND CAST(CONVERT(NVARCHAR, AgentPaymentsMain.Export_Date, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
     AND CAST(CONVERT(NVARCHAR, AgentPaymentsMain.Export_Date, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)
     AND RTRIM(Agents_Comp.Descn) = 'Openwork'
GROUP BY PaymentsPending.CommissionType, PaymentsPending.CommissionTypeDesc

SELECT Type,
  [Commission Type],
  [Cash Allocated To Payments],
  Error
FROM #BatchFINSTAT0033b
ORDER BY [Type], [Commission Type]
GO
