CREATE PROCEDURE [dbo].[cscp_FINSTAT0034c] @UserID VARCHAR(255), @DueDate VARCHAR(10)
AS

IF ISDATE(@DueDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Franchise Code'
      , NULL AS 'Franchise'
      , NULL AS 'OutstandingClawbackLess90'
      , NULL AS 'OutstandingClawback90to365'
      , NULL AS 'OutstandingClawbackMore365'
      , NULL AS 'OutstandingClawbackTotal'
      , 'Invalid Due Date Entered. Please enter it in the format dd/mm/yyyy' AS [Error]
   RETURN 0
END

IF OBJECT_ID('tempdb..#FINSTAT0034c') IS NOT NULL
   DROP TABLE #FINSTAT0034c

SELECT 
      DISTINCT
      CASE 
         WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN Agents_fr.Code
         ELSE AgentsMain.Code 
      END AS 'Franchise Code'
   ,  CASE 
         WHEN AgentsMain.Firm IS NOT NULL AND RTRIM(AgentsMain.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown'))
         ELSE RTRIM(ISNULL(AgentsMain.DESCN, 'Unknown'))
      END AS 'Franchise'
   ,  AgentsMain.Code AS 'Agent Code' --Added to ensure uniqueness/omitted in final resultset

   , (SELECT ISNULL(SUM(ISNULL(CAST((PaymentsPending.AMOUNT) AS DECIMAL(15,2)), 0.00)), 0.00)  
      FROM mstt_PaymentsPending PaymentsPending
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = PaymentsPending.TransactionID
         INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
         INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
         LEFT JOIN mstt_AgentPayments AgentPayments ON PaymentsPending.ID = AgentPayments.AGMID
         LEFT JOIN mstt_Agents Agents_1 ON Agents_1.CODE = PaymentsPending.AGENT_CODE

      WHERE PaymentsPending.CommissionType = 2 -- Clawback commission
      AND PaymentsPending.PaymentDueDate IS NOT NULL
      AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME)) > 0 
      AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME)) < 91 
      AND (CAST(CONVERT(NVARCHAR, AgentPayments.Export_Date, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME) 
           OR AgentPayments.Export_Date IS NULL)
      AND RTRIM(Agents_1.DESCN) <> 'Openwork' --exclude all Openwork clawback

      AND PolicyTransactions.AgentCode = AgentsMain.CODE
     ) AS 'OutstandingClawbackLess90'

   , (SELECT ISNULL(SUM(ISNULL(CAST((PaymentsPending.AMOUNT) AS DECIMAL(15,2)), 0.00)), 0.00)  
      FROM mstt_PaymentsPending PaymentsPending
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = PaymentsPending.TransactionID
         INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
         INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
         LEFT JOIN mstt_AgentPayments AgentPayments ON PaymentsPending.ID = AgentPayments.AGMID
         LEFT JOIN mstt_Agents Agents_1 ON Agents_1.CODE = PaymentsPending.AGENT_CODE

      WHERE PaymentsPending.CommissionType = 2 -- Clawback commission
      AND PaymentsPending.PaymentDueDate IS NOT NULL
      AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME)) > 90 
      AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME)) < 365 
      AND (CAST(CONVERT(NVARCHAR, AgentPayments.Export_Date, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME) 
           OR AgentPayments.Export_Date IS NULL)
      AND RTRIM(Agents_1.DESCN) <> 'Openwork' --exclude all Openwork clawback

      AND PolicyTransactions.AgentCode = AgentsMain.CODE
     ) AS 'OutstandingClawback90to365'

   , (SELECT ISNULL(SUM(ISNULL(CAST((PaymentsPending.AMOUNT) AS DECIMAL(15,2)), 0.00)), 0.00)  
      FROM mstt_PaymentsPending PaymentsPending
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = PaymentsPending.TransactionID
         INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
         INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
         LEFT JOIN mstt_AgentPayments AgentPayments ON PaymentsPending.ID = AgentPayments.AGMID
         LEFT JOIN mstt_Agents Agents_1 ON Agents_1.CODE = PaymentsPending.AGENT_CODE

      WHERE PaymentsPending.CommissionType = 2 -- Clawback commission
      AND PaymentsPending.PaymentDueDate IS NOT NULL
      AND DATEDIFF(DAY, CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME)) > 364 
      AND (CAST(CONVERT(NVARCHAR, AgentPayments.Export_Date, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME) 
           OR AgentPayments.Export_Date IS NULL)
      AND RTRIM(Agents_1.DESCN) <> 'Openwork' --exclude all Openwork clawback

      AND PolicyTransactions.AgentCode = AgentsMain.CODE
     ) AS 'OutstandingClawbackMore365'

   , (SELECT ISNULL(SUM(ISNULL(CAST((PaymentsPending.AMOUNT) AS DECIMAL(15,2)), 0.00)), 0.00)  
      FROM mstt_PaymentsPending PaymentsPending
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = PaymentsPending.TransactionID
         INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
         INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
         LEFT JOIN mstt_AgentPayments AgentPayments ON PaymentsPending.ID = AgentPayments.AGMID
         LEFT JOIN mstt_Agents Agents_1 ON Agents_1.CODE = PaymentsPending.AGENT_CODE

      WHERE PaymentsPending.CommissionType = 2 -- Clawback commission
      AND PaymentsPending.PaymentDueDate IS NOT NULL
      AND CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) < CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME) 
      AND (CAST(CONVERT(NVARCHAR, AgentPayments.Export_Date, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME) 
           OR AgentPayments.Export_Date IS NULL)
       AND RTRIM(Agents_1.DESCN) <> 'Openwork' --exclude all Openwork clawback

       AND PolicyTransactions.AgentCode = AgentsMain.CODE
      ) AS 'OutstandingClawbackTotal'

   , NULL AS [Error]

INTO #FINSTAT0034c

FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN mstt_PaymentsPending PaymentsPending ON PaymentsPending.TransactionID = PolicyTransactions.ID
INNER JOIN mstt_Agents AgentsMain ON PolicyTransactions.AgentCode = AgentsMain.Code                  --restrict to
INNER JOIN mstt_Agents Company ON AgentsMain.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
LEFT JOIN mstt_AgentPayments AgentPayments ON PaymentsPending.ID = AgentPayments.AGMID
LEFT JOIN mstt_Agents Agents_1 ON Agents_1.CODE = PaymentsPending.AGENT_CODE
LEFT JOIN mstt_Agents Agents_fr ON AgentsMain.Firm = Agents_fr.CODE

WHERE PaymentsPending.CommissionType = 2 -- Clawback commission
AND PaymentsPending.PaymentDueDate IS NOT NULL
AND CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) < CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME) 
AND (CAST(CONVERT(NVARCHAR, AgentPayments.Export_Date, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @DueDate, 112) AS DATETIME) 
     OR AgentPayments.Export_Date IS NULL)
AND RTRIM(Agents_1.DESCN) <> 'Openwork' --exclude all Openwork clawback

ORDER BY [Franchise Code], [Franchise]

SELECT 
     [Franchise Code]
   , [Franchise]
   , ISNULL(SUM(ISNULL(CAST([OutstandingClawbackLess90] AS DECIMAL(15,2)), 0.00)), 0.00) AS [OutstandingClawbackLess90]
   , ISNULL(SUM(ISNULL(CAST([OutstandingClawback90to365] AS DECIMAL(15,2)), 0.00)), 0.00) AS [OutstandingClawback90to365]
   , ISNULL(SUM(ISNULL(CAST([OutstandingClawbackMore365] AS DECIMAL(15,2)), 0.00)), 0.00) AS [OutstandingClawbackMore365]
   , ISNULL(SUM(ISNULL(CAST([OutstandingClawbackTotal] AS DECIMAL(15,2)), 0.00)), 0.00) AS [OutstandingClawbackTotal]
   , [Error]
FROM  #FINSTAT0034c
GROUP BY [Franchise Code], [Franchise], [Error]
ORDER BY [Franchise Code], [Franchise]

DROP TABLE #FINSTAT0034c

GO
