CREATE PROCEDURE [dbo].[cscp_FINSTAT0036a] @UserID VARCHAR(255), @SoldType VARCHAR(10),@StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

/*
  RH 19 Feb 2007
  Swift SR6 introduces new Status value of 3
  Need to pick this up as well as 2

*/

IF ISDATE(@StartDate) = 0 Or ISDATE(@EndDate) = 0
BEGIN
  SELECT 
      NULL AS [Type of DA]
    , NULL AS [Amount Due]
    , NULL AS [Amount Rec]
    , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
           WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
      END AS [Error]
   RETURN 0
END

IF (CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
BEGIN
  SELECT 
      NULL AS [Type of DA]
    , NULL AS [Amount Due]
    , NULL AS [Amount Rec]
    , 'Start Date cannot be greater than End Date' AS [Error]
   RETURN 0
END

SELECT DISTINCT 
      ExpectationMain.Type AS 'Type'

   ,  ISNULL(ExpectationMain.Type_Description, 'Unknown') AS 'Type of DA'

   , (SELECT ISNULL(SUM(ISNULL(CAST((Expectation.AMOUNT_DUE) AS DECIMAL(15,2)), 0.00)), 0.00)  
      FROM mstt_Expectation Expectation
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
         INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
         INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
      WHERE Expectation.DATE_RECV IS NOT NULL
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)
      AND Expectation.Status in(2,3)
      AND Expectation.Adjust = 2    
      AND ( ((@SoldType = 'T' OR @SoldType = 'F' OR @SoldType = 'L') AND PolicyTransactions.CommType = @SoldType) OR
            (@SoldType = 'A') ) --ALL Sold Types
      AND Expectation.Type = ExpectationMain.Type 
     ) AS 'Amount Due'

   , (SELECT ISNULL(SUM(ISNULL(CAST((Expectation.AMOUNT_REC) AS DECIMAL(15,2)), 0.00)), 0.00)  
      FROM mstt_Expectation Expectation
         INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
         INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
         INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
      WHERE Expectation.DATE_RECV IS NOT NULL
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)
      AND Expectation.Status in(2,3)
      AND Expectation.Adjust = 2    
      AND ( ((@SoldType = 'T' OR @SoldType = 'F' OR @SoldType = 'L') AND PolicyTransactions.CommType = @SoldType) OR
            (@SoldType = 'A') ) --ALL Sold Types
      AND Expectation.Type = ExpectationMain.Type 
     ) AS 'Amount Rec'

   , NULL AS [Error]

FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN mstt_Expectation ExpectationMain ON ExpectationMain.TransactionID = PolicyTransactions.ID
INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business

WHERE (ExpectationMain.Type NOT IN (3,5,6,7,8,9,11,12,13,14)
       OR ExpectationMain.Type IS NULL)
AND ExpectationMain.DATE_RECV IS NOT NULL
AND CAST(CONVERT(NVARCHAR, ExpectationMain.DATE_RECV, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
AND CAST(CONVERT(NVARCHAR, ExpectationMain.DATE_RECV, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)
AND ExpectationMain.Status in (2,3)
AND ExpectationMain.Adjust = 2    
AND ( ((@SoldType = 'T' OR @SoldType = 'F' OR @SoldType = 'L') AND PolicyTransactions.CommType = @SoldType) OR
      (@SoldType = 'A') ) --ALL Sold Types

ORDER BY [Type]


GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0036b]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[cscp_FINSTAT0036b] @UserID VARCHAR(255), @SoldType VARCHAR(10), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

/*
  RH 19 Feb 2007
  Swift SR6 introduces new Status value of 3
  Need to pick this up as well as 2 when we look at status 2
  
  Change is made to function rather than this proc

*/


IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
   SELECT 
      NULL AS [Status at present]
    , NULL AS [Type of DA]
    , NULL AS [Amount Due]
    , NULL AS [Amount Rec]
    , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
           WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
      END AS [Error]
   RETURN 0
END

IF (CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
BEGIN
  SELECT 
      NULL AS [Status at present]
    , NULL AS [Type of DA]
    , NULL AS [Amount Due]
    , NULL AS [Amount Rec]
    , 'Start Date cannot be greater than End Date' AS [Error]
   RETURN 0
END

SELECT 
     'Due and not adjusted' AS 'Status at present'
   , Type AS Type
   , DAType AS 'Type of DA'
   , AmtDue AS 'Amount Due'
   , AmtRec AS 'Amount Rec'
   , NULL AS 'Error'
FROM DBO.cscf_DADifference(@SoldType, @StartDate, @EndDate, 1, 0)
UNION ALL
SELECT 
     'Due and adjusted' AS 'Status at present'
   , Type AS Type
   , DAType AS 'Type of DA'
   , AmtDue AS 'Amount Due'
   , AmtRec AS 'Amount Rec'
   , NULL AS 'Error'
FROM DBO.cscf_DADifference(@SoldType, @StartDate, @EndDate, 1, 1)
UNION ALL
SELECT 
     'Received and not adjusted' AS 'Status at present'
   , Type AS Type
   , DAType AS 'Type of DA'
   , AmtDue AS 'Amount Due'
   , AmtRec AS 'Amount Rec'
   , NULL AS 'Error'
FROM DBO.cscf_DADifference(@SoldType, @StartDate, @EndDate, 2, 0)
UNION ALL
SELECT 
     'Received and adjusted' AS 'Status at present'
   , Type AS Type
   , DAType AS 'Type of DA'
   , AmtDue AS 'Amount Due'
   , AmtRec AS 'Amount Rec'
   , NULL AS 'Error'
FROM DBO.cscf_DADifference(@SoldType, @StartDate, @EndDate, 2, 1)
UNION ALL
SELECT 
     'Received, adjusted & reconciled' AS 'Status at present'
   , Type AS Type
   , DAType AS 'Type of DA'
   , AmtDue AS 'Amount Due'
   , AmtRec AS 'Amount Rec'
   , NULL AS 'Error'
FROM DBO.cscf_DADifference(@SoldType, @StartDate, @EndDate, 2, 2)

ORDER BY Type


GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT0037]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
