GO


CREATE   PROCEDURE [dbo].[cscp_FINSTAT0037] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

----------------------------------------------------------------------------------------------------------------
-- Report name: FINSTAT0037 - Practice Asset Unwind and Agency Period Sales
-- Brief desc: This report will provide the ability to account for Openwork Access Limited (OAL) 
--             and Access Franchise Management Limited (AFML)
-- Author(s): John Petchey (CSC)
-- Parameter(s): 1) UserId
--               2) Opening date
--               3) Closing date
-- Outstanding Issue(s): None
----------------------------------------------------------------------------------------------------------------

/*
  RH 19 Feb 2007
  Swift SR6 introduces new Status value of 3
  Need to pick this up as well as 2

*/


-- ************************ to execute (e.g.): *****************
--SET DATEFORMAT dmy
--EXEC cscp_FINSTAT0037 'JNP', '01/01/2006', '01/10/2006'
-- ************************ to execute (e.g.): ******************************

--declare @StartDate datetime
--declare @EndDate datetime
--set @StartDate = '01 Sep 2006'
--set @EndDate = '30 Sep 2006'

DECLARE @OWDate DATETIME
SET @OWDate = '1 Jun 2005'

--5.1 Derive Access Agent List
select Code as AccessAgentCode, 
  MCVDate,
  isnull(TradingName, Descn) as AccessAgentName
into #AccessAgents  
from mstt_Agents
where AgentType = 46
and CompetentStatus in (1,2)

--select * from #AccessAgents order by mcvdate

--5.2 Derive Access Sellers List
select ahh.AgentCode as SellerCode,
  aa.AccessAgentCode,
  min(StartDate) as AccessStartDate,
  max(EndDate) as AccessEndDate 
into #AccessSellers
from msit_AgentHierarchyHistory ahh
  inner join #AccessAgents aa
    on ahh.DetailAgentCode = aa.AccessAgentCode
where ahh.DefaultValue = 1
and ahh.ParticipantType = 9
group by ahh.AgentCode, aa.AccessAgentCode

--5.3 Derive Seller Previous Business
select sub.SellerCode,
  ahh.DetailAgentCode as PreviousBusiness
into #AccessPreviousBusiness
from msit_AgentHierarchyHistory ahh
  inner join 
    (select ahh1.AgentCode as SellerCode,
      ahh1.ParticipantType,
      max(ahh1.EndDate) as MaxEndDate
    from msit_AgentHierarchyHistory ahh1
      inner join #AccessSellers acs
        on ahh1.AgentCode = acs.SellerCode
    where ahh1.EndDate is not null
    and ahh1.EndDate < acs.AccessStartDate    
    and ahh1.ParticipantType in (6,7,8)
    group by ahh1.AgentCode,
      ahh1.ParticipantType) as sub
  on ahh.AgentCode = sub.SellerCode
  and ahh.ParticipantType = sub.ParticipantType
  and ahh.EndDate = sub.MaxEndDate
--where ahh.DefaultValue = 1

--Combine all these
select aa.AccessAgentCode,
  aa.AccessAgentName,
  aa.MCVDate,
  acs.SellerCode,
  acs.AccessStartDate,
  acs.AccessEndDate,
  apb.PreviousBusiness
into #AccessDetails
from #AccessSellers acs
  left join #AccessAgents aa
    on acs.AccessAgentCode = aa.AccessAgentCode
  left join #AccessPreviousBusiness apb
    on acs.SellerCode = apb.SellerCode

--select * from #AccessDetails

--5.4 Derive Active Transaction List
select e.TransactionId,
  min(e.Date_recv) as IncomeRecognitionDate
into #ActiveTransactionList
from mstt_Expectation e
  inner join mstt_Commissions c
    on e.TransactionId = c.TransactionId
where e.Status in(2,3)
and 
(c.Agent_Code = '10005'
  or exists (select 'x' 
    from #AccessDetails ad 
    where c.AccessAgentCode = ad.AccessAgentCode 
    and c.Agent_Code = ad.SellerCode
    and c.TransactionDate > ad.MCVDate)
  or exists (select 'x' 
    from #AccessDetails ad 
    where coalesce(c.FranchiseAgentCode, c.DirectlyAuthorisedAgentCode) = ad.PreviousBusiness 
    and c.Agent_Code = ad.SellerCode
    and c.TransactionDate > ad.MCVDate))
group by e.TransactionId
having min(e.Date_recv) --(Income Recognition Date)
   < getdate()

--5.5 Select Bonus Payments
select pp.Agent_Code as BusinessCode,
  aa.AccessAgentName as BusinessName,
  coalesce(nullif(pp.DUE_DATE, '31 Dec 1899'), pp.PaymentDueDate, pp.CreateDateTime) as DueDate,
  case when aa.MCVDate <= @OWDate -- < '01 Jun 2005' 
    then 'AFML' 
    else 'OAL' 
  end as Company,
  case when coalesce(nullif(pp.DUE_DATE, '31 Dec 1899'), pp.PaymentDueDate, pp.CreateDateTime) >= aa.MCVDate 
    then 'Agency Period Sales' 
    else 'Agency Period Sales' 
  end as ReportType,
  pp.CommissionTypeDesc as CommissionType,
  pp.Amount as [Commission/Fee],
  ap.Export_Date as PaidViaBACS,
  aa.MCVDate
into #BonusPayments
from mstt_PaymentsPending pp
  inner join #AccessAgents aa
    on pp.Agent_Code = aa.AccessAgentCode
  left join mstt_AgentPayments ap
    on pp.ID = ap.AGMID
where pp.CommissionType = 20
and coalesce(nullif(pp.DUE_DATE, '31 Dec 1899'), pp.PaymentDueDate, pp.CreateDateTime) between @StartDate and @EndDate

--5.6 Select Expectations
select e.TransactionId, 
  e.Type, 
  atl.IncomeRecognitionDate, 
  e.Status, 
  e.id,
  e.Type_Description as CommissionType
into #ExpectationTransactions
from mstt_Expectation e
  inner join #ActiveTransactionList atl
    on e.TransactionId = atl.TransactionId
where e.Type in (1,2,4,10,15,16,17,18,19)
and (e.Date_Recv between @StartDate and @EndDate
or e.Date_Due between @StartDate and @EndDate)

--5.6.2 Get Payments for the 'Status = 2 or 3' (matched) expectation records with entry on mstt_paymentspending
select e.TransactionId,
        e.ID as ExpID, 
  e.IncomeRecognitionDate, 
  p.Amount as [Commission/Fee],
  p.PACC_ID,
  p.Agent_Code,
  p.AccessAgentCode,
  e.Type as CommTypeCode,
  e.CommissionType,
  case 
    when p.Agent_Code = '10005' then p.Agent_Code
    when p.AccessAgentCode in (select distinct AccessAgentCode from #AccessAgents) then p.AccessAgentCode
    when p.Agent_Code in (select distinct SellerCode from #AccessSellers) 
      and coalesce(nullif(p.FranchiseAgentCode, ''), 
          nullif(p.DirectlyAuthorisedAgentCode, '')) in 
          (select distinct PreviousBusiness from #AccessPreviousBusiness) 
          then coalesce(nullif(p.FranchiseAgentCode, ''), 
            nullif(p.DirectlyAuthorisedAgentCode, ''))
  else null
  end as BusinessCode,
  cast(null as varchar(255)) as BusinessName,
  cast(null as datetime) as DueDate,
  cast(null as varchar(255)) as Company,
  cast(null as varchar(255)) as ReportType,
  --cast(null as varchar(255)) as CommissionType,
  cast(null as varchar(255)) as [Regular/Single],
  cast('Unknown' as varchar(255)) as ProductSubGroup,
  cast(null as varchar(255)) as CommissionBasis,
  cast(null as datetime) as PaidViaBACS,
  cast(null as DateTime) as MCVDate
into #PaidTransactions
from #ExpectationTransactions e
  inner join mstt_PaymentsPending p
    on e.id = p.PACC_ID
  --inner join mstt_Commissions c
  --  on e.TransactionId = c.TransactionId
  --  and p.Agent_Code = c.Agent_Code
  --  and e.Type = c.CommissionType
where p.Agent_Code not in ('10002','10004')
and (case 
    when p.Agent_Code = '10005' then p.Agent_Code
    when p.AccessAgentCode in (select distinct AccessAgentCode from #AccessAgents) then p.AccessAgentCode
    when p.Agent_Code in (select distinct SellerCode from #AccessSellers) 
      and coalesce(nullif(p.FranchiseAgentCode, ''), 
          nullif(p.DirectlyAuthorisedAgentCode, '')) in 
          (select distinct PreviousBusiness from #AccessPreviousBusiness) 
          then coalesce(nullif(p.FranchiseAgentCode, ''), 
            nullif(p.DirectlyAuthorisedAgentCode, ''))
  else null
  end) is not NULL

--Jump now to 5.6.6 to fill in columns for PaidTransactions
-- 5.6.6  Get Other Fields
--Get Business Name
update pt
set BusinessName = isnull(a.TradingName, a.Descn)
from #PaidTransactions pt
  inner join mstt_Agents a
    on pt.BusinessCode = a.Code
where BusinessCode is not null

--Get DueDate
update pt
set DueDate = e.Date_Due
from #PaidTransactions pt
  inner join mstt_Expectation e
                on pt.pacc_id = e.id
--    on pt.TransactionId = e.TransactionId
--    and pt.CommTypeCode = e.Type

--Get Company
update pt
set Company = case 
        when exists (select 'x' 
        from #AccessDetails ad
        where pt.BusinessCode = isnull(ad.PreviousBusiness,'x')
        and ad.MCVDate <= @OWDate) then 'AFML'
--        and ad.MCVDate < '01 Jun 2005') then 'AFML'
        when exists (select 'x' 
        from #AccessAgents aa
        where pt.BusinessCode = aa.AccessAgentCode
        and aa.MCVDate <= @OWDate) then 'AFML'
--        and aa.MCVDate < '01 Jun 2005') then 'AFML'
    else 'OAL' end
from #PaidTransactions pt

--Get ReportType
update pt
set pt.ReportType = 'Agency Period Sales'
from #PaidTransactions pt
  inner join #AccessAgents aa
    on pt.BusinessCode = aa.AccessAgentCode
    
update pt
--set ReportType = case when res.IncomeRecognitionDate >= ad.MCVDate then 'Agency Period Sales' else 'Practice Asset Unwind' end
set pt.ReportType = 'Practice Asset Unwind'
from #PaidTransactions pt
  inner join #AccessDetails ad
    on pt.BusinessCode = ad.PreviousBusiness
        inner join mstt_Expectation ex on ex.ID = pt.PACC_ID
where pt.ReportType is null
and isnull(ex.DATE_RECV,'1901/01/01') >= ad.MCVDate

update pt
set ReportType = 'Practice Asset Unwind'
from #PaidTransactions pt
where ReportType is null and Agent_Code = 10005

--Get CommissionType
--update pt
--set CommissionType = e.Type_Description
--from #PaidTransactions pt
--  inner join mstt_Expectation e
--    on pt.TransactionId = e.TransactionId 
--    and pt.CommTypeCode = e.Type  


--Get [Regular/Single]
update pt
set [Regular/Single] = case when ptrans.Frequency = 6 then 'Single' else 'Regular' end
from #PaidTransactions pt
  inner join mstt_PolicyTransactions ptrans
    on pt.TransactionId = ptrans.Id

--Get ProductSubGroup
update pt
set ProductSubGroup = cpsg.ProductSubGroupName
from #PaidTransactions pt
  inner join mstt_Commissions c
    on pt.TransactionId = c.TransactionId
  inner join msit_CodeProductSubGroup cpsg
    on c.ProductSubGroupCode = cpsg.Code

--Get CommissionBasis
update pt
set CommissionBasis = ptrans.CommissionTypeDesc
from #PaidTransactions pt
  inner join mstt_Expectation e
    on pt.TransactionId = e.TransactionId
    and pt.CommTypeCode = e.Type  
  inner join mstt_PolicyTransactions ptrans
    on pt.TransactionId = ptrans.id
where e.Type in (1,2,17)    

--Get PaidViaBACS 
update pt
set PaidViaBACS = ap.Export_Date
from #PaidTransactions pt
--  inner join mstt_Expectation e
--
--    on pt.TransactionId = e.TransactionId
--    and pt.CommTypeCode = e.Type  
  inner join mstt_PaymentsPending pp
    on pt.TransactionId = pp.TransactionId
    and pt.PACC_ID = pp.PACC_ID
                and pt.Agent_Code = pp.Agent_Code
  inner join mstt_AgentPayments ap
    on pp.ID = ap.AGMID
--  inner join mstt_Commissions c
--    on pp.Agent_Code = c.Agent_Code
--    and pp.TransactionId = c.TransactionId

--Get MCVDate
update pt
set MCVDate = aa.MCVDate
from #PaidTransactions pt
  inner join #AccessAgents aa
    on pt.BusinessCode = aa.AccessAgentCode

update pt
set MCVDate = ad.MCVDate
from #PaidTransactions pt
  inner join #AccessDetails ad
    on pt.BusinessCode = ad.PreviousBusiness
where pt.MCVDate is null

--This section below is now about finding the expectations that do not have an associated payment, OR 
--are expectation status of 1

--5.6.3 Split each Expectation 
select et.TransactionId,
        et.ID,
  et.IncomeRecognitionDate,
  c.Agent_Code,
  c.AccessAgentCode,
  c.CommissionType,
  coalesce(c.AccessAgentCode, c.FranchiseAgentCode, c.DirectlyAuthorisedAgentCode) as Firm,
  --sum(c.FixedAmount) as TransactionDA
  case 
    when c.CommissionType = 1 and c.DistributionAllowance > 0 
      then c.FixedAmount / c.DistributionAllowance
  else c.Agent_Perc / 100
  end as AgentSplit
into #ExpectationSplits
from #ExpectationTransactions et
  inner join mstt_Commissions c
    on et.TransactionId = c.TransactionId
    and et.Type = c.CommissionType
where ((c.CommissionType = 1 and et.Type in (1,2,17))
or (c.CommissionType = 4 and et.Type in (4,16,18))
or (c.CommissionType = 10 and et.Type in (10,17,19)))
and c.Agent_Code not in ('10002', '10004')
and (not exists (select 'x' from #PaidTransactions pt
        where et.TransactionId = pt.TransactionId)
  or et.Status = 1)
        
--5.6.4 For each split determine if it is relevant for the Report 
select es.TransactionId,
        es.ID,
  es.IncomeRecognitionDate,
        es.Agent_Code,
  case 
    when es.Agent_Code = '10005' then es.Agent_Code
    when es.AccessAgentCode in (select distinct AccessAgentCode from #AccessAgents) then es.AccessAgentCode
    when es.Agent_Code in (select distinct SellerCode from #AccessSellers) 
      and es.Firm in (select distinct PreviousBusiness from #AccessPreviousBusiness) then es.Firm
  else null
  end as BusinessCode,
  es.AgentSplit,
  es.CommissionType as CommTypeCode,
  cast(000.00000 as Float) as [Commission/Fee],
  cast(null as varchar(255)) as BusinessName,
  cast(null as datetime) as DueDate,
  cast(null as varchar(255)) as Company,
  cast(null as varchar(255)) as ReportType,
  cast(null as varchar(255)) as CommissionType,
  cast(null as varchar(255)) as [Regular/Single],
  cast('Unknown' as varchar(255)) as ProductSubGroup,
  cast(null as varchar(255)) as CommissionBasis,
  cast(null as datetime) as PaidViaBACS,
  cast(null as DateTime) as MCVDate
into #RelevantExpectationSplits
from #ExpectationSplits es
where (case 
    when es.Agent_Code = '10005' then es.Agent_Code
    when es.AccessAgentCode in (select distinct AccessAgentCode from #AccessAgents) then es.AccessAgentCode
    when es.Agent_Code in (select distinct SellerCode from #AccessSellers) 
      and es.Firm in (select distinct PreviousBusiness from #AccessPreviousBusiness) then es.Firm
  else null
  end) is not null

--select * from #RelevantExpectationSplits

--5.6.5 If BusinessCode has been populated for the split then derive the Commission/Fee 
update res
set [Commission/Fee] = case 
        when e.Status in(2,3) then e.Amount_Rec
        when e.Status = 1 then e.Amount_Due
      end 
      *
      res.AgentSplit
from #RelevantExpectationSplits res
  inner join mstt_Expectation e
    on res.TransactionId = e.TransactionId
    and res.CommTypeCode = e.Type
  inner join mstt_Commissions c
    on res.TransactionId = c.TransactionId
    and res.CommTypeCode = c.CommissionType
where BusinessCode is not null
and isnull(res.AgentSplit,0) <> 0

-- 5.6.6  Get Other Fields
--Get Business Name
update res
set BusinessName = isnull(a.TradingName, a.Descn)
from #RelevantExpectationSplits res
  inner join mstt_Agents a
    on res.BusinessCode = a.Code
where BusinessCode is not null

--Get DueDate
update res
set DueDate = e.Date_Due
from #RelevantExpectationSplits res
  inner join mstt_Expectation e
                on res.ID = e.ID
--    on res.TransactionId = e.TransactionId
--    and res.CommTypeCode = e.Type

--Get Company
update res
set Company = case 
        when exists (select 'x' 
        from #AccessDetails ad
        where res.BusinessCode = isnull(ad.PreviousBusiness,'x')
        and ad.MCVDate <= @OWDate) then 'AFML'
--        and ad.MCVDate < '01 Jun 2005') then 'AFML'
        when exists (select 'x' 
        from #AccessAgents aa
        where res.BusinessCode = aa.AccessAgentCode
        and aa.MCVDate <= @OWDate) then 'AFML'
--        and aa.MCVDate < '01 Jun 2005') then 'AFML'
    else 'OAL' end
from #RelevantExpectationSplits res

--Get ReportType
update res
--set ReportType = case when res.IncomeRecognitionDate >= aa.MCVDate then 'Agency Period Sales' else 'Practice Asset Unwind' end
set ReportType = 'Agency Period Sales'
from #RelevantExpectationSplits res
  inner join #AccessAgents aa
    on res.BusinessCode = aa.AccessAgentCode
    
update res
--set ReportType = case when res.IncomeRecognitionDate >= ad.MCVDate then 'Agency Period Sales' else 'Practice Asset Unwind' end
set ReportType = 'Practice Asset Unwind'
from #RelevantExpectationSplits res
  inner join #AccessDetails ad
    on res.BusinessCode = ad.PreviousBusiness
        inner join mstt_Expectation ex on ex.ID = res.ID
where ReportType is null
and isnull(ex.DATE_RECV,'1901/01/01') >= ad.MCVDate

update res
set ReportType = 'Practice Asset Unwind'
from #RelevantExpectationSplits res
where ReportType is null and Agent_Code = 10005

--Get CommissionType
update res
set CommissionType = e.Type_Description
from #RelevantExpectationSplits res
  inner join mstt_Expectation e
                on res.ID = e.ID
--    on res.TransactionId = e.TransactionId  
--    and res.CommTypeCode = e.Type 


--Get [Regular/Single]
update res
set [Regular/Single] = case when pt.Frequency = 6 then 'Single' else 'Regular' end
from #RelevantExpectationSplits res
  inner join mstt_PolicyTransactions pt
    on res.TransactionId = pt.Id

--Get ProductSubGroup
update res
set ProductSubGroup = cpsg.ProductSubGroupName
from #RelevantExpectationSplits res
  inner join mstt_Commissions c
    on res.TransactionId = c.TransactionId
  inner join msit_CodeProductSubGroup cpsg
    on c.ProductSubGroupCode = cpsg.Code


--Get CommissionBasis
update res
set CommissionBasis = pt.CommissionTypeDesc
from #RelevantExpectationSplits res
  inner join mstt_Expectation e
    on res.TransactionId = e.TransactionId
    and res.CommTypeCode = e.Type 
  inner join mstt_PolicyTransactions pt
    on e.TransactionId = pt.id
where e.Type in (1,2,17)  

--Get PaidViaBACS 
update res
set PaidViaBACS = ap.Export_Date
from #RelevantExpectationSplits res
--  inner join mstt_Expectation e
--    on res.TransactionId = e.TransactionId
--    and res.CommTypeCode = e.Type 
  inner join mstt_PaymentsPending pp
                on res.ID = pp.ID
                and res.Agent_Code = pp.Agent_Code
--    on e.TransactionId = pp.TransactionId
--    and e.ID = pp.PACC_ID
  inner join mstt_AgentPayments ap
    on pp.ID = ap.AGMID
--  inner join mstt_Commissions c
--    on pp.Agent_Code = c.Agent_Code
--    and pp.TransactionId = c.TransactionId

--Get MCVDate
update res
set MCVDate = aa.MCVDate
from #RelevantExpectationSplits res
  inner join #AccessAgents aa
    on res.BusinessCode = aa.AccessAgentCode

update res
set MCVDate = ad.MCVDate
from #RelevantExpectationSplits res
  inner join #AccessDetails ad
    on res.BusinessCode = ad.PreviousBusiness


--5.7 Display Report
--/*
select 
  case 
    when Company = 'AFML' and ReportType = 'Practice Asset Unwind' then 1
    when Company = 'AFML' and ReportType = 'Agency Period Sales' then 2
    when Company = 'OAL' and ReportType = 'Practice Asset Unwind' then 3
    when Company = 'OAL' and ReportType = 'Agency Period Sales' then 4
  end as Seq,
  Company,
  ReportType,
  BusinessCode, 
  BusinessName, 
  --IncomeRecognitionDate,
  [Regular/Single], 
  CommissionType,
  CommissionBasis, 
  PaidViaBACS,  
  ProductSubGroup,
  [Commission/Fee],
  --MCVDate,
  --DueDate,
  null as Error
from #RelevantExpectationSplits
where isnull([Commission/Fee],0) <> 0
and BusinessCode is not null
union all
--*/
select 
  case 
    when Company = 'AFML' and ReportType = 'Practice Asset Unwind' then 1
    when Company = 'AFML' and ReportType = 'Agency Period Sales' then 2
    when Company = 'OAL' and ReportType = 'Practice Asset Unwind' then 3
    when Company = 'OAL' and ReportType = 'Agency Period Sales' then 4
  end as Seq,
  Company,
  ReportType,
  BusinessCode, 
  BusinessName, 
  --IncomeRecognitionDate,
  [Regular/Single], 
  CommissionType,
  CommissionBasis, 
  PaidViaBACS,  
  ProductSubGroup,
  [Commission/Fee],
  --MCVDate,
  --DueDate,
  null as Error
from #PaidTransactions
where isnull([Commission/Fee],0) <> 0
and BusinessCode is not null
union all 
select 
  case 
    when Company = 'AFML' and ReportType = 'Practice Asset Unwind' then 1
    when Company = 'AFML' and ReportType = 'Agency Period Sales' then 2
    when Company = 'OAL' and ReportType = 'Practice Asset Unwind' then 3
    when Company = 'OAL' and ReportType = 'Agency Period Sales' then 4
  end as Seq,
  Company,
  ReportType,
  BusinessCode, 
  BusinessName, 
  --null as IncomeRecognitionDate,
  null as [Regular/Single], 
  CommissionType,
  null as CommissionBasis, 
  PaidViaBACS,  
  null as ProductSubGroup,
  [Commission/Fee],
  --MCVDate,
  --DueDate,
  null as Error
from #BonusPayments
where isnull([Commission/Fee],0) <> 0
and BusinessCode is not null
order by 1,2,3 desc, 4, 10, 9, 6, 5 --5.7.1


drop table #AccessAgents
drop table #AccessSellers
drop table #AccessPreviousBusiness
drop table #AccessDetails
drop table #ActiveTransactionList
drop table #BonusPayments
drop table #ExpectationTransactions
--drop table #ExpectationSplits
drop table #PaidTransactions
--drop table #RelevantExpectationSplits


/*

IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
   SELECT 
      NULL AS [Seq],
      NULL AS [Section],
      NULL AS [Franchise Code],
      NULL AS [Franchise],
      NULL AS [RegularSingle],
      NULL AS [ProdSubGroup],
      NULL AS [CommissionType],
      NULL AS [CommissionFee],
      CASE 
         WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Opening Date Entered. Please enter it in the format dd/mm/yyyy'
         WHEN ISDATE(@EndDate) = 0 THEN  'Invalid Closing Date Entered. Please enter it in the format dd/mm/yyyy.'           
      END AS [Error]
   RETURN 0
END

-- Select all of the data into a temporary table
IF OBJECT_ID('tempdb..#FINSTAT0037') IS NOT NULL
   DROP TABLE #FINSTAT0037

SELECT CASE 
          WHEN Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' THEN Agents_fr.Code
          ELSE Agents.Code 
       END AS 'Franchise Code',
       CASE 
          WHEN Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' THEN RTRIM(ISNULL(Agents_fr.DESCN, 'Unknown')) 
          ELSE RTRIM(ISNULL(Agents.DESCN, 'Unknown')) 
       END AS [Franchise],
       CASE 
          WHEN Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' THEN Agents_fr.MCVDate
          ELSE Agents.MCVDate
       END AS [MCVDate],
       PolicyTransactions39.TransactionDate AS [WrittenDate],
       CASE 
          WHEN PolicyTransactions39.Frequency IS NULL THEN 'Unknown'
          WHEN PolicyTransactions39.Frequency = 6 THEN 'Single'
          ELSE 'Regular'
       END AS [RegularSingle],
       ISNULL(CodeProductSubGroup.ProductSubGroupName, 'Unknown') AS [ProdSubGroup],
       ISNULL(Expectation.Type_Description, 'Unknown') AS [CommissionType],
       CASE
          WHEN Expectation.Type IN (2, 15, 16, 17, 18, 19) THEN ISNULL(dbo.cscf_CalcCommissionDue(Expectation.ID), 0) * (-1)
          ELSE ISNULL(dbo.cscf_CalcCommissionDue(Expectation.ID), 0)
       END AS [CommissionFee],
       NULL AS [Error]
INTO #FINSTAT0037
FROM mstt_Expectation Expectation
INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
LEFT JOIN mstt_CodeProductSubGroup CodeProductSubGroup ON Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode
INNER JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
INNER JOIN mstt_Agents Agents_fr ON Agents.Firm = Agents_fr.CODE
INNER JOIN mstt_PolicyTransactions PolicyTransactions39 ON PolicyTransactions39.PolicyID = PolicyTransactions.PolicyID AND PolicyTransactions39.TransType = 39
WHERE (Expectation.Type NOT IN (3,5,6,7,8,9,11,12,13,14)
       OR Expectation.Type IS NULL)
  AND (Agents.Firm IS NOT NULL AND RTRIM(Agents.Firm) <> '' AND Agents_fr.AgentType = 46
       OR (Agents.Firm IS NULL OR RTRIM(Agents.Firm) = '') AND Agents.AgentType = 46)
  AND Expectation.DATE_DUE IS NOT NULL
  AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
ORDER BY [Franchise Code], [Franchise], [RegularSingle], [ProdSubGroup], [CommissionType]

DECLARE @OWDate DATETIME
SET @OWDate = '01/06/2005'

-- Section 1: Extract the 'AFML - Practice Asset Unwind' data from the temporary table
SELECT 1 AS [Seq],
       'AFML - Practice Asset Unwind' AS [Section],
       [Franchise Code],
       Franchise,
       RegularSingle,
       ProdSubGroup,
       CommissionType,
       ISNULL(SUM(ISNULL(CAST(CommissionFee AS DECIMAL(15,2)), 0.00)), 0.00) AS [CommissionFee],
       NULL AS [Error]
FROM #FINSTAT0037 FINSTAT0037
WHERE CAST(CONVERT(NVARCHAR, WrittenDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, MCVDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, MCVDate, 112) AS DATETIME) < CAST(CONVERT(NVARCHAR, @OWDate, 112) AS DATETIME) 
  AND CommissionFee <> 0.00
GROUP BY [Franchise Code], Franchise, RegularSingle, ProdSubGroup, CommissionType

UNION ALL

-- Section 2: Extract the 'AFML - Agency Period Sales' data from the temporary table
SELECT 2 AS [Seq],
       'AFML - Agency Period Sales' AS [Section],
       [Franchise Code],
       Franchise,
       RegularSingle,
       ProdSubGroup,
       CommissionType,
       ISNULL(SUM(ISNULL(CAST(CommissionFee AS DECIMAL(15,2)), 0.00)), 0.00) AS [CommissionFee],
       NULL AS [Error]
FROM #FINSTAT0037 FINSTAT0037
WHERE CAST(CONVERT(NVARCHAR, WrittenDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, MCVDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, MCVDate, 112) AS DATETIME) < CAST(CONVERT(NVARCHAR, @OWDate, 112) AS DATETIME) 
  AND CommissionFee <> 0.00
GROUP BY [Franchise Code], Franchise, RegularSingle, ProdSubGroup, CommissionType

UNION ALL

-- Section 3: Extract the 'OAL - Practice Asset Unwind' data from the temporary table
SELECT 3 AS [Seq],
       'OAL - Practice Asset Unwind' AS [Section],
       [Franchise Code],
       Franchise,
       RegularSingle,
       ProdSubGroup,
       CommissionType,
       ISNULL(SUM(ISNULL(CAST(CommissionFee AS DECIMAL(15,2)), 0.00)), 0.00) AS [CommissionFee],
       NULL AS [Error]
FROM #FINSTAT0037 FINSTAT0037
WHERE CAST(CONVERT(NVARCHAR, WrittenDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, MCVDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, MCVDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @OWDate, 112) AS DATETIME) 
  AND CommissionFee <> 0.00
GROUP BY [Franchise Code], Franchise, RegularSingle, ProdSubGroup, CommissionType

UNION ALL

-- Section 4: Extract the 'OAL - Agency Period Sales' data from the temporary table
SELECT 4 AS [Seq],
       'OAL - Agency Period Sales' AS [Section],
       [Franchise Code],
       Franchise,
       RegularSingle,
       ProdSubGroup,
       CommissionType,
       ISNULL(SUM(ISNULL(CAST(CommissionFee AS DECIMAL(15,2)), 0.00)), 0.00) AS [CommissionFee],
       NULL AS [Error]
FROM #FINSTAT0037
WHERE CAST(CONVERT(NVARCHAR, WrittenDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, MCVDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, MCVDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @OWDate, 112) AS DATETIME) 
  AND CommissionFee <> 0.00
GROUP BY [Franchise Code], Franchise, RegularSingle, ProdSubGroup, CommissionType

ORDER BY [Seq], [Franchise Code], [Franchise], [RegularSingle], [ProdSubGroup], [CommissionType]

-- 6. Tidy up
DROP TABLE #FINSTAT0037

*/


GO
/****** Object:  StoredProcedure [dbo].[cscp_FINSTAT00HT]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_FINSTAT00HT] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

-- 1. Input date validation
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
   SELECT 
      NULL AS [Section],
      NULL AS [Description],
      NULL AS [Opening],
      NULL AS [Movement],
      NULL AS [Closing],
      NULL AS [PLControlBalance],
      CASE 
         WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
         WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
      END AS [Error]
   RETURN 0
END

-- 2. convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

-- 3. Extract Expectation data into a temp table
IF OBJECT_ID('tempdb..#FINSTAT0028aExpectation') IS NOT NULL
   DROP TABLE #FINSTAT0028aExpectation

SELECT Expectation.ID, 
       Expectation.Type,
       Expectation.TransactionID,
       ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) AS Amount_Due,
       ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) AS Amount_Rec,
       dbo.cscf_CalcMarginPercent(Expectation.ID) AS Margin_Pct,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Rec,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Rec,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) AS Date_Due,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #FINSTAT0028aExpectation
FROM mstt_Expectation Expectation
   INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
   INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
   INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (1, 2, 4, 10, 15, 16, 17, 18, 19)       --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD    --of the temp table
       OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD   --by omitting data which
           AND Expectation.DATE_RECV IS NOT NULL))          --we KNOW we don't need
GROUP BY Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

-- 3.1 bypass Margin Calcs for margin and commission values to avoid calling cscf_CalcMarginPercent more than once per Expectation
UPDATE #FINSTAT0028aExpectation
SET Margin_Due = ISNULL(CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Due = ISNULL(CAST((Amount_Due - CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00),
    Margin_Rec = ISNULL(CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Rec = ISNULL(CAST((Amount_Rec - CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00)

CREATE CLUSTERED INDEX ind_FINSTAT0028 ON #FINSTAT0028aExpectation (ID, Type, TransactionID, Amount_Due, Amount_Rec, Margin_Pct, Margin_Due, Commission_Due, Margin_Rec, Commission_Rec, Date_Due, Date_Recv, IRD)

-- 4. Extract report data into a temp table
IF OBJECT_ID('tempdb..#FINSTAT0028a') IS NOT NULL
   DROP TABLE #FINSTAT0028a

-- 4.1 Distribution Allowance
SELECT 'Distribution Allowance' AS [Section],
       1 AS [Section Seq],
       CASE --Pad out each description to at least 7 chars (by adding trailing blanks) to avoid error in SRS
          WHEN LEN(Codes.Description) < 7 THEN Codes.Description + SPACE(7 - LEN(Codes.Description))
          ELSE Codes.Description
       END AS [Description],
       Codes.Code AS [Type],
       -- 4.1.1 Sub-query for Opening DA
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv < @OD
                   )
                  )

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv < @OD
                   )
                  ) * (-1)

                WHEN Codes.Code IN (5, 6) THEN -- Suspense
                  (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_Expectation AS Expect
                   WHERE Type = Codes.Code
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) < @OD
                     AND INIT_ID IS NULL
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Opening],
       -- 4.1.2 Sub-query for DA Movement
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  )

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)

                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  ) * (-1)

                WHEN Codes.Code IN (5, 6) THEN -- Suspense
                  (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_Expectation AS Expect
                   WHERE Type = Codes.Code
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) >= @OD
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) <= @CD
                     AND INIT_ID IS NULL
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Movement],
       -- 4.1.3 Sub-query for Closing DA
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv <= @CD
                   )
                  )

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Due IS NOT NULL
                      AND Date_Recv <= @CD
                   )
                  ) * (-1)

                WHEN Codes.Code IN (5, 6) THEN -- Suspense
                  (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_Expectation AS Expect
                   WHERE Type = Codes.Code
                     AND CAST(CONVERT(NVARCHAR, Date_Recv, 112) AS DATETIME) <= @CD
                     AND INIT_ID IS NULL
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Closing],
       CAST(NULL AS DECIMAL (15,2)) AS [PLControlBalance],
       NULL AS [Error]
INTO #FINSTAT0028a
FROM msit_MIWarehouseCodesAndDescriptions Codes
WHERE ColumnName = 'CommissionType'
  AND Codes.Code IN (1, 2, 4, 5, 6, 10, 15, 16, 17, 18, 19)

UNION ALL

-- 4.2 Non Openwork Ltd Commissions, Expenses & Charges
SELECT 'Non Openwork Ltd Commissions, Expenses & Charges' AS [Section],
       2 AS [Section Seq],
       CASE --Pad out each description to at least 7 chars (by adding trailing blanks) to avoid error in SRS
          WHEN LEN(Codes.Description) < 7 THEN Codes.Description + SPACE(7 - LEN(Codes.Description))
          ELSE Codes.Description
       END AS [Description],
       Codes.Code AS [Type],
       -- 4.2.1 Sub-query for Opening non-Openwork
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM mstt_AgentPayments AS AgPay
                    LEFT JOIN mstt_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.PaymentType = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) < @OD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Recv < @OD
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD < @OD
                      AND Date_Due < @OD
                      AND ((Date_Recv >= @OD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   ) * (-1)
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM mstt_AgentPayments AS AgPay
                    LEFT JOIN mstt_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.PaymentType = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) < @OD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code 
                     AND Agents.Descn <> 'Openwork'
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) < @OD
                     AND (CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) >= @OD
                       OR AgPay.Export_Date IS NULL)
                  ) * (-1)

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code 
                     AND Agents.Descn <> 'Openwork'
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) < @OD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) < @OD))
                     AND (CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) >= @OD
                       OR AgPay.Export_Date IS NULL)
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Opening],
       -- 4.2.2 Sub-query for non-Openwork Movement
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND Date_Recv <= @CD
                      AND Amount_Rec <> 0.00
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                            AND Date_Recv >= @OD
                           )
                        OR (IRD <= @CD
                            AND Date_Due > @CD
                            AND Date_Recv >= @OD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                      AND ((IRD >= @OD
                            AND IRD <= @CD
                            AND Date_Due <= @CD
                           )
                        OR (IRD < @OD
                            AND Date_Due >= @OD
                            AND Date_Due <= @CD
                           )
                          )
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                         - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND (IRD < @OD
                           AND Date_Due < @OD
                           AND Date_Recv >= @OD
                           AND Date_Recv <= @CD
                           AND Amount_Rec <> 0.00
                          )
                   )
                  )

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                  )

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) >= @OD))
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
                  )

                ELSE
                   0
             END
       ) AS [Movement],
       -- 4.2.3 Sub-query for Closing non-Openwork
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   )
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD  AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   )
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM mstt_AgentPayments AS AgPay
                    LEFT JOIN mstt_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.PaymentType = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) <= @CD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (2, 15, 16, 17, 18, 19) THEN -- Clawbacks & Adjustments
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Recv <= @CD
                   ) * (-1)
                   +
                   (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM #FINSTAT0028aExpectation AS Expect
                    WHERE Type = Codes.Code
                      AND IRD <= @CD
                      AND Date_Due <= @CD
                      AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
                   ) * (-1)
                   -
                   (SELECT ISNULL(SUM(ISNULL(CAST(AgPay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                    FROM mstt_AgentPayments AS AgPay
                    LEFT JOIN mstt_Agents AS Agents ON AgPay.Agent_Code = Agents.Code
                    WHERE AgPay.PaymentType = Codes.Code
                      AND CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) <= @CD
                      AND Agents.Descn <> 'Openwork'
                   )
                  ) * (-1)

                WHEN Codes.Code IN (8) THEN -- Standing Orders
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                     AND (CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) > @CD
                          OR AgPay.Export_Date IS NULL)
                  ) * (-1)

                WHEN Codes.Code IN (20) THEN -- Manual (Bonus Payments)
                  (SELECT ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
                   FROM mstt_PaymentsPending AS Pay
                   LEFT JOIN mstt_AgentPayments AS AgPay ON Pay.Id = AgPay.AgmId
                   LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
                   WHERE Pay.CommissionType = Codes.Code
                     AND Agents.Descn <> 'Openwork'
                     AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
                       OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
                     AND (CAST(CONVERT(NVARCHAR, AgPay.Export_Date, 112) AS DATETIME) > @CD
                          OR AgPay.Export_Date IS NULL)
                  ) * (-1)

                ELSE
                   0
             END
       ) AS [Closing],
       CAST(NULL AS DECIMAL (15,2)) AS [PLControlBalance],
       NULL AS [Error]
FROM msit_MIWarehouseCodesAndDescriptions Codes
WHERE ColumnName = 'CommissionType'
  AND Codes.Code IN (1, 2, 4, 8, 10, 15, 16, 17, 18, 19, 20)

UNION ALL

-- 4.3 Openwork Ltd Commissions, Expenses & Charges
SELECT 'Openwork Ltd Commissions, Expenses & Charges' AS [Section],
       3 AS [Section Seq],
       CASE --Pad out each description to at least 7 chars (by adding trailing blanks) to avoid error in SRS
          WHEN LEN(Codes.Description) < 7 THEN Codes.Description + SPACE(7 - LEN(Codes.Description))
          ELSE Codes.Description
       END AS [Description],
       Codes.Code AS [Type],
       -- 4.3.1 Sub-query for Opening Openwork
       (SELECT 
             CASE
                WHEN Codes.Code IN (1, 4, 10) THEN -- IC, RC & Trail
                  ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
