CREATE PROCEDURE [dbo].[cscp_FranchiseAccount] @UserID VARCHAR(255)
AS
SELECT  Agents.Code ,
  BankDetails.SortCode,
  RIGHT('00000000' + BankDetails.AccountNumber,8) AS 'AccountNumber',
  BankDetails.AccountName,
  BankDetails.BankName

FROM mstt_Agents AS Agents
LEFT JOIN mstt_AgentBankDetails AS BankDetails ON Agents.Code = BankDetails.AgentCode
WHERE Agents.CompetentStatus = 1 AND  Agents.AgentTypeGrouping = 1
  AND BankDetails.AuthorisedOn IS NOT NULL
  AND BankDetails.AuthorisedOn <> ''
  AND NOT EXISTS (SELECT OldBankDetails.AccountNumber -- exclude historical bank accounts
                  FROM mstt_AgentBankDetails OldBankDetails
                  WHERE OldBankDetails.ID <> BankDetails.ID
                    AND OldBankDetails.AgentCode = BankDetails.AgentCode
                    AND OldBankDetails.AuthorisedOn > BankDetails.AuthorisedOn)
ORDER BY Agents.Code

GO
