CREATE PROCEDURE [dbo].[cscp_FSDScheduleECommissionPayments] @UserID VARCHAR(255), @StartDate varchar(10), @EndDate varchar(10)
AS

/***********************************************************************************************************************
Mike Cawood - SR9 Changes - 22 April 2008

1. Allow Start and End Date to be more than one month apart and varied from current constraints.
2. Derive AgentType from msit_AgentTypeHistory (new Swift table) on Proposal Date (if TransactionID) or CreateDateTime.
3. Select payments on CreateDateTime.
4. Include payments not linked to Transaction.


Mike Cawood - SQL 2005 Upgrade - 1 Sept 2009

1. Amend formatting of PaymentsPending.AMOUNT to avoid error when run in SQL 2005 environment.
2. Add Date and Amount to Sort Sequence.

Paul Robathan - 11 Sept 2009 - change AmountPaid to be a numeric rather than a string as the RS report expects a numeric value

***********************************************************************************************************************/


SET DATEFORMAT dmy

IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Sales Manager Name'
      , NULL AS 'Client Name'
      , NULL AS 'Policy Reference'
      , NULL AS 'Amount to be Paid'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

-- NOTE: 52 Sales Manager 1 or 53 Sales Manager 2 or 54 Sales Manager 3 or 55 Sales Manager 4 

SELECT  Distinct Agents.name,
  ISNULL(LTRIM(RTRIM(Agents.Descn)),'') AS [Sales Manager Name],
  case when Clients.Client_Num is not null then             --MPC: 22/04/08 SR9(4)
        ISNULL(RTRIM(SUBSTRING(Clients.Firstnames, 1, PATINDEX('%[^ ] %', Clients.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Clients.Name), '') 
  else RTRIM(PaymentsPending.Notes) end AS [Client Name],           --MPC: 22/04/08 SR9(4)
  case when Policies.Pol_Num is not null                --MPC: 22/04/08 SR9(4)
  then ISNULL( LTRIM( RTRIM( Policies.PolicyRef)),'') 
  else RTRIM(PaymentsPending.CommissionTypeDesc) end AS [Policy Reference],     --MPC: 22/04/08 SR9(4)
--MPC: 01/09/2009 OLD Code below
--  ISNULL(CAST(Ltrim(Rtrim(PaymentsPending.AMOUNT)) AS DECIMAL(15,2)),0.00) AS [Amount to be Paid],
--MPC: 01/09/2009 NEW Code below
--  Ltrim(Rtrim(ISNULL(CAST(PaymentsPending.AMOUNT AS DECIMAL(15,2)),0.00))) AS [Amount to be Paid],
-- PR 11/09/2009 AmountPaid line above replaced with fix in line below.
  CAST(ISNULL(PaymentsPending.AMOUNT,0.00) AS DECIMAL(15,2)) AS [Amount to be Paid],
    CAST(CONVERT(NVARCHAR, PaymentsPending.CreateDateTime, 112) AS DATETIME) AS [Error]   --MPC: 22/04/08 SR9(4)

FROM    mstt_PaymentsPending AS PaymentsPending
        INNER JOIN mstt_Agents AS Agents ON PaymentsPending.Agent_Code = Agents.Code
  LEFT OUTER JOIN mstt_PolicyTransactions AS Trx ON PaymentsPending.TransactionID = Trx.ID  --MPC: 22/04/08 SR9(4)
  LEFT OUTER JOIN mstt_Policies AS Policies ON Policies.Pol_Num = Trx.PolicyID      --MPC: 22/04/08 SR9(4)
  LEFT OUTER JOIN mstt_Clients AS Clients ON Policies.Client_Num=Clients.Client_Num   --MPC: 22/04/08 SR9(4)
        LEFT OUTER JOIN msit_AgentTypeHistory ATH ON ATH.AgentCode = PaymentsPending.Agent_Code   --MPC: 22/04/08 SR9(2)
  AND CAST(CONVERT(NVARCHAR, coalesce(Trx.ProposalDate,PaymentsPending.CreateDateTime), 112) AS DATETIME) between ATH.StartDate and isnull(ATH.EndDate,'31 Dec 2999') --MPC: 22/04/08 SR9(2)
        
WHERE Coalesce(ATH.AgentType,Agents.AgentType) IN (52,53,54,55)   --MPC: 22/04/08 SR9(2)
--  AND CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)  --MPC: 22/04/08 SR9(3)
--  AND CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)  --MPC: 22/04/08 SR9(3)
  AND CAST(CONVERT(NVARCHAR, PaymentsPending.CreateDateTime, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)  --MPC: 22/04/08 SR9(3)
  AND CAST(CONVERT(NVARCHAR, PaymentsPending.CreateDateTime, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)  --MPC: 22/04/08 SR9(3)

ORDER BY 1,2,4,6,5  --MPC: 01/09/2009


GO
