CREATE PROCEDURE [dbo].[cscp_FSDScheduleECommissionPayments_190508_old] @UserID VARCHAR(255), @StartDate varchar(10), @EndDate varchar(10)
AS

Declare @TempDate varchar(10)

SET DATEFORMAT dmy

IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Sales Manager Name'
      , NULL AS 'Client Name'
      , NULL AS 'Policy Reference'
      , NULL AS 'Amount to be Paid'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

SET @TempDate=CONVERT(VARCHAR, DATEADD(MONTH, 1,@StartDate) ,103)

IF DAY(@StartDate)<>11 OR DAY(@EndDate)<>10 OR (MONTH(@TempDate) <> MONTH(@EndDate) OR YEAR(@TempDate) <> YEAR(@EndDate))
   OR CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME)
BEGIN
  SELECT 
        NULL AS 'Sales Manager Name'
      , NULL AS 'Client Name'
      , NULL AS 'Policy Reference'
      , NULL AS 'Amount to be Paid'
      , CASE 
             WHEN DAY(@StartDate)<>11 THEN 'Invalid Start Date Entered. Start date must be 11th of the month.'
             WHEN DAY(@EndDate)<> 10 THEN 'Invalid End Date Entered. End date must be 10th of the month.'  
             WHEN CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME) THEN 'Invalid End Date Entered. End date cannot be in the future.'
             WHEN MONTH(@TempDate) <> MONTH(@EndDate) OR YEAR(@TempDate) <> YEAR(@EndDate) THEN  'Invalid End Date Entered. End date must be one month following Start date.'  
        END AS [Error]
   RETURN 0
END 


SELECT  Distinct Agents.name,
  ISNULL(LTRIM(RTRIM(Agents.Descn)),'') AS [Sales Manager Name],
        ISNULL(RTRIM(SUBSTRING(Clients.Firstnames, 1, PATINDEX('%[^ ] %', Clients.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Clients.Name), '') AS [Client Name],
        ISNULL(LTRIM(RTRIM(Policies.PolicyRef)),'') AS [Policy Reference],
        ISNULL(CAST(PaymentsPending.AMOUNT AS DECIMAL(15,2)), 0.00) AS [Amount to be Paid],
        NULL AS [Error]
FROM    mstt_PaymentsPending AS PaymentsPending
        INNER JOIN mstt_Agents  AS Agents on PaymentsPending.Agent_Code=Agents.Code
  INNER JOIN mstt_PolicyTransactions AS Trx ON PaymentsPending.TransactionID = Trx.ID
  INNER JOIN mstt_Policies AS Policies ON Policies.Pol_Num = Trx.PolicyID
  INNER JOIN mstt_Clients AS Clients ON Policies.Client_Num=Clients.Client_Num
  
WHERE Agents.AgentType IN (52,53,54,55) -- 52 Sales Manager 1 or 53 Sales Manager 2 or 54 Sales Manager 3 or 55 Sales Manager 4 
  AND CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, PaymentsPending.PaymentDueDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 

ORDER BY  Agents.name,[Policy Reference]



GO
