GO

CREATE PROCEDURE [dbo].[cscp_FSDTrailFeeExpectation] @UserID VARCHAR(255), @Month VARCHAR(2), @Year VARCHAR(5), @Frequency VARCHAR(1), @Variance VARCHAR(3)
AS
-- Check for year entered
IF LEN(@Year) > 4 OR (@Year < '1900') OR (@Year > '9999')
BEGIN
  SELECT 
        NULL AS 'ZFSGroup'
      , NULL AS 'ProductProvider'
      , NULL AS 'PlanNumber'
      , NULL AS 'CaseID'
      , NULL AS 'DueDate'
      , NULL AS 'ReceivedDate'
      , NULL AS 'Expectation'
      , NULL AS 'Payment'
      , NULL AS 'Difference'
      , NULL AS 'PercentDifference'
      , 'Invalid Year Entered. Year must be between 1900 and 9999' AS [Error]
   RETURN 0
END
SELECT 
     CASE PolicyTransactions.ZFSGroupFlag 
        WHEN 'Y' THEN 'ZFS Group'
        WHEN 'N' THEN 'Non ZFS Group'
        ELSE 'Unknown'
     END AS 'ZFSGroup'
   , PolicyTransactions.ProductProviderCode AS 'ProductProvider'
   , Policies.CONT_NUM AS 'PlanNumber'
   , Policies.PolicyRef AS 'CaseID'
   , CONVERT(VARCHAR, Expectation.DATE_DUE, 103) AS 'DueDate'
   , CONVERT(VARCHAR, Expectation.DATE_RECV, 103) AS 'ReceivedDate'
   , ISNULL(CAST(Expectation.AMOUNT_DUE AS DECIMAL(15,2)), 0.00) AS 'Expectation'
   , ISNULL(CAST(Expectation.AMOUNT_REC AS DECIMAL(15,2)), 0.00) AS 'Payment'
   , (ISNULL(CAST(Expectation.AMOUNT_DUE AS DECIMAL(15,2)), 0.00) - 
      ISNULL(CAST(Expectation.AMOUNT_REC AS DECIMAL(15,2)), 0.00)) AS 'Difference'
   , CAST((ABS(ISNULL(CAST(Expectation.AMOUNT_DUE AS DECIMAL(15,2)), 0.00) - 
               ISNULL(CAST(Expectation.AMOUNT_REC AS DECIMAL(15,2)), 0.00)) * 100.00)/
          (ISNULL(CAST(Expectation.AMOUNT_DUE AS DECIMAL(15,2)), 0.00))
     AS DECIMAL(15,2)) AS 'PercentDifference'
   , NULL AS [Error]
FROM mstt_Expectation Expectation 
   INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID 
   INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
WHERE Expectation.Type = '10' --Trail Fee
AND   Expectation.Status = '2' --Reconciled
AND   PolicyTransactions.Frequency = @Frequency --Annually/Monthly/Single
AND   Expectation.DATE_RECV IS NOT NULL
AND   CAST(MONTH(Expectation.DATE_RECV) AS VARCHAR(2)) = @Month
AND   CAST(YEAR(Expectation.DATE_RECV) AS VARCHAR(4)) = @Year
AND   CAST((ABS(ISNULL(CAST(Expectation.AMOUNT_DUE AS DECIMAL(15,2)), 0.00) - 
                ISNULL(CAST(Expectation.AMOUNT_REC AS DECIMAL(15,2)), 0.00)) * 100.00)/
           (ISNULL(CAST(Expectation.AMOUNT_DUE AS DECIMAL(15,2)), 0.00))
      AS DECIMAL(15,2)) >= CAST(@Variance AS DECIMAL(15,2))
ORDER BY [ZFSGroup], [ProductProvider], [CaseID]

GO
