CREATE PROCEDURE [dbo].[cscp_GetSvrName] @AgentCode AS VARCHAR(10)
AS
DECLARE @AgentName AS VARCHAR(255)

IF @AgentCode = '' OR @AgentCode IS NULL
   SET @AgentName = 'Report for: All of Openwork'
ELSE
BEGIN
   SET @AgentName = (SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '')
                                  + ISNULL(RTRIM(Agents.Name), '')
                    FROM mstt_Agents Agents
                    WHERE Agents.Code = @AgentCode)
   IF @AgentName = '' OR @AgentName IS NULL
      SET @AgentName = 'Report for Supervisor: Unknown'
   ELSE
      SET @AgentName = 'Report for Supervisor: ' + @AgentName + ' (' + @AgentCode + ')'
END

SELECT @AgentName AS [Svr Name]

GO
