CREATE PROCEDURE [dbo].[cscp_GetVarianceList]
AS
IF OBJECT_ID('tempdb..#Temp') IS NOT NULL
   DROP TABLE #Temp
CREATE TABLE #Temp (Variance INT)
DECLARE @Count INT
SET @Count = 0
WHILE @Count <= 100
BEGIN
   INSERT INTO #Temp
   SELECT @Count AS 'Variance'
   SET @Count = @Count + 5
END
SELECT [Variance] FROM #Temp
DROP TABLE #Temp

GO
