CREATE PROCEDURE [dbo].[cscp_ICOBExtract] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10), @ProdType CHAR(3)
AS

/*  RH 29 May

  Reworked for performance and to remove embedded user defined function calls
  PR 10 Oct

  Changes for OriginatingSource transformation
*/


--DECLARE @StartDate as VARCHAR(10), @EndDate as VARCHAR(10), @ProdType as CHAR(3)
--SET @StartDate ='2006/06/01'
--SET @EndDate = '2006/06/02'
--SET @ProdType = 'G'

declare @tune int
select @tune=0

IF OBJECT_ID('tempdb..#ICOBPOLTABLE') IS NOT NULL
   DROP TABLE #ICOBPOLTABLE

IF OBJECT_ID('tempdb..#ICOBCLIENT') IS NOT NULL
   DROP TABLE #ICOBCLIENT

IF OBJECT_ID('tempdb..#ICOBPOLDATES') IS NOT NULL
   DROP TABLE #ICOBPOLDATES

IF OBJECT_ID('tempdb..#ICOBPOLDATES') IS NOT NULL
   DROP TABLE #ICOBPOLS

IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS [Title]
      , NULL AS [Initials] 
      , NULL AS [Surname] 
      , NULL AS [Addr1] 
      , NULL AS [Addr2] 
      , NULL AS [Addr3] 
      , NULL AS [Addr4] 
      , NULL AS [Addr5] 
      , NULL AS [Addr6] 
      , NULL AS [Agent Code] 
      , NULL AS [Application Date]
      , NULL AS [Provider/Product/Polno/Case Id] 
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

if @tune = 1 select 'StartTime',getdate()

SELECT  Policies.Client_Num,
    Policies.Plan_Code,
    Policies.ServicingAgentCode
INTO #ICOBPOLTABLE -- Get a list of all non-risk policies
FROM mstt_Policies AS Policies
LEFT JOIN msit_TrackItems TrackItems ON Policies.Pol_num = TrackItems.PolicyID AND TrackItems.Description LIKE 'case check for%'
LEFT JOIN mstt_Agents AS Agents ON Agents.Code = Policies.ServicingAgentCode
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
LEFT JOIN msit_S_Life AS Life ON Policies.Pol_Num = Life.Pol_Num
WHERE Policies.OriginatingSource = 2
  AND Policies.ServicingAgentCode <> '1005202' --dodgy Swift cases are being put under this agent code and need to be excluded
  AND (TrackItems.ID IS NULL OR TrackItems.CompletedState NOT IN ('0','1'))
  AND CAST(CONVERT(NVARCHAR,Policies.PROP_DATE,112) AS DATETIME) >= CAST(CONVERT(NVARCHAR,@StartDate,112) AS DATETIME) AND CAST(CONVERT(NVARCHAR,Policies.PROP_DATE,112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,@EndDate,112) AS DATETIME)
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
  AND Agents.AgentType <> 5 -- this will replaced by NASP
    AND Policies.Plan_Code IN ('ASU','B&C','IPP','DMC','TERM','CRITILL')
  AND (Policies.Risk = 0 
    OR (Policies.Plan_Code IN ('ASU','B&C','IPP'))
--    OR (Policies.Plan_Code = 'PTERM' AND Life.Sum_Ass <= 500000 AND Policies.Replacement = 0)
    OR (Policies.Plan_Code = 'TERM' AND Life.Sum_Ass <= 500000  
    AND ((Life.JointFirstNames IS NULL
      AND Life.JointSurnames IS NULL
      AND Life.JointGender IS NULL
      AND Life.JointBirthDate IS NULL
      AND Life.JointSmoker IS NULL
      AND Policies.InTrust = -1)
    OR Life.JointFirstNames IS NOT NULL
    OR Life.JointSurnames IS NOT NULL
    OR Life.JointGender IS NOT NULL
    OR Life.JointBirthDate IS NOT NULL
    OR Life.JointSmoker IS NOT NULL)
       )
    OR (Policies.Plan_Code IN ('DMC','CRITILL') 
    AND (Life.Sum_Ass <= 500000 OR Life.Sum_Ass IS NULL) 
    AND (Life.Crit_Sumas <= 500000 OR Life.Crit_Sumas IS NULL)
    AND ((Life.JointFirstNames IS NULL
        AND Life.JointSurnames IS NULL
        AND Life.JointGender IS NULL
        AND Life.JointBirthDate IS NULL
        AND Life.JointSmoker IS NULL
        AND Policies.InTrust = -1)
      OR Life.JointFirstNames IS NOT NULL
      OR Life.JointSurnames IS NOT NULL
      OR Life.JointGender IS NOT NULL
      OR Life.JointBirthDate IS NOT NULL
      OR Life.JointSmoker IS NOT NULL
      OR ((Life.JointFirstNames IS NULL
        AND Life.JointSurnames IS NULL
        AND Life.JointGender IS NULL
        AND Life.JointBirthDate IS NULL
        AND Life.JointSmoker IS NULL
        AND (Policies.InTrust <> -1 OR Policies.InTrust IS NULL))
        AND (Life.Sum_Ass = 0 OR Life.Sum_Ass IS NULL OR Life.Sum_Ass >= Life.Crit_Sumas)
         )
        )
       )
  )

if @tune = 1 select 'Make Index',getdate()

CREATE CLUSTERED INDEX PolIndex ON #ICOBPOLTABLE (Client_Num, Plan_Code)

if @tune = 1 select 'Part 2',getdate()

SELECT DISTINCT Clients.CLIENT_NUM,
    RTRIM(Clients.Title) AS [Title],
         SUBSTRING(Clients.Firstnames, PATINDEX('%[^ ]%', Clients.Firstnames + ' '), 1) -- first initial
           + ' ' + SUBSTRING(Clients.Firstnames, PATINDEX('%[^ ] %', Clients.Firstnames + ' ') + 2, 1) -- second initial
           AS [Initials],
         RTRIM(Clients.Name) AS [Surname],
    convert(varchar(255),case Clients.Address1 when '' then null else Clients.Address1 end) Address1,
    convert(varchar(255),case Clients.Address2 when '' then null else Clients.Address2 end) Address2,
    convert(varchar(255),case Clients.Address3 when '' then null else Clients.Address3 end) Address3,
    convert(varchar(255),case Clients.Address4 when '' then null else Clients.Address4 end) Address4,
    convert(varchar(255),case Clients.Address5 when '' then null else Clients.Address5 end) Address5,
    convert(varchar(255),case Clients.Postcode when '' then null else Clients.Postcode end) Postcode,
    CONVERT(VARCHAR(2000),NULL) PolDates,
    CONVERT(VARCHAR(2000),NULL) PolDetails
INTO #ICOBCLIENT
FROM mstt_Clients AS Clients 
INNER JOIN #ICOBPOLTABLE AS Policies ON Policies.CLIENT_NUM = Clients.CLIENT_NUM

CREATE CLUSTERED INDEX CliIndex ON #ICOBCLIENT (Client_Num)

if @tune = 1 select 'Part 3',getdate()

-- shuffle up the addresses so no gaps

while exists (select * from #ICOBCLIENT where Address1 is null and coalesce(Address2, Address3, Address4, Address5, Postcode) is not null)
  UPDATE  #ICOBCLIENT
  SET Address1 = Address2,
    Address2 = Address3,
    Address3 = Address4,
    Address4 = Address5,
    Address5 = Postcode,
    Postcode = null
  where Address1 is null

while exists (select * from #ICOBCLIENT where Address2 is null and coalesce(Address3, Address4, Address5, Postcode) is not null)
  UPDATE  #ICOBCLIENT
  SET Address2 = Address3,
    Address3 = Address4,
    Address4 = Address5,
    Address5 = Postcode,
    Postcode = null
  where Address1 is not null
    and Address2 is null

while exists (select * from #ICOBCLIENT where Address3 is null and coalesce(Address4, Address5, Postcode) is not null)
  UPDATE  #ICOBCLIENT
  SET Address3 = Address4,
    Address4 = Address5,
    Address5 = Postcode,
    Postcode = null
  where Address1 is not null
    and Address2 is not null
    and Address3 is null

while exists (select * from #ICOBCLIENT where Address4 is null and coalesce(Address5, Postcode) is not null)
  UPDATE  #ICOBCLIENT
  SET Address4 = Address5,
    Address5 = Postcode,
    Postcode = null
  where Address1 is not null
    and Address2 is not null
    and Address3 is not null
    and Address4 is null

while exists (select * from #ICOBCLIENT where Address5 is null and Postcode is not null)
  UPDATE  #ICOBCLIENT
  SET Address5 = Postcode,
    Postcode = null
  where Address1 is not null
    and Address2 is not null
    and Address3 is not null
    and Address4 is not null
    and Address5 is null


