if @tune = 1 select 'Part 5',getdate()

-- earliest policy for each client

while exists (select * from #ICOBPOLDATES)
begin
  UPDATE  #ICOBCLIENT
  set PolDates =  ISNULL(PolDates + CHAR(13), '') + #ICOBPOLDATES.PROP_DATE
  from  #ICOBCLIENT client
    inner join #ICOBPOLDATES on client.CLIENT_NUM = #ICOBPOLDATES.CLIENT_NUM
    inner join 
    (
    select  CLIENT_NUM,
      min(POL_NUM) MinPolNum
    FROM  #ICOBPOLDATES
    group by CLIENT_NUM
    ) FirstPol on #ICOBPOLDATES.CLIENT_NUM = FirstPol.CLIENT_NUM and #ICOBPOLDATES.POL_NUM = FirstPol.MinPolNum
  
  -- delete earliest pol_num for eeach client as its been used
  delete  #ICOBPOLDATES
  from  #ICOBPOLDATES 
    inner join 
    (
    select  CLIENT_NUM,
      min(POL_NUM) MinPolNum
    FROM  #ICOBPOLDATES
    group by CLIENT_NUM
    ) FirstPol on #ICOBPOLDATES.CLIENT_NUM = FirstPol.CLIENT_NUM and #ICOBPOLDATES.POL_NUM = FirstPol.MinPolNum
  
end


