SELECT DISTINCT 
    Clients.Title,
    Clients.Initials,
    Clients.Surname,
    Clients.Address1 AS [Addr1],
    Clients.Address2 AS [Addr2],
    Clients.Address3 AS [Addr3],
    Clients.Address4 AS [Addr4],
    Clients.Address5 AS [Addr5],
    Clients.Postcode AS [Addr6],
    Policies.ServicingAgentCode AS [Agent Code],
    Clients.PolDates AS [Application Date],
    Clients.PolDetails AS [Provider/Product/Polno/Case Id],
    NULL AS [Error]
FROM #ICOBPOLTABLE AS Policies
INNER JOIN #ICOBCLIENT AS Clients ON Policies.CLIENT_NUM = Clients.CLIENT_NUM
where   
  (@ProdType = 'G'  --Clients with GI only
  and exists (select * from #ICOBPOLTABLE i where i.CLIENT_NUM = Policies.CLIENT_NUM and i.Plan_Code IN ('ASU','B&C'))
  and not exists (select * from #ICOBPOLTABLE i where i.CLIENT_NUM = Policies.CLIENT_NUM and i.Plan_Code IN ('DMC','TERM','CRITILL','IPP','LTA'))
  )
  or
  (@ProdType = 'P'  --Clients with Prot only
  and not exists (select * from #ICOBPOLTABLE i where i.CLIENT_NUM = Policies.CLIENT_NUM and i.Plan_Code IN ('ASU','B&C'))
  and exists (select * from #ICOBPOLTABLE i where i.CLIENT_NUM = Policies.CLIENT_NUM and i.Plan_Code IN ('DMC','TERM','CRITILL','IPP','LTA'))
  ) 
  or
  (@ProdType = 'GP'  --Clients with GI and Prot
  and exists (select * from #ICOBPOLTABLE i where i.CLIENT_NUM = Policies.CLIENT_NUM and i.Plan_Code IN ('ASU','B&C'))
  and exists (select * from #ICOBPOLTABLE i where i.CLIENT_NUM = Policies.CLIENT_NUM and i.Plan_Code IN ('DMC','TERM','CRITILL','IPP','LTA'))
  )

ORDER BY [Agent Code], [Surname], [Initials]



