/****** Object:  StoredProcedure [dbo].[cscp_InvalidClientPostCodes]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[cscp_InvalidClientPostCodes] @UserID Varchar(255)
AS

select  Client.Refer
  ,Case
  When Agents.AgentTypeDescription is not null then Agents.AgentTypeDescription
  Else 'Client'
  End as [ClientType]
  ,ISNULL(RTRIM(SUBSTRING(Client.FirstNames, 1, PATINDEX('%[^ ] %', Client.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Client.Name), '') AS [Name]
  ,'Current' as [Type]
  ,Client.Address1
  ,Client.Address2
  ,Client.Address3
  ,Client.Town
  ,Client.County
  ,Client.POSTCODE
  ,'' as [Country]
  ,Client.Name as [SortName]
from msit_s_client as Client
left join mstt_Agents as Agents on Client.Refer = Agents.Code
where len(rtrim(Client.POSTCODE)) > 8
   or (dbo.cscf_PostCodeValid(rtrim(Client.POSTCODE)) = 0 and Client.POSTCODE is not null and RTRIM(Client.POSTCODE) <> '')
   or dbo.cscf_DummyPostCode(rtrim(Client.POSTCODE)) = 1
   or ((Client.POSTCODE is null or Client.POSTCODE = ' ') and Client.Address1 is not null and RTRIM(Client.Address1) <> '')
union all
select  Client.Refer
  ,Case
  When Agents.AgentTypeDescription is not null then Agents.AgentTypeDescription
  Else 'Client'
  End as [ClientType]
  ,ISNULL(RTRIM(SUBSTRING(Client.FirstNames, 1, PATINDEX('%[^ ] %', Client.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Client.Name), '') AS [Name]
  ,'Correspondence'
  ,Client.CorrAddress1
  ,Client.CorrAddress2
  ,Client.CorrAddress3
  ,Client.CorrTown
  ,Client.CorrCounty
  ,Client.CorrPostCode
  ,Client.CorrCountry
  ,Client.Name as [SortName]
from msit_s_client as Client
left join mstt_Agents as Agents on Client.Refer = Agents.Code
where len(rtrim(Client.CorrPostCode)) > 8
   or (dbo.cscf_PostCodeValid(rtrim(Client.CorrPostCode)) = 0 and Client.CorrPostCode is not null and RTRIM(Client.CorrPostCode) <> '')
   or dbo.cscf_DummyPostCode(rtrim(Client.CorrPostCode)) = 1
   or ((Client.CorrPostCode is null or Client.CorrPostCode = ' ') and Client.CorrAddress1 is not null and RTRIM(Client.CorrAddress1) <> '')
union all
select  Client.Refer 
  ,Case
  When Agents.AgentTypeDescription is not null then Agents.AgentTypeDescription
  Else 'Client'
  End as [ClientType]
  ,ISNULL(RTRIM(SUBSTRING(Client.FirstNames, 1, PATINDEX('%[^ ] %', Client.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Client.Name), '') AS [Name]
  ,'Old'
  ,Client.OldAddress1
  ,Client.OldAddress2
  ,Client.OldAddress3
  ,Client.OldTown
  ,Client.OldCounty
  ,Client.OldPostCode
  ,Client.OldCountry
  ,Client.Name as [SortName]
from msit_s_client as Client
left join mstt_Agents as Agents on Client.Refer = Agents.Code
where (len(rtrim(Client.OldPostCode)) > 8
   or (dbo.cscf_PostCodeValid(rtrim(Client.OldPostCode)) = 0 and Client.OldPostCode is not null and RTRIM(Client.OldPostCode) <> '')
   or dbo.cscf_DummyPostCode(rtrim(Client.OldPostCode)) = 1)
   or ((Client.OldPostCode is null or Client.OldPostCode = ' ') and Client.OldAddress1 is not null and RTRIM(Client.OldAddress1) <> '')

order by ClientType, Client.Name


GO
/****** Object:  StoredProcedure [dbo].[cscp_InvalidHierarchy]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[cscp_InvalidHierarchy] @UserID VARCHAR(255)
AS

SELECT  Business.Code AS [BusinessCode]
  ,CASE
      WHEN Business.TradingName IS NOT NULL THEN RTRIM(Business.TradingName)
      ELSE RTRIM(Business.Descn)
   END AS [BusinessName]
  ,Business.Manager2Code AS [BusinessRSM]
  ,(SELECT ISNULL(RTRIM(FirstNames) + ' ', '') + ISNULL(RTRIM(Name), '') FROM mstt_Agents WHERE Code = Business.Manager2Code) AS [RSMName]
  ,Business.Manager4Code AS [BusinessASM]
  ,(SELECT ISNULL(RTRIM(FirstNames) + ' ', '') + ISNULL(RTRIM(Name), '') FROM mstt_Agents WHERE Code = Business.Manager4Code) AS [ASMName]
  ,Agents.Code AS [AgentCode]
  ,ISNULL(RTRIM(Agents.FirstNames) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [AgentName]
  ,Agents.Manager2Code AS [AgentsRSM]
  ,(SELECT ISNULL(RTRIM(FirstNames) + ' ', '') + ISNULL(RTRIM(Name), '') FROM mstt_Agents WHERE Code = Agents.Manager2Code) AS [AgentRSMName]
  ,Agents.Manager4Code AS [AgentsASM]
  ,(SELECT ISNULL(RTRIM(FirstNames) + ' ', '') + ISNULL(RTRIM(Name), '') FROM mstt_Agents WHERE Code = Agents.Manager4Code) AS [AgentASMName]
  ,Agents.Name
FROM  mstt_Agents Business
INNER JOIN mstt_Agents Agents ON Business.Code = Agents.Firm
  AND (Business.Manager2Code <> Agents.Manager2Code OR Business.Manager4Code <> Agents.Manager4Code)
WHERE Business.agentTypeGrouping = 1
  AND   Business.CompetentStatus IN (1,5) --active/pre-appointed businesses only
  AND   Agents.CompetentStatus IN (1,5) --active/pre-appointed individuals only
ORDER BY [BusinessName], Agents.Name


GO
/****** Object:  StoredProcedure [dbo].[cscp_LicenceExpired]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_LicenceExpired] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0
BEGIN
  SELECT 
        NULL AS 'Agent ID'
      , NULL AS 'Adviser'
      , NULL AS 'LicenceID'
      , NULL AS 'Licence'
      , NULL AS 'Licence Start Date'
      , NULL AS 'Licence Expiry Date'
      , NULL AS 'Licence End Date'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
       WHEN ISDATE(@EndDate) = 0 THEN 'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy'
        END AS [Error]
   RETURN 0
END
IF (CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
BEGIN
  SELECT 
        NULL AS 'Agent ID'
      , NULL AS 'Adviser'
      , NULL AS 'LicenceID'
      , NULL AS 'Licence'
      , NULL AS 'Licence Start Date'
      , NULL AS 'Licence Expiry Date'
      , NULL AS 'Licence End Date'
      , 'Start Date cannot be greater than End Date' AS 'Error'
   RETURN 0
END
  SELECT Agents.Code AS [AgentID],
         ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser],
         mstt_AgentLicence.LicenceCode AS [LicenceID],
         mstt_AgentLicence.LicenceDescription AS [Licence],
         CONVERT(VARCHAR, mstt_AgentLicence.StartDate, 103) AS [Licence Start Date],
         CONVERT(VARCHAR, mstt_AgentLicence.ExpiryDate, 103) AS [Licence Expiry Date],
         CONVERT(VARCHAR, mstt_AgentLicence.EndDate, 103) AS [Licence End Date]
  FROM mstt_agents as Agents
  LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
  INNER JOIN mstt_AgentLicence ON mstt_AgentLicence.AgentID = Agents.id
  AND (mstt_AgentLicence.StartDate IS NOT NULL) -- open
      AND (mstt_AgentLicence.EndDate IS NULL 
    AND CAST(CONVERT(NVARCHAR, mstt_AgentLicence.ExpiryDate , 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
    AND CAST(CONVERT(NVARCHAR, mstt_AgentLicence.ExpiryDate , 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)
    )
  WHERE (Agents.CompetentStatus = 1 OR Agents.CompetentStatus = 5) --Active/Pre-App Agents only
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
  AND Agents.AgentTypeB30=2
  ORDER BY [Adviser] ASC, mstt_AgentLicence.ExpiryDate ASC, [LicenceID]

GO
