CREATE PROCEDURE [dbo].[cscp_M1_EarlyPaymentsMissingClawbacks] @UserID VARCHAR(255)
AS

SELECT UnmatchedPaymentsPending.Agent_Code AS AgentCode
     , RTRIM(Agents.DESCN) AS AgentName
     , ISNULL(RTRIM(UnmatchedPaymentsPending.Notes), 'Error: No Claim Ref') AS PolicyNumber
     , CONVERT(VARCHAR, UnmatchedPaymentsPending.Due_Date, 103) AS DueDate
     , CAST(UnmatchedPaymentsPending.Amount AS DECIMAL(15,2)) AS Amount
     , CAST(UnmatchedPaymentsPending.Amount_Paid AS DECIMAL(15,2)) AS AmountPaid
     , RTRIM(AuthorisedBy.Description) AS AuthorisedBy
     , CONVERT(VARCHAR, UnmatchedPaymentsPending.AuthorisedDate, 103) AS AuthorisedDate
     , RTRIM(CreatedBy.Description) AS CreatedBy
     , CONVERT(VARCHAR, UnmatchedPaymentsPending.CreatedDate, 103) AS CreatedDate
     , CONVERT(VARCHAR, AgentPayments.EXPORT_DATE, 103) AS PaidDate

FROM msit_S_AGMFIL UnmatchedPaymentsPending
LEFT JOIN mstt_Agents Agents ON UnmatchedPaymentsPending.Agent_Code = Agents.Code
LEFT JOIN mstt_PolicyTransactions PolicyTransactions ON UnmatchedPaymentsPending.TransactionID = PolicyTransactions.ID
LEFT JOIN mstt_Policies Policies ON PolicyTransactions.PolicyID = Policies.Pol_Num
LEFT JOIN msit_IntUsers AuthorisedBy ON UnmatchedPaymentsPending.AuthorisedBy = AuthorisedBy.ID
LEFT JOIN msit_IntUsers CreatedBy ON UnmatchedPaymentsPending.CreatedBy = CreatedBy.ID
LEFT JOIN mstt_AgentPayments AgentPayments ON AgentPayments.AGMID = UnmatchedPaymentsPending.ID

WHERE UnmatchedPaymentsPending.Type = 21 -- 'Mortgage Early Payment'
  AND UnmatchedPaymentsPending.Amount > 0
  AND NOT EXISTS (SELECT ID
                  FROM msit_S_AGMFIL MatchingPaymentsPending
                  WHERE MatchingPaymentsPending.Agent_Code = UnmatchedPaymentsPending.Agent_Code
                    AND MatchingPaymentsPending.Notes = UnmatchedPaymentsPending.Notes --Policy Number
                    AND MatchingPaymentsPending.Amount = (UnmatchedPaymentsPending.Amount * (-1))
                 )

ORDER BY AgentCode, AgentName

GO
