CREATE PROCEDURE [dbo].[cscp_M2] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS [CASE ID]
      , NULL AS [JOBTYPE] 
      , NULL AS [COMPANY] 
      , NULL AS [PLAN] 
      , NULL AS [PRODUCT] 
      , NULL AS [SALES PROCESS] 
      , NULL AS [REPLACEMNT] 
      , NULL AS [UNDISCLOSED REPLACEMNT] 
      , NULL AS [COMMENTS]
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

SELECT Policies.PolicyRef AS [CASE ID],
       AgentJobHistory.Job AS [JOB TYPE],
       Policies.COMP_CODE AS [COMPANY], 
       Policies.PlanDescription AS [PLAN],  
       Policies.ProductCode AS [PRODUCT], 
       CASE Policies.SalesProcess
            WHEN '0' THEN 'Full'
            WHEN '1' THEN 'Simplified'
            WHEN '2' THEN 'Other' 
            ELSE 'UnKnown' 
       END AS [SALES PROCESS], 
       CASE Policies.Replacement
            WHEN '0' THEN 'N'
            WHEN '1' THEN 'A'
            WHEN '2' THEN 'B'
            WHEN '3' THEN 'C'
       END AS [REPLACEMNT], 
       CASE Policies.UndisclosedReplacement 
              WHEN '0' THEN 'N'
              WHEN '1' THEN 'A'
              WHEN '2' THEN 'B'
              WHEN '3' THEN 'C'
              WHEN '4' THEN 'P'
             ELSE 'UnKnown' 
       END AS [UNDISCLOSED REPLACEMNT], 
       RTRIM(TrackGroups.NBCCComments) AS [COMMENTS],
       NULL AS [Error]

FROM msit_trackgroups TrackGroups 
INNER JOIN mstt_policies AS Policies ON TrackGroups.PolicyID = Policies.POL_NUM
INNER JOIN  mstt_policytransactions AS PolicyTransactions ON Policies.POL_NUM =   PolicyTransactions.PolicyID
LEFT JOIN MSIT_AgentJobHistory  AgentJobHistory  ON PolicyTransactions.AgentCode = AgentJobHistory.AgentCode

WHERE TrackGroups.NBCCHeaderID IS NOT NULL
  AND TrackGroups.NBCCStatus IS NOT NULL
  AND TrackGroups.CaseCheckValidatedDate >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND TrackGroups.CaseCheckValidatedDate <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)
  AND (TrackGroups.policyid IN (SELECT DISTINCT trackgroups_comment.policyid
                                    FROM msit_trackgroups trackgroups_comment
                                    WHERE trackgroups_comment.NBCCComments like 'Abbey Replacement%'
                                    ) 
  OR AgentJobHistory.Job = 'EXABBEY')

ORDER BY [CASE ID]


GO
