CREATE PROCEDURE [dbo].[cscp_M2_AdjustmentsMade] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10), @AgentCode VARCHAR(7)
AS

--Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
SELECT NULL AS PaymentType
     , NULL AS AgentCode
     , NULL AS AgentName
     , NULL AS PolicyNumber
     , NULL AS DueDate
     , NULL AS Amount
     , NULL AS AmountPaid
     , NULL AS AuthorisedBy
     , NULL AS AuthorisedDate
     , NULL AS CreatedBy
     , NULL AS CreatedDate
     , NULL AS PaidDate
     , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
            WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
       END AS [Error]
   RETURN 0
END

SELECT ISNULL(CommissionTypes.Description, PaymentsPending.Type) AS PaymentType
     , PaymentsPending.Agent_Code AS AgentCode
     , RTRIM(Agents.DESCN) AS AgentName
     , ISNULL(RTRIM(PaymentsPending.Notes), 'Error: No Claim Ref') AS PolicyNumber
     , CONVERT(VARCHAR, PaymentsPending.Due_Date, 103) AS DueDate
     , CAST(PaymentsPending.Amount AS DECIMAL(15,2)) AS Amount
     , CAST(PaymentsPending.Amount_Paid AS DECIMAL(15,2)) AS AmountPaid
     , RTRIM(AuthorisedBy.Description) AS AuthorisedBy
     , CONVERT(VARCHAR, PaymentsPending.AuthorisedDate, 103) AS AuthorisedDate
     , RTRIM(CreatedBy.Description) AS CreatedBy
     , CONVERT(VARCHAR, PaymentsPending.CreatedDate, 103) AS CreatedDate
     , CONVERT(VARCHAR, AgentPayments.EXPORT_DATE, 103) AS PaidDate
     , NULL AS Error

FROM msit_S_AGMFIL PaymentsPending
LEFT JOIN mstt_Agents Agents ON PaymentsPending.Agent_Code = Agents.Code
LEFT JOIN mstt_PolicyTransactions PolicyTransactions ON PaymentsPending.TransactionID = PolicyTransactions.ID
LEFT JOIN mstt_Policies Policies ON PolicyTransactions.PolicyID = Policies.Pol_Num
LEFT JOIN msit_IntUsers AuthorisedBy ON PaymentsPending.AuthorisedBy = AuthorisedBy.ID
LEFT JOIN msit_IntUsers CreatedBy ON PaymentsPending.CreatedBy = CreatedBy.ID
INNER JOIN mstt_AgentPayments AgentPayments ON AgentPayments.AGMID = PaymentsPending.ID
LEFT JOIN msit_MIWarehouseCodesAndDescriptions CommissionTypes ON CommissionTypes.ColumnName = 'CommissionType' 
                                                                AND PaymentsPending.Type = CommissionTypes.Code

WHERE PaymentsPending.Type IN (20, 21) -- 'Bonus Payment' & 'Mortgage Early Payment'
  AND CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)
  AND (@AgentCode = 'ALL' OR Agents.Code = @AgentCode)

ORDER BY AgentCode, AgentName, PaymentsPending.Type

GO
