  AND CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, AgentPayments.EXPORT_DATE, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

ORDER BY Seq, AgentCode


