CREATE PROCEDURE [dbo].[cscp_M6_IncompleteProcessing] @UserID VARCHAR(255)
AS

SELECT PaymentsPending.Agent_Code AS AgentCode
     , RTRIM(Agents.DESCN) AS AgentName
     , ISNULL(CommissionTypes.Description, PaymentsPending.Type) AS PaymentType
     , CASE PaymentsPending.Authorised
          WHEN 2 THEN 'Pending'
          ELSE 'Authorised - Unpaid'
       END AS PaymentStatus
     , ISNULL(RTRIM(PaymentsPending.Notes), 'Error: No Claim Ref') AS PolicyNumber
     , CONVERT(VARCHAR, PaymentsPending.Due_Date, 103) AS DueDate
     , CAST(PaymentsPending.Amount AS DECIMAL(15,2)) AS Amount
     , CAST(PaymentsPending.Amount_Paid AS DECIMAL(15,2)) AS AmountPaid
     , RTRIM(AuthorisedBy.Description) AS AuthorisedBy
     , CONVERT(VARCHAR, PaymentsPending.AuthorisedDate, 103) AS AuthorisedDate
     , RTRIM(CreatedBy.Description) AS CreatedBy
     , CONVERT(VARCHAR, PaymentsPending.CreatedDate, 103) AS CreatedDate

FROM msit_S_AGMFIL PaymentsPending
LEFT JOIN mstt_Agents Agents ON PaymentsPending.Agent_Code = Agents.Code
LEFT JOIN mstt_PolicyTransactions PolicyTransactions ON PaymentsPending.TransactionID = PolicyTransactions.ID
LEFT JOIN mstt_Policies Policies ON PolicyTransactions.PolicyID = Policies.Pol_Num
LEFT JOIN msit_IntUsers AuthorisedBy ON PaymentsPending.AuthorisedBy = AuthorisedBy.ID
LEFT JOIN msit_IntUsers CreatedBy ON PaymentsPending.CreatedBy = CreatedBy.ID
LEFT JOIN msit_MIWarehouseCodesAndDescriptions CommissionTypes ON CommissionTypes.ColumnName = 'CommissionType' 
                                                               AND PaymentsPending.Type = CommissionTypes.Code

WHERE PaymentsPending.Type IN (20, 21) -- 'Bonus Payment' & 'Mortgage Early Payment'
  AND CAST(CONVERT(NVARCHAR, PaymentsPending.Due_Date, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME)
  AND (PaymentsPending.Authorised = 2 OR (PaymentsPending.Authorised = 0 and PaymentsPending.Status = 'F'))

ORDER BY AgentCode, AgentName

GO
/****** Object:  StoredProcedure [dbo].[cscp_MR0001a]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[cscp_MR0001a] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

--1. Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Provider'
      , NULL AS 'ZFS Group APE'
      , NULL AS 'Non-ZFS Group APE'
      , NULL AS 'APE'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

--2. Convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

--3. Extract Expectation data into a temp table
IF OBJECT_ID('tempdb..#MR0001aExpectation') IS NOT NULL
   DROP TABLE #MR0001aExpectation

SELECT Expectation.ID, 
       Expectation.Type,
       Expectation.TransactionID,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #MR0001aExpectation
FROM mstt_Expectation Expectation
   INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
   INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
   INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (1)               --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD    --of the temp table
       OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD   --by omitting data which
           AND Expectation.DATE_RECV IS NOT NULL))          --we KNOW we don't need
GROUP BY Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID

CREATE CLUSTERED INDEX ind_MR0001 ON #MR0001aExpectation (ID, Type, TransactionID, IRD)

--4. Extract report data into another temp table
IF OBJECT_ID('tempdb..#MR0001a') IS NOT NULL
   DROP TABLE #MR0001a

SELECT 
     DISTINCT ProductProviders.ReportingProductProviderName AS 'Provider'
   , ProductProviders.ProductProviderCode AS 'Provider Code' --Added to ensure uniqueness/omitted in final resultset

   , (SELECT ISNULL(SUM(ISNULL(CAST(PolicyTransactions.APE AS DECIMAL(15,2)), 0.00)), 0.00)
      FROM mstt_PolicyTransactions PolicyTransactions
         INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
      WHERE EXISTS
          (SELECT Expectation.TransactionID
           FROM #MR0001aExpectation Expectation 
           WHERE Expectation.TransactionID = PolicyTransactions.ID
             AND Expectation.IRD >= @OD
             AND Expectation.IRD <= @CD
          )
      AND PolicyTransactions.ZFSGroupFlag = 'Y' --ZFS Group Providers
      AND (Policies.COMP_CODE = ProductProviders.ProductProviderCode
           OR ((Policies.COMP_CODE IS NULL OR Policies.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
               AND ProductProviders.ProductProviderCode IS NULL))
     ) AS 'ZFS Group APE'

   , (SELECT ISNULL(SUM(ISNULL(CAST(PolicyTransactions.APE AS DECIMAL(15,2)), 0.00)), 0.00)
      FROM mstt_PolicyTransactions PolicyTransactions
         INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
      WHERE EXISTS
          (SELECT Expectation.TransactionID
           FROM #MR0001aExpectation Expectation 
           WHERE Expectation.TransactionID = PolicyTransactions.ID
             AND Expectation.IRD >= @OD
             AND Expectation.IRD <= @CD
          )
      AND (PolicyTransactions.ZFSGroupFlag = 'N' OR PolicyTransactions.ZFSGroupFlag IS NULL) --Non-ZFS Group (or unknown) Providers
      AND (Policies.COMP_CODE = ProductProviders.ProductProviderCode
           OR ((Policies.COMP_CODE IS NULL OR Policies.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
               AND ProductProviders.ProductProviderCode IS NULL))
     ) AS 'Non-ZFS Group APE'

   , (SELECT ISNULL(SUM(ISNULL(CAST(PolicyTransactions.APE AS DECIMAL(15,2)), 0.00)), 0.00)
      FROM mstt_PolicyTransactions PolicyTransactions
         INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID
      WHERE EXISTS
          (SELECT Expectation.TransactionID
           FROM #MR0001aExpectation Expectation 
           WHERE Expectation.TransactionID = PolicyTransactions.ID
             AND Expectation.IRD >= @OD
             AND Expectation.IRD <= @CD
          )
      AND (Policies.COMP_CODE = ProductProviders.ProductProviderCode
           OR ((Policies.COMP_CODE IS NULL OR Policies.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
               AND ProductProviders.ProductProviderCode IS NULL))
     ) AS 'APE'

   , NULL AS [Error]

INTO #MR0001a
FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID 
LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = Policies.COMP_CODE

--5. Select data for report
SELECT 
     CASE WHEN [Provider] IS NOT NULL THEN [Provider] ELSE 'Unknown' END AS [Provider]
   , ISNULL(SUM(ISNULL(CAST([ZFS Group APE] AS DECIMAL(15,2)), 0.00)), 0.00) AS [ZFS Group APE]
   , ISNULL(SUM(ISNULL(CAST([Non-ZFS Group APE] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Non-ZFS Group APE]
   , ISNULL(SUM(ISNULL(CAST([APE] AS DECIMAL(15,2)), 0.00)), 0.00) AS [APE]
   , [Error]
FROM  #MR0001a
WHERE APE <> 0.00
GROUP BY [Provider], [Error]
ORDER BY [Provider]

--6. Tidy Up
DROP TABLE #MR0001a
DROP TABLE #MR0001aExpectation

GO
/****** Object:  StoredProcedure [dbo].[cscp_MR0001b]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
