CREATE PROCEDURE [dbo].[cscp_MR0003a] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

--1. Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Group/NonGroup - Life companies only'
      , NULL AS 'Provider'
      , NULL AS 'Gross Distribution Allowance'
      , NULL AS 'Clawback'
      , NULL AS 'Net Distribution Allowance'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

--2. Convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

--3. Extract Expectation data into a temp table
IF OBJECT_ID('tempdb..#MR3aExpectation') IS NOT NULL
   DROP TABLE #MR3aExpectation

SELECT Expectation.ID, 
       Expectation.Type,
       Expectation.TransactionID,
       Expectation.COMP_CODE,
       CASE Expectation.Type
          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          WHEN 4 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          WHEN 10 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1) -- types 2, 15, 16, 17, 18, 19
       END AS Amount_Due,
       CASE Expectation.Type
          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN 4 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN 10 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) * (-1) -- types 2, 15, 16, 17, 18, 19
       END AS Amount_Rec,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) AS Date_Due,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #MR3aExpectation
FROM mstt_Expectation Expectation
   INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
   INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
   INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (1, 2, 4, 10, 15, 16, 17, 18, 19)       --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD    --of the temp table
       OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD   --by omitting data which
           AND Expectation.DATE_RECV IS NOT NULL))          --we KNOW we don't need
GROUP BY Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
         Expectation.COMP_CODE,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

CREATE CLUSTERED INDEX ind_MR3a ON #MR3aExpectation (ID, Type, TransactionID, COMP_CODE, Amount_Due, Amount_Rec, Date_Due, Date_Recv, IRD)

--4. Extract report data into another temp table
IF OBJECT_ID('tempdb..#MR3a') IS NOT NULL
   DROP TABLE #MR3a

SELECT DISTINCT 
     CASE PolicyTransactions.ZFSGroupFlag 
        WHEN 'Y' THEN 'ZFS'
        WHEN 'N' THEN '3rd Parties'
        ELSE 'Unknown'
     END AS [Group/NonGroup - Life companies only]

   , ProductProviders.ReportingProductProviderName AS [Provider]

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR3aExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (Expectation1.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Expectation1.COMP_CODE IS NULL OR Expectation1.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR3aExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (Expectation1.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Expectation1.COMP_CODE IS NULL OR Expectation1.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR3aExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (Expectation1.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Expectation1.COMP_CODE IS NULL OR Expectation1.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         )
        )
    ) AS [Gross Distribution Allowance]

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR3aExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (Expectation1.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Expectation1.COMP_CODE IS NULL OR Expectation1.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR3aExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (Expectation1.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Expectation1.COMP_CODE IS NULL OR Expectation1.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR3aExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (Expectation1.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Expectation1.COMP_CODE IS NULL OR Expectation1.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         )
        )
    ) AS [Clawback]

   , NULL AS [Net Distribution Allowance]

   , NULL AS [Error]

INTO #MR3a
FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN #MR3aExpectation Expectation ON Expectation.TransactionID = PolicyTransactions.ID
LEFT JOIN mstt_ProductProviders ProductProviders ON ProductProviders.ProductProviderCode = Expectation.Comp_Code

--5. Select data for report
SELECT DISTINCT
      [Group/NonGroup - Life companies only]
      ,CASE
          WHEN Provider IS NOT NULL THEN Provider
          ELSE 'Unknown'
       END AS [Provider]
      ,ISNULL(SUM(ISNULL(CAST([Gross Distribution Allowance] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Gross Distribution Allowance]
      ,ISNULL(SUM(ISNULL(CAST([Clawback] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Clawback]
      ,ISNULL(SUM(ISNULL(CAST([Gross Distribution Allowance] AS DECIMAL(15,2)), 0.00)), 0.00)
       + ISNULL(SUM(ISNULL(CAST([Clawback] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Net Distribution Allowance]
      , NULL AS [Error]
FROM #MR3a
WHERE [Gross Distribution Allowance] <> 0.00 OR [Clawback] <> 0.00
GROUP BY [Group/NonGroup - Life companies only],[Provider]
ORDER BY [Group/NonGroup - Life companies only]

--6. Tidy Up
DROP TABLE #MR3aExpectation
DROP TABLE #MR3a

GO
