              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (Expectation1.COMP_CODE = ProductProviders.ProductProviderCode
               OR ((Expectation1.COMP_CODE IS NULL OR Expectation1.COMP_CODE NOT IN (SELECT ProductProviderCode FROM mstt_ProductProviders))
                   AND ProductProviders.ProductProviderCode IS NULL))
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5aExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (Expectation1.COMP_CODE = ProductProviders.ProductProviderCode
