            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
