                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5bExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5bExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         ) * (-1)
        )
    ) AS [Gross Commission Franchise]

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5bExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5bExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5bExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         ) * (-1)
        )
    ) AS [Clawback due from Franchise]

   , ' ' AS [Net Commission Franchise]

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5bExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5bExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5bExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         ) * (-1)
        )
    ) AS [Gross Margin Openwork]

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5bExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5bExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5bExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
         ) * (-1)
        )
    ) AS [Clawback Due From Openwork]

   , ' ' AS [Net Margin Openwork]

   , NULL AS [Error]

INTO #MR5b
FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN #MR5bExpectation Expectation ON Expectation.TransactionID = PolicyTransactions.ID
INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code
LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON Expectation.Type = Codes.Code AND ColumnName = 'CommissionType'

UNION ALL

SELECT DISTINCT 
     CASE PolicyTransactions.ZFSGroupFlag 
        WHEN 'Y' THEN 'ZFS'
        WHEN 'N' THEN '3rd Parties'
        ELSE 'Unknown'
     END AS [Group/NonGroup - Life companies only]

   , PaymentsPending.CommissionType AS [Type]
   , ISNULL(Codes.Description, 'Unknown') AS [Type of Distribution Allowance]

   , (SELECT 
          ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM mstt_PaymentsPending AS Pay
          LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
          LEFT JOIN mstt_PolicyTransactions PolicyTransactions1 ON Pay.TransactionID = PolicyTransactions1.ID
          WHERE Pay.CommissionType = Codes.Code
            AND Agents.Descn <> 'Openwork'
            AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
              OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) >= @OD))
            AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
              OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
     ) AS [Gross Commission Franchise]

   , 0.00 AS [Clawback due from Franchise]

   , ' ' AS [Net Commission Franchise]

   , (SELECT 
          ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM mstt_PaymentsPending AS Pay
          LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
          LEFT JOIN mstt_PolicyTransactions PolicyTransactions1 ON Pay.TransactionID = PolicyTransactions1.ID
          WHERE Pay.CommissionType = Codes.Code
            AND Agents.Descn <> 'Openwork'
            AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
              OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) >= @OD))
            AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
              OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
            AND (PolicyTransactions1.ZFSGroupFlag = PolicyTransactions.ZFSGroupFlag
                 OR (PolicyTransactions1.ZFSGroupFlag IS NULL AND PolicyTransactions.ZFSGroupFlag IS NULL))
     ) * (-1) AS [Gross Margin Openwork]

   , 0.00 AS [Clawback Due From Openwork]

   , ' ' AS [Net Margin Openwork]

   , NULL AS [Error]

FROM mstt_PaymentsPending PaymentsPending
LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON PaymentsPending.CommissionType = Codes.Code AND ColumnName = 'CommissionType'
LEFT JOIN mstt_PolicyTransactions PolicyTransactions ON PaymentsPending.TransactionID = PolicyTransactions.ID
WHERE Codes.Code IN ('20')

--5. Select data for report
SELECT 
      [Group/NonGroup - Life companies only]
      ,Type
      ,[Type of Distribution Allowance]
      ,ISNULL(SUM(ISNULL(CAST([Gross Commission Franchise] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Gross Commission Franchise]
      ,ISNULL(SUM(ISNULL(CAST([Clawback due from Franchise] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Clawback due from Franchise]
      ,[Net Commission Franchise]
      ,ISNULL(SUM(ISNULL(CAST([Gross Margin Openwork] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Gross Margin Openwork]
      ,ISNULL(SUM(ISNULL(CAST([Clawback Due From Openwork] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Clawback Due From Openwork]
      ,[Net Margin Openwork]
      , NULL AS [Error]
FROM #MR5b
WHERE [Gross Commission Franchise] <> 0.00 OR [Clawback due from Franchise] <> 0.00 OR [Gross Margin Openwork] <> 0.00 OR [Clawback Due From Openwork] <> 0.00
GROUP BY [Group/NonGroup - Life companies only], Type, [Type of Distribution Allowance]
,[Net Commission Franchise],[Net Margin Openwork]
ORDER BY [Group/NonGroup - Life companies only], Type

--6. Tidy Up
DROP TABLE #MR5bExpectation
DROP TABLE #MR5b

