CREATE PROCEDURE [dbo].[cscp_MR0005c] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

--1. Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'Product'
      , NULL AS 'Product Sub Group'
      , NULL AS 'Gross Commission Franchise'
      , NULL AS 'Clawback due from Franchise'
      , NULL AS 'Net Commission Franchise'
      , NULL AS 'Gross Margin Openwork'
      , NULL AS 'Clawback Due From Openwork'
      , NULL AS 'Net Margin Openwork'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

--2. Convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

--3. Extract Expectation data into a temp table
IF OBJECT_ID('tempdb..#MR5cExpectation') IS NOT NULL
   DROP TABLE #MR5cExpectation

IF OBJECT_ID('tempdb..#MR5cExpectation') IS NOT NULL
   DROP TABLE #MR5cExpectation

SELECT Expectation.ID, 
       Expectation.Type,
       Expectation.TransactionID,
       CASE Expectation.Type
          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          WHEN 4 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          WHEN 10 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1) -- types 2, 15, 16, 17, 18, 19
       END AS Amount_Due,
       CASE Expectation.Type
          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN 4 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN 10 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) * (-1) -- types 2, 15, 16, 17, 18, 19
       END AS Amount_Rec,
       dbo.cscf_CalcMarginPercent(Expectation.ID) AS Margin_Pct,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Due,
       CAST(NULL AS DECIMAL(15,2)) AS Margin_Rec,
       CAST(NULL AS DECIMAL(15,2)) AS Commission_Rec,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) AS Date_Due,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #MR5cExpectation
FROM mstt_Expectation Expectation
   INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
   INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
   INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (1, 2, 4, 10, 15, 16, 17, 18, 19)       --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD    --of the temp table
       OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD   --by omitting data which
           AND Expectation.DATE_RECV IS NOT NULL))          --we KNOW we don't need
GROUP BY Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

-- 3.1 bypass Margin Calcs for margin and commission values to avoid calling cscf_CalcMarginPercent more than once per Expectation
UPDATE #MR5cExpectation
SET Margin_Due = ISNULL(CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Due = ISNULL(CAST((Amount_Due - CAST((Amount_Due * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00),
    Margin_Rec = ISNULL(CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2)), 0.00),
    Commission_Rec = ISNULL(CAST((Amount_Rec - CAST((Amount_Rec * Margin_Pct) AS DECIMAL(15,2))) AS DECIMAL(15,2)), 0.00)

CREATE CLUSTERED INDEX ind_MR5c ON #MR5cExpectation (ID, Type, TransactionID, Amount_Due, Amount_Rec, Margin_Pct, Margin_Due, Commission_Due, Margin_Rec, Commission_Rec, Date_Due, Date_Recv, IRD)

--4. Extract report data into another temp table
IF OBJECT_ID('tempdb..#MR5c') IS NOT NULL
   DROP TABLE #MR5c

SELECT DISTINCT
     ISNULL(CodeProductGroup.ProductGroupName, 'Unknown') AS 'Product'
   , ISNULL(CodeProductSubGroup.ProductSubGroupName, 'Unknown') AS 'Product Sub Group'

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         ) * (-1)
        )
    ) AS [Gross Commission Franchise]

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Commission_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Commission_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         ) * (-1)
        )
    ) AS [Clawback due from Franchise]

   , ' ' AS [Net Commission Franchise]

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         ) * (-1)
        )
    ) AS [Gross Margin Openwork]

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         )
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Margin_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Margin_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #MR5cExpectation AS Expectation1
          INNER JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Expectation1.TransactionID
          INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
         ) * (-1)
        )
    ) AS [Clawback Due From Openwork]

   , ' ' AS [Net Margin Openwork]

   , NULL AS [Error]

INTO #MR5c
FROM mstt_PolicyTransactions PolicyTransactions
INNER JOIN #MR5cExpectation Expectation ON Expectation.TransactionID = PolicyTransactions.ID
INNER JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID 
LEFT JOIN mstt_CodeProductGroup CodeProductGroup ON Policies.ProductGroupCode = CodeProductGroup.ProductGroupCode
LEFT JOIN mstt_CodeProductSubGroup CodeProductSubGroup ON CodeProductSubGroup.ProductGroupCode = CodeProductGroup.ProductGroupCode

UNION ALL

SELECT DISTINCT
     ISNULL(CodeProductGroup.ProductGroupName, 'Unknown') AS 'Product'
   , ISNULL(CodeProductSubGroup.ProductSubGroupName, 'Unknown') AS 'Product Sub Group'

   , (SELECT 
          ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM mstt_PaymentsPending AS Pay
          LEFT JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Pay.TransactionID
          LEFT JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
          WHERE Pay.CommissionType IN (20)
            AND Agents.Descn <> 'Openwork'
            AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
              OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) >= @OD))
            AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
              OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
    ) AS [Gross Commission Franchise]

   , 0.00 AS [Clawback due from Franchise]

   , ' ' AS [Net Commission Franchise]

   , (SELECT 
          ISNULL(SUM(ISNULL(CAST(Pay.Amount AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM mstt_PaymentsPending AS Pay
          LEFT JOIN mstt_PolicyTransactions PolicyTransactions1 ON PolicyTransactions1.ID = Pay.TransactionID
          LEFT JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions1.PolicyID
          LEFT JOIN mstt_Agents AS Agents ON Pay.Agent_Code = Agents.Code
          WHERE Pay.CommissionType IN (20)
            AND Agents.Descn <> 'Openwork'
            AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) >= @OD
              OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) >= @OD))
            AND (CAST(CONVERT(NVARCHAR, Pay.PaymentDueDate, 112) AS DATETIME) <= @CD
              OR (Pay.PaymentDueDate IS NULL AND CAST(CONVERT(NVARCHAR, Pay.CreatedDate, 112) AS DATETIME) <= @CD))
            AND (Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
               OR (Policies.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
    ) * (-1) AS [Gross Margin Openwork]

   , 0.00 AS [Clawback Due From Openwork]

   , ' ' AS [Net Margin Openwork]

   , NULL AS [Error]

FROM mstt_PaymentsPending PaymentsPending
LEFT JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = PaymentsPending.TransactionID
LEFT JOIN mstt_Policies Policies ON Policies.POL_NUM = PolicyTransactions.PolicyID 
LEFT JOIN mstt_CodeProductGroup CodeProductGroup ON Policies.ProductGroupCode = CodeProductGroup.ProductGroupCode
LEFT JOIN mstt_CodeProductSubGroup CodeProductSubGroup ON Policies.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode
LEFT JOIN msit_MIWarehouseCodesAndDescriptions Codes ON PaymentsPending.CommissionType = Codes.Code AND ColumnName = 'CommissionType'

--5. Select data for report
SELECT 
      [Product]
      ,[Product Sub Group]
      ,ISNULL(SUM(ISNULL(CAST([Gross Commission Franchise] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Gross Commission Franchise]
      ,ISNULL(SUM(ISNULL(CAST([Clawback due from Franchise] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Clawback due from Franchise]
      ,[Net Commission Franchise]
      ,ISNULL(SUM(ISNULL(CAST([Gross Margin Openwork] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Gross Margin Openwork]
      ,ISNULL(SUM(ISNULL(CAST([Clawback Due From Openwork] AS DECIMAL(15,2)), 0.00)), 0.00) AS [Clawback Due From Openwork]
      ,[Net Margin Openwork]
      , NULL AS [Error]
FROM #MR5c
WHERE [Gross Commission Franchise] <> 0.00 OR [Clawback due from Franchise] <> 0.00 OR [Gross Margin Openwork] <> 0.00 OR [Clawback Due From Openwork] <> 0.00
GROUP BY [Product],[Product Sub Group]
,[Net Commission Franchise],[Net Margin Openwork]
ORDER BY [Product]

--6. Tidy Up
DROP TABLE #MR5cExpectation
DROP TABLE #MR5c

GO
