CREATE PROCEDURE [dbo].[cscp_NewStarters] @UserID VARCHAR(255)
AS

SELECT
  ISNULL(RTRIM(SUBSTRING(Agents.FirstNames, 1, PATINDEX('%[^ ] %', Agents.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Name]
, Agents.CODE AS 'Code'
, ISNULL(RTRIM(SUBSTRING(Agents_SVR.FirstNames, 1, PATINDEX('%[^ ] %', Agents_SVR.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_SVR.Name), '') AS [Supervisor]
, ISNULL(RTRIM(SUBSTRING(Agents_MGR.FirstNames, 1, PATINDEX('%[^ ] %', Agents_MGR.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_MGR.Name), '') AS [Recruitment Manager]
, CONVERT(VARCHAR, AgentCompetence.DateCreated, 103) AS 'Competence Created'
, CodeComplianceCategory.Code AS 'Competency' --Competency Type
, DATEDIFF(Week, CAST(CONVERT(NVARCHAR, AgentCompetence.DateCreated, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME)) AS 'Weeks'
, '' AS 'Sales Recruitment Comments'
, ISNULL(RTRIM(SUBSTRING(Agents_4.FirstNames, 1, PATINDEX('%[^ ] %', Agents_4.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_4.Name), '') AS [Area] --for group title

FROM mstt_Agents Agents 
     INNER JOIN msit_AgentCompetence AgentCompetence ON Agents.ID = AgentCompetence.AgentID 
     INNER JOIN msit_CodeComplianceCategory CodeComplianceCategory ON AgentCompetence.CodeComplianceCategoryID = CodeComplianceCategory.ID
     LEFT JOIN mstt_Agents AS Agents_SVR ON Agents.SpanSupervisorCode = Agents_SVR.CODE
     LEFT JOIN mstt_Agents AS Agents_MGR ON Agents.RecruitedByCode = Agents_MGR.CODE
     LEFT JOIN mstt_Agents AS Agents_4 ON Agents.Manager4Code = Agents_4.CODE
     LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code

WHERE AgentCompetence.AchievedDate IS NULL
AND   AgentCompetence.EndDate IS NULL
AND   DATEDIFF(Week, CAST(CONVERT(NVARCHAR, AgentCompetence.DateCreated, 112) AS DATETIME), CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME)) > 8
AND   Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents
AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised

ORDER BY Area, Weeks DESC, Agents.CODE


GO
/****** Object:  StoredProcedure [dbo].[cscp_NoReportees]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
