CREATE PROCEDURE [dbo].[cscp_NoReportees] @UserID VARCHAR(255)
AS
SELECT ISNULL(RTRIM(SUBSTRING(AgentsSvr.FirstNames, 1, PATINDEX('%[^ ] %', AgentsSvr.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(AgentsSvr.Name), '') AS [Svisor Name],
       AgentsSvr.Code AS [Unique Id],
       (SELECT dbo.cscf_GetAgentSectors(AgentsSvr.ID, GetDate())) AS [Sectors Held],
       (SELECT dbo.cscf_GetAgentSectorsNoStartDate(AgentsSvr.ID)) AS [No Start Date],
       AgentsSvr.SupervisorTypeCode AS [Svisor Type],
       NULL AS [Notes], -- user field
       'Supervisor''s Supervisor: '
        + ISNULL(RTRIM(SUBSTRING(AgentsSOS.FirstNames, 1, PATINDEX('%[^ ] %', AgentsSOS.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(AgentsSOS.Name), '')
        + RTRIM(ISNULL(' (' + AgentsSOS.Code + ')', '')) AS [SOS], -- sort/group by field
       CASE Agents_mgr2.AgentCategory
          WHEN 'ASQMNS' THEN 'Area Sales Quality Manager: '
          ELSE 'Regional Sales Manager: '
       END
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr2.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr2.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr2.Name), '')
        + RTRIM(ISNULL(' (' + Agents_mgr2.Code + ')', '')) AS [Mgr2], -- sort/group by field
       'Area Sales Director: '
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr4.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr4.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr4.Name), '') AS [Mgr4] -- sort/group by field
FROM mstt_Agents AS AgentsSvr
LEFT JOIN mstt_Agents AS AgentsSOS ON AgentsSvr.SpanSupervisorCode = AgentsSOS.Code
LEFT JOIN mstt_Agents AS Agents_mgr2 ON AgentsSOS.Manager2Code = Agents_mgr2.Code
LEFT JOIN mstt_Agents AS Agents_mgr4 ON Agents_mgr2.Manager4Code = Agents_mgr4.Code
LEFT JOIN mstt_Agents AS Business ON COALESCE(AgentsSvr.DirectlyAuthorisedCode, AgentsSvr.OfficeCode, AgentsSvr.AccessAgentCode, AgentsSvr.StrategicAllianceCode) = Business.Code
WHERE AgentsSvr.CanSupervise = 1 -- is a supervisor
  AND AgentsSvr.AgentTypeB30 = 2 -- exclude businesses
  AND AgentsSvr.CompetentStatus = 1 -- include Active advisers only
  AND AgentsSvr.AgentType NOT IN (3, 17, 44, 5, 45) -- exlcude IAR, Staff, Company Sec, Admin, 10% shareholder
  AND AgentsSvr.AgentCategory <> 'RI' -- exclude RI
  AND NOT EXISTS (SELECT AgentsReportee.Code
                  FROM mstt_Agents AS AgentsReportee
                  WHERE AgentsReportee.SaleSupervisorCode = AgentsSvr.CODE
                     OR AgentsReportee.SpanSupervisorCode = AgentsSvr.CODE
                 ) -- but has no reportees
 AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
ORDER BY [Mgr4], [Mgr2], [SOS], [Svisor Name]

GO
