CREATE PROCEDURE [dbo].[cscp_NoSupervisors] @UserID VARCHAR(255)
AS
SELECT ISNULL(RTRIM(SUBSTRING(Agents.FirstNames, 1, PATINDEX('%[^ ] %', Agents.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents.Name), '') AS [Adviser Name],
       Agents.Code AS [Adviser Unique Id],
       Agents.AgentTypeDescription AS [Type],
       Agents.AgentCategory AS [Category],
       AgentLicence.LicenceCode AS [LicenceID],
       CONVERT(VARCHAR, AgentLicence.StartDate, 103) AS [Licence Start Date],
       NULL AS [Notes], -- user field
       CASE Agents_mgr2.AgentCategory
          WHEN 'ASQMNS' THEN 'Area Sales Quality Manager: '
          ELSE 'Regional Sales Manager: '
       END
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr2.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr2.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr2.Name), '')
        + RTRIM(ISNULL(' (' + Agents_mgr2.Code + ')', '')) AS [Mgr2], -- sort/group by field
       'Area Sales Director: '
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr4.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr4.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr4.Name), '') AS [Mgr4] -- sort/group by field

FROM mstt_Agents AS Agents
LEFT JOIN mstt_Agents AS Agents_mgr2 ON Agents.Manager2Code = Agents_mgr2.Code
LEFT JOIN mstt_Agents AS Agents_mgr4 ON Agents.Manager4Code = Agents_mgr4.Code
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
INNER JOIN mstt_AgentLicence AS AgentLicence ON AgentLicence.AgentID = Agents.id
WHERE (Agents.SaleSupervisorCode = '10012' OR Agents.SpanSupervisorCode = '10012')
  AND Agents.AgentTypeB30 = 2 -- exclude businesses
  AND Agents.CompetentStatus = 1 -- include Active advisers only
  AND (AgentLicence.LicenceCode not like '[QSU]%' AND AgentLicence.EndDate is NULL)
ORDER BY [Mgr4], [Mgr2], [Adviser Name]


GO
/****** Object:  StoredProcedure [dbo].[cscp_PFANoFranchise]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[cscp_PFANoFranchise] @UserID VARCHAR(255)
AS

SELECT Agents.Code AS [Unique ID],
       ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser Name],
       Agents.AgentTypeDescription AS [Adviser Type],
       Agents.AgentCategory AS [Adviser Category],
       CASE
          WHEN (Agents.Firm IS NULL OR Agents.Firm = '') 
             THEN 'Individual is not attached to a Business'

          WHEN Agents.Firm IS NOT NULL AND Agents.Firm <> '' 
           AND (Agents_1.CompetentStatus NOT IN (1, 5) OR Agents_1.CompetentStatus IS NULL)
             THEN 'Business (' + Agents_1.Code + ') is "' + ISNULL(Agents_1.CompetentStatusDescription, 'Unknown Status') + '"'

          WHEN Agents.Firm IS NOT NULL AND Agents.Firm <> '' 
           AND Agents_1.CompetentStatus IN (1, 5)
           AND (Agents_1.Manager2Code IS NULL OR Agents_1.Manager2Code = '')
             THEN 'Business (' + Agents_1.Code + ') is not attached to an RSM'

          WHEN Agents.Firm IS NOT NULL AND Agents.Firm <> '' 
           AND Agents_1.CompetentStatus IN (1, 5)
           AND Agents_1.Manager2Code IS NOT NULL AND Agents_1.Manager2Code <> ''
           AND (Agents_2.CompetentStatus NOT IN (1, 5) OR Agents_2.CompetentStatus IS NULL)
             THEN 'RSM (' + Agents_2.Code + ') is "' + ISNULL(Agents_2.CompetentStatusDescription, 'Unknown Status') + '"'

          WHEN Agents.Firm IS NOT NULL AND Agents.Firm <> '' 
           AND Agents_1.CompetentStatus IN (1, 5)
           AND Agents_1.Manager2Code IS NOT NULL AND Agents_1.Manager2Code <> ''
           AND Agents_2.CompetentStatus IN (1, 5)
           AND (Agents_2.Manager4Code IS NULL OR Agents_2.Manager4Code = '')
             THEN 'RSM (' + Agents_2.Code + ') is not attached to an ASD'

          WHEN Agents.Firm IS NOT NULL AND Agents.Firm <> '' 
           AND Agents_1.CompetentStatus IN (1, 5)
           AND Agents_1.Manager2Code IS NOT NULL AND Agents_1.Manager2Code <> ''
           AND Agents_2.CompetentStatus IN (1, 5)
           AND Agents_2.Manager4Code IS NOT NULL AND Agents_2.Manager4Code <> ''
           AND (Agents_3.CompetentStatus NOT IN (1, 5) OR Agents_3.CompetentStatus IS NULL)
             THEN 'ASD (' + Agents_3.Code + ') is "' + ISNULL(Agents_3.CompetentStatusDescription, 'Unknown Status') + '"'

          ELSE 'Unknown'
       END AS [Reason]

FROM mstt_Agents AS Agents
LEFT JOIN mstt_Agents AS Agents_1 ON Agents.Firm = Agents_1.CODE -- Business
LEFT JOIN mstt_Agents AS Agents_2 ON Agents_1.Manager2Code = Agents_2.CODE -- RSM
LEFT JOIN mstt_Agents AS Agents_3 ON Agents_2.Manager4Code = Agents_3.CODE -- ASD

WHERE Agents.AgentType IN (3, 4, 43, 51, 5) -- IARs, Sellers, Practice Principles, PFA Principals, PAs
  AND Agents.CompetentStatus IN (1, 5) -- Active/Pre-App Agents only
  AND ((Agents.Firm IS NULL OR Agents.Firm = '') -- not attached to a business
     OR 
       (Agents.Firm IS NOT NULL AND Agents.Firm <> '' 
        AND (Agents_1.CompetentStatus NOT IN (1, 5) OR Agents_1.CompetentStatus IS NULL)) -- inactive Business
     OR 
       (Agents.Firm IS NOT NULL AND Agents.Firm <> '' 
        AND Agents_1.CompetentStatus IN (1, 5)
        AND (Agents_1.Manager2Code IS NULL OR Agents_1.Manager2Code = '')) -- business not attached to an RSM
     OR 
       (Agents.Firm IS NOT NULL AND Agents.Firm <> '' 
        AND Agents_1.CompetentStatus IN (1, 5)
        AND Agents_1.Manager2Code IS NOT NULL AND Agents_1.Manager2Code <> ''
        AND (Agents_2.CompetentStatus NOT IN (1, 5) OR Agents_2.CompetentStatus IS NULL)) -- inactive RSM
     OR
       (Agents.Firm IS NOT NULL AND Agents.Firm <> '' 
        AND Agents_1.CompetentStatus IN (1, 5)
        AND Agents_1.Manager2Code IS NOT NULL AND Agents_1.Manager2Code <> ''
        AND Agents_2.CompetentStatus IN (1, 5)
        AND (Agents_2.Manager4Code IS NULL OR Agents_2.Manager4Code = '')) -- RSM not attached to an ASD
     OR
       (Agents.Firm IS NOT NULL AND Agents.Firm <> '' 
        AND Agents_1.CompetentStatus IN (1, 5)
        AND Agents_1.Manager2Code IS NOT NULL AND Agents_1.Manager2Code <> ''
        AND Agents_2.CompetentStatus IN (1, 5)
        AND Agents_2.Manager4Code IS NOT NULL AND Agents_2.Manager4Code <> ''
        AND (Agents_3.CompetentStatus NOT IN (1, 5) OR Agents_3.CompetentStatus IS NULL)) -- inactive ASD
      )

ORDER BY Agents.Code

GO
