CREATE PROCEDURE [dbo].[cscp_PracticeNoPFA] @UserID VARCHAR(255)
AS
SELECT CASE
          WHEN Practice.TradingName IS NOT NULL AND RTRIM(Practice.TradingName) <> '' THEN RTRIM(Practice.TradingName) 
          ELSE Practice.Descn
       END AS 'TradingName', 
       Practice.AgentTypeDescription AS 'PracticeType',
       Practice.Code AS 'Practice code'
FROM mstt_agents Practice
WHERE Practice.CompetentStatus = 1 
  AND Practice.AgentCategory IN ('PRAC')
  AND Practice.AgentType <> 49
  AND (SELECT COUNT(Principal.Code)  -- Exactly one active Principle
       FROM mstt_Agents Principal
       WHERE Practice.Code = Principal.Firm
         AND Principal.AgentType = 43 -- Principal
         AND Principal.AgentCategory IN ('PRINNS', 'PRINSL')
      ) = 1
  AND NOT EXISTS (SELECT OtherAgents.Code  -- No Active PFA’s with this firm code
                  FROM mstt_agents OtherAgents 
                  WHERE Practice.Code = OtherAgents.Firm
                    AND OtherAgents.CompetentStatus = 1
                    AND OtherAgents.AgentCategory = 'PFA' 
                 )
ORDER BY Practice.Code


GO
/****** Object:  StoredProcedure [dbo].[cscp_RefresherLatePass]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_RefresherLatePass] @UserID VARCHAR(255)
AS
-- Determine decision date for exam taken
DECLARE @TodayMinus7Days AS DATETIME
SELECT @TodayMinus7Days = DateAdd(Day, -7, GetDate())
SELECT AgentExams.AgentCode AS [Adviser ID],
       ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser Name],
       AgentExams.Type AS [Exam Code],
       AgentExams.AgentExamDescription AS [Exam Description],
       CONVERT(VARCHAR, AgentExams.DateTaken, 103) AS [Date Taken],
       CASE AgentExams.Result
          WHEN 1 THEN 'Pass'
          WHEN 2 THEN 'Fail'
          ELSE ''
       END AS [Result],
       AgentExams.Percentage AS [Mark],
       AgentLicence.LicenceCode AS [Licence Code],
       AgentLicence.LicenceDescription AS [Licence Description],
       CONVERT(VARCHAR, AgentLicence.StartDate, 103) AS [Licence Start Date],
       CONVERT(VARCHAR, AgentLicence.ExpiryDate, 103) AS [Licence Expiry Date],
       CONVERT(VARCHAR, AgentLicence.EndDate, 103) AS [Licence End Date]
FROM mstt_AgentExams AS AgentExams
INNER JOIN mstt_Agents AS Agents ON Agents.Code = AgentExams.AgentCode
LEFT JOIN msit_CodeAgentExams AS CodeAgentExams ON CodeAgentExams.Code = AgentExams.Type
LEFT JOIN msit_CodeExamLicence AS CodeExamLicence ON CodeExamLicence.CodeAgentExamsID = CodeAgentExams.ID
INNER JOIN mstt_AgentLicence AS AgentLicence ON AgentLicence.CodeLicenceID = CodeExamLicence.CodeLicenceID -- adviser has an end-dated licence
       AND AgentLicence.AgentID = Agents.ID
       AND (AgentLicence.StartDate IS NOT NULL AND CAST(CONVERT(NVARCHAR,AgentLicence.StartDate ,112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,getdate() ,112) AS DATETIME))
       AND (AgentLicence.EndDate IS NOT NULL AND CAST(CONVERT(NVARCHAR,AgentLicence.EndDate ,112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,getdate() ,112) AS DATETIME))
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
WHERE AgentExams.Result = 1 -- passed exam
  AND Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents only
  AND Agents.AgentTypeB30=2
  AND CAST(CONVERT(NVARCHAR, AgentExams.DateTaken, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, AgentExams.DateTaken, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @TodayMinus7Days, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, AgentLicence.EndDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, DateAdd(Month, -6, AgentExams.DateTaken)) AS DATETIME)
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
  AND NOT EXISTS -- adviser does not have a valid licence of the same type (i.e. as well as an end-dated one)
     (SELECT AgentLicence_2.CodeLicenceID
      FROM mstt_AgentLicence AS AgentLicence_2
      WHERE AgentLicence_2.CodeLicenceID = CodeExamLicence.CodeLicenceID
        AND AgentLicence_2.AgentID = Agents.ID
        AND (AgentLicence_2.StartDate IS NOT NULL AND CAST(CONVERT(NVARCHAR,AgentLicence_2.StartDate ,112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,getdate() ,112) AS DATETIME))
        AND (AgentLicence_2.EndDate IS NULL OR CAST(CONVERT(NVARCHAR,AgentLicence_2.EndDate ,112) AS DATETIME) >= CAST(CONVERT(NVARCHAR,getdate() ,112) AS DATETIME)) 
        AND AgentLicence_2.CodeLicenceID = AgentLicence.CodeLicenceID
     )
ORDER BY [Adviser Name], AgentExams.DateTaken, AgentExams.Type

GO
/****** Object:  StoredProcedure [dbo].[cscp_ReplLicsExpired]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_ReplLicsExpired] @UserID VARCHAR(255)
AS
-- Determine decision dates
DECLARE @TodayMinus9Months AS DATETIME
SELECT @TodayMinus9Months = DateAdd(Month, -9, GetDate())
DECLARE @TodayMinus12Months AS DATETIME
SELECT @TodayMinus12Months = DateAdd(Month, -12, GetDate())
-- Delete temp table before use
IF OBJECT_ID('tempdb..#Temp') IS NOT NULL
   DROP TABLE #Temp
-- Report query
SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser],
       Agents.Code AS [Unique Id],
       dbo.cscf_GetAgentSectors(Agents.ID, GetDate()) AS [SectorsHeld],
       AgentLicence.LicenceCode AS [Licence],
       CONVERT(VARCHAR, AgentLicence.StartDate, 103) AS [Licence Start Date],
       (SELECT CONVERT(VARCHAR, MAX(Policies.Prop_Date), 103) -- submission date of last replacement sale
        FROM mstt_Policies AS Policies
        WHERE Policies.ServicingAgentCode = Agents.CODE
          AND Policies.Replacement > 0 -- replacement category A, B or C (= 1, 2 or 3)
       ) AS [Last Repl Sale],
       'X' AS [Highlight],
       'Supervisor: '
        + ISNULL(RTRIM(SUBSTRING(AgentsSvr.FirstNames, 1, PATINDEX('%[^ ] %', AgentsSvr.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(AgentsSvr.Name), '')
        + RTRIM(ISNULL(' (' + AgentsSvr.Code + ')', '')) AS [Svr], -- sort/group by field
       CASE Agents_mgr2.AgentCategory
          WHEN 'ASQMNS' THEN 'Area Sales Quality Manager: '
          ELSE 'Regional Sales Manager: '
       END
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr2.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr2.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr2.Name), '')
        + RTRIM(ISNULL(' (' + Agents_mgr2.Code + ')', '')) AS [Mgr2], -- sort/group by field
       'Area Sales Director: '
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr4.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr4.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr4.Name), '') AS [Mgr4] -- sort/group by field
INTO #Temp
FROM mstt_Agents AS Agents
INNER JOIN mstt_AgentLicence AS AgentLicence ON AgentLicence.AgentID = Agents.id
  AND AgentLicence.CodeLicenceID IN (79, 80) -- replacement licences
  AND (AgentLicence.StartDate IS NOT NULL -- licence open
       AND CAST(CONVERT(NVARCHAR,AgentLicence.StartDate,112) AS DATETIME) < CAST(CONVERT(NVARCHAR,@TodayMinus9Months,112) AS DATETIME))  -- licence more than 9 months old
  AND (AgentLicence.EndDate IS NULL OR CAST(CONVERT(NVARCHAR,AgentLicence.EndDate,112) AS DATETIME) >= CAST(CONVERT(NVARCHAR,getdate(),112) AS DATETIME)) -- licence still open
LEFT JOIN mstt_Agents AS AgentsSvr ON Agents.SpanSupervisorCode = AgentsSvr.Code
LEFT JOIN mstt_Agents AS Agents_mgr2 ON AgentsSvr.Manager2Code = Agents_mgr2.Code
LEFT JOIN mstt_Agents AS Agents_mgr4 ON Agents_mgr2.Manager4Code = Agents_mgr4.Code
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
WHERE Agents.AgentTypeB30 = 2 -- individuals only (exclude businesses)
  AND Agents.CompetentStatus = 1 -- Active only
  AND Agents.AgentType NOT IN (3, 17, 44, 5, 45) -- not an IAR, Staff, Company Sec, Admin, 10% shareholder
  AND Agents.AgentCategory <> 'RI' -- not an RI
  AND (Agents.SupervisorTypeCode IS NULL
  OR Agents.SupervisorTypeCode NOT IN ('PSUPNA', 'SUPNA', 'SOSNA')) --exclude non-selling supervisors
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
  AND (SELECT COUNT(*) -- no replacement sales within last 9 months
       FROM mstt_Policies AS Policies
       WHERE Policies.ServicingAgentCode = Agents.CODE
         AND Policies.Replacement > 0 -- replacement category A, B or C (= 1, 2 or 3)
         AND CAST(CONVERT(NVARCHAR,Policies.Prop_Date,112) AS DATETIME)  >= CAST(CONVERT(NVARCHAR,@TodayMinus9Months,112) AS DATETIME)   -- submitted within last 9 months
      ) = 0
ORDER BY [Mgr4], [Mgr2], [Svr], [Adviser], [Licence]
--determine which rows in #Temp need to be highlighted as more than 12 months old
UPDATE #Temp
SET HighLight = (SELECT CASE 
                           WHEN CAST(CONVERT(NVARCHAR, CONVERT(DATETIME, [Licence Start Date], 103),112) AS DATETIME) < CAST(CONVERT(NVARCHAR,@TodayMinus12Months ,112) AS DATETIME)
                            AND (CAST(CONVERT(NVARCHAR,CONVERT(DATETIME, [Last Repl Sale], 103),112) AS DATETIME) < CAST(CONVERT(NVARCHAR,@TodayMinus12Months ,112) AS DATETIME)
                                 OR [Last Repl Sale] IS NULL)
                              THEN 'R' -- licence and last sale 12 months old = red
                           WHEN CAST(CONVERT(NVARCHAR,CONVERT(DATETIME, [Licence Start Date], 103),112) AS DATETIME) < CAST(CONVERT(NVARCHAR,@TodayMinus9Months ,112) AS DATETIME)
                            AND (CAST(CONVERT(NVARCHAR,CONVERT(DATETIME, [Last Repl Sale], 103),112) AS DATETIME) < CAST(CONVERT(NVARCHAR,@TodayMinus9Months ,112) AS DATETIME)
                                 OR [Last Repl Sale] IS NULL)
                              THEN 'A' -- licence abd last sale 9 months old = amber
                           ELSE 'N'
                 END
                )
--report from #Temp
SELECT * FROM #Temp
DROP TABLE #Temp

GO
/****** Object:  StoredProcedure [dbo].[cscp_RMAR0012a]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[cscp_RMAR0012a] @UserID VARCHAR(255), @StartDate VARCHAR(255), @EndDate VARCHAR(10)
AS

--1. Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR  ISDATE(@EndDate) = 0
BEGIN
  SELECT 
        NULL AS 'Revenue Category'
      , NULL AS 'Product Sub Group'
      , NULL AS 'APE'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN 'Invalid Closing Date Entered. Please enter it in the format dd/mm/yyyy' 
        END AS 'Error'
   RETURN 0
END

IF OBJECT_ID('tempdb..#RMAR0012a') IS NOT NULL
   DROP TABLE #RMAR0012a

--2. Convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

--3. Extract Expectation data into a temp table
IF OBJECT_ID('tempdb..#RMAR0012aExpectation') IS NOT NULL
   DROP TABLE #RMAR0012aExpectation

SELECT Expectation.ID, 
       Expectation.Type,
       Expectation.TransactionID,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #RMAR0012aExpectation
FROM mstt_Expectation Expectation
   INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
   INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
   INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (1)               --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD    --of the temp table
       OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD   --by omitting data which
           AND Expectation.DATE_RECV IS NOT NULL))          --we KNOW we don't need
GROUP BY Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID

CREATE CLUSTERED INDEX ind_MR0001 ON #RMAR0012aExpectation (ID, Type, TransactionID, IRD)

--4. Extract report data into another temp table
--4.1 Select data for populated Revenue Categories first
SELECT DISTINCT
        ISNULL(CodeRevenueCategoryCode.RevenueCategoryCode, 99) AS 'SeqNo' -- 99 ensures 'Unknown' category is last in sort order
      , ISNULL(CodeRevenueCategoryCode.RevenueCategoryDescription, 'Unknown') AS 'Revenue Category' 
      , ISNULL(CodeProductSubGroup.ProductSubGroupName, 'Unknown') AS 'Product Sub Group'
      , (SELECT ISNULL(SUM(ISNULL(CAST(PolicyTransactions_APE.APE AS DECIMAL(15,2)), 0.00)), 0.00)
         FROM mstt_PolicyTransactions PolicyTransactions_APE
         LEFT JOIN mstt_ProductHierarchy ProductHierarchy on ProductHierarchy.ProductCode = PolicyTransactions_APE.CommProductCode 
         LEFT JOIN mstt_CodeRevenueCategoryCode CodeRevenueCategoryCode_APE ON CodeRevenueCategoryCode_APE.RevenueCategoryCode = ProductHierarchy.RevenueCategoryCode
         WHERE EXISTS
               (SELECT Expectation.TransactionID
                FROM #RMAR0012aExpectation Expectation 
                WHERE Expectation.TransactionID = PolicyTransactions_APE.ID
                  AND Expectation.IRD >= @OD
                  AND Expectation.IRD <= @CD
               )
           AND (CodeRevenueCategoryCode_APE.RevenueCategoryCode = CodeRevenueCategoryCode.RevenueCategoryCode 
             OR (CodeRevenueCategoryCode_APE.RevenueCategoryCode IS NULL AND CodeRevenueCategoryCode.RevenueCategoryCode IS NULL))
           AND (PolicyTransactions_APE.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode 
             OR (PolicyTransactions_APE.ProductSubGroupCode IS NULL AND CodeProductSubGroup.ProductSubGroupCode IS NULL))
        )  AS 'APE'
      , NULL AS [Error]
INTO #RMAR0012a
FROM mstt_PolicyTransactions PolicyTransactions
LEFT JOIN mstt_ProductHierarchy ProductHierarchy on ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
LEFT JOIN mstt_CodeRevenueCategoryCode CodeRevenueCategoryCode ON CodeRevenueCategoryCode.RevenueCategoryCode = ProductHierarchy.RevenueCategoryCode
LEFT JOIN mstt_CodeProductSubGroup CodeProductSubGroup ON PolicyTransactions.ProductSubGroupCode = CodeProductSubGroup.ProductSubGroupCode

--4.2 Remove any rows with zero APE
DELETE FROM #RMAR0012a
WHERE APE = 0.00

--4.3 Now add any Revenue Categories missing from the temporary table so that all are present
INSERT INTO #RMAR0012a
SELECT  CodeRevenueCategoryCode.RevenueCategoryCode AS 'SeqNo'
      , CodeRevenueCategoryCode.RevenueCategoryDescription AS 'Revenue Category' 
      , ' ' AS 'Product Sub Group'
      , 0.00 AS 'APE'
      , NULL AS 'Error'
FROM mstt_CodeRevenueCategoryCode CodeRevenueCategoryCode
WHERE NOT EXISTS (SELECT SeqNo
                  FROM #RMAR0012a
                  WHERE SeqNo = CodeRevenueCategoryCode.RevenueCategoryCode)

--5. Select data for report in SeqNo order
SELECT  [Revenue Category]
      , [Product Sub Group]
      , [APE]
      , [Error]
FROM  #RMAR0012a
ORDER BY [SeqNo], [Product Sub Group]

--6. Tidy Up
DROP TABLE #RMAR0012a
DROP TABLE #RMAR0012aExpectation


GO
/****** Object:  StoredProcedure [dbo].[cscp_RMAR0013]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [dbo].[cscp_RMAR0013] @UserID VARCHAR(255), @AgentCategory VARCHAR(8), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

--1. Validate @StartDate and @EndDate
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS 'SeqNo'
      , NULL AS 'Revenue Category'
      , NULL AS 'Distribution Allowance'
      , NULL AS 'Clawback'
      , NULL AS 'Net DA'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END

--2. Convert input dates into DateTime's
DECLARE @OD DATETIME, @CD DATETIME
SET @OD = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
SET @CD = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

--3. Extract Expectation data into a temp table
IF OBJECT_ID('tempdb..#RMAR13Expectation') IS NOT NULL
   DROP TABLE #RMAR13Expectation

SELECT Expectation.ID, 
       Expectation.Type,
       Expectation.TransactionID,
       CASE Expectation.Type
          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          WHEN 4 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          WHEN 10 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) 
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00) * (-1) -- types 2, 15, 16, 17, 18, 19
       END AS Amount_Due,
       CASE Expectation.Type
          WHEN 1 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN 4 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          WHEN 10 THEN ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          ELSE ISNULL(SUM(ISNULL(CAST(Expectation.Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00) * (-1) -- types 2, 15, 16, 17, 18, 19
       END AS Amount_Rec,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) AS Date_Due,
       CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) AS Date_Recv,
       (SELECT TOP 1 CAST(CONVERT(NVARCHAR, Expectation2.Date_Recv, 112) AS DATETIME)
        FROM mstt_Expectation Expectation2
           INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation2.TransactionID
           INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
           INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
        WHERE Date_Recv IS NOT NULL
          AND Expectation.TransactionID = Expectation2.TransactionID
          AND Expectation.Type = Expectation2.Type
        ORDER BY Date_Recv) AS IRD
INTO #RMAR13Expectation
FROM mstt_Expectation Expectation
   INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
   INNER JOIN mstt_Agents Agents ON PolicyTransactions.AgentCode = Agents.Code                          --restrict to
   INNER JOIN mstt_Agents Company ON Agents.CompanyCode = Company.Code and Company.Descn = 'Openwork'   --OW business
WHERE Expectation.Type IN (1, 2, 4, 10, 15, 16, 17, 18, 19)       --cut down the size
  AND (CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME) <= @CD    --of the temp table
       OR (CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME) <= @CD   --by omitting data which
           AND Expectation.DATE_RECV IS NOT NULL))          --we KNOW we don't need
GROUP BY Expectation.ID,
         Expectation.Type,
         Expectation.TransactionID,
         CAST(CONVERT(NVARCHAR, Expectation.DATE_DUE, 112) AS DATETIME),
         CAST(CONVERT(NVARCHAR, Expectation.DATE_RECV, 112) AS DATETIME)

CREATE CLUSTERED INDEX ind_RMAR13 ON #RMAR13Expectation (ID, Type, TransactionID, Amount_Due, Amount_Rec, Date_Due, Date_Recv, IRD)

--4. Extract report data
SELECT 
     CodeRevenueCategoryCode.RevenueCategoryCode AS 'SeqNo'
   , CodeRevenueCategoryCode.RevenueCategoryDescription AS 'Revenue Category'

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
          LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND ((@AgentCategory <> 'ALL' AND Agents.AgentCategory = @AgentCategory) OR --filter on agentcategory
                 (@AgentCategory = 'ALL')) --Show all agent categories
            AND ProductHierarchy.RevenueCategoryCode = CodeRevenueCategoryCode.RevenueCategoryCode
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
          LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND ((@AgentCategory <> 'ALL' AND Agents.AgentCategory = @AgentCategory) OR --filter on agentcategory
                 (@AgentCategory = 'ALL')) --Show all agent categories
            AND ProductHierarchy.RevenueCategoryCode = CodeRevenueCategoryCode.RevenueCategoryCode
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
          LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND ((@AgentCategory <> 'ALL' AND Agents.AgentCategory = @AgentCategory) OR --filter on agentcategory
                 (@AgentCategory = 'ALL')) --Show all agent categories
            AND ProductHierarchy.RevenueCategoryCode = CodeRevenueCategoryCode.RevenueCategoryCode
         )
        )
     ) AS 'Distribution Allowance'

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
          LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND ((@AgentCategory <> 'ALL' AND Agents.AgentCategory = @AgentCategory) OR --filter on agentcategory
                 (@AgentCategory = 'ALL')) --Show all agent categories
            AND ProductHierarchy.RevenueCategoryCode = CodeRevenueCategoryCode.RevenueCategoryCode
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
          LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND ((@AgentCategory <> 'ALL' AND Agents.AgentCategory = @AgentCategory) OR --filter on agentcategory
                 (@AgentCategory = 'ALL')) --Show all agent categories
            AND ProductHierarchy.RevenueCategoryCode = CodeRevenueCategoryCode.RevenueCategoryCode
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
          LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND ((@AgentCategory <> 'ALL' AND Agents.AgentCategory = @AgentCategory) OR --filter on agentcategory
                 (@AgentCategory = 'ALL')) --Show all agent categories
            AND ProductHierarchy.RevenueCategoryCode = CodeRevenueCategoryCode.RevenueCategoryCode
         )
        )
     ) AS 'Clawback'

   , '' AS 'Net DA'
   , NULL AS [Error]

FROM mstt_CodeRevenueCategoryCode CodeRevenueCategoryCode -- For all Revenue Categories even if totals are zero

UNION ALL

--separate query for null ProductHierarchy.RevenueCategoryCode to retain full list of Revenue Categories in above query
SELECT 
     99 AS 'SeqNo'  -- 99 ensures 'Unknown' category is last in sort order
   , 'Unknown' AS 'Revenue Category'

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
          LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
                  AND Date_Recv >= @OD
                 )
                )
            AND ((@AgentCategory <> 'ALL' AND Agents.AgentCategory = @AgentCategory) OR --filter on agentcategory
                 (@AgentCategory = 'ALL')) --Show all agent categories
            AND ProductHierarchy.RevenueCategoryCode IS NULL
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
          LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND ((@AgentCategory <> 'ALL' AND Agents.AgentCategory = @AgentCategory) OR --filter on agentcategory
                 (@AgentCategory = 'ALL')) --Show all agent categories
            AND ProductHierarchy.RevenueCategoryCode IS NULL
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
          LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
          WHERE Type IN (1, 4, 10, 17, 18, 19)
            AND Type = Expectation.TYPE
            AND (IRD < @OD
                 AND Date_Due < @OD
                 AND Date_Recv >= @OD
                 AND Date_Recv <= @CD
                 AND Amount_Rec <> 0.00
                )
            AND ((@AgentCategory <> 'ALL' AND Agents.AgentCategory = @AgentCategory) OR --filter on agentcategory
                 (@AgentCategory = 'ALL')) --Show all agent categories
            AND ProductHierarchy.RevenueCategoryCode IS NULL
         )
        )
     ) AS 'Distribution Allowance'

   , (SELECT 
        ((SELECT ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
          LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND Date_Recv <= @CD
            AND Amount_Rec <> 0.00
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                  AND Date_Recv >= @OD
                 )
              OR (IRD <= @CD
                  AND Date_Due > @CD
