                 )
                )
            AND ((@AgentCategory <> 'ALL' AND Agents.AgentCategory = @AgentCategory) OR --filter on agentcategory
                 (@AgentCategory = 'ALL')) --Show all agent categories
            AND ProductHierarchy.RevenueCategoryCode IS NULL
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
          LEFT JOIN mstt_Agents Agents ON Agents.CODE = PolicyTransactions.AgentCode
          WHERE Type IN (2, 15, 16)
            AND Type = Expectation.TYPE
            AND ((Date_Recv > @CD AND Amount_Rec <> 0.00) OR Date_Recv IS NULL)
            AND ((IRD >= @OD
                  AND IRD <= @CD
                  AND Date_Due <= @CD
                 )
              OR (IRD < @OD
                  AND Date_Due >= @OD
                  AND Date_Due <= @CD
                 )
                )
            AND ((@AgentCategory <> 'ALL' AND Agents.AgentCategory = @AgentCategory) OR --filter on agentcategory
                 (@AgentCategory = 'ALL')) --Show all agent categories
            AND ProductHierarchy.RevenueCategoryCode IS NULL
         ) * (-1)
         +
         (SELECT ISNULL(SUM(ISNULL(CAST(Amount_Due AS DECIMAL(15,2)), 0.00)), 0.00)
               - ISNULL(SUM(ISNULL(CAST(Amount_Rec AS DECIMAL(15,2)), 0.00)), 0.00)
          FROM #RMAR13Expectation AS Expectation
          INNER JOIN mstt_PolicyTransactions PolicyTransactions ON PolicyTransactions.ID = Expectation.TransactionID
          LEFT JOIN mstt_ProductHierarchy ProductHierarchy ON ProductHierarchy.ProductCode = PolicyTransactions.CommProductCode 
