SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO


CREATE PROCEDURE [dbo].[cscp_SalesQualityMatrix] @UserID VARCHAR(255)
AS

SELECT
    ISNULL(RTRIM(SUBSTRING(Agents_Svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_Svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_Svr.Name), '') AS 'SvrName'
   ,ISNULL(RTRIM(SUBSTRING(Agents_Mgr2.Firstnames, 1, PATINDEX('%[^ ] %', Agents_Mgr2.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_Mgr2.Name), '') AS 'Mgr2Name'
   ,ISNULL(RTRIM(SUBSTRING(Agents_Mgr4.Firstnames, 1, PATINDEX('%[^ ] %', Agents_Mgr4.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_Mgr4.Name), '') AS 'Mgr4Name'
   ,ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS 'Name'
   ,Agents.CODE AS 'Code'
   ,(SELECT ISNULL(SUM(ISNULL(Enquiry.Points,0)),0) 
     FROM msit_CodeAreaOfConcern CodeAreaOfConcern
        LEFT OUTER JOIN msit_S_ENQURY Enquiry ON Enquiry.AreaOfConcernCode = CodeAreaOfConcern.Code
        LEFT OUTER JOIN mstt_Clients Clients ON Clients.CLIENT_NUM = Enquiry.CLIENT_NUM
     WHERE Clients.REFER = Agents.CODE 
     AND (CAST(CONVERT(NVARCHAR, Enquiry.ExpiryDate, 112) AS DATETIME) IS NULL OR
         (CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, Enquiry.ExpiryDate, 112) AS DATETIME)))
    ) AS 'Total Points'
   ,CodeAreaOfConcern.Description AS 'Description'
   ,Enquiry.Points AS 'Points'
   ,CONVERT(VARCHAR, Enquiry.ExpiryDate, 103) AS 'Expiry Date'

FROM mstt_Agents Agents
  LEFT OUTER JOIN mstt_Clients Clients ON Agents.CODE = Clients.REFER 
  LEFT OUTER JOIN msit_S_ENQURY Enquiry ON Clients.CLIENT_NUM = Enquiry.CLIENT_NUM
  LEFT OUTER JOIN msit_CodeAreaOfConcern CodeAreaOfConcern ON Enquiry.AreaOfConcernCode = CodeAreaOfConcern.Code
  LEFT OUTER JOIN mstt_Agents Agents_Svr ON Agents.SpanSupervisorCode = Agents_Svr.Code
  LEFT OUTER JOIN mstt_Agents Agents_Mgr2 ON Agents.Manager2Code = Agents_Mgr2.Code
  LEFT OUTER JOIN mstt_Agents Agents_Mgr4 ON Agents.Manager4Code = Agents_Mgr4.Code
   
WHERE (CodeAreaOfConcern.CategoryCode = 'CRG')
AND Agents.CompetentStatus = 1 --Active Agents
AND (CAST(CONVERT(NVARCHAR, Enquiry.ExpiryDate, 112) AS DATETIME) IS NULL OR
    (CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, Enquiry.ExpiryDate, 112) AS DATETIME)))
AND NOT EXISTS (SELECT ID
                FROM msit_S_ENQURY Enquiry_Reversed
                LEFT JOIN msit_CodeAreaOfConcern CodeAreaOfConcern_Reversed ON Enquiry_Reversed.AreaOfConcernCode = CodeAreaOfConcern_Reversed.Code
                WHERE Enquiry.client_num = Enquiry_Reversed.client_num
                AND ISNULL(Enquiry.AreaofConcernCode, 0) = ISNULL(Enquiry_Reversed.AreaofConcernCode, 0)
                AND ISNULL(CodeAreaOfConcern.Description, '') = ISNULL(CodeAreaOfConcern_Reversed.Description, '')
                AND ISNULL(Enquiry.BreachType, 0) = ISNULL(Enquiry_Reversed.BreachType, 0)
                AND ISNULL(Enquiry.ExpiryDate, 0) = ISNULL(Enquiry_Reversed.ExpiryDate, 0)
                AND Enquiry.Points + Enquiry_Reversed.Points = 0
                AND (ISNULL(Enquiry.ReversalReason, 0) <> 0 OR ISNULL(Enquiry_Reversed.ReversalReason, 0) <> 0)
                AND Enquiry.id <> Enquiry_Reversed.id
               ) -- exclude all reversed breaches

ORDER BY [Total Points] DESC, [Name], Enquiry.ExpiryDate 


GO
/****** Object:  StoredProcedure [dbo].[cscp_SCAgents]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[cscp_SCAgents] @UserID VARCHAR(255)
AS

SELECT
  ISNULL(RTRIM(SUBSTRING(Agents.FirstNames, 1, PATINDEX('%[^ ] %', Agents.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Name]
, Agents.CODE AS 'Code'
, ISNULL(RTRIM(SUBSTRING(Agents_SVR.FirstNames, 1, PATINDEX('%[^ ] %', Agents_SVR.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_SVR.Name), '') AS [Supervisor]
, CONVERT(VARCHAR, Agents.DateStarted, 103) AS 'Start Date'
, (CASE WHEN (Agents.AgentType = 52 OR Agents.AgentType = 53 OR Agents.AgentType = 54 OR Agents.CanSupervise = 1) --SQM/RSM
        THEN 'Y' ELSE 'N' END
  ) AS 'Manager'
, AgentCompetence.ComplianceCategoryCode AS 'Competency' --Compliance Category COB/MCOB/ICOB
, AgentCompetence.AgentControlFunctionCode AS 'Status' --Competency Code/Status
, TrackItems.Notes AS 'Notes'
, ISNULL(RTRIM(SUBSTRING(Agents_4.FirstNames, 1, PATINDEX('%[^ ] %', Agents_4.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_4.Name), '') AS [Area] --for group title

FROM mstt_Agents Agents 
      INNER JOIN mstt_AgentCompetence AgentCompetence ON Agents.ID = AgentCompetence.AgentID 
        AND (AgentCompetence.DateAppointed IS NOT NULL AND CAST(CONVERT(NVARCHAR, AgentCompetence.DateAppointed, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME))
        AND (AgentCompetence.EndDate IS NULL OR CAST(CONVERT(NVARCHAR, AgentCompetence.EndDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME))
      LEFT JOIN mstt_Agents AS Agents_SVR ON Agents.SpanSupervisorCode = Agents_SVR.CODE
      LEFT JOIN mstt_Agents AS Agents_4 ON Agents.Manager4Code = Agents_4.CODE
      LEFT JOIN msit_TrackItems AS TrackItems ON Agents.CODE = TrackItems.AgentCode
            AND ((TrackItems.CodeTrackItemCode = 'SSTS200A' AND AgentCompetence.ComplianceCategoryCode = 'ICOB-PP')
              OR (TrackItems.CodeTrackItemCode = 'SSTS250A' AND AgentCompetence.ComplianceCategoryCode = 'ICOB-GI')
              OR (TrackItems.CodeTrackItemCode = 'SSTS300A' AND AgentCompetence.ComplianceCategoryCode = 'MCOB')
              OR (TrackItems.CodeTrackItemCode = 'SSTS350A' AND AgentCompetence.ComplianceCategoryCode = 'COB'))
      LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code

WHERE AgentCompetence.AgentID IN 
      (SELECT AgentCompetence.AgentID 
       FROM mstt_AgentCompetence AgentCompetence
       WHERE AgentCompetence.AgentControlFunctionCode = 'SC'
  AND (AgentCompetence.DateAppointed IS NOT NULL AND CAST(CONVERT(NVARCHAR, AgentCompetence.DateAppointed, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME))
        AND (AgentCompetence.EndDate IS NULL OR CAST(CONVERT(NVARCHAR, AgentCompetence.EndDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, getdate(), 112) AS DATETIME))
      )
AND   Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents
AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised

ORDER BY Area, Agents.CODE

GO
/****** Object:  StoredProcedure [dbo].[cscp_SectorChange]    Script Date: 7/3/2026 3:44:25 PM ******/
