CREATE PROCEDURE [dbo].[cscp_SectorChange] @UserID VARCHAR(255), @StartDate AS VARCHAR(10), @EndDate AS VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS [id]
      , NULL AS [Adviser Oscar Code] 
      , NULL AS [Adviser] 
      , NULL AS [Sector Code] 
      , NULL AS [Sector Description] 
      , NULL AS [Sector Start Date] 
      , NULL AS [Sector End Date] 
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END
IF (CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
BEGIN
  SELECT 
        NULL AS [id]
      , NULL AS [Adviser Oscar Code] 
      , NULL AS [Adviser] 
      , NULL AS [Sector Code] 
      , NULL AS [Sector Description] 
      , NULL AS [Sector Start Date] 
      , NULL AS [Sector End Date] 
      , 'Start Date cannot be greater than End Date' AS [Error]
   RETURN 0
END
SELECT Agents.Code, 
       RTRIM(Agents.OSCARAgentPrefix) + RTRIM(Agents.OSCARAgentSerial) + RTRIM(Agents.OSCARAgentSuffix) AS [Adviser Oscar Code],       
       ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser],
       mstt_AgentSector.ClusterSectorCode AS [Sector Code],
       mstt_AgentSector.ClusterSectorDescription AS [Sector Description],
       CONVERT(VARCHAR, mstt_AgentSector.StartDate, 103) AS [Sector Start Date],
       CONVERT(VARCHAR, mstt_AgentSector.EndDate, 103) AS [Sector End Date]
FROM mstt_agents as Agents
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
INNER JOIN mstt_AgentSector ON mstt_AgentSector.AgentID = Agents.id
   AND mstt_AgentSector.StartDate IS NOT NULL
   AND ((CAST(CONVERT(NVARCHAR,mstt_AgentSector.StartDate ,112) AS DATETIME) >= CAST(CONVERT(NVARCHAR,@StartDate ,112) AS DATETIME) AND CAST(CONVERT(NVARCHAR,mstt_AgentSector.StartDate ,112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,@EndDate ,112) AS DATETIME))
    OR (CAST(CONVERT(NVARCHAR,mstt_AgentSector.EndDate ,112) AS DATETIME) <= CAST(CONVERT(NVARCHAR,@EndDate ,112) AS DATETIME) AND CAST(CONVERT(NVARCHAR,mstt_AgentSector.EndDate ,112) AS DATETIME) >= CAST(CONVERT(NVARCHAR,@StartDate ,112) AS DATETIME)))
WHERE (Agents.CompetentStatus = 1 OR Agents.CompetentStatus = 5) --Active/Pre-App Agents only
ORDER BY [Adviser] ASC, mstt_AgentSector.ClusterSectorCode

GO
/****** Object:  StoredProcedure [dbo].[cscp_SpanOfControl]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[cscp_SpanOfControl] @UserID VARCHAR(255), @AgentCode CHAR(7)
AS

--Drop temporary table if exists
IF OBJECT_ID('tempdb..#SOCQualityPoints') IS NOT NULL
   DROP TABLE #SOCQualityPoints

-- 3a. Create temp table to hold each adviser's quality points
SELECT Agents.Code AS [Code],
       ISNULL(SUM(ISNULL(Enquiry.Points, 0)), 0) AS [Points]
INTO #SOCQualityPoints
FROM mstt_Agents Agents
LEFT JOIN mstt_Clients Clients ON Clients.REFER = Agents.Code
LEFT JOIN msit_S_ENQURY Enquiry ON Clients.CLIENT_NUM = Enquiry.CLIENT_NUM 
                                AND Enquiry.EnquiryType = 3 --Breach
                                AND Enquiry.BreachType = 1 --Adviser
                                AND (Enquiry.ExpiryDate IS NULL
                                  OR CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, Enquiry.ExpiryDate, 112) AS DATETIME))
GROUP BY Agents.Code
ORDER BY Agents.Code

CREATE INDEX ind_QualityPoints ON #SOCQualityPoints (Code)

-- 3b. Span supervisor
SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser],
       Agents.CODE AS [Agent Code],
       CASE
          WHEN Agents.AgentCategory IN ('PARSL', 'PRINSL', 'PRISL', 'PTNRSL') THEN 'Y'
          ELSE ''
       END AS [PP/Ptnr], --Practice Principal / Partner
       'Span Supervisor: ' + ISNULL(RTRIM(Agents_svr.Code) + ' - ', '') + ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') AS [Supervisor],
       RTRIM(Agents_pr.TradingName) AS [Practice Name],
       (SELECT dbo.cscf_GetAgentSectors(Agents.ID, GetDate())) AS [Sector],
       (SELECT dbo.cscf_GetAgentAbbrevCompetencies(Agents.ID, GetDate())) AS [Competency],
       QualityPoints.Points AS [QualityPoints],
       (SELECT RiskRating.Description
        FROM msit_CodeRiskRating RiskRating
        WHERE (CAST(CONVERT(NVARCHAR, RiskRating.EndDate, 112) AS DATETIME) IS NULL OR
              (CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, RiskRating.EndDate, 112) AS DATETIME)))
          AND RiskRating.StartPoints <= QualityPoints.Points
          AND RiskRating.EndPoints >= QualityPoints.Points
       ) AS [RiskRating],
       CASE Agents.CanSupervise
          WHEN 1 THEN Agents.SupervisorTypeCode
          ELSE ''
       END AS [Supervisor?],
       'Area Sales Director: ' + ISNULL(RTRIM(SUBSTRING(Agents_mgr4.Firstnames, 1, PATINDEX('%[^ ] %', Agents_mgr4.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_mgr4.Name), '') AS [Mgr4], -- for sorting/grouping
       1 AS [Seq]

FROM mstt_Agents AS Agents
LEFT JOIN #SOCQualityPoints AS QualityPoints ON QualityPoints.Code = Agents.Code
LEFT JOIN mstt_Agents AS Agents_svr ON Agents.SpanSupervisorCode = Agents_svr.CODE
LEFT JOIN mstt_Agents AS Agents_pr ON Agents.OfficeCode = Agents_pr.CODE
LEFT JOIN mstt_Agents AS Agents_mgr4 ON Agents_svr.Manager4Code = Agents_mgr4.CODE
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code

WHERE Agents.SpanSupervisorCode IS NOT NULL AND Agents.SpanSupervisorCode <> ''
  AND Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents only
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
  AND Agents.AgentType NOT IN (3, 17, 44, 5, 45) -- exclude IAR, Staff, Company Sec, Admin, 10% shareholder
  AND Agents.AgentCategory NOT IN ('DIRNS', 'MBRNS', 'PRNNS', 'PTNRNS') -- exclude DIRNS, MBRNS, PRNNS, PTNRNS
  AND Agents.Code <> '10012' -- exclude Agent Unique ID = 10012
  AND Agents_svr.Code <> '10012' -- exclude Agents whose supervisor has Unique ID = 10012
  AND ((@AgentCode <> '' AND Agents.SpanSupervisorCode = @AgentCode)
       OR @AgentCode = '' OR @AgentCode IS NULL)

UNION ALL

-- 3c. Sale supervisor
SELECT ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser],
       Agents.CODE AS [Agent Code],
       CASE
          WHEN Agents.AgentCategory IN ('PARSL', 'PRINSL', 'PRISL', 'PTNRSL') THEN 'Y'
          ELSE ''
       END AS [PP/Ptnr], --Practice Principal / Partner
       'Sale Supervisor: ' + ISNULL(RTRIM(Agents_svr.Code) + ' - ', '') + ISNULL(RTRIM(SUBSTRING(Agents_svr.Firstnames, 1, PATINDEX('%[^ ] %', Agents_svr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_svr.Name), '') AS [Supervisor],
       RTRIM(Agents_pr.TradingName) AS [Practice Name],
       (SELECT dbo.cscf_GetAgentSectors(Agents.ID, GetDate())) AS [Sector],
       (SELECT dbo.cscf_GetAgentAbbrevCompetencies(Agents.ID, GetDate())) AS [Competency],
       QualityPoints.Points AS [QualityPoints],
       (SELECT RiskRating.Description
        FROM msit_CodeRiskRating RiskRating
        WHERE (CAST(CONVERT(NVARCHAR, RiskRating.EndDate, 112) AS DATETIME) IS NULL OR
              (CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, RiskRating.EndDate, 112) AS DATETIME)))
          AND RiskRating.StartPoints <= QualityPoints.Points
          AND RiskRating.EndPoints >= QualityPoints.Points
       ) AS [RiskRating],
       CASE Agents.CanSupervise
          WHEN 1 THEN Agents.SupervisorTypeCode
          ELSE ''
       END AS [Supervisor?],
       'Area Sales Director: ' + ISNULL(RTRIM(SUBSTRING(Agents_mgr4.Firstnames, 1, PATINDEX('%[^ ] %', Agents_mgr4.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents_mgr4.Name), '') AS [Mgr4], -- for sorting/grouping
       2 AS [Seq]

FROM mstt_Agents AS Agents
LEFT JOIN #SOCQualityPoints AS QualityPoints ON QualityPoints.Code = Agents.Code
LEFT JOIN mstt_Agents AS Agents_svr ON Agents.SaleSupervisorCode = Agents_svr.CODE
LEFT JOIN mstt_Agents AS Agents_pr ON Agents.OfficeCode = Agents_pr.CODE
LEFT JOIN mstt_Agents AS Agents_mgr4 ON Agents_svr.Manager4Code = Agents_mgr4.CODE
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code

WHERE Agents.AgentType IN (52, 53, 54) --only report 'Sale' if a manager 1 to 3
  AND Agents.AgentCategory IN ('RSMSL', 'SQMSL', 'SRSMSL') --only report 'Sale' if 'selling' versions of above managers
  AND Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents only
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
  AND Agents.AgentType NOT IN (3, 17, 44, 5, 45) -- exclude IAR, Staff, Company Sec, Admin, 10% shareholder
  AND Agents.AgentCategory NOT IN ('DIRNS', 'MBRNS', 'PRNNS', 'PTNRNS') -- exclude DIRNS, MBRNS, PRNNS, PTNRNS
  AND Agents.Code <> '10012' -- exclude Agent Unique ID = 10012
  AND Agents_svr.Code <> '10012' -- exclude Agents whose supervisor has Unique ID = 10012
  AND Agents.SaleSupervisorCode IS NOT NULL AND Agents.SaleSupervisorCode <> ''
  AND ((@AgentCode <> '' AND Agents.SaleSupervisorCode = @AgentCode)
       OR @AgentCode = '' OR @AgentCode IS NULL)

ORDER BY [Seq], [Mgr4], [Supervisor], [Agent Code]

-- Tidy up
DROP TABLE #SOCQualityPoints


GO
/****** Object:  StoredProcedure [dbo].[cscp_SQMMissingSectors]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
