CREATE PROCEDURE [dbo].[cscp_SQMMissingSectors] @UserID VARCHAR(255)
AS
SELECT ISNULL(RTRIM(SUBSTRING(Agents.FirstNames, 1, PATINDEX('%[^ ] %', Agents.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [SQM Name],
       Agents.Code AS [SQM Id],
       dbo.cscf_GetAgentSectors(Agents.ID, GetDate()) AS [Sectors Held],
       dbo.cscf_GetAgentSectorsNoStartDate(Agents.ID) AS [No Start Date],
       dbo.cscf_AgentHasLicence(Agents.ID, GetDate(), 'ERIN') AS [ERIN Held],
       dbo.cscf_AgentHasLicence(Agents.ID, GetDate(), 'PAL4') AS [PAL4 Held],
       NULL AS [Notes], -- user field
       CASE Agents_mgr2.AgentCategory
          WHEN 'ASQMNS' THEN 'Area Sales Quality Manager: '
          ELSE 'Regional Sales Manager: '
       END
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr2.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr2.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr2.Name), '')
        + RTRIM(ISNULL(' (' + Agents_mgr2.Code + ')', '')) AS [Mgr2], -- sort/group by field
       'Area Sales Director: '
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr4.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr4.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr4.Name), '') AS [Mgr4] -- sort/group by field

FROM mstt_Agents AS Agents
--LEFT JOIN mstt_Agents AS AgentsSOS ON Agents.SpanSupervisorCode = AgentsSOS.Code
LEFT JOIN mstt_Agents AS Agents_mgr2 ON Agents.Manager2Code = Agents_mgr2.Code
LEFT JOIN mstt_Agents AS Agents_mgr4 ON Agents.Manager4Code = Agents_mgr4.Code
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
WHERE Agents.AgentTypeB30 = 2 -- exclude businesses
  AND Agents.AgentType = 52 -- include Mgr1s only
  AND Agents.AgentCategory IN ('SQMNS', 'SQMSL') -- include SQMs only
  AND Agents.CompetentStatus = 1 -- include Active advisers only
  AND (dbo.cscf_AgentHasSector(Agents.ID, GetDate(), 'FP') = 'N' -- agent does not have valid 'FP' sector
    OR dbo.cscf_AgentHasLicence(Agents.ID, GetDate(), 'ERIN') = 'N'
    OR dbo.cscf_AgentHasLicence(Agents.ID, GetDate(), 'PAL4') = 'N') -- agent does not have valid 'ERIN' or 'PAL4' licence
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised

ORDER BY [Mgr4], [Mgr2], [SQM Name]


GO
/****** Object:  StoredProcedure [dbo].[cscp_SQSTAbbeyM4]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[cscp_SQSTAbbeyM4] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS

IF ISDATE(@StartDate) = 0 Or ISDATE(@EndDate) = 0
BEGIN
  SELECT 
        NULL AS 'Type'
      , NULL AS 'Month Total'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END


-- 1. Abbey final pass replacements
SELECT 'Replacements Assessed as OK Final' AS [Type], 
       count(msit_trackgroups.NBCCFinalStatus) AS [Month Total]
FROM msit_trackgroups 
INNER JOIN mstt_Policies ON msit_trackgroups.PolicyID = mstt_Policies.POL_NUM 
INNER JOIN  msit_PolicyQualityCheckB30 ON msit_trackgroups.PolicyID =  msit_PolicyQualityCheckB30.PolicyID
INNER JOIN  mstt_policytransactions AS PolicyTransactions ON mstt_Policies.POL_NUM =   PolicyTransactions.PolicyID
LEFT JOIN MSIT_AgentJobHistory  AgentJobHistory  ON PolicyTransactions.AgentCode = AgentJobHistory.AgentCode
WHERE  msit_trackgroups.NBCCHeaderID IS NOT NULL
  AND msit_trackgroups.NBCCStatus IS NOT NULL 
  AND msit_trackgroups.NBCCFinalStatus IS NOT NULL  
  AND (msit_trackgroups.policyid IN (SELECT DISTINCT trackgroups_comment.policyid
                                    FROM msit_trackgroups trackgroups_comment
                                    WHERE trackgroups_comment.NBCCComments like 'Abbey Replacement%'
                                    )   OR  AgentJobHistory.Job = 'EXABBEY')
  AND ( msit_PolicyQualityCheckB30.UndisclosedReplacement > 0  
    OR ( msit_PolicyQualityCheckB30.UndisclosedReplacement IS NULL AND msit_PolicyQualityCheckB30.Replacement > 0))
  AND (
  (msit_trackgroups.FinalCheckValidatedDate >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
   AND msit_trackgroups.FinalCheckValidatedDate <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)
   AND msit_trackgroups.NBCCFinalStatus in ('Pass', 'Pass with comments'))
  OR
  (msit_trackgroups.CaseCheckValidatedDate >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND msit_trackgroups.CaseCheckValidatedDate <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)            
  AND msit_trackgroups.NBCCStatus <> 'Fail')
      )
    

-- 2. Abbey initial pass replacements
UNION
SELECT 'Replacements Assessed as OK Initial' AS [Type],
       count(msit_trackgroups.NBCCStatus) AS [Month Total]
FROM msit_trackgroups 
INNER JOIN mstt_Policies ON msit_trackgroups.PolicyID = mstt_Policies.POL_NUM 
INNER JOIN  msit_PolicyQualityCheckB30 ON msit_trackgroups.PolicyID =  msit_PolicyQualityCheckB30.PolicyID
INNER JOIN  mstt_policytransactions AS PolicyTransactions ON mstt_Policies.POL_NUM =   PolicyTransactions.PolicyID
LEFT JOIN MSIT_AgentJobHistory  AgentJobHistory  ON PolicyTransactions.AgentCode = AgentJobHistory.AgentCode
WHERE  msit_trackgroups.NBCCStatus IS NOT NULL 
  AND (msit_trackgroups.policyid IN (SELECT DISTINCT trackgroups_comment.policyid
                                    FROM msit_trackgroups trackgroups_comment
                                    WHERE trackgroups_comment.NBCCComments like 'Abbey Replacement%'
                                    )  OR   AgentJobHistory.Job = 'EXABBEY' )
  AND msit_trackgroups.CaseCheckValidatedDate  >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND msit_trackgroups.CaseCheckValidatedDate <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
  AND msit_trackgroups.NBCCStatus <> 'Fail'
  AND ( msit_PolicyQualityCheckB30.UndisclosedReplacement > 0  OR ( msit_PolicyQualityCheckB30.UndisclosedReplacement IS NULL AND msit_PolicyQualityCheckB30.Replacement > 0))


-- 3. Ex Abbey replacements
UNION
SELECT 'Replacements Assessed for Ex-Abbey Life' AS [Type],
       count(msit_trackgroups.NBCCStatus) AS [Month Total]
FROM msit_trackgroups 
INNER JOIN mstt_Policies ON msit_trackgroups.PolicyID = mstt_Policies.POL_NUM 
INNER JOIN  msit_PolicyQualityCheckB30 ON msit_trackgroups.PolicyID =  msit_PolicyQualityCheckB30.PolicyID
INNER JOIN  mstt_policytransactions AS PolicyTransactions ON mstt_Policies.POL_NUM =   PolicyTransactions.PolicyID
LEFT JOIN MSIT_AgentJobHistory  AgentJobHistory  ON PolicyTransactions.AgentCode = AgentJobHistory.AgentCode
WHERE  msit_trackgroups.NBCCStatus IS NOT NULL 
  AND (msit_trackgroups.policyid IN (SELECT DISTINCT trackgroups_comment.policyid
                                    FROM msit_trackgroups trackgroups_comment
                                    WHERE trackgroups_comment.NBCCComments like 'Abbey Replacement%'
                                    )  OR   AgentJobHistory.Job = 'EXABBEY')
  AND  msit_trackgroups.CaseCheckValidatedDate >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND msit_trackgroups.CaseCheckValidatedDate <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)
  AND ( msit_PolicyQualityCheckB30.UndisclosedReplacement > 0  OR ( msit_PolicyQualityCheckB30.UndisclosedReplacement IS NULL AND msit_PolicyQualityCheckB30.Replacement > 0))

-- 4. Abbey final fail replacements
UNION
SELECT 'Replacements With Final Assessment Fail' AS [Type],
       count(msit_trackgroups.NBCCFinalStatus) AS [Month Total]
FROM msit_trackgroups 
INNER JOIN mstt_Policies ON msit_trackgroups.PolicyID = mstt_Policies.POL_NUM 
INNER JOIN  msit_PolicyQualityCheckB30 ON msit_trackgroups.PolicyID =  msit_PolicyQualityCheckB30.PolicyID
INNER JOIN  mstt_policytransactions AS PolicyTransactions ON mstt_Policies.POL_NUM =   PolicyTransactions.PolicyID
LEFT JOIN MSIT_AgentJobHistory  AgentJobHistory  ON PolicyTransactions.AgentCode = AgentJobHistory.AgentCode
WHERE msit_trackgroups.NBCCFinalStatus IS NOT NULL
  AND (msit_trackgroups.policyid IN (SELECT DISTINCT trackgroups_comment.policyid
                                    FROM msit_trackgroups trackgroups_comment
                                    WHERE trackgroups_comment.NBCCComments like 'Abbey Replacement%'
                                    )  OR   AgentJobHistory.Job = 'EXABBEY')
  AND msit_trackgroups.FinalCheckValidatedDate  >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND msit_trackgroups.FinalCheckValidatedDate <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)
  AND msit_trackgroups.NBCCFinalStatus = 'Fail' 
  AND ( msit_PolicyQualityCheckB30.UndisclosedReplacement > 0  OR ( msit_PolicyQualityCheckB30.UndisclosedReplacement IS NULL AND msit_PolicyQualityCheckB30.Replacement > 0))


GO
/****** Object:  StoredProcedure [dbo].[cscp_SQSTWeekly]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- Get the relevant track items, competence details and manager details for each agent beneath the agent code passed in
CREATE PROCEDURE [dbo].[cscp_SQSTWeekly] @UserID VARCHAR(255), @StartDate VARCHAR(10), @EndDate VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
  NULL AS 'ID'
      , NULL AS 'Turnaround'
      , NULL AS 'Assessed'
      , NULL AS 'Awaiting'
      , NULL AS 'Fails'
      , NULL AS 'Over_30'
      , NULL AS 'QFails'
      , NULL AS 'Volume'
      , NULL AS 'Reply_Assessed'
      , NULL AS 'Reply_Failed'
      , NULL AS 'Reply_Turnaround'
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS 'Error'
   RETURN 0
END
SELECT  mstt_Agents.PortalLogon AS [ID],
  --Cases in Turnaround, get case check items where the due date is after the validate date, for the logon we're dealing with
  (SELECT COUNT(DISTINCT(msit_TrackGroups.PolicyID))
  FROM  msit_TrackGroups 
    INNER JOIN msit_TrackItems ON msit_TrackGroups.ID  = msit_TrackItems.TrackGroupID
    AND msit_TrackItems.AssignToUserID = msit_IntUsers.ID --only get items assigned to the current ID
  WHERE msit_TrackGroups.NBCCHeaderID IS NOT NULL --is a case check
    AND msit_TrackGroups.CaseCheckValidatedDate IS NOT NULL --has been validated
    AND msit_TrackItems.FollowUpDate IS NOT NULL -- has a due date
    AND msit_TrackGroups.CaseCheckValidatedDate <= msit_TrackItems.FollowUpDate  -- has been validate before the due date
    AND msit_TrackItems.Description LIKE 'case check for%'
    AND (CAST(CONVERT(NVARCHAR, msit_TrackGroups.CaseCheckValidatedDate, 112) AS DATETIME) 
      BETWEEN CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
      AND CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
    ) AS [Turnaround], 
  --Cases Assessed
  (SELECT COUNT(DISTINCT(msit_TrackGroups.PolicyID))
  FROM  msit_TrackGroups 
    INNER JOIN msit_TrackItems ON msit_TrackItems.TrackGroupID = msit_TrackGroups.ID
    AND msit_TrackItems.AssignToUserID = msit_IntUsers.ID --only get items assigned to the current ID
  WHERE msit_TrackGroups.NBCCHeaderID IS NOT NULL --double check it is a case check Track Group
    AND msit_TrackGroups.CaseCheckValidatedDate IS NOT NULL --case checks that have been validated
    AND (CAST(CONVERT(NVARCHAR, msit_TrackGroups.CaseCheckValidatedDate, 112) AS DATETIME) 
      BETWEEN CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
      AND CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
    AND msit_TrackItems.Description LIKE 'case check for%'
    ) AS [Assessed],  
  --Cases Awaiting Reply
  (SELECT COUNT(DISTINCT(msit_TrackGroups.PolicyID))
  FROM  msit_TrackGroups 
    INNER JOIN msit_TrackItems ON msit_TrackItems.TrackGroupID = msit_TrackGroups.ID
    AND msit_TrackItems.AssignToUserID = msit_IntUsers.ID --only get items assigned to the current ID
  WHERE ((msit_TrackGroups.Description LIKE 'decide if response received within 10 days%') --is one of these three track groups
    OR (msit_TrackGroups.Description LIKE 'decide if response received within 20 days%') 
    OR (msit_TrackGroups.Description LIKE 'decide if response received within 22 days%'))
    AND msit_TrackItems.CompletedState = 0 -- outstanding
    ) AS [Awaiting],
  --Cases Failed
  (SELECT COUNT(DISTINCT(msit_TrackGroups.PolicyID))
  FROM  msit_TrackGroups
    INNER JOIN msit_TrackItems ON msit_TrackItems.TrackGroupID = msit_TrackGroups.ID
    AND msit_TrackItems.AssignToUserID = msit_IntUsers.ID --only get items assigned to the current ID
  WHERE msit_TrackGroups.NBCCHeaderID IS NOT NULL -- is a case check
    AND msit_TrackGroups.NBCCStatus ='Fail' -- and it failed the initial validate
    AND msit_TrackItems.Description LIKE 'case check for%'
    AND (CAST(CONVERT(NVARCHAR, msit_TrackGroups.CaseCheckValidatedDate, 112) AS DATETIME) 
      BETWEEN CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
      AND CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
    ) AS [Fails], 
  --Cases over 30 days
  (SELECT COUNT(DISTINCT(MainGroup.PolicyID))
  FROM  msit_TrackGroups AS MainGroup 
    INNER JOIN msit_TrackItems AS MainItems ON MainItems.TrackGroupID = MainGroup.ID
    AND MainItems.AssignToUserID = msit_IntUsers.ID --only get items assigned to the current ID
  WHERE ((MainGroup.Description LIKE 'decide if response received within 10 days%')--is one of these three track groups
    OR (MainGroup.Description LIKE 'decide if response received within 20 days%') 
    OR (MainGroup.Description LIKE 'decide if response received within 22 days%'))
    AND MainItems.CompletedState = 0 -- outstanding
    AND CAST(CONVERT(NVARCHAR, GetDate(), 112) AS DATETIME) --more than 30 days since the validate date of the most recent failed validate
    >= (DATEADD(Day, 31,  CAST(CONVERT(NVARCHAR, (SELECT TOP 1 msit_TrackGroups.CaseCheckValidatedDate --uses 31 as warehouse is already a day old
      FROM  msit_TrackGroups
        INNER JOIN msit_TrackItems ON msit_TrackItems.TrackGroupID = msit_TrackGroups.ID
        AND msit_TrackGroups.Description LIKE 'case check for%'
        AND msit_TrackItems.Description LIKE 'case check for%'
      WHERE   msit_TrackGroups.NBCCHeaderID IS NOT NULL
        AND msit_TrackGroups.CaseCheckValidatedDate IS NOT NULL
        AND msit_TrackGroups.NBCCStatus IS NOT NULL
        AND msit_TrackGroups.NBCCStatus = 'fail'
        AND msit_TrackGroups.PolicyID = MainGroup.PolicyID
        ORDER BY msit_TrackGroups.CaseCheckValidatedDate DESC), 112) AS DATETIME)))
    ) AS [Over_30], 
  --Quality fails
  (SELECT COUNT(DISTINCT(MainItem.PolicyID))
  FROM  msit_TrackItems AS MainItem
  WHERE MainItem.Description LIKE 'initial check corrected - record reasons in notes%'
    AND MainItem.CompletedState = 1 --is completed
    AND (CAST(CONVERT(NVARCHAR, MainItem.ClearedDate, 112) AS DATETIME) 
      BETWEEN  CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
      AND CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
    AND msit_IntUsers.ID = (SELECT  TOP 1 msit_TrackItems.AssignToUserID  --told to use ID of person who did first case check
          FROM  msit_TrackGroups          --this might not be the person who actually made the error, but Anne Harrison is happy with this. 
            INNER JOIN msit_TrackItems ON msit_TrackItems.TrackGroupID = msit_TrackGroups.ID
            AND msit_TrackGroups.Description LIKE 'case check for%'
            AND msit_TrackItems.Description LIKE 'case check for%'
          WHERE   msit_TrackGroups.NBCCHeaderID IS NOT NULL
            AND msit_TrackGroups.NBCCStatus IS NOT NULL
            --AND msit_TrackGroups.PolicyID = MainItem.PolicyID
            ORDER BY msit_TrackGroups.CaseCheckValidatedDate ASC)
  ) AS [QFails],
  --Quality volume
  (SELECT COUNT(DISTINCT(msit_TrackGroups.PolicyID))
  FROM  msit_TrackGroups
    INNER JOIN msit_TrackItems ON msit_TrackItems.TrackGroupID = msit_TrackGroups.ID
    AND msit_TrackItems.AssignToUserID = msit_IntUsers.ID --only get items assigned to the current ID
  WHERE msit_TrackGroups.Description LIKE 'decide if the initial check is to continue%'
    AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 112) AS DATETIME) 
      BETWEEN CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
    AND NOT EXISTS (SELECT  Items.TrackGroupID 
        FROM  msit_TrackItems AS Items     --no items linked to the above group are outstanding 
        WHERE   Items.CompletedState = 0 
          AND Items.TrackGroupID = msit_TrackGroups.ID))
   AS [Volume],
  --Reply assessed
  (SELECT COUNT(DISTINCT(msit_TrackGroups.PolicyID))
  FROM  msit_TrackGroups
    INNER JOIN msit_TrackItems ON msit_TrackItems.TrackGroupID = msit_TrackGroups.ID
    AND msit_TrackItems.AssignToUserID = msit_IntUsers.ID --only get items assigned to the current ID
  WHERE msit_TrackGroups.Description LIKE 'is more information still needed from the adviser%'
    AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 112) AS DATETIME) 
      BETWEEN CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND  CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
    AND NOT EXISTS (SELECT  Items.TrackGroupID 
        FROM  msit_TrackItems AS Items     --no items linked to the above group are outstanding 
        WHERE   Items.CompletedState = 0 
          AND Items.TrackGroupID = msit_TrackGroups.ID))
  AS [Reply_Assessed],
  --Reply failed
  (SELECT COUNT(DISTINCT(msit_TrackItems.PolicyID))
  FROM  msit_TrackItems 
  WHERE msit_TrackItems.Description LIKE 'more information is needed - contact the adviser%'
    AND msit_TrackItems.AssignToUserID = msit_IntUsers.ID --only get items assigned to the current ID
    AND msit_TrackItems.CompletedState = 1 --is completed 
    AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 112) AS DATETIME) 
      BETWEEN CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
    ) AS [Reply_Failed], --only get items assigned to the current ID
  --Reply in Turnaround
  (SELECT COUNT(DISTINCT(msit_TrackGroups.PolicyID))
  FROM  msit_TrackGroups 
    INNER JOIN msit_TrackItems ON msit_TrackItems.TrackGroupID = msit_TrackGroups.ID
    AND msit_TrackGroups.Description LIKE 'is more information still needed from the adviser%'
    AND msit_TrackItems.AssignToUserID = msit_IntUsers.ID --only get items assigned to the current ID
  WHERE DATEADD(Day, 2, CAST(CONVERT(NVARCHAR, msit_TrackItems.RequestedDate, 112) AS DATETIME)) --item was completed within 2 days of the generated date
    <= CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 112) AS DATETIME)
    AND (CAST(CONVERT(NVARCHAR, msit_TrackItems.ClearedDate, 112) AS DATETIME) 
      BETWEEN CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
      AND CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)) 
    ) AS [Reply_Turnaround],
  NULL AS 'Error'
FROM  mstt_Agents
  INNER JOIN msit_IntUsers ON msit_IntUsers.AssociatedAgent = mstt_Agents.CODE AND mstt_Agents.AgentCategory like 'SQST%' --only agents with a category of SQST....
ORDER BY [ID]

GO
/****** Object:  StoredProcedure [dbo].[cscp_SupervisorAdviserMismatch]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO




CREATE PROCEDURE [dbo].[cscp_SupervisorAdviserMismatch] @UserID VARCHAR(255)
AS

/* 
Mike Cawood -   9 August 2007 - Include Manager Supervisors
    15 August 2007 - Rename BQM as QM
*/

IF OBJECT_ID('tempdb..#SupervisorAdviserMismatch') IS NOT NULL
   DROP TABLE #SupervisorAdviserMismatch

SELECT  Distinct case when AgentsSvr.AgentType in (52) then 'QM: ' else 'Supervisor: '  end --MPC 15/08/2007
  + ISNULL(LTRIM(RTRIM(SUBSTRING(AgentsSvr.FirstNames, 1, PATINDEX('%[^ ] %', AgentsSvr.FirstNames + ' ')))) + ' ', '')
  + ISNULL(RTRIM(AgentsSvr.Name), '')
  + RTRIM(ISNULL(' ' +AgentsSvr.Code , ''))  AS [Svisor Name],
  ISNULL(RTRIM(SUBSTRING(Agents.FirstNames, 1, PATINDEX('%[^ ] %', Agents.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents.Name), '') AS [Adviser Name],
        Agents.Code AS [Unique Id],
  Agents.ID AS AgentID,
  AgentsSvr.ID AS AgentsSvrID,
        NULL AS [Notes], -- user field
        /*CASE Agents_mgr1.AgentCategory
          WHEN 'ASQMNS' THEN 'Area Sales Quality Manager: '
          ELSE 'Regional Sales Manager: '
        END*/
  Case when AgentsSvr.AgentType not in (52) THEN    --MPC 09/08/2007 
  'QM: '              --MPC 15/08/2007 
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr1.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr1.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr1.Name), '')
        + RTRIM(ISNULL(' ' + Agents_mgr1.Code , '')) 
  END AS [Mgr1], -- sort/group by field   --MPC 09/08/2007
       'Area Sales Director: '
        + ISNULL(RTRIM(SUBSTRING(Agents_mgr4.FirstNames, 1, PATINDEX('%[^ ] %', Agents_mgr4.FirstNames + ' '))) + ' ', '')
        + ISNULL(RTRIM(Agents_mgr4.Name), '') AS [Mgr4] -- sort/group by field        

INTO #SupervisorAdviserMismatch

FROM mstt_Agents AS Agents
LEFT JOIN mstt_Agents AS AgentsSvr ON  AgentsSvr.CODE = Agents.SpanSupervisorCode 
LEFT JOIN mstt_Agents AS Agents_mgr1 ON AgentsSvr.SpanSupervisorCode = Agents_mgr1.Code
LEFT JOIN mstt_Agents AS Agents_mgr4 
ON (case when AgentsSvr.AgentType in (52) then AgentsSvr.Manager4Code else Agents_mgr1.Manager4Code end) = Agents_mgr4.Code --MPC 09/08/2007
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
WHERE   Agents.CompetentStatus = 1  -- include Active advisers only
  AND Agents.AgentType NOT IN (3, 17, 44, 5, 45) -- exlcude IAR, Staff, Company Sec, Admin, 10% shareholder
  AND Agents.AgentCategory <> 'RI' -- exclude RI
  --AND Agents.CanSupervise = 1 -- is a supervisor
  --AND Agents.SupervisorTypeCode NOT IN ('RSOS', 'SOS', 'SOSNA')
  --AND Agents.AgentType NOT IN (52,53,54,55) --exclude ‘Manager 1’, ‘Manager 2’, ‘Manager 3’ , ‘Manager 4’
  AND Agents.AgentTypeB30 = 2 -- exclude businesses
  AND Agents.spansupervisorcode IN (SELECT  code FROM mstt_Agents Agents
                                    WHERE competentstatus = 1 -- svr active only
                                    AND Cansupervise = 1 -- is a svr
            AND AgentType NOT IN (53, 54, 55) --MPC 09/08/2007 Include BQM Manager1
--MPC 09/08/2007                               AND SupervisorTypeCode NOT IN ('RSOS', 'SOS', 'SOSNA') -- svr is not an SOS
--MPC 09/08/2007                               AND AgentType NOT IN (52, 53, 54, 55) -- svr not a mgr1, 2, 3 or 4
                                    AND Agents.AgentTypeB30 = 2 -- svr not a business
                                   )
   AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised

SELECT  [Svisor Name],
  [Adviser Name],
  [Unique Id],
  [Notes],
  CASE CHARINDEX(',',Licences,len(Licences))
          WHEN 0 THEN Licences
    WHEN NULL THEN NULL
          ELSE SUBSTRING(Licences,1,len(Licences)-1)
        END AS Licences,
  [Mgr1],
  [Mgr4] 
FROM(
  SELECT  [Svisor Name],
    [Adviser Name],
    [Unique Id],
    [Notes],
    (SELECT dbo.cscf_GetAgentLicences(AgentID,AgentsSvrID)) AS Licences,
    [Mgr1],
    [Mgr4]
  FROM #SupervisorAdviserMismatch) AS SupervisorAdviserMismatch 
WHERE len(Licences)>0 and len(ltrim(rtrim([Svisor Name])))>11
ORDER BY [Mgr4],[Mgr1], [Svisor Name],[Adviser Name]


IF OBJECT_ID('tempdb..#SupervisorAdviserMismatch') IS NOT NULL
   DROP TABLE #SupervisorAdviserMismatch



GO
/****** Object:  StoredProcedure [dbo].[cscp_SupervisorLics]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_SupervisorLics] @UserID VARCHAR(255), @StartDate AS VARCHAR(10), @EndDate AS VARCHAR(10)
AS
IF ISDATE(@StartDate) = 0 OR ISDATE(@EndDate) = 0 
BEGIN
  SELECT 
        NULL AS [Adviser]
      , NULL AS [Unique Id]
      , NULL AS [Lic Code] 
      , NULL AS [Lic Description] 
      , NULL AS [Start Date] 
      , NULL AS [Expiry Date]
      , CASE WHEN ISDATE(@StartDate) = 0 THEN 'Invalid Start Date Entered. Please enter it in the format dd/mm/yyyy'
             WHEN ISDATE(@EndDate) = 0 THEN  'Invalid End Date Entered. Please enter it in the format dd/mm/yyyy.'           
        END AS [Error]
   RETURN 0
END
IF (CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) > CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
BEGIN
  SELECT 
        NULL AS [Adviser]
      , NULL AS [Unique Id]
      , NULL AS [Lic Code] 
      , NULL AS [Lic Description] 
      , NULL AS [Start Date] 
      , NULL AS [Expiry Date]
      , 'Start Date cannot be greater than End Date' AS [Error]
   RETURN 0
END
SELECT ISNULL(RTRIM(SUBSTRING(Agents.FirstNames, 1, PATINDEX('%[^ ] %', Agents.FirstNames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '') AS [Adviser],
       Agents.Code AS [Unique Id],
       AgentLicence.LicenceCode AS [Lic Code],
       AgentLicence.LicenceDescription AS [Lic Description],
       CONVERT(VARCHAR, AgentLicence.StartDate, 103) AS [Start Date],
       CONVERT(VARCHAR, AgentLicence.ExpiryDate, 103) AS [Expiry Date],
       NULL AS [Error]
FROM mstt_Agents AS Agents
INNER JOIN mstt_AgentLicence AS AgentLicence ON AgentLicence.AgentID = Agents.id
LEFT JOIN mstt_Agents AS Business ON COALESCE(Agents.DirectlyAuthorisedCode, Agents.OfficeCode, Agents.AccessAgentCode, Agents.StrategicAllianceCode) = Business.Code
WHERE AgentLicence.CodeLicenceTypeID = 6 -- Supervisor licences
  AND AgentLicence.EndDate IS NULL
  AND CAST(CONVERT(NVARCHAR, AgentLicence.ExpiryDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  AND CAST(CONVERT(NVARCHAR, AgentLicence.ExpiryDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) -- Parameters
  AND Agents.CompetentStatus IN (1, 5) --Active/Pre-App Agents only
  AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
ORDER BY [Lic Code], [Expiry Date], [Adviser]

GO
/****** Object:  StoredProcedure [dbo].[cscp_UncompletedEvents]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
