/****** Object:  StoredProcedure [dbo].[cscp_UPV08_PortalCodes]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[cscp_UPV08_PortalCodes] @UserID VARCHAR(255)
AS

SELECT IntUsers.Name AS [PortalCode],
       IntUsers.Description AS [Name],
       IntUsers.AssociatedAgent AS [UniqueId],
       Agents.AgentTypeDescription AS [Role],
       Agents.AgentCategory AS [Category],
       IntUsersT.Name AS [Template]
FROM msit_IntUsers IntUsers
LEFT JOIN mstt_Agents Agents ON Agents.Code = IntUsers.AssociatedAgent
LEFT JOIN msit_IntUserTemplates Template ON IntUsers.ID = Template.UserID
LEFT JOIN msit_IntUsers IntUsersT ON Template.TemplateUserID = IntUsersT.ID
WHERE IntUsers.Name LIKE 'PTL%'
ORDER BY [PortalCode]
GO
