CREATE PROCEDURE [dbo].[cscp_ValidateBusinessStructure] @UserID VARCHAR(255), @BusinessType VARCHAR(1)
AS

-- 2.1 Categories 1, 2 & 3
SELECT Reasons.Code AS [Reason],
       Reasons.Description AS [ReasonForReporting],
       BusAgt.AgentTypeDescription AS [Business Type],
       BusAgt.CODE AS [Business Unique ID],
       BusAgt.DESCN AS [Business Name],
       BusAgt.AgentCategoryDescription AS [Business Category],
       Agt.AgentCategoryDescription AS [Agent Category],
       Agt.CODE AS [Agent Unique ID],
       Agt.DESCN AS [Agent Name],
       Agt.AgentTypeDescription AS [Agent Type],
       Agt.CompetentStatusDescription AS [Agent Status]
FROM DBO.cscf_61Reasons() Reasons
LEFT JOIN mstt_Agents BusAgt ON (BusAgt.AgentCategoryDescription = Reasons.AgentType1 OR
                                (Reasons.AgentType2 IS NOT NULL AND BusAgt.AgentCategoryDescription = Reasons.AgentType2))
                            AND BusAgt.CompetentStatus = 1
                            AND ((@BusinessType = 'N' AND BusAgt.AgentType IN (2,46)) OR
                                 (@BusinessType = 'F' AND BusAgt.AgentType = 2) OR
                                 (@BusinessType = 'A' AND BusAgt.AgentType = 46)
                                )
                            AND (SELECT COUNT(PrincipalAgt.Code)
                                 FROM mstt_Agents PrincipalAgt
                                 WHERE PrincipalAgt.Firm = BusAgt.Code
                                   AND PrincipalAgt.AgentType = 43 -- Principal
                                   AND PrincipalAgt.AgentCategory IN (Reasons.AgentCategory1, Reasons.AgentCategory2) -- specified categories
                                   AND PrincipalAgt.CompetentStatus = 1
                                ) < Reasons.Number -- less than specified number of active principals
LEFT JOIN mstt_Agents Agt ON Agt.Firm = BusAgt.Code 
                         AND Agt.AgentType <> 49 -- exclude directly authorised
                         AND Agt.Code <> BusAgt.Code -- exclude the actual business
WHERE Reasons.Code IN (1,2,3)

UNION ALL

-- 2.2 Category 4
SELECT Reasons.Code AS [Reason],
       Reasons.Description AS [ReasonForReporting],
       BusAgt.AgentTypeDescription AS [Business Type],
       BusAgt.CODE AS [Business Unique ID],
       BusAgt.DESCN AS [Business Name],
       BusAgt.AgentCategoryDescription AS [Business Category],
       Agt.AgentCategoryDescription AS [Agent Category],
       Agt.CODE AS [Agent Unique ID],
       Agt.DESCN AS [Agent Name],
       Agt.AgentTypeDescription AS [Agent Type],
       Agt.CompetentStatusDescription AS [Agent Status]
FROM DBO.cscf_61Reasons() Reasons
LEFT JOIN mstt_Agents BusAgt ON (BusAgt.AgentCategoryDescription = Reasons.AgentType1 OR
                                (Reasons.AgentType2 IS NOT NULL AND BusAgt.AgentCategoryDescription = Reasons.AgentType2))
                            AND BusAgt.CompetentStatus = 1
                            AND ((@BusinessType = 'N' AND BusAgt.AgentType IN (2,46)) OR
                                 (@BusinessType = 'F' AND BusAgt.AgentType = 2) OR
                                 (@BusinessType = 'A' AND BusAgt.AgentType = 46)
                                )
                            AND (SELECT COUNT(PrincipalAgt.Code)
                                 FROM mstt_Agents PrincipalAgt
                                 WHERE PrincipalAgt.Firm = BusAgt.Code
                                   AND PrincipalAgt.AgentType = 43 -- Principal
                                   AND PrincipalAgt.AgentCategory IN (Reasons.AgentCategory1, Reasons.AgentCategory2) -- specified categories
                                   AND PrincipalAgt.CompetentStatus = 1
                                ) > Reasons.Number -- more than specified number of active principals
LEFT JOIN mstt_Agents Agt ON Agt.Firm = BusAgt.Code 
                         AND Agt.AgentType <> 49 -- exclude directly authorised
                         AND Agt.Code <> BusAgt.Code -- exclude the actual business
WHERE Reasons.Code = 4

UNION ALL

-- 2.3 Category 5
SELECT Reasons.Code AS [Reason],
       Reasons.Description AS [ReasonForReporting],
       BusAgt.AgentTypeDescription AS [Business Type],
       BusAgt.CODE AS [Business Unique ID],
       BusAgt.DESCN AS [Business Name],
       BusAgt.AgentCategoryDescription AS [Business Category],
       Agt.AgentCategoryDescription AS [Agent Category],
       Agt.CODE AS [Agent Unique ID],
       Agt.DESCN AS [Agent Name],
       Agt.AgentTypeDescription AS [Agent Type],
       Agt.CompetentStatusDescription AS [Agent Status]
FROM DBO.cscf_61Reasons() Reasons
LEFT JOIN mstt_Agents BusAgt ON (BusAgt.AgentCategoryDescription = Reasons.AgentType1 OR
                                (Reasons.AgentType2 IS NOT NULL AND BusAgt.AgentCategoryDescription = Reasons.AgentType2))
                            AND BusAgt.CompetentStatus = 1
                            AND ((@BusinessType = 'N' AND BusAgt.AgentType IN (2,46)) OR
                                 (@BusinessType = 'F' AND BusAgt.AgentType = 2) OR
                                 (@BusinessType = 'A' AND BusAgt.AgentType = 46)
                                )
                            AND EXISTS (SELECT PrincipalAgt.Code
                                        FROM mstt_Agents PrincipalAgt
                                        WHERE PrincipalAgt.Firm = BusAgt.Code
                                          AND NOT (PrincipalAgt.AgentType = 43 -- Principal
                                               AND PrincipalAgt.AgentCategory IN (Reasons.AgentCategory1, Reasons.AgentCategory2) -- specified categories
                                            OR PrincipalAgt.AgentType IN (3,5)) -- Administrator, IAR
                                          AND PrincipalAgt.CompetentStatus = 1
                                       ) -- any invalid agent types
LEFT JOIN mstt_Agents Agt ON Agt.Firm = BusAgt.Code 
                         AND Agt.AgentType <> 49 -- exclude directly authorised
                         AND Agt.Code <> BusAgt.Code -- exclude the actual business
WHERE Reasons.Code = 5

UNION ALL

-- 2.4 Category 6
SELECT Reasons.Code AS [Reason],
       Reasons.Description AS [ReasonForReporting],
       BusAgt.AgentTypeDescription AS [Business Type],
       BusAgt.CODE AS [Business Unique ID],
       BusAgt.DESCN AS [Business Name],
       BusAgt.AgentCategoryDescription AS [Business Category],
       Agt.AgentCategoryDescription AS [Agent Category],
       Agt.CODE AS [Agent Unique ID],
       Agt.DESCN AS [Agent Name],
       Agt.AgentTypeDescription AS [Agent Type],
       Agt.CompetentStatusDescription AS [Agent Status]
FROM DBO.cscf_61Reasons() Reasons
LEFT JOIN mstt_Agents BusAgt ON (BusAgt.AgentCategoryDescription = Reasons.AgentType1 OR
                                (Reasons.AgentType2 IS NOT NULL AND BusAgt.AgentCategoryDescription = Reasons.AgentType2))
                            AND BusAgt.CompetentStatus = 1
                            AND ((@BusinessType = 'N' AND BusAgt.AgentType IN (2,46)) OR
                                 (@BusinessType = 'F' AND BusAgt.AgentType = 2) OR
                                 (@BusinessType = 'A' AND BusAgt.AgentType = 46)
                                )
                            AND NOT EXISTS (SELECT PrincipalAgt.Code
                                            FROM mstt_Agents PrincipalAgt
                                            WHERE PrincipalAgt.Firm = BusAgt.Code
                                              AND PrincipalAgt.AgentType = 43 -- Principal
                                              AND PrincipalAgt.AgentCategory IN (Reasons.AgentCategory1, Reasons.AgentCategory2) -- specified categories
                                              AND PrincipalAgt.CompetentStatus = 1
                                           ) -- no active Principals or PFA Principals
                            AND EXISTS (SELECT SellerAgt.Code
                                        FROM mstt_Agents SellerAgt
                                        WHERE SellerAgt.Firm = BusAgt.Code
                                          AND SellerAgt.GivesAdvice = 'Y'
                                          AND SellerAgt.CompetentStatus = 1
                                       ) -- any selling agents
LEFT JOIN mstt_Agents Agt ON Agt.Firm = BusAgt.Code 
                         AND Agt.AgentType <> 49 -- exclude directly authorised
                         AND Agt.Code <> BusAgt.Code -- exclude the actual business
WHERE Reasons.Code = 6

UNION ALL

-- 2.5 Category 7
SELECT Reasons.Code AS [Reason],
       Reasons.Description AS [ReasonForReporting],
       BusAgt.AgentTypeDescription AS [Business Type],
       BusAgt.CODE AS [Business Unique ID],
       BusAgt.DESCN AS [Business Name],
       BusAgt.AgentCategoryDescription AS [Business Category],
       Agt.AgentCategoryDescription AS [Agent Category],
       Agt.CODE AS [Agent Unique ID],
       Agt.DESCN AS [Agent Name],
       Agt.AgentTypeDescription AS [Agent Type],
       Agt.CompetentStatusDescription AS [Agent Status]
FROM DBO.cscf_61Reasons() Reasons
LEFT JOIN mstt_Agents BusAgt ON BusAgt.AgentCategoryDescription IN ('Practice', 'Sole Trader', 'Limited Liability Partnership', 'Partnership', 'Limited Company')
                            AND BusAgt.CompetentStatus = 1
                            AND ((@BusinessType = 'N' AND BusAgt.AgentType IN (2,46)) OR
                                 (@BusinessType = 'F' AND BusAgt.AgentType = 2) OR
                                 (@BusinessType = 'A' AND BusAgt.AgentType = 46)
                                )
                            AND NOT EXISTS (SELECT SellerAgt.Code
                                            FROM mstt_Agents SellerAgt
                                            WHERE SellerAgt.Firm = BusAgt.Code
                                              AND SellerAgt.GivesAdvice = 'Y'
                                              AND SellerAgt.CompetentStatus = 1
                                       ) -- no selling agents
LEFT JOIN mstt_Agents Agt ON Agt.Firm = BusAgt.Code 
                         AND Agt.AgentType <> 49 -- exclude directly authorised
                         AND Agt.Code <> BusAgt.Code -- exclude the actual business
WHERE Reasons.Code = 7

ORDER BY Reason, BusAgt.CODE, Agt.CODE


GO
