CREATE PROCEDURE [dbo].[cscp_WorkflowExceptions] @UserID VARCHAR(255)
AS

SELECT 'Users not in Teams without associated Adviser Id' AS [HEADING1],
IntUsers.Description AS [Description],
IntUsers.Name AS [Name],
' ' AS [UniqueID],
' ' AS [Role],
' ' AS [Status],
Users.Name AS [Team]
FROM msit_IntUsers IntUsers
LEFT JOIN msit_IntTeamUsers TeamUsers ON IntUsers.Id = TeamUsers.UserID
LEFT JOIN msit_IntUserTemplates Templates ON IntUsers.Id = Templates.UserID
LEFT JOIN msit_IntUsers Users ON Templates.TemplateUserID = Users.ID
WHERE (IntUsers.AssociatedAgent IS NULL OR IntUsers.AssociatedAgent = ' ')
AND TeamUsers.UserID IS NULL
AND LEFT(IntUsers.Name,3) = 'ptl'

UNION ALL

SELECT 'Users in Teams with associated  Adviser Id' AS [HEADING2],
IntUsers.Description,
IntUsers.Name,
IntUsers.AssociatedAgent AS [UniqueID],
Agents.AgentCategory AS [Role],
Agents.CompetentStatusDescription AS [Status],
Teams.Name AS [Team]
FROM msit_IntUsers IntUsers
INNER JOIN mstt_Agents Agents ON IntUsers.AssociatedAgent = Agents.Code
INNER JOIN msit_IntTeamUsers TeamUsers ON IntUsers.ID = TeamUsers.UserID
LEFT JOIN msit_IntTeams Teams ON TeamUsers.TeamId = Teams.ID
WHERE (IntUsers.AssociatedAgent IS NOT NULL AND IntUsers.AssociatedAgent <> ' ')
AND LEFT(IntUsers.Name,3) = 'ptl'
AND Agents.AgentType <>17


GO
